//频道排行组件
import dome from "../../templates/Jxranking.ejs";
import { ControlEditor } from "../../../../editor/ControlEditor";
import { map } from "../../../../decorator/controlmap";

@map("排行", "nc.ncctrl.jxranking", "Jxranking")
export class Jxranking extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.headerName = "专题排行";
    this.moreUrl = "";
    this.numIcon = "1";
    this.listDataImg = [];
    this.listData = [];
    this.httpUrl = "/yyzx/pdgl/homePageFiveRanking";
    //字体颜色
    this.fontColor = "";
    this.columns = [
      {
        link: "",
        id: "",
        param2: "",
        param1: "",
      },
    ];
  }
  initTemplate() {
    return dome(this);
  }
  renderContext(refresh) {
    super.renderContext();
    this.root.event.on(PageEvent.READY, (args) => {
      this._handlers.headerLeft.html(this.headerName);
      this.changeIcon();
      this.updateData();
    });
  }
  renderReady() {
    super.renderReady();
  }
  //注册事件
  initEvent() {
    let that = this;
    this.element.on("click.ds_jx_headerMore", ".ds_jx_headerMore", function() {
      //登录权限设置
      let userId = dsf.getCookie("userId");
      if (!userId) {
        window.parent.openLogin();
        return;
      }
      self.location.href = dsf.url.getWebPath($(this).attr("_href"));
    });
    this.element.on("click", ".readMore", function() {
      that.isLogin($(this).data("link"));
    });
  }
  isLogin(url) {
    //登录权限设置
    let userId = dsf.getCookie("userId");
    if (!userId) {
      window.parent.openLogin();
      return;
    }
    if (!url) {
      return;
    }
    if (url.indexOf("http://") !== -1 || url.indexOf("https://") !== -1) {
      window.open(url);
    } else {
      window.open(dsf.url.getWebPath(url));
    }
  }
  changeColor() {
    if (this.fontColor) {
      this._handlers.headerLeft.css({ color: this.fontColor });
      this._handlers.moreUrl.css({ color: this.fontColor });
      this._handlers.left.css({ background: this.fontColor });
      let that = this;
      this.element.find(".list ul").hover(
        function() {
          $(this)
            .find(".item_li")
            .css("color", that.fontColor);
        },
        function() {
          $(this)
            .find(".item_li")
            .css("color", "#333");
        }
      );
    }
  }
  get _numIcon() {
    return this.numIcon;
  }
  set _numIcon(val) {
    this.numIcon = val;
    this.changeIcon();
    this.updateData();
  }
  //自定义事件--切换背景icon
  changeIcon() {
    // let arr = new Array(3).fill(0);
    let arr = [0, 0, 0];
    arr.forEach((item, index) => {
      let string = "tbg";
      if (Number(this.numIcon) !== 1) {
        string = "jiangbei";
      }
      arr[index] = dsf.url.getWebPath(
        `/res/dsf_styles/themes/nc/jx/${string}${index + 1}.png`
      );
    });
    this.listDataImg = arr;
  }
  //参数设置
  // renderClassColumns() {
  //   console.log(this.$columns);
  // }
  get _columns() {
    return this.columns;
  }
  set _columns(val) {
    this.columns = val;
    this.updateData();
  }
  get _httpUrl() {
    return this.httpUrl;
  }
  set _httpUrl(url) {
    this.httpUrl = url;
    this.updateData();
  }
  //接口调用
  updateData() {
    let loadding = dsf.layer.loadding();
    dsf.http
      .request(dsf.url.getWebPath(this.httpUrl), {}, "GET")
      .done((response) => {
        if (response.state === 20000) {
          let res = response.data;
          res.length &&
            res.forEach((item, index) => {
              item.imgUrl = this.listDataImg[index];
            });
          this.listData = res;
          this.renderHtml();
        } else {
          dsf.layer.message("加载数据出错", false);
        }
      })
      .error(function(response) {
        dsf.layer.message("加载数据出错", false);
      })
      .always(function() {
        dsf.layer.close(loadding);
      })
      .exec();
  }
  //渲染html
  renderHtml() {
    let html = "";
    if (this.listData && this.listData.length) {
      this.listData.forEach((item, index) => {
        let link = this.columns[0].link || "";
        let indexDom = index < 3 ? `<img src="${item.imgUrl}"/>` : index + 1;
        html += `
          <ul>
            <div data-link='${link}${link.indexOf("?") !== -1 ? "&" : "?"}id=${
          item[this.columns[0].id]
        }' class='readMore'>
            <li class='item_li'>
                <div class="ds_jx_num">
                ${indexDom}
                </div>
                <div class="ds_jx_featlist">${item[this.columns[0].param1] ||
                  ""}</div>
                <div class="ds_jx_freq">${item[this.columns[0].param2] ||
                  0}</div>
            </li>
          </div>
        </ul>
        `;
      });
    } else {
      html = `
        <div style="text-align: center; padding: 75px 0;"><img src=${dsf.url.getWebPath(
          "/res/dsf_styles/themes/img/nodata.png"
        )}></div>
      `;
    }
    this._handlers.listHandler.html(html);
    this.changeColor();
  }
}
