import dome from '../templates/NcNmDetail.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map('内蒙详情', 'nc.teas.nmdetail', 'NcNmDetail')

export class NcNmDetail extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this._desingerClass = ControlEditor;
		this.getUrlType = dsf.url.queryString('type');
		this.indexUrl = "/dsfa/nc/pc/main/views/main.html";

		this.isShowTitle = true;
	}

	initTemplate() {
		return dome(this);
	}

	createElement() { // 创建控件的html元素对象,自动调用initTemplate
		super.createElement();
		this.detailTitleBar = this._handlers.titleBar
	}

	renderContext() {
		super.renderContext();
		if (this._root._isDesign) {
			this.renderdefaultPage();
		} else {
			this.getDetail();
		}
		let titleBarStr = '';
		this.getUrlType = dsf.url.queryString('type');
		if (this.getUrlType == 'base_show') {
			titleBarStr = '<span id="index">首页</span><i class="dot"></i><span id="ziyuan">资源中心</span><i class="dot"></i><span id="baseShow">基地展示</span>';
		} else if (this.getUrlType == 'good_course') {
			titleBarStr = '<span id="index">首页</span><i class="dot"></i><span id="ziyuan">资源中心</span><i class="dot"></i><span id="goodCourse">好课程</span>';
		} else if (this.getUrlType == 'information') {
			titleBarStr = '<span id="index">首页</span><i class="dot"></i><span id="ziyuan">资源中心</span><i class="dot"></i><span id="information">资料</span>';
		} else if (this.getUrlType == 'tzgg') {
			titleBarStr = '<span id="index">首页</span><i class="dot"></i><span id="notice">公告</span>';
		} else {
			titleBarStr = '<span id="index">首页</span><i class="dot"></i><span id="notice">公告</span>';
		}
		this.detailTitleBar.html(titleBarStr);
		this.detailTitleBar.on("click", "#index", $.proxy(this.clickIndex, this)); // 点击首页
		this.detailTitleBar.on("click", "#ziyuan", $.proxy(this.clickResource, this)); // 点击资源中心
		// this.detailTitleBar.on("click", "#notice", $.proxy(this.clickNotice, this)); //点击公告

		if (this.getUrlType == 'instruction') {
			this.detailTitleBar.remove();
		}

	};

	renderReady() {
		super.renderReady();
	}

	//点击首页
	clickIndex() {
		var elid = $(window.parent.document).find("#J_content");
		$(elid).attr(
			"src",
			dsf.url.getWebPath(
				"/nc/mhsy/views/sy_nmnc.html")
		)
		// let url = dsf.url.getWebPath("/nc/pc/main/views/main.html")
		// dsf.openUrl(1, url);
	}
	// 点击资源中心
	clickResource() {
		var elid = $(window.parent.document).find("#J_content");
		var url;
		this.getUrlType = dsf.url.queryString('type');
		switch(this.getUrlType) {
			case "information":
				url =	"/nc/mhsy/views/xw.html?gitTitle=资料&newlmld=f8283c9dc8b843d29b7f1702bd2edd40";
				break;
			case "good_course":
				url = "/nc/news/views/good_course.html";
				break;
			case "base_show":
				url = "/nc/news/views/base_show.html";
				break;
			default: 
				url = "/nc/kck/mhkc/views/kclb.html?foot=1";
				break;
		}
		$(elid).attr( "src", dsf.url.getWebPath(url) );
		var elid = $(window.parent.document).find("#J_content");
		
		// url = "/nc/mhsy/views/xw.html?gitTitle=资料&newlmld=f8283c9dc8b843d29b7f1702bd2edd40";
		// $(elid).attr( "src", dsf.url.getWebPath( url) )
	}
	// 点击公告
	// clickNotice() {
	// 	var elid = $(window.parent.document).find("#J_content");
	// 	$(elid).attr(
	// 		"src",
	// 		dsf.url.getWebPath(
	// 			"/nc/news/views/notice_list.html")
	// 	)
	// }

	getDetail() {
		let loading = dsf.layer.loadding();
		let url = 'nc/news/findNewsDetail';
		let sourceUrl = dsf.url.getWebPath(url);
		let params = {
			id: dsf.url.queryString('id') || 'cbd2121e74c84972934631789bc1d9a9',
			preview: dsf.url.queryString('preview') || '',
		};
		dsf.http.request(sourceUrl, params, 'Get')
			.done((res) => {
				if (res.success && res.state == 20000) {
					this.renderPage(res.data);
				} else {
					dsf.layer.message('请求失败4');
				}
			})
			.error((err) => {
				dsf.layer.message('接口异常,请稍后重试', false);
			})
			.always(() => {
				dsf.layer.close(loading)
			}).exec();
	}

	// 详情DOM
	renderPage(data) {
		let listStr = '';
	  if(data && !data.content){
			listStr = '<h5 class="news_title">' + data.name + '</h5>\n' +
			'        <div class="news_info" id="news_info">\n' +
			'            <span><i id="news_info_icon"></i>' + (data.time ? data.time : '暂无') + '</span>\n' +
			'            <span><i></i>' + (data.llcs ? data.llcs : '暂无') + '</span>\n' +
			'        </div>\n' +
			'        <div class="news_contnet">暂无数据</div>';
		}else	if (data) {
			listStr = '<h5 class="news_title">' + data.name + '</h5>\n' +
				'        <div class="news_info" id="news_info">\n' +
				'            <span><i id="news_info_icon"></i>' + (data.time ? data.time : '暂无') + '</span>\n' +
				'            <span><i></i>' + (data.llcs ? data.llcs : '暂无') + '</span>\n' +
				'        </div>\n' +
				'        <div class="news_contnet">\n' +
				'            ' + data.content+ '\n' +
				'        </div>';
		}else {
			listStr = "<div class='have_not_data'>暂无数据</div>";
			this._handlers['newsWrap'].css({ 'text-align': 'center' });
		}
		this._handlers['newsWrap'].html(listStr);
		// this.buttonsClick();

		if (this.getUrlType == 'tzgg') { // 公告
			$('#news_info_icon').addClass("time_icon");
		}
		if (this.getUrlType == 'good_course') { // 好课程
			$('#news_info_icon').addClass("ren_icon");
		}
		if (this.getUrlType == 'base_show' || this.getUrlType == 'information') { // 基地展示、资料
			$('#news_info').remove();
		}

		if (this.getUrlType == 'instruction') {
			$('#news_info').remove();
			this.detailTitleBar.remove();
		}
	}
	// 默认详情DOM
	renderdefaultPage() {
		let list = '<h5 class="news_title">今年以来习近平总书记国内考察纪实</h5>\n' +
			'        <div class="news_info">\n' +
			'            <span><i class="icon iconfont icon-shijian"></i>2019-08-09</span>\n' +
			'            <span><i class="icon iconfont icon-yanjing"></i>10254</span>\n' +
			'        </div>\n' +
			'        <div class="news_contnet">\n' +
			'            今年是中朝建交70周年。在这个历史性时刻，应朝鲜劳动党委员长、国务委员会委员长金正恩同志邀请，我怀着“传承友谊、续写新篇”的美好愿望，即将对朝鲜民主主义人民共和国进行国事访问。回想当年，两党两国老一辈领导人怀着共同的理想信念和深厚的革命友谊，携手缔造了中朝传统友谊，为我们留下了共同的宝贵财富。中朝几代领导人一直保持着密切交往，就传承中朝传统友谊、造福两国人民深入沟通、真诚合作，书写了国际关系史上的佳话。长期以来，在中朝两党坚强领导下，不论是在共同反对外来侵略、争取国 家独立和民族解放的斗争中，还是在开展社会主义革命和建设事业中，两国人民都彼此信赖，相互支持，相互帮助，结下了深厚友情，可以说是“历久弥坚金不换”。 亲望亲好，邻望邻好。作为好同志、好邻居，无论国际风云如何变幻，中国党和政府巩固发展中朝友好合作关系的坚定立场都没有变也不会变，中方将坚定支持金正恩委员长带领朝鲜党和人民贯彻落实新战略路线，集中精力发展经济、改善民生，推动朝鲜社会主义建设取得新的更大成就。\n' +
			'        </div>';
		this._handlers['newsWrap'].html(list);
	}
}
