import dome from "../templates/Ncstudentlist.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("学员列", "nc.teas.ncstudentlist", "Ncstudentlist")
export class Ncstudentlist extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.moresrc = "";
    this.listColor = "#D60C0C"; //分隔条颜色
    this.parms = {
      pageNum: "1",
      pageSize: 5,
    };
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    if (this._root._isDesign) {
    } else {
      this.parms.ztbId = parent.rparms.ztbid || "";
    }
  }

  renderContext(refresh) {
    super.renderContext();
    this.changeColor();
  }
  changeColor() {
    let dom = $($(".nc_studentlist .titlebox i")[0]);
    console.log(dom);
    if (!this.listColor) {
      dom.addClass("commonBgColor");
    } else {
      dom.removeClass("commonBgColor");
      dom.css({
        "background-color": this.listColor,
      });
    }
  }
  showlist() {
    let _this = this;
    let url = dsf.url.getWebPath("nc/xxgl/xys/findXysByZtbId");
    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          let shtml = "",
            sd = data.data;
          _this.$studentlist = _this._handlers["studentlist"];
          console.log(sd);
          if (sd.length == 0) {
            shtml =
              '<div style="text-align: center; padding: 30px 0;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"></div>';
          } else {
            for (var i = 0, len = sd.length; i < len; i++) {
              shtml +=
                `<div class="stuspeakitem jsstuspeakitem" id="` +
                sd[i].id +
                `">
												<span class="ell">` +
                (sd[i].name == null ? "" : sd[i].name) +
                `</span><p class="ell" title="` +
                (sd[i].title == null ? "" : sd[i].title) +
                `">` +
                (sd[i].title == null ? "" : sd[i].title) +
                `</p>
											</div>`;
            }
          }
          _this.$studentlist.html(shtml);
          _this.$studentlist.find(".jsstuspeakitem").click(function() {
            let id = $(this).attr("id");
            if (id) {
              var ur = dsf.url.getWebPath("nc/mhsy/views/xysxq.html?id=" + id);
              dsf.openUrl(1, ur);
            } else {
              layer.msg("id异常", { icon: 0, time: 2000 });
            }
          });
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {})
      .exec();
  }
  morecl() {
    let _this = this;
    _this.$jsstumore = _this._handlers["jsstumore"];
    _this.$jsstumore.click(function() {
      let urls = dsf.url.getWebPath(_this.moresrc);
      dsf.openUrl(1, urls);
    });
  }
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
    this.showlist();
    this.morecl();
  }
  initEvent() {}
}
