import dome from "../templates/NcAChannel.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("首页学堂频道", "nc.teas.achannel", "NcAChannel")
export class NcAChannel extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.$useVdom = true;

      this.$test = [];
      this.sdata = {
         titleicon: "/res/dsf_styles/themes/styleClass/channelicon.png", //标题图片
         titleText: "频道",
         titleTextcolor: "",
         isshowBar: false, //是否显示菜单
         issBarcoloract: "#FF6A00", //菜单选中色

         borderstyle: "#fdc8c8 2px dotted", //边框样式
         gtitlebg: "#fff", //头部整栏背景
         titletxtbgcolor: '#da0000',
         titletxtbgl: "/res/dsf_styles/themes/nc/nm/tit-left.png", //标题文字背景
         titletxtbgr: "/res/dsf_styles/themes/nc/nm/tit-right.png", //标题文字背景
         morebtnbg: "#fff,/res/dsf_styles/themes/nc/nm/more01.png",//更多按钮的背景
         moretext: '更多',

         isshowChooseBtn: true, //是否显示操作按钮
         Btntext: "按钮名称", //操作按钮文本
         Btnurl: "", //操作按钮链接

         ismoreBtn: true, //是否显示更多按钮
         moreBtnUrl: "nc/kck/mhkc/views/kclb.html", //更多按钮链接
         moreBtnColor: "", //更多按钮颜色

      };
      //		主要内容
      this.parms = {
         title: "",
         pageNo: 1,
         pageSize: 6,
         typeValue: "01",
      };
      this.$pageSize = 6;


      //		点击某一项需跳转的页面路由
      this.$detailUrl = "nc/pc/channelDetail/views/channelDetail.html";
      this.$baractnum = 1;
   }


   set pageSize(val) {
      this.$paseSize = val;
      this.parms.pageSize = this.$paseSize;
   }

   get pageSize() {
      return this.$pageSize;
   }


   initTemplate() {
      return dome(this);
   }

   createElement() {
      super.createElement();
   }

   renderContext(refresh) {
      super.renderContext();
      if (this._root._isDesign) {	//配置页面

         if (this.sdata.titleicon == "") {
            this._handlers.jstitleicon.parents(".titimgbox").hide();
         } else {
            this._handlers.jstitleicon.parents(".titimgbox").show();
            this._handlers.jstitleicon.attr("src", dsf.url.getWebPath(this.sdata.titleicon));
         }
         this._handlers.jstitletext.find("span").text(this.sdata.titleText);
         //    文字显示区域
         this._handlers.jstitletext.find("span").css({
            "color": this.sdata.titleTextcolor,
            "background": this.sdata.titletxtbgcolor,
         })


         if (this.sdata.titletxtbgl == '' || this.sdata.titletxtbgr == '') {//如果没有配置图片就去掉边距
            this._handlers.jstitletext.find("span").css('padding', 0)
            this._handlers.jstitletext.css('padding', 0)
         }
         this._handlers.jstitletext.css({
            "background": ' url(' + dsf.url.getWebPath(this.sdata.titletxtbgl) + ') no-repeat,'
               + 'url(' + dsf.url.getWebPath(this.sdata.titletxtbgr) + ') no-repeat 100% 0',
         });
         this._handlers.jstitlebox.css({
            "border": this.sdata.borderstyle,
            "background": this.sdata.gtitlebg,
         });
         // let morearr=this.sdata.morebtnbg.split(',');
         let morearr = this.sdata.morebtnbg ? this.sdata.morebtnbg.split(',') : [];
         // this._handlers.jsmorebtn.css({
         // 	"color": this.sdata.moreBtnColor,
         // 	"background": morearr[0] +' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
         // 	"background-size":'100% 100%'
         // });
         if (morearr.length > 1) {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
               "background-size": '100% 100%'
            });
         } else {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath('/res/dsf_styles/themes/nc/nm/more01.png') + ') no-repeat',
               "background-size": '100% 100%'
            });
         }
      } else {             //预览时
         if (this.sdata.titleicon == "") {
            this._handlers.jstitleicon.parents(".titimgbox").hide();
         } else {
            this._handlers.jstitleicon.parents(".titimgbox").show();
            this._handlers.jstitleicon.attr("src", dsf.url.getWebPath(this.sdata.titleicon));
         }
         this._handlers.jstitletext.find("span").text(this.sdata.titleText);
         //    文字显示区域
         this._handlers.jstitletext.find("span").css({
            "color": this.sdata.titleTextcolor,
            "background": this.sdata.titletxtbgcolor,
         })


         if (this.sdata.titletxtbgl == '' || this.sdata.titletxtbgr == '') {//如果没有配置图片就去掉边距
            this._handlers.jstitletext.find("span").css('padding', 0)
            this._handlers.jstitletext.css('padding', 0)
         }
         this._handlers.jstitletext.css({
            "background": ' url(' + dsf.url.getWebPath(this.sdata.titletxtbgl) + ') no-repeat,'
               + 'url(' + dsf.url.getWebPath(this.sdata.titletxtbgr) + ') no-repeat 100% 0',
         });
         this._handlers.jstitlebox.css({
            "border": this.sdata.borderstyle,
            "background": this.sdata.gtitlebg,
         });
         // let morearr=this.sdata.morebtnbg.split(',');
         let morearr = this.sdata.morebtnbg ? this.sdata.morebtnbg.split(',') : [];
         // this._handlers.jsmorebtn.css({
         // 	"color": this.sdata.moreBtnColor,
         // 	"background": morearr[0] +' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
         // 	"background-size":'100% 100%'
         // });
         if (morearr.length > 1) {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
               "background-size": '100% 100%'
            });
         } else {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath('/res/dsf_styles/themes/nc/nm/more01.png') + ') no-repeat',
               "background-size": '100% 100%'
            });
         }

         this.isshowChooseBtnfun();
         this.isshowMoreBtnfun();

         if (this._root._isDesign) {
            this.ncchannelListDemo();
         } else {
            this.ncchannelList();
         }
      };
   }
   renderReady() {
      //组件加载完成后执行
      super.renderReady();
      this.root.event.on(PageEvent.READY, (args) => {
         this.sdata.aitemHoverColor = this.sdata.aitemHoverColor === undefined ? "#FF6A00" : this.sdata.aitemHoverColor;
         this.changeColor();
      });
   }
   initEvent() { }

   changeColor() {
      const _this = this;
      this._handlers.jschannerlist.find(".aitem").hover(
         function () {
            $(this)
               .children(".rightcontent")
               .css("background-color", _this.sdata.aitemHoverColor || "transparent");
            $(this)
               .find(".colorb")
               .css("border-right-color", _this.sdata.aitemHoverColor || "transparent");
            if (!_this.sdata.aitemHoverColor || _this.sdata.aitemHoverColor === "#fff" || _this.sdata.aitemHoverColor === "#ffffff") {
               $(this)
                  .find(".rightcontent, .right-tit, .channer-text, .cnumbox span")
                  .css("color", "#333333");
            } else {
               $(this)
                  .find(".rightcontent, .right-tit, .channer-text, .cnumbox span")
                  .css("color", "#ffffff");
            }
         },
         function () {
            $(this)
               .children(".rightcontent")
               .css("background-color", "transparent");
            $(this)
               .find(".colorb")
               .css("border-right-color", "transparent");
            $(this)
               .find(".rightcontent, .right-tit, .channer-text, .cnumbox span")
               .css("color", "#333333");
         }
      );
   }
   // 配置项----------------------------------------------------------
   //是否显示操作按钮
   isshowChooseBtnfun() {
      console.log(this.sdata.isshowChooseBtn);
      let _this = this;
      _this.$jschoosebtn = _this._handlers["jschoosebtn"];
      if (this.sdata.isshowChooseBtn) {
         _this.$jschoosebtn.removeClass("none");
      } else {
         _this.$jschoosebtn.addClass("none");
      }
      _this.$jschoosebtn.click(function () {
         let url = dsf.url.getWebPath(_this.sdata.Btnurl);
         dsf.openUrl(1, url);
         // window.location.href = dsf.url.getAbsolutePath(url);
      });
   }
   //是否显示更多按钮
   isshowMoreBtnfun() {
      let _this = this;
      _this.$jsmorebtn = _this._handlers["jsmorebtn"];
      if (this.sdata.ismoreBtn) {
         _this.$jsmorebtn.removeClass("none");
      } else {
         _this.$jsmorebtn.addClass("none");
      }
      _this._handlers["jsmorebtn"].click(function (evt) {
         let userId = dsf.getCookie("userId");
         if (!userId) {
            window.parent.openLogin();
            evt.preventDefault();
         }
         //  else {
         // 	let path = dsf.url.getWebPath(_this.sdata.moreBtnUrl);
         // 	dsf.openUrl(1, path)
         // }
      });
   }
   set detailurlfun(v) {
      this.$detailUrl = v;
      this.domUpdate();
   }
   get detailurlfun() {
      return this.$detailUrl;
   }
   set labelcolor(v) {
      this.plancoursedata.labelcolor = v;
      this.domUpdate();
   }
   get labelcolor() {
      return this.plancoursedata.labelcolor;
   }

   set btncolor(v) {
      this.plancoursedata.btncolor = v;
   }
   get btncolor() {
      return this.plancoursedata.btncolor;
   }


   set baract(v) {
      this.$baractnum = v;
      this.domUpdate();
   }
   get baract() {
      return this.$baractnum;
   }
   //新增配置项
   set gtitheight(v) {
      this.sdata.titheight = v;
      this.domUpdate();
   }
   get gtitheight() {
      return this.sdata.titheight;
   }

   set gtitleborder(v) {
      this.sdata.borderstyle = v;
      this.domUpdate();
   }
   get gtitleborder() {
      return this.sdata.borderstyle;
   }

   set gtitlebg(v) {
      this.sdata.gtitlebg = v;
      this.domUpdate();
   }
   get gtitlebg() {
      return this.sdata.gtitlebg;
   }


   set gtitletxtbgcolor(v) {
      this.sdata.titletxtbgcolor = v;
      this.domUpdate();
   }
   get gtitletxtbgcolor() {
      return this.sdata.titletxtbgcolor;
   }


   set gtitletxtbgl(v) {
      this.sdata.titletxtbgl = v;
      this.domUpdate();
   }
   get gtitletxtbgl() {
      return this.sdata.titletxtbgl;
   }

   set gtitletxtbgr(v) {
      this.sdata.titletxtbgr = v;
      this.domUpdate();
   }
   get gtitletxtbgr() {
      return this.sdata.titletxtbgr;
   }

   set gmorebtnbg(v) {
      this.sdata.morebtnbg = v;
      this.domUpdate();
   }
   get gmorebtnbg() {
      return this.sdata.morebtnbg;
   }

   set gmoretext(v) {
      this.sdata.moretext = v;
      this.domUpdate();
   }
   get gmoretext() {
      return this.sdata.moretext;
   }


   //配置项----------------------------------------------------------end

   geturls(cover) {
      let urls = "";
      if (cover) {
         let cov = JSON.parse(cover);
         if ($.isArray(cov)) {
            urls = cov[0].relativePath;
         }
      } else {
         urls = "res/dsf_styles/themes/nc/404.png";
      }
      return urls;
   }
   ncchannelList() {
      let loading = dsf.layer.loadding();
      let _this = this;
      let url = dsf.url.getWebPath("yyzx/pdgl/pdglList");
      dsf.http
         .request_sync(url, _this.parms, "get")
         .done(function (data) {
            if (data.state == 20000) {
               let sd = data.data.list,
                  shtml = "";
               _this.$jschannerlist = _this._handlers["jschannerlist"];
               console.log(sd);
               if (sd.length > 0) {
                  for (var i = 0, len = sd.length; i < len; i++) {
                     let urls = _this.geturls(sd[i].cover);
                     shtml +=
                        `<div class="aitem" id="` +
                        sd[i].nc_zyb_id +
                        `">
								   		<div class="imgbox"><img src="` +
                        dsf.url.getWebPath(urls) +
                        `" onerror="onerror=null;src='` +
                        dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") +
                        `'" data-adaptive-background="1" data-description="grandpa" /></div>
								   		<div class="rightcontent">
								   			<div class="right-tit ell">` +
                        sd[i].title +
                        `</div>
								   			<div class="channer-text ell2">
								   				<p>` +
                        (sd[i].abstract == null ? "" : sd[i].abstract) +
                        `</p>
								   			</div>
								   			<div class="cnumbox">
								   				<i class="iconfont icon-icon_yulan"></i><span>` +
                        (sd[i].djs == null ? "0" : sd[i].djs) +
                        `</span>
								   			</div>
								   			<b class="colorb b1"></b><b class="colorb b2"></b>
								   		</div>
								   </div>`;
                  }
               } else {
                  shtml += '<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>';
               }
               _this.$jschannerlist.html(shtml);
               _this.$jschannerlist.find(".aitem").click(function () {
                  let id = $(this).attr("id");
                  let userId = dsf.getCookie("userId");
                  if (!userId) {
                     window.parent.openLogin();
                     return;
                  }
                  dsf.openUrl(1, dsf.url.getWebPath(_this.$detailUrl + "?id=") + id);
               });
            }
         })
         .error(function (err) {
            console.log(err);
         })
         .always(function () {
            dsf.layer.close(loading);
         })
         .exec();
   }
   ncchannelListDemo() {
      let shtml = "";
      for (var i = 0, len = 6; i < len; i++) {
         shtml += `<div class="aitem">
				   		<div class="imgbox"><img src="/dsfa/res/dsf_styles/themes/nc/404.png" alt=""></div>
				   		<div class="rightcontent">
				   			<div class="right-tit ell">数字化助推“中国之治”数字化助推“中国之治”数字化助推“中国之治”数字化助推“中国之治”数字化助推“中国之治”</div>
				   			<div class="channer-text ell2">
				   				<p>国务院发文延长春节假期，众多企业纷纷响应国家号召，推迟上班时间或采取国务院发文延长春节假期，众多企业纷纷响应国家号召，推迟上班时间或采取国务院发文延长春节假期，众多企业纷纷响应国家号召，推迟上班时间或采取</p>
				   			</div>
				   			<div class="cnumbox">
				   				<i class="iconfont icon-icon_yulan"></i><span>10254</span>
				   			</div>
				   		</div>
				   </div>`;
      }
      this._handlers.jschannerlist.html(shtml);
   }
}
