import dome from '../templates/NcANmkecheng.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map('蒙语课程', 'nc.teas.anmkecheng', 'NcANmkecheng')
export class NcANmkecheng extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.errimg = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.type = '';
    this.total = 0;
    this.parms = {
      pageNum: 1,
      pageSize: 5,
      namespace: 'nc.mongolianCourse',
      pageName: 'dataList',
      query: JSON.stringify({
        searchValue: '',
        // dsfa_cms_cm_id: '1a4671a86d144d98a3ccb9f02934a691',
      }),
    };
    this.dsfa_id = '1a4671a86d144d98a3ccb9f02934a691';
    this.isShowSearch = false;
    this.common = {};
    this.title = '蒙语课程';
    this.logoIcon = '/res/dsf_styles/themes/nc/i-zy6.png'; // 默认的标识图标路径;
    this.searchIcon = '/res/dsf_styles/themes/nc/sousuo02.png'; // 默认的搜索图标路径;
    this.labelColor = '#C90C0A'; //默认的标签颜色;
    this.borderColor = '#C90C0A'; //默认的标签边框颜色;
    this.logoColor = '#C90C0A';
    this.searchColor = '#C90C0A';
    this.newslistboxId = 'roomlist__' + parseInt(Math.random() * 99999999);
    this.leftboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
    this.rightboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
  }

  initTemplate() {
    return dome(this);
  }
  getlist() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('meta/list/data'); //
    dsf.http
      .request_sync(url, _this.parms, 'get')
      .done(function(res) {
        if (res.state == 20000) {
          _this.common = [...res.data];
          _this.recentNewslist();
        } else if (res.state == 20001) {
          layui.use('layer', function() {
            layer.msg(res.message, { icon: 0, time: 2000 });
          });
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();

    dsf.http
      .request_sync(dsf.url.getWebPath('meta/list/count'), _this.parms, 'get')
      .done(function(res) {
        if (res.state == 20000) {
          _this.total = res.data.count;
        } else if (res.state == 20001) {
          layui.use('layer', function() {
            layer.msg(res.message, { icon: 0, time: 2000 });
          });
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }
  createElement() {
    super.createElement();
    this._handlers.title.html(dsf.url.queryString('gitTitle') || this.title);
    this._handlers.newsinp.attr('placeholder', dsf.url.queryString('placeholder') || '请输入');
  }

  renderContext(refresh) {
    super.renderContext();
  }
  geturls(cover) {
    let urls = '';
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
    } else {
      urls = 'res/dsf_styles/themes/nc/404.png';
    }
    return urls;
  }
  getbtns(arr) {
    let shtml = '';
    if (arr && arr.length > 0) {
      for (var i = 0, len = arr.length; i < len; i++) {
        shtml +=
          '<button type="button"  class="jschannelbtn layui-btn layui-btn-sm layui-btn-primary">' +
          arr[i] +
          '</button>';
      }
    }
    return shtml;
  }

  recentNewslist() {
    let _this = this,
      shtml = '',
      isaddHtml = '',
      sd = this.common; // this.common.list;
    _this.$newslistbox = _this._handlers['newslistbox'];
    if (sd.length == 0) {
      _this.$newslistbox.html(
        "<div style='text-align: center; margin: 20px;'><img src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"
      );
      $('#demo2').hide();
      return false;
    }
    _this.type = sd.length > 0 ? sd[0]['nc_news_matchCmDataSource.cms_cm_code'] : '';

    {
      const common_key = 'nc_mongolianCourse_datasource.';
      for (var i = 0, len = sd.length; i < len; i++) {
        let v = sd[i];
        let urls = _this.geturls(v[common_key + 'cover']);

        if (v.SFJRZX == 0) {
          isaddHtml = `<span class="jsadd act">加入在学</span>`;
        } else {
          isaddHtml = ``;
        }
        shtml += `<div class="aitem" id="${v['_id']}">
            <div class="aimgbox">
				      <img src="${dsf.url.getWebPath(urls)}" data-adaptive-background="1" data-description="grandpa"
				        onerror="onerror=null;this.src='${dsf.url.getWebPath(
                  'res/dsf_styles/themes/nc/404.png'
                )}'"/>
							<div class="imgtext">
							  <div class="choosebox">
								  <span class="choose1" style="display: ${v[common_key + 'kcfs'] ? 'inline-block' : 'none'}">
								    ${v[common_key + 'kcfs'] ? v[common_key + 'kcfs'] : ''}
								  </span>
									<span class="choose2" style="display: ${
                    v[common_key + 'sfbx'] == '1' ? 'inline-block' : 'none'
                  }">必</span>
									<span class="choose3" style="display: ${
                    v[common_key + 'sfnew'] == 1 ? 'inline-block' : 'none'
                  }">新</span>
							  </div>
								<div class="timecenter">
									<b class="iconfont icon1 icon-shijian"/>
									<b>${!!v[common_key + 'kcsc'] ? v[common_key + 'kcsc'] : ''}</b>
								</div>
							</div>
						</div>
						<div class="item-foot">
							<div class="ctitle ell2">${!!v[common_key + 'title'] ? v[common_key + 'title'] : ''}</div>
							<div class="cteacher">
							  <i class="iconfont icon-touxiang"/><span class="ell">讲师:${
                  !!v[common_key + 'skjsunit'] ? v[common_key + 'skjsunit'] : ''
                }</span>
              </div>
							<div class="cstyle-hour">   
                <p class="p1">
                 <i   class="iconfont icon-shijian"/>
                <span>${!!v[common_key + 'kcxs'] ? v[common_key + 'kcxs'] : 0}
                <span>学时</span>
                </><p>
							</div>
							<div class="clabel">${_this.gettex(v.LABEL_TEXT)}</div>
            </div>
            <div class="hbox">
              <p class="ell2">${!!v[common_key + 'title'] ? v[common_key + 'title'] : ''}</p>
              <div class="btnbox">
                <span class="jsstyle">马上学习</span>
                ${isaddHtml}
              </div>
            </div>
          </div>`;
      }
    }

    $('#demo2').show();
    _this.$newslistbox.html(shtml);
    /*   _this.$newslistbox.find('.leftimgbox,p').click(function() {
      let id = $(this)
        .parents('.news_item')
        .attr('id');
      var elid = $(window.parent.document).find('#J_content');
      $(elid).attr(
        'src',
        dsf.url.getWebPath(`/nc/news/views/nm_details.html?id=${id}&type=${_this.type}`)
      );
    }); */
  }

  gettex(text) {
    var shtml = '';
    if (text) {
      var arr = text.split('^');
      for (var i = 0, len = arr.length; i < len; i++) {
        shtml += '<span>' + arr[i] + '</span>';
      }
    }
    return shtml;
  }

  newsserch() {
    let _this = this;
    _this.$newslistbox = _this._handlers['newsserch'];
    _this.$newsinp = _this._handlers['newsinp'];

    function search() {
      let query = JSON.parse(_this.parms.query);
      query.searchValue = _this.$newsinp.val();
      _this.parms.query = JSON.stringify(query);
      _this.parms.pageNum = 1;
    }

    _this.$newslistbox.click(function() {
      search();
      _this.getlist();
      _this.getPage();
    });

    _this.$rightbox = _this._handlers['rightbox'];
    _this.$rightbox.keyup(function() {
      if (event.keyCode == 13) {
        search();
        _this.getlist();
        _this.getPage();
      }
    });
  }

  getPage() {
    let _this = this;
    layui.use(['laypage', 'layer'], function() {
      var laypage = layui.laypage,
        layer = layui.layer;
      laypage.render({
        elem: 'demo2',
        limit: _this.parms.pageSize,
        count: _this.total,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ['prev', 'page', 'next', 'count'],
        jump: function(obj, first) {
          if (!first) {
            _this.parms.pageNum = obj.curr;
            _this.getlist();
          }
        },
      });
    });
  }
  renderReady() {
    super.renderReady();
    var _this = this;
    _this.newsserch();
    layui.use(['carousel', 'form'], function() {
      var carousel = layui.carousel,
        form = layui.form;
      carousel.render({
        elem: '#test2',
        interval: 10000,
        height: '100%',
        width: '100%',
        arrow: 'none',
      });
    });
    _this.getlist();
    _this.getPage();

    //修改超出省略
    this.root.event.on(PageEvent.READY, args => {
      let oList = document.querySelectorAll('.changeell3');
      $(oList).each(function(item) {
        let oHeight = $(this).height();
        if (oHeight / 30 > 3) {
          $(this).addClass('text texter');
        }
      });
    });
  }

  initEvent() {
    this.changeIsShowSearch();
  }
  getLogoIcon() {
    return dsf.url.getWebPath(this.logoIcon);
  }
  getSerachIcon() {
    return dsf.url.getWebPath(this.searchIcon);
  }
  // 配置标识图标;
  changeLogoIcon() {
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
				
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
				background-image:url(${logoIconSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			   backgroun-color:${this.logoColor} !important;
		}`
    );
  }
  // 配置搜索图标;
  changeSearchIcon() {
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
				
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
				background-image:url( ${imgSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
  // 标签颜色
  changeLabelColor() {
    console.log(this.labelColor);
    this._handlers.labelColor.html(`
	.${this.newslistboxId} .jschannelbtn{
	   color: ${this.labelColor} !important;
	}
	.${this.newslistboxId} .jschannelbtn{
	   border-color: ${this.labelColor} !important;
	}
	.
	
 `);
  }
  // 是否隐藏搜索框
  changeIsShowSearch(val = this.isShowSearch) {
    if (val) {
      this._handlers.rightbox.css({
        // display: `${type} !important`,
        opacity: 0,
        top: '-500px',
      });
    } else {
      this._handlers.rightbox.css({
        opacity: 1,
        top: 0,
      });
    }
  }
  // 列表查询参数
  changePageName() {
    console.log(this.parms.pageName);
    switch (this.parms.pageName) {
      case 'goodCourseList':
        this.title = '好课程';
        this.parms.query = JSON.stringify({
          searchValue: '',
          dsfa_cms_cm_id: '7be6d3aed2be45718c4f5a4aa4d98899',
        });
        break;
      default:
        this.title = '基地展示';
        this.parms.query = JSON.stringify({
          searchValue: '',
          dsfa_cms_cm_id: '1a4671a86d144d98a3ccb9f02934a691',
        });
        break;
    }
  }

  // 标识背景色
  changeLogoColor() {
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
			background-image:url(${logoIconSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.logoColor} !important;
		}`
    );
  }
  // 搜索背景色
  changeSearchColor() {
    //var imgSrc = dsf.url.getWebPath(this.searchIcon);
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
			background-image:url( ${imgSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
}
