import dom from "../templates/NcOnStudyList.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("在学列表", "nc.teas.nconstudylist", "NcOnStudyList")
export class NcOnStudyList extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.$showNumber = 4;
    this.$sourceUrl = null;
    this.$moreSrc = null;
    this._desingerClass = ControlEditor;

    this.randomClass = "ds_nc_OnStudy__" + parseInt(Math.random() * 999999);
    this.old_conTitleBarColor = "#d40000";
    this.old_wrapColor = "#d40000";
    this.old_itemBxColor = "#d40000";
    this.old_endTimeColor = "#C90C0A";
    this.old_studyBtnColor = "#D40000";
    this.styleMap = {};
  }

  set sourceUrl(val) {
    this.$sourceUrl = val;
  }

  get sourceUrl() {
    return this.$sourceUrl;
  }

  set moreSrc(val) {
    this.$moreSrc = val;
  }

  get moreSrc() {
    return this.$moreSrc;
  }

  get showNumber() {
    return this.$showNumber;
  }

  set showNumber(val) {
    return (this.$showNumber = val);
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    let that = this;
    super.renderContext();
    that.onStudyWrap = that._handlers["onStudyWrap"];
    that.onStudy = that._handlers["onStudy"];
    if (!this._root._isDesign) {
      that.getOnStudyList();
      let mStr =
        "<a href='javascript:void(0)' style='color:#fff;'>\
         <i class='icon iconfont icon-hao'></i>\
         </a>";
      that._handlers["moreHandle"].html(mStr);
      that._handlers["moreHandle"].click(function() {
        if (that.$moreSrc.trim() !== "") {
          const ur = dsf.url.getWebPath(that.$moreSrc);
          dsf.openUrl(1, ur);
        }
        //          window.parent.location.href = window.parent.location.href.split('?')[0] + '?hasRead=0&type=2&selItem=2&path=' + dsf.Base64.encode(path);
      });
    }
    // **************
    this.conTitleBarColor !== void 0
      ? this.setConTitleBarColor(this.conTitleBarColor)
      : this.setConTitleBarColor(this.old_conTitleBarColor);
    this.wrapColor !== void 0
      ? this.setWrapColor(this.wrapColor)
      : this.setWrapColor(this.old_wrapColor);
    this.itemBxColor !== void 0
      ? this.setItemBxColor(this.itemBxColor)
      : this.setItemBxColor(this.old_itemBxColor);
    this.endTimeColor !== void 0
      ? this.setEndTimeColor(this.endTimeColor)
      : this.setEndTimeColor(this.old_endTimeColor);
    this.studyBtnColor !== void 0
      ? this.setStudyBtnColor(this.studyBtnColor)
      : this.setStudyBtnColor(this.old_studyBtnColor);
    this.updataStyle();
  }

  getOnStudyList() {
    let that = this;
    if (!that.$sourceUrl) that.$sourceUrl = "nc/ztb/tea/getStudentZtbList";
    that.$sourceUrl = dsf.url.getWebPath(that.$sourceUrl);
    let params = {
      userid: dsf.getCookie("userId") || "eafe290932464971b0e036c38a92f882",
    };
    let loading = dsf.layer.loadding();
    dsf.http
      .request(that.$sourceUrl, params, "GET")
      .done(function(res) {
        if (res.success) {
          if (res.data.length == 0) {
            that.onStudy
              .html("<p class='remind'>您没有在学专题班，去推荐看看吧~</p>")
              .addClass("noData");
            return;
          }
          that.renderPage(res.data); //在学专题班
        }
      })
      .error(function(err) {
        console.log(err);
        dsf.layer.message("接口异常，请稍后再试");
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }

  renderPage(data, type) {
    let listStr = "";
    let defaultImg = "/dsfa/res/dsf_styles/themes/nc/404.png";
    for (var i = 0; i < data.length; ++i) {
      let item = data[i];
      let imgStr = `<img src="${
        !!item["cover"]
          ? dsf.url.getWebPath(JSON.parse(item["cover"])[0]["relativePath"])
          : defaultImg
      }" onerror='onerror=null;src="${defaultImg}"' alt=''/>`;
      listStr +=
        "<div class='com-item'>" +
        "           <div class='item-img-wrap'>" +
        "              " +
        imgStr +
        "           </div>" +
        "           <div class='item-desc-wrap'>" +
        "              <h3 class='item-desc-title curTilClick' data-id='" +
        item["nc_zyb_id"] +
        "'>" +
        // "               <a href='/dsfa/nc/pc/stylecenterindex/views/stylecenterindex.html?id=" + item['nc_zyb_id'] + "' target='_blank'>" +
        "                 " +
        (item["sfbx"] == 1
          ? "<span class='item-bx item-bx-red'>必修</span>"
          : "") +
        "                 " +
        (!!item["title"] && item["title"].length > 30
          ? item["title"].substring(0, 30) + "..."
          : item["title"]) +
        "                 <span class='item-s-e-time'>" +
        "                    <i class='icon-time'></i>" +
        "                    " +
        (!!item["pxrq_sdate"] ? item["pxrq_sdate"].substring(5, 10) : "") +
        "                    " +
        (!!item["pxrq_sdate"] && !!item["pxrq_edate"] ? "至" : "") +
        "                    " +
        (!!item["pxrq_edate"] ? item["pxrq_edate"].substring(5, 10) : "") +
        "                 </span>" +
        // "               </a>" +
        "              </h3>" +
        "              <p class='item-dept'>" +
        "                 <span>主办单位: " +
        (!!item["zbdw"] ? item["zbdw"] : "暂无") +
        "</span>" +
        "              </p>" +
        "              <ul class='item-class-info'>" +
        "                 <li>" +
        "                    <span>必修学时：" +
        (!!item["bxryxs"] ? item["bxryxs"] + "学时" : "") +
        "</span>" +
        "                 </li>" +
        "                 <li>" +
        "                    <span>选修学时：" +
        (!!item["xxryxs"] ? item["xxryxs"] + "学时" : "") +
        "</span>" +
        "                 </li>" +
        "                 <li>" +
        "                    <span>学员人数：" +
        (!!item["studentsCount"] ? item["studentsCount"] : 0) +
        "人</span>" +
        "                 </li>" +
        "           </ul>" +
        "           <p class='item-end-time'>" +
        (!!item["syts"] && item["syts"] > 0
          ? "距离班级结束" + item["syts"] + "天"
          : "") +
        "</p>" +
        "              " +
        studyState(item["state"], item["nc_zyb_id"]) +
        "     </div>" +
        "</div>";
    }
    this.onStudy.html(listStr);
    $(".btnToCourse").click(function() {
      let state = $(this).attr("data-state");
      let id = $(this).attr("data-id");
      let $that = $(this);
      if (state !== "3" || state !== "4") {
        if (state == 0) {
          let userId = dsf.getCookie("userId");
          if (userId) {
            dsf.layer.confirm(
              "您确定要报名吗?",
              () => {
                let loading = dsf.layer.loadding();
                let singUrl = dsf.url.getWebPath("ztb/xymd/addXymdBm");
                let params = {
                  nc_zyb_id: id,
                  nc_students_id: userId,
                };
                dsf.http
                  .request(singUrl, params, "POST")
                  .done(function(res) {
                    if (res.success) {
                      if (res.data) {
                        $that.attr("data-state", 1);
                        $that.html("开始学习");
                        dsf.layer.message("报名成功", true);
                      }
                    } else {
                      dsf.layer.message(res.message, false);
                    }
                  })
                  .error(function(err) {
                    console.log(err);
                    dsf.layer.message(err.message, false);
                  })
                  .always(function() {
                    dsf.layer.close(loading);
                  })
                  .exec();
              },
              () => {
                console.log("取消报名");
              }
            );
          } else {
            window.parent.openLogin();
          }
        } else {
          let path = dsf.url.getWebPath(
            "nc/pc/course/views/course.html?type=1&id=" + id
          );
          window.open(path);
        }
      }
    });
    $(".curTilClick").click(function() {
      let id = $(this).attr("data-id");
      let path = dsf.url.getWebPath(
        "nc/pc/stylecenterindex/views/stylecenterindex.html?id=" + id
      );
      window.open(path);
    });
  }

  /********** json事件——颜色设置 *************/
  mapObj(obj) {
    if (!obj) {
      return;
    }
    let arr = [];
    for (let item in obj) {
      console.log(item);
      arr.push(obj[item]);
    }
    return arr;
  }
  updataStyle() {
    //  this._handlers.onStudyStyle.html(Object.values(this.styleMap).join(""));
    this._handlers.onStudyStyle.html(this.mapObj(this.styleMap).join("")); //兼容IE11处理
  }
  setConTitleBarColor(v) {
    if (v.trim() !== "") {
      this.styleMap.conTitleBarColor = `.${this.randomClass} .com-title b{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.conTitleBarColor = "";
    }
  }
  setWrapColor(v) {
    if (v.trim() !== "") {
      this.styleMap.wrapColor = `.${this.randomClass} .com-icon-wrap{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.wrapColor = "";
    }
  }
  setItemBxColor(v) {
    if (v.trim() !== "") {
      this.styleMap.itemBxColor = `.${this.randomClass} .item-bx{
            color: ${v} !important;
            border-color: ${v} !important;
         }`;
    } else {
      this.styleMap.itemBxColor = "";
    }
  }
  setEndTimeColor(v) {
    if (v.trim() !== "") {
      this.styleMap.endTimeColor = `.${this.randomClass} .item-end-time{
            color: ${v} !important;
         }`;
    } else {
      this.styleMap.endTimeColor = "";
    }
  }
  setStudyBtnColor(v) {
    if (v.trim() !== "") {
      this.styleMap.studyBtnColor = `.${this.randomClass} .item-study-btn{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.studyBtnColor = "";
    }
  }

  changeConTitleBarColor() {
    this.setConTitleBarColor(this.conTitleBarColor);
    this.updataStyle();
  }
  changeWrapColor() {
    this.setWrapColor(this.wrapColor);
    this.updataStyle();
  }
  changeItemBxColor() {
    this.setItemBxColor(this.itemBxColor);
    this.updataStyle();
  }
  changeEndTimeColor() {
    this.setEndTimeColor(this.endTimeColor);
    this.updataStyle();
  }
  changeStudyBtnColor() {
    this.setStudyBtnColor(this.studyBtnColor);
    this.updataStyle();
  }
}
function studyState(state, id) {
  let text = "";
  if (state !== 4) {
    //封闭式
    if (state == 0) {
      text = "报名";
    } else if (state == 1) {
      text = "开始学习";
    } else if (state == 2) {
      text = "继续学习";
    } else if (state == 3) {
      text = "已结业";
    }
    return (
      "<button class='item-study-btn btnToCourse " +
      (state == 3 || state == 4 ? "item-state-bg" : "") +
      "' data-state='" +
      state +
      "' data-id='" +
      id +
      "'>" +
      "        <a  class='isBeginStudy' href='javascript:void(0);' style='color:#fff;'>" +
      text +
      "</a>" +
      "     </button>"
    );
  } else {
    return "";
  }
}
