import dome from '../templates/NcNotice.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';
import { express } from './../../../core/express';

@map("公告", 'nc.teas.notice', 'NcNotice')
export class NcNotice extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.defualtImgUrl = '/res/dsf_styles/themes/img/500.png';
    this.totalCount = null;
    this.listItem = null; // 保存点击时一项的数据
    this.type = 'tzgg';

    this.$requestUrl = "";
    this.$pagesize = 10;
    this.$titleFontCo = '#c90c0a';
    this.$timeFontColor = '#c90c0a';
    this.$isShowTitle = true;
    this.$listFirstParams = 'nc_news_matchCmDataSource.ds_create_time';
    this.$listSecondParams = 'nc_news_matchCmDataSource.cname';
    this.$detailurlfun = "/nc/news/views/nm_details.html?id=@[_id]&type=@[nc_news_matchCmDataSource.cms_cm_code]";
    this.pageConfig = {
      pageSize: this.pagesize,
      pageNum: 1,
      // query: JSON.stringify({ searchValue: '', dsfa_cms_cm_id: 'f2e1651fe85045609d53b37e722340ca' }),
      query: JSON.stringify({
        searchValue: '',
        dsfa_cms_cm_id: 'f2e1651fe85045609d53b37e722340ca',
      }),
      namespace: "nc.news",
      pageName: "notice_list"
    }

    // 头部标题
    this.title = '公告';
    this.logoIcon = '/res/dsf_styles/themes/nc/i-zy7.png'; // 默认的标识图标路径;
    this.searchIcon = '/res/dsf_styles/themes/nc/sousuo02.png'; // 默认的搜索图标路径;
    this.labelColor = '#C90C0A'; //默认的标签颜色;
    this.borderColor = '#C90C0A'; //默认的标签边框颜色;
    this.logoColor = '#C90C0A';
    this.searchColor = '#C90C0A';
    this.newslistboxId = 'roomlist__' + parseInt(Math.random() * 99999999);
    this.leftboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
    this.rightboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
    this.isShowSearch = false;
  }

  set requestUrl(val) {
    this.$requestUrl = val;
  }
  get requestUrl() {
    return this.$requestUrl;
  }

  set pagesize(val) {
    this.$pagesize = val;
  }
  get pagesize() {
    return this.$pagesize;
  }

  set titleFontCo(val) {
    this.$titleFontCo = val;
  }
  get titleFontCo() {
    return this.$titleFontCo;
  }

  set timeFontColor(val) {
    this.$timeFontColor = val;
  }
  get timeFontColor() {
    return this.$timeFontColor;
  }

  set isShowTitle(val) {
    this.$isShowTitle = val;
  }
  get isShowTitle() {
    return this.$isShowTitle;
  }
  set detailurlfun(v) {
    this.$detailurlfun = v;
  }
  get detailurlfun() {
    return this.$detailurlfun;
  }

  set listFirstParams(val) {
    this.$listFirstParams = val;
  }
  get listFirstParams() {
    return this.$listFirstParams;
  }
  set listSecondParams(val) {
    this.$listSecondParams = val;
  }
  get listSecondParams() {
    return this.$listSecondParams;
  }

  initTemplate() {
    return dome(this);
  }

  createElement() { // 创建控件的html元素对象,自动调用initTemplate
    super.createElement();
    this.noticeListWrap = this._handlers.noticeList;
    this.noticeIndexWrap = this._handlers.index;
    this.noticeNotice = this._handlers.notice;
    this._handlers.title.html(dsf.url.queryString('gitTitle') || this.title);
    this._handlers.newsinp.attr('placeholder', dsf.url.queryString('placeholder') || '请输入');

    this.$listFirstParams = !this.$listFirstParams ? 'nc_news_matchCmDataSource.ds_create_time' : this.$listFirstParams;
    this.$listSecondParams = !this.$listSecondParams ? 'nc_news_matchCmDataSource.cname' : this.$listSecondParams;

  }


  renderContext(refresh) { // 设置控件内容，自身样式属性等
    super.renderContext();
    this.getlist();
    this.getPage();
    if (!this._root.isDesign) {
      this.requestUrl = '/dsfa/meta/list/data'
      this.loadData()
    } else {
      this.requestUrl = dsf.url.getWebPath("teas/tempdata/ncInformation.json")
      let args = {}
      this.loadData(args);
    }

  }
  renderReady() {//组件加载完成后执行
    super.renderReady();
    this.newsserch();
    this.titleFontCo = this.titleFontCo === undefined ? "#C90C0A" : this.titleFontCo;
    this.timeFontColor = this.timeFontColor === undefined ? "#C90C0A" : this.timeFontColor;
    this.changeColor();
    this.changeIsShowSearch();
  }
  loadData(args) { // 数据
    let _this = this, str = "", param = {}, item = [];
    param = $.extend({}, args, this.pageConfig)
    dataRequst.call(this, this.requestUrl, param, "GET", function (args) {
      _(args.data).forEach(val => {
        str += createHtml.call(_this, val);
      });
      item = _(args.data);
      _this.noticeListWrap.on('click', '.ds_nc_listitem', item, function () {
        let listItem = item['__wrapped__'][$(this).index()];
        if (!_this.detailurlfun || !_this.detailurlfun.includes('id=') || !_this.detailurlfun.includes('type=')) { // 设计器未动态设计id或type
          _this.$detailurlfun = `${_this.detailurlfun}?id=${listItem['_id']}&type=${listItem['nc_news_matchCmDataSource.cms_cm_code']}`;
          _this.clickDetail()
        } else {
          _this.clickListItem(listItem)
        }
      });

      _this.noticeListWrap.html(str);
    })
  }
  getlist() {// 分页接口
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath("meta/list/count");

    dsf.http
      .request_sync(url, _this.pageConfig, "get")
      .done(function (data) {
        if (data.state == 20000) {
          _this.totalCount = data.data.count;
        }
      })
      .error(function (err) { })
      .always(function () {
        dsf.layer.close(loading);
      })
      .exec();
  }
  getPage() { // 分页
    let _this = this;
    layui.use("laypage", function () {
      var laypage = layui.laypage;
      laypage.render({
        elem: "notice_page",
        limit: _this.pageConfig.pageSize,
        count: _this.totalCount,
        groups: 4,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ["prev", "page", "next", "count"],
        jump: function (obj, first) {
          if (!first) {
            _this.pageConfig.pageNum = obj.curr;
            _this.getlist();
            _this.loadData();
          }
        },
      });
    });
  }
  // 点击列表 跳转详情页面
  clickListItem(data) { // 动态配置参数
    this.listItem = data;
    let v = dsf.Express.replace(this.detailurlfun, this.listItem)
    v = dsf.url.getAbsolutePath(v);
    v = dsf.url.analysis(v)
    // dsf.openUrl(1, v);
    var elid = $(window.parent.document).find("#J_content");
    $(elid).attr("src",v)
  }
  // 无配置项跳转
  clickDetail(item) {
    // dsf.openUrl(1, this.detailurlfun);
    var elid = $(window.parent.document).find("#J_content");
		$(elid).attr(
			"src",
			dsf.url.getWebPath(this.detailurlfun)
		)
  }
  // 改变标题字体颜色,时间颜色
  changeColor() {
    $(".ds_nc_notice_title .red").css("color", this.titleFontCo);
    $(".ds_nc_notice_ul .ds_nc_notice_time").css("color", this.timeFontColor);
  }
  // 标签颜色
  changeLabelColor() {
    console.log(this.labelColor, '====', this.newslistboxId);
    this._handlers.labelColor.html(`
    .${this.newslistboxId} .jschannelbtn{
       color: ${this.labelColor} !important;
    }
    .${this.newslistboxId} .jschannelbtn{
       border-color: ${this.labelColor} !important;
    }
    .
    
   `);
  }
  // 标识背景色
  changeLogoColor() {
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
			background-image:url(${logoIconSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.logoColor} !important;
		}`
    );
  }
  // 配置标识图标;
  changeLogoIcon() {
    //   var logoStyle = "#D60C0C " + "url("+this.logoIcon+")" +" no-repeat center";
    //   console.log(logoStyle);
    //   this._handlers["leftBox"].find("span").css({"background":logoStyle});
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
				
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
				background-image:url(${logoIconSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			   backgroun-color:${this.logoColor} !important;
		}`
    );
  }
  // 搜索背景色
  changeSearchColor() {
    //var imgSrc = dsf.url.getWebPath(this.searchIcon);
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
			background-image:url( ${imgSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
  // 搜索事件
  newsserch() {
    let _this = this;
    _this.$newslistbox = _this._handlers['newsserch'];
    _this.$newsinp = _this._handlers['newsinp'];
    let query = JSON.parse(_this.pageConfig.query);
    _this.$newslistbox.click(function () {
      // _this.pageConfig.title = _this.$newsinp.val();
      query.searchValue = _this.$newsinp.val();
      _this.pageConfig.query = JSON.stringify(query);
      _this.pageConfig.pageNum = 1;
      _this.getlist();
      _this.getPage();
      _this.loadData();
    });

    _this.$rightbox = _this._handlers['rightbox'];
    _this.$rightbox.keyup(function () {
      if (event.keyCode == 13) {
        // _this.pageConfig.title = _this.$newsinp.val();
        query.searchValue = _this.$newsinp.val();
        _this.pageConfig.query = JSON.stringify(query);
        _this.pageConfig.pageNum = 1;
        _this.getlist();
        _this.getPage();
        _this.loadData();
      }
    });
  }
  // 配置搜索图标;
  changeSearchIcon() {
    //   var searchIconStyle= "#C90C0A " + "url("+this.searchIcon+")" +" no-repeat center";
    //   this._handlers["newsserch"].css({background:searchIconStyle});
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
				
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
				background-image:url( ${imgSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
  // 是否隐藏搜索框
  changeIsShowSearch() {
    console.log(this.isShowSearch);
    let type = 'block';
    if (this.isShowSearch) {
      type = 'none';
    }
    document.getElementsByClassName('rightbox')[0].style['display'] = type;
    // this._handlers.rightbox.css({
    //   display: `${type} !important`,
    // });
  }
  getLogoIcon() {
    return dsf.url.getWebPath(this.logoIcon);
  }
  getSerachIcon() {
    return dsf.url.getWebPath(this.searchIcon);
  }
}
// 数据请求封装方法
function dataRequst(url, args, queryway, callback) {
  let loadding = dsf.layer.loadding();
  dsf.http.request(url, args, queryway, callback)
    .done(function (response) {
      if (response.success) {
        if (callback) callback(response)
      } else {
        dsf.layer.message("请求失败,请稍后再试", false)
      }
    })
    .error(function (err) {
      dsf.layer.message("请求失败,请稍后再试", false)
    })
    .always(function () {
      dsf.layer.close(loadding);
    }).exec();
}
// 创建列表dom字符串
function createHtml(item) {
  let str = "";
  str = '<li class="ds_nc_listitem">' +
    '<span class="ds_nc_notice_time">' + item[this.listFirstParams] + '</span>' +
    '<div class="des">' + item[this.listSecondParams] + '</div>' +
    '</li>'
  return str
}
