import dome from '../templates/NcInstructions.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("操作指南", 'nc.teas.instruction', 'NcInstructions')
export class NcInstructions extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.ncNmDetailUrl = "/dsfa/nc/news/views/nm_details.html";
    this.ncNmDetailType = "instruction";
    this.idParams = {
      ml: '3fbb05b3174042a19efc6bba0214d538',
      xygk: '7a9a4d9af681459498459a0cd5b67f47',
      msfy: 'beb78a8ff17544ec862d0edfa828a208',
      wlxypt: 'da619bfbc4c44308a10e49309d6afe5c',
      xyzc: 'a47618a71287412e94f62dbfc6311967',
      xydl: 'd5de2c607e814a9a9da801033562ac5f',
      xysysm: '62055d74c52246b099da9a6456ca7b41'
    }
  }

  initTemplate() {
    return dome(this);
  }

  createElement() { // 创建控件的html元素对象,自动调用initTemplate
    super.createElement();
    this.iframeInstruct = this._handlers.iframeInstruct;
  }

  renderContext(refresh) { // 设置控件内容，自身样式属性等
    super.renderContext();
    this.iframeInstruct.attr('src', this.ncNmDetailUrl + '?type=' + this.ncNmDetailType + '&id=' + this.idParams.ml + '');
    let _this = this;

      this._handlers.ml.on("click", function(){// 目录
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.ml + '');
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.xygk.on("click", function(){// 学院概况
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.xygk + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.msfy.on("click", function(){// 盟市分院
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.msfy + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.wlxypt.on("click", function(){// 网络学院平台
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.wlxypt + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.xyzc.on("click", function(){// 学员注册
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.xyzc + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.xydl.on("click", function(){// 学员登录
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.xydl + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

      this._handlers.xysysm.on("click", function(){// 学员使用说明
        _this.iframeInstruct.attr('src', _this.ncNmDetailUrl + '?type=' + _this.ncNmDetailType + '&id=' + _this.idParams.xysysm + '')
        $('.ds_nc_instruct_ul').find('.ds_nc_instruct_bar_li').removeClass('hover')
        $(this).addClass('hover')
      })

  }
  renderReady() {//组件加载完成后执行
    super.renderReady();
  }

  set detailurlfun(val) {
    this.ncNmDetailUrl = val;
  }
  get detailurlfun(){
    return this.ncNmDetailUrl;
  }
}
