import dome from '../templates/NcCourseHeader.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("课程详情头", 'nc.teas.nccourseheader', 'NcCourseHeader')

export class NcCourseHeader extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this.$sourceUrl = null;
      this.$defaultImg = "/dsfa/res/dsf_styles/themes/img/nc_404.png";
      this._desingerClass = ControlEditor;
   }

   set sourceUrl(val) {
      this.$sourceUrl = val;
   }

   get sourceUrl() {
      return this.$sourceUrl;
   }

   initTemplate() {
      return dome(this);
   }

   renderContext() {
      super.renderContext();
      this.$courseHead = this._handlers['courseHead'];
      if (!this._root._isDesign) {
         this.getCourseHeader();
      }
   }

   getCourseHeader() {
      let that = this;
      if (!that.$sourceUrl) that.$sourceUrl = 'home/ztb/ztbid';
      let params = {
         id: dsf.url.queryString('id')
      };
      that.$sourceUrl = dsf.url.getWebPath(that.$sourceUrl);
      console.log(that.$sourceUrl);
      let loading = dsf.layer.loadding();
      dsf.http.request(that.$sourceUrl, params, "GET")
         .done(function (res) {
            console.log(res)
            if (res.success) {
               if (!!res.data) {
                  that.renderPage(res.data);
               }
            } else {
               dsf.layer.message(res.message, false);
               that.noData();
            }
         })
         .error(function (err) {
            dsf.layer.message('请求异常,稍后重试', false);
            that.noData();
         })
         .always(function () {
            dsf.layer.close(loading);
         }).exec();
   }
   renderPage(data) {
      let showReducePersonStr = data['STATE'] == 0 ? "<span class='course-reduce-person'>剩余" + (!!data['systudent'] ? data['systudent'] : '') + "人</span>" : '';
      let singUpStr = "<div class='course-singUp'>" +
         "                  " + showReducePersonStr +
         "                 <button class='btn-singUp'>" + (data['STATE'] == 0 ? '立即报名' : data['STATE'] == 1 ? '开始学习' : data['STATE'] == 2 ? '继续学习' : '继续学习') + "</button>" +
         "             </div>";
      let hasSingUpStr = "<p class='course-study-state'>" +
         "                    <span>" +
         "                       <i class='d-icon d-xj'></i>考试" +
         "                    </span>" +
         "                    <span>" +
         "                       <i class='d-icon d-ks'></i>小结" +
         "                    </span>" +
         "                    <span>" +
         "                       <i class='d-icon d-wh'></i>" +
         "                    </span>" +
         "                </p>";
      let pasStr = "<div class='course-has-pass'>" +
         "              <i class='icon-pass'></i>" +
         "          </div>";
      let labStr = '';
      if (!!data['label_text']) {
         let labArr = data['label_text'].split('^');
         for (let i = 0; i < labArr.length; ++i) {
            labStr += "<li>" +
               "        <button class='label-btn'>" + labArr[i] + "</button>" +
               "      </li>";
         }
      };
      let imgStr = `<img src="${!!data['cover'] ? dsf.url.getWebPath((JSON.parse(data['cover'])[0]['relativePath'])) : ''}" onerror='onerror=null;src="${this.$defaultImg}"' alt=''/>`
      let headStr = "<div class='course-inner'>" +
         "              <div class='course-img-wrap'>" +
         "              " + imgStr +
         "              </div>" +
         "              <div class='course-info-wrap'>" +
         "                 <h3 class='course-info-title'>" +
         "                    <span class='course-ipt' style='display:" + (data['sfbx'] == 0 ? 'none' : 'inline-block') + ";'>必修</span>" +
         "                    <span class='course-title'>" + (!!data['title'] ? data['title'] : '暂无') + "</span>" +
         "                    <i class='d-icon d-fx'></i>" +
         "                    " + (data['STATE'] !== '0' ? hasSingUpStr : '') +
         "                 </h3>" +
         "                 <ul class='course-detail-msg'>" +
         "                    <li>" +
         "                       <span class='msg-title'>开班时间: </span>" +
         "                       <span class='msg-content'>" +
         '                          ' + (!!data['pxrq_sdate'] ? data['pxrq_sdate'] : '') +
         '                          ' + '至' +
         '                          ' + (!!data['pxrq_edate'] ? data['pxrq_edate'] : '') +
         "                       </span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>报名日期: </span>" +
         "                       <span class='msg-content'>" +
         '                          ' + (!!data['bmrq_sdate'] ? data['bmrq_sdate'] : '') +
         '                          ' + '至' +
         '                          ' + (!!data['bmrq_edate'] ? data['bmrq_edate'] : '') +
         "                       </span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>必修课程: </span>" +
         "                       <span class='msg-content'>" +
         '                          ' + (!!data['bxcount'] ? data['bxcount'] : '') + '门' +
         '                          ' + (!!data['bxxs'] ? data['bxxs'] : 0) + '学时' +
         "                       </span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>选修课程: </span>" +
         "                       <span class='msg-content'>" +
         '                          ' + (!!data['xxcount'] ? data['xxcount'] : 0) + '门' +
         '                          ' + (!!data['xxxs'] ? data['xxxs'] : 0) + '学时' +
         "                       </span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>主办单位: </span>" +
         "                       <span class='msg-content'>" + (!!data['zbdw'] ? data['zbdw'] : '暂无') + "</span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>承办单位: </span>" +
         "                       <span class='msg-content'>" + (!!data['cjdw'] ? data['cjdw'] : '暂无') + "</span>" +
         "                    </li>" +
         "                    <li>" +
         "                       <span class='msg-title'>学院人数: </span>" +
         "                       <span class='msg-content'>" + (!!data['studentNum'] ? data['studentNum'] : 0) + "</span>" +
         "                    </li>" +
         "                 </ul>" +
         "                 <ul class='course-label-btn'>" +
         "                    " + labStr +
         "                 </ul>" +
         "                 " + (singUpStr) +
         "                 " + (data['STATE'] == 3 ? pasStr : '') +
         "             </div>" +
         "        </div>";
      this.$courseHead.html(headStr);
   }

   noData() {
      this.$courseHead.html("<img style='position: relative' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({
         'text-align': 'center'
      });
   }
}


