import dome from "../templates/NcMainChannel.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("主菜单频道", "nc.teas.ncmainchannel", "NcMainChannel")
export class NcMainChannel extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.errimg = "/dsfa/res/dsf_styles/themes/nc/404.png";
    this.parms = {
      title: "",
      pageNo: "1",
      pageSize: "6",
      typeValue: "01",
    };
    this.common = {};
    this.logoIcon = "/res/dsf_styles/themes/nc/channelicon.png"; // 默认的标识图标路径;
    this.searchIcon = "/res/dsf_styles/themes/nc/sousuo02.png"; // 默认的搜索图标路径;
    this.labelColor = "#C90C0A"; //默认的标签颜色;
    this.borderColor = "#C90C0A"; //默认的标签边框颜色;
    this.logoColor = "#C90C0A";
    this.searchColor = "#C90C0A";
    this.newslistboxId = "roomlist__" + parseInt(Math.random() * 99999999);
    this.leftboxSpanId = "span_" + parseInt(Math.random() * 9999999);
    this.rightboxSpanId = "span_" + parseInt(Math.random() * 9999999);
  }

  initTemplate() {
    return dome(this);
  }
  getlist() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath("yyzx/pdgl/pdglListtab");
    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          console.log(data);
          _this.common = data.data;
          _this.recentNewslist();
        } else if (data.state == 20001) {
          layui.use("layer", function() {
            layer.msg(data.message, { icon: 0, time: 2000 });
          });
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }
  createElement() {
    super.createElement();
    this._handlers.title.html(dsf.url.queryString("gitTitle") || "专题");
    this._handlers.newsinp.attr(
      "placeholder",
      dsf.url.queryString("placeholder") || "请输入"
    );
  }

  renderContext(refresh) {
    super.renderContext();
  }
  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
    } else {
      urls = "res/dsf_styles/themes/nc/404.png";
    }
    return urls;
  }
  getbtns(arr) {
    let shtml = "";
    if (arr && arr.length > 0) {
      for (var i = 0, len = arr.length; i < len; i++) {
        shtml +=
          '<button type="button"  class="jschannelbtn layui-btn layui-btn-sm layui-btn-primary">' +
          arr[i] +
          "</button>";
      }
    }
    return shtml;
  }

  recentNewslist() {
    let _this = this,
      shtml = "",
      sd = this.common.list;
    _this.$newslistbox = _this._handlers["newslistbox"];
    if (sd.length == 0) {
      _this.$newslistbox.html(
        "<div style='text-align: center; margin: 20px;'><img src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"
      );
      $("#demo2").hide();
      return false;
    }
    for (var i = 0, len = sd.length; i < len; i++) {
      let urls = _this.geturls(sd[i].cover);
      //			onerror="onerror=null;src='`+dsf.url.getWebPath('res/dsf_styles/themes/nc/404.png')+`'"
      shtml +=
        '<div class="news_item" id="' +
        sd[i].nc_zyb_id +
        '">' +
        '<div class="leftimgbox">' +
        '<img src="' +
        dsf.url.getWebPath(urls) +
        '" onerror=\'onerror=null;src="' +
        dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") +
        "\"'/>" +
        "</div>" +
        '<div class="rightconbox">' +
        '<p class="ell" title="' +
        (sd[i].title == undefined ? "" : sd[i].title) +
        '">' +
        (sd[i].title == undefined ? "" : sd[i].title) +
        "</p>" +
        '<h6 class="ell3 changeell3">' +
        (sd[i].abstract == undefined ? "" : sd[i].abstract) +
        "</h6>" +
        '<div class="choosebtns">' +
        _this.getbtns(sd[i].label_text) +
        "</div>" +
        '<h5 class="rightcon2"><i></i><span>' +
        (sd[i].djs == null ? "0" : sd[i].djs) +
        "</span></h5>" +
        '<h5 class="rightcon1"><i></i><span>' +
        (sd[i].dys == null ? "0" : sd[i].dys) +
        "</span></h5>" +
        "</div>" +
        "</div>";
    }
    $("#demo2").show();
    _this.$newslistbox.html(shtml);
    _this.$newslistbox.find(".leftimgbox,p").click(function() {
      let id = $(this)
        .parents(".news_item")
        .attr("id");
      dsf.openUrl(
        1,
        "/dsfa/nc/pc/channelDetail/views/channelDetail.html?id=" + id
      );
    });
  }

  newsserch() {
    let _this = this;
    _this.$newslistbox = _this._handlers["newsserch"];
    _this.$newsinp = _this._handlers["newsinp"];
    _this.$newslistbox.click(function() {
      _this.parms.title = _this.$newsinp.val();
      _this.parms.pageNo = 1;
      _this.getlist();
      _this.getPage();
    });

    _this.$rightbox = _this._handlers["rightbox"];
    _this.$rightbox.keyup(function() {
      if (event.keyCode == 13) {
        _this.parms.title = _this.$newsinp.val();
        _this.parms.pageNum = 1;
        _this.getlist();
        _this.getPage();
      }
    });
  }

  getPage() {
    let _this = this;

    layui.use(["laypage", "layer"], function() {
      var laypage = layui.laypage,
        layer = layui.layer;
      laypage.render({
        elem: "demo2",
        limit: _this.parms.pageSize,
        count: _this.common.cnt,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ["prev", "page", "next", "count"],
        jump: function(obj, first) {
          if (!first) {
            _this.parms.pageNo = obj.curr;
            _this.getlist();
          }
        },
      });
    });
  }
  renderReady() {
    super.renderReady();
    var _this = this;
    _this.newsserch();
    layui.use(["carousel", "form"], function() {
      var carousel = layui.carousel,
        form = layui.form;
      carousel.render({
        elem: "#test2",
        interval: 10000,
        height: "100%",
        width: "100%",
        arrow: "none",
      });
    });
    _this.getlist();
    _this.getPage();

    //修改超出省略
    this.root.event.on(PageEvent.READY, (args) => {
      let oList = document.querySelectorAll(".changeell3");
      $(oList).each(function(item) {
        let oHeight = $(this).height();
        if (oHeight / 30 > 3) {
          $(this).addClass("text texter");
        }
      });
    });
  }

  initEvent() {}
  getLogoIcon() {
    return dsf.url.getWebPath(this.logoIcon);
  }
  getSerachIcon() {
    return dsf.url.getWebPath(this.searchIcon);
  }
  // 配置标识图标;
  changeLogoIcon() {
    //   var logoStyle = "#D60C0C " + "url("+this.logoIcon+")" +" no-repeat center";
    //   console.log(logoStyle);
    //   this._handlers["leftBox"].find("span").css({"background":logoStyle});
    if (this.logoIcon == "") {
      this._handlers["logo_icon"].html(
        `.${this.leftboxSpanId}{
				
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers["logo_icon"].html(
      `.${this.leftboxSpanId}{
				background-image:url(${logoIconSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
		}`
    );
  }
  // 配置搜索图标;
  changeSearchIcon() {
    //   var searchIconStyle= "#C90C0A " + "url("+this.searchIcon+")" +" no-repeat center";
    //   this._handlers["newsserch"].css({background:searchIconStyle});
    if (this.serachIcon == "") {
      this._handlers["logo_icon"].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers["serach_icon"].html(
      `.${this.rightboxSpanId}{
				background-image:url( ${imgSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
		}`
    );
  }
  // 标签颜色
  changeLabelColor() {
    console.log(this.labelColor);
    this._handlers.labelColor.html(`
	.${this.newslistboxId} .jschannelbtn{
	   color: ${this.labelColor} !important;
	}
	.${this.newslistboxId} .jschannelbtn{
	   border-color: ${this.labelColor} !important;
	}
	.
	
 `);
  }
  // 标识背景色
  changeLogoColor() {
    if (this.logoIcon == "") {
      this._handlers["logo_icon"].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers["logo_icon"].html(
      `.${this.leftboxSpanId}{
			background-image:url(${logoIconSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
		}`
    );
  }
  // 搜索背景色
  changeSearchColor() {
    //var imgSrc = dsf.url.getWebPath(this.searchIcon);
    if (this.serachIcon == "") {
      this._handlers["logo_icon"].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers["serach_icon"].html(
      `.${this.rightboxSpanId}{
			background-image:url( ${imgSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
		}`
    );
  }
}
