  //按钮操作
    liveOper(item) {
        let _this = this;
        let _info = item;
        let _userId = dsf.getCookie('userId');
        if (_userId && _userId != '' && _info.btnOper != -1) { //_userId && _userId != ''  //_userId == ''
            //按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看d
            if (_info.btnOper) {
                if (_info.btnOper == 3) {
                    //预约
                    _this.handleState(_info);
                } else if (_info.btnOper == 4) {
                    //取消预约
                    // _this.handleState(_info);
                } else if (_info.btnOper == 5 && _info.playstatus != 0) {
                    //回看
                    let _url = dsf.url.getWebPath("nc/zbgl/playback");
                    dsf.http.request(
                        _url,
                        {
                            zbid: _info.nc_zbgl_jbxx_id
                        },
                        "POST"
                    )
                        .done(function (data) {
                            if (data.state == '20000') {
                                let Url = '';
                                //回看 playstatus==1 进入我们系统的直播页面 2 进入钉钉的直播
                                if (_info.playstatus == 1) {
                                    Url = dsf.url.getWebPath('nc/pc/live/views/live.html') + '?id=' + _info['nc_zbgl_jbxx_id'];
                                } else if (_info.playstatus == 2) {
                                    Url = dsf.url.getAbsolutePath(_info.playback_url);
                                }
                                dsf.openUrl(1, Url);
                            } else {
                                dsf.layer.message(data.message, false);
                            }
                        })
                        .error(function (err) {
                            console.log(err);
                        })
                        .always(function () {

                        }).exec();
                    /*if(_info.playstatus == 2){
                        let jumpUrl = _info.playback_url;
                        window.open(jumpUrl, '_blank');
                    }else if(_info.playstatus == 1){
                        let jumpUrl = _info.playback_url;
                        window.open(jumpUrl, '_blank');
                    }*/

                } else if (_info.btnOper == 1) {
                    //直播预约
                    _this.handleState(_info);
                }
            }
        } else {
            //登录
            window.parent.openLogin();
        }


    }
    //直播状态处理
    handleState(item){
        let _this = this;
        let url = dsf.url.getWebPath("nc/zbgl/zbOp");
        _this.liveActive = item;
        let _optype = item.btnOper == 3 ? 1 : item.btnOper == 5 ? 2 : item.btnOper == 4 ? 3 : item.btnOper == 1 ? 4 : null;
        //btnOper按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看
        //_optype操作类型(1预约，2.观看，3取消预约,4.加入直播 )
        if(_optype){
            let parms = {
                nc_zbid : item.nc_zbgl_jbxx_id,
                nc_students_id : dsf.getCookie('userId'),//实际不需要
                optype : _optype
            };
            if (_optype == 4){
                dsf.http.request(
                    url,
                    parms,
                    "POST"
                )
                    .done(function (data) {
                        if (data.state == '20000') {
                            _this.getLiveList(_this.liveParms);
                            _this.liveActive.hoverChange = 2;
                            _this.domUpdate();
                        } else {
                            dsf.layer.message(data.message, false);
                        }
                    })
                    .error(function (err) {
                        console.log(err);
                    })
                    .always(function () {

                    }).exec();
            }else{
                dsf.http.request(
                    url,
                    parms,
                    "POST"
                )
                    .done(function (data) {
                        if (data.state == '20000') {
                            _this.getLiveList(_this.liveParms);
                            _this.domUpdate();
                        } else {
                            dsf.layer.message(data.message, false);
                        }
                    })
                    .error(function (err) {
                        console.log(err);
                    })
                    .always(function () {

                    }).exec();
            }

        }
    }
  //格式化时间
    formatterDate(date,type){
      if (type == 'month'){
          let _month = date.getMonth() + 1;
          if (_month >= 1 && _month <= 9) {
              _month = "0" + _month;
          }
          return _month
      }else if (type == 'date'){
          let _date = date.getDate();
          if (_date >= 0 && _date <= 9) {
              _date = "0" + _date;
          }
          return _date
      }else if (type == 'time'){
          let _h = date.getHours().toString();
          let _m = date.getMinutes().toString();
          if (_h >= 0 && _h <= 9) {
              _h = "0" + _h;
          }
          if (_m >= 0 && _m <= 9) {
              _m = "0" + _m;
          }
          // let _s = date.getSeconds().toString();
          return _h + ':' + _m;
      }

    }
//鼠标划入
    liveActiveEnter(idx){
        let _this = this;
        let _userId = dsf.getCookie('userId');
        //_userId == ''
        // _userId && _userId != '' && _this.$liveList[idx].btnOper == 2
        if(_userId && _userId != '' && _this.$liveList[idx].btnOper == 2){
            _this.$liveList[idx].hoverChange = 2;
            _this.domUpdate();
        }
    }
    liveActiveLeave(idx){
        this.$liveList[idx].hoverChange = 1;
        this.domUpdate();
    }
    //获取图片地址
    getImageSrc(cover){
      let _this = this;
      if(cover){
          return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath)
      }else{
          return _this.$defaultImgUrl;
      }
    }
