  /**
   * 请求数据
   */
  postData (parms) {
    let loading = dsf.layer.loadding();
    let url = dsf.url.getWebPath('nc/zbgl/list');
    dsf.http.request(
      url, parms, "get"
    ).done(response => {
      if (response.state === 20000) {
        // 请求成功
        this.postDataSuccess(response.data.records);
      } else {
        // 请求失败
        dsf.layer.message(response.message, false);
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }

  /**
   * 请求成功处理
   */
  postDataSuccess (data) {
    this.$userId = dsf.getCookie('userId');

    this.$liveList = data.map((v, i) => {
      let _obj = {};
      let _ndate = new Date();
      let _sdate = new Date(Date.parse((v.zbrq_sdate).replace(/-/g, "/")));
      let _edate = new Date(Date.parse((v.zbrq_edate).replace(/-/g, "/")));
      //日期
      _obj.month = ((_ndate.getMonth() === _sdate.getMonth()) && (_ndate.getDate() === _sdate.getDate()))?"今天"
          : this.formatterDate(_sdate,'month') + '.' + this.formatterDate(_sdate,'date');
      //开始时间
      _obj.sTime = this.formatterDate(_sdate,'time');
      //结束时间
      _obj.eTime = this.formatterDate(_edate,'time');
      //封面
      _obj.cover = v.cover;
      //直播名称
      _obj.name = v.name;
      //主讲人-职务
      _obj.speaker =  v.speaker + (v.job ? "-" + v.job : "");
      //预约人数
      _obj.yypeo = v.yypeo;
      //直播时长
      _obj.sc = v.sc;
      //直播状态
      _obj.state = v.state; //1直播中，2预约，3回放
      //预约状态
      _obj.isyy_value = v.isyy_value;//（当前登录人 已登录0:未预约，1：已预约),-1:未登录

      if (v.state === 1){
        //标签显示
        _obj.iconText = '直播中';
        //按钮显示
        _obj.btnText = '进入直播';
        //info.isyy_value是否已预约（当前登录人 已登录0:未预约，1：已预约),-1:未登录
        //按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看
        _obj.btnOper = v.isyy_value === -1 ? -1
            : v.isyy_value === 0 ? 1
                : v.isyy_value === 1 ? 2
                    : '';

      }else if (v.state === 2){
        _obj.iconText = '未开始';
        _obj.btnText = v.isyy_value === 0 || v.isyy_value === -1 ? '预约':v.isyy_value == 1 ? '已预约':'';
        _obj.btnOper = v.isyy_value === -1 ? -1
            : v.isyy_value === 0 ? 3
                : v.isyy_value === 1 ? 4
                    : '';
      }else if (v.state === 3){
        _obj.iconText = '已结束';
        _obj.btnText = '回放';
        _obj.btnOper = v.isyy_value == -1 ? -1
            :5;
      }
      //剩余天数
      _obj.syts = v.syts;
      //直播时长（暂无）

      //回放地址
      _obj.playback_url = v.playback_url;

      //回放状态 （1.视频点播，2.钉钉回放地址，0.不能回放
      _obj.playstatus = v.playstatus;

      //直播id
      _obj.nc_zbgl_jbxx_id = v.nc_zbgl_jbxx_id;

      //直播群名字
      _obj.group_name = v.group_name;

      //直播二维码
      _obj.qrcodeurl = v.qrcodeurl ? dsf.url.getWebPath(v.qrcodeurl):'';

      //显示样式切换
      _obj.hoverChange = 1;
      //索引
      _obj.idx = i;

      return _obj;
    });

    this.domUpdate();
  }
