import dome from '../templates/NcResourceInfor.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map('资源中心', 'nc.teas.resource', 'NcResourceInfor')
export class NcResourceInfor extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.errimg = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.detailurlfun = '/nc/news/views/nm_details.html?id=@[_id]&type=@[nc_news_matchCmDataSource.cms_cm_code]';
    this.type = '';
    this.total = 0;
    this.parms = {
      pageNum: 1,
      pageSize: 10,
      namespace: 'nc.news',
      pageName: 'information_list',
      query: JSON.stringify({
        searchValue: '',
        dsfa_cms_cm_id: 'ee41d31cc8e44e22a04310a05ae27fbc',
      }),
    };
    this.dsfa_id = '1a4671a86d144d98a3ccb9f02934a691';
    this.isShowSearch = false;
    this.common = {};
    this.title = '资料';
    this.logoIcon = '/res/dsf_styles/themes/nc/i-zy5.png'; // 默认的标识图标路径;
    this.searchIcon = '/res/dsf_styles/themes/nc/sousuo02.png'; // 默认的搜索图标路径;
    this.labelColor = '#C90C0A'; //默认的标签颜色;
    this.borderColor = '#C90C0A'; //默认的标签边框颜色;
    this.logoColor = '#C90C0A';
    this.searchColor = '#C90C0A';
    this.newslistboxId = 'roomlist__' + parseInt(Math.random() * 99999999);
    this.leftboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
    this.rightboxSpanId = 'span_' + parseInt(Math.random() * 9999999);
  }

  initTemplate() {
    return dome(this);
  }
  getlist() { // 获取列表数据
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('meta/list/data'); // 列表
    dsf.http
      .request_sync(url, _this.parms, 'get')
      .done(function (res) {
        if (res.state == 20000) {
          console.log('res=>', res);
          _this.common = [...res.data];
          _this.recentNewslist();
        } else if (res.state == 20001) {
          layui.use('layer', function () {
            layer.msg(res.message, { icon: 0, time: 2000 });
          });
        }
      })
      .error(function (err) {
        console.log(err);
      })
      .always(function () {
        dsf.layer.close(loading);
      })
      .exec();

    // 分页请求
    dsf.http
      .request_sync(dsf.url.getWebPath('meta/list/count'), _this.parms, 'get') // 列表总条数
      .done(function (res) {
        if (res.state == 20000) {
          console.log('res=>', res);
          _this.total = res.data.count;
        } else if (res.state == 20001) {
          layui.use('layer', function () {
            layer.msg(res.message, { icon: 0, time: 2000 });
          });
        }
      })
      .error(function (err) {
        console.log(err);
      })
      .always(function () {
        dsf.layer.close(loading);
      })
      .exec();
  }
  createElement() {
    super.createElement();
    this._handlers.title.html(dsf.url.queryString('gitTitle') || this.title);
    this._handlers.newsinp.attr('placeholder', dsf.url.queryString('placeholder') || '请输入');
  }

  renderContext(refresh) {
    super.renderContext();
    this.changeIsShowSearch();
  }

  recentNewslist() {
    let _this = this,
      shtml = '',
      sd = this.common; // this.common.list;
    _this.$newslistbox = _this._handlers['newslistbox'];
    if (sd.length == 0) {
      _this.$newslistbox.html(
        "<div style='text-align: center; margin: 20px;'><img src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"
      );
      $('#demo2').hide();
      return false;
    }
    _this.type = sd[0]['nc_news_matchCmDataSource.cms_cm_code'];
    sd.forEach(item => {
      shtml += `
      <li class="ds_nc_listitem" data-id=${item["nc_news_matchCmDataSource.dsfa_cms_content_id"]}>
        <span>${item["nc_news_matchCmDataSource.cname"]}</span>
      </li>
      `
    });

    $('#demo2').show();
    _this.$newslistbox.html(shtml);
    _this.$newslistbox.find('.ds_nc_listitem').click(function () {
      _this.id = $(this).attr('data-id');
      console.log(sd, _this.type)
      let listItem = sd[$(this).index()];
      // dsf.openUrl(1, `${_this.detailUrl}?id=${id}&type=${_this.type}`);
      if (!_this.detailurlfun || !_this.detailurlfun.includes('id=') || !_this.detailurlfun.includes('type=')) { // 设计器未动态设计id或type
        _this.detailurlfun = `${_this.detailurlfun}?id=${_this.id}&type=${_this.type}`;
        _this.clickDetail()
      } else {
        _this.clickListItem(listItem)
      }
    });;
  } 

  // 点击列表 跳转详情页面
  clickListItem(data) {
    this.listItem = data;
    let v = dsf.Express.replace(this.detailurlfun, this.listItem)
    v = dsf.url.getAbsolutePath(v);
    v = dsf.url.analysis(v)
    // dsf.openUrl(1, v);
    var elid = $(window.parent.document).find("#J_content");
    $(elid).attr( "src",v )

  }
  // 无配置项跳转详情
  clickDetail() {
    // dsf.openUrl(1, this.detailurlfun);
    var elid = $(window.parent.document).find("#J_content");
    $(elid).attr(
      "src",
      dsf.url.getWebPath(this.detailurlfun)
    )
  }
  // 搜索事件
  newsserch() {
    let _this = this;
    _this.$newslistbox = _this._handlers['newsserch'];
    _this.$newsinp = _this._handlers['newsinp'];
    let query = JSON.parse(_this.parms.query);
    _this.$newslistbox.click(function () {
      // _this.parms.title = _this.$newsinp.val();
      query.searchValue = _this.$newsinp.val();
      _this.parms.query = JSON.stringify(query);
      _this.parms.pageNum = 1;
      _this.getlist();
      _this.getPage();
    });

    _this.$rightbox = _this._handlers['rightbox'];
    _this.$rightbox.keyup(function () {
      if (event.keyCode == 13) {
        // _this.parms.title = _this.$newsinp.val();
        query.searchValue = _this.$newsinp.val();
        _this.parms.query = JSON.stringify(query);
        _this.parms.pageNum = 1;
        _this.getlist();
        _this.getPage();
      }
    });
  }

  getPage() {
    let _this = this;
    layui.use(['laypage', 'layer'], function () {
      var laypage = layui.laypage,
        layer = layui.layer;
      laypage.render({
        elem: 'demo2',
        limit: _this.parms.pageSize,
        count: _this.total,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ['prev', 'page', 'next', 'count'],
        jump: function (obj, first) {
          if (!first) {
            _this.parms.pageNum = obj.curr;
            _this.getlist();
          }
        },
      });
    });
  }
  renderReady() {
    super.renderReady();
    var _this = this;
    _this.newsserch();
    layui.use(['carousel', 'form'], function () {
      var carousel = layui.carousel,
        form = layui.form;
      carousel.render({
        elem: '#test2',
        interval: 10000,
        height: '100%',
        width: '100%',
        arrow: 'none',
      });
    });
    _this.getlist();
    _this.getPage();

    //修改超出省略
    this.root.event.on(PageEvent.READY, args => {
      let oList = document.querySelectorAll('.changeell3');
      $(oList).each(function (item) {
        let oHeight = $(this).height();
        if (oHeight / 30 > 3) {
          $(this).addClass('text texter');
        }
      });
    });
  }

  initEvent() { }
  getLogoIcon() {
    return dsf.url.getWebPath(this.logoIcon);
  }
  getSerachIcon() {
    return dsf.url.getWebPath(this.searchIcon);
  }
  // 配置标识图标;
  changeLogoIcon() {
    //   var logoStyle = "#D60C0C " + "url("+this.logoIcon+")" +" no-repeat center";
    //   console.log(logoStyle);
    //   this._handlers["leftBox"].find("span").css({"background":logoStyle});
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
				
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
				background-image:url(${logoIconSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			   backgroun-color:${this.logoColor} !important;
		}`
    );
  }
  // 配置搜索图标;
  changeSearchIcon() {
    //   var searchIconStyle= "#C90C0A " + "url("+this.searchIcon+")" +" no-repeat center";
    //   this._handlers["newsserch"].css({background:searchIconStyle});
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
				
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
				background-image:url( ${imgSrc}) !important;
				background-repeat:no-repeat;
				background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
  // 标签颜色
  changeLabelColor() {
    console.log(this.labelColor, '====', this.newslistboxId);
    this._handlers.labelColor.html(`
	.${this.newslistboxId} .jschannelbtn{
	   color: ${this.labelColor} !important;
	}
	.${this.newslistboxId} .jschannelbtn{
	   border-color: ${this.labelColor} !important;
	}
	.
	
 `);
  }
  // 是否隐藏搜索框
  changeIsShowSearch() {
    console.log(this.isShowSearch);
    let type = 'block';
    if (this.isShowSearch) {
      type = 'none';
    }
    document.getElementsByClassName('rightbox')[0].style['display'] = type;
    // this._handlers.rightbox.css({
    //   display: `${type} !important`,
    // });
  }
  // 列表查询参数
  // changePageName() {
  //   console.log(this.parms.pageName);
  //   switch (this.parms.pageName) {
  //     case 'goodCourseList':
  //       this.title = '好课程';
  //       this.parms.query = JSON.stringify({
  //         searchValue: '',
  //         dsfa_cms_cm_id: '7be6d3aed2be45718c4f5a4aa4d98899',
  //       });
  //       break;
  //     default:
  //       this.title = '基地展示';
  //       this.parms.query = JSON.stringify({
  //         searchValue: '',
  //         dsfa_cms_cm_id: '1a4671a86d144d98a3ccb9f02934a691',
  //       });
  //       break;
  //   }
  // }

  // 标识背景色
  changeLogoColor() {
    if (this.logoIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.logoColor} !important;
			}`
      );
      return;
    }
    var logoIconSrc = this.getLogoIcon();
    this._handlers['logo_icon'].html(
      `.${this.leftboxSpanId}{
			background-image:url(${logoIconSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.logoColor} !important;
		}`
    );
  }
  // 搜索背景色
  changeSearchColor() {
    //var imgSrc = dsf.url.getWebPath(this.searchIcon);
    if (this.serachIcon == '') {
      this._handlers['logo_icon'].html(
        `.${this.leftboxSpanId}{
				background-image:none !important;
				background-color:${this.searchColor} !important;
			}`
      );
      return;
    }
    var imgSrc = this.getSerachIcon();
    this._handlers['serach_icon'].html(
      `.${this.rightboxSpanId}{
			background-image:url( ${imgSrc}) !important;
			background-repeat:no-repeat;
			background-position:cnetr;
			background-color:${this.searchColor} !important;
		}`
    );
  }
}
