import dom from '../templates/NcFamousTeacherDetail.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';
@map("名师详情", 'nc.teas.famousteacher', 'NcFamousTeacherDetail')
export class NcFamousTeacherDetail extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this.$sourceUrl = null;
      this._desingerClass = ControlEditor;
      this.defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
      this.teachersID = '';
   }
   set sourceUrl(val) {
      this.$sourceUrl = val;
   }
   get sourceUrl() {
      return this.$sourceUrl;
   }

   initTemplate() {
      return dom(this);
   }

   createElement() {
      super.createElement();
   }

   renderContext() {
      this.$course = this._handlers['courseWrap'];
      super.renderContext();
//    if (!this._root._isDesign) {
         this.getTeacherID();
         this.getCourse();
//    }
   }

   renderReady() {
      super.renderReady();
   }

   renderComplete() {
      super.renderComplete();
   }
   getTeacherID() {
      let teacherID = window.parent.document.getElementById("famous_teacher_frame").contentWindow.location.search;
      this.teachersID = teacherID.substring(4);
      if (!this.teacherID) {
         this.teachersID = dsf.url.queryString('id');
      }
   }

   getCourse() {
      let that = this;
      let loading = dsf.layer.loadding();
      if (!that.$sourceUrl) that.$sourceUrl = 'nc/szk/ms/findMsDetail';
      let params = {
         id: that.teachersID
      };
      that.$sourceUrl = dsf.url.getWebPath(that.$sourceUrl);
      dsf.http.request(that.$sourceUrl, params, "GET")
         .done(function (res) {
         	console.log(res);
            if (res.success) {
               that.renderHead(res.data);
               that.renderArea(res.data.label_text);
               that.renderIntro(res.data.description);
               that.renderPage(res.data);
//             that.inquireSubscribe(res.data);
               that.getSubscribe(res.data);
               $('.course_total').html(res.data.courseNum);
            } else {
               dsf.layer.message(res.message, false);
            }
         })
         .error(function (err) {
            dsf.layer.message('接口异常,请稍后重试', false);
         })
         .always(function () {
            dsf.layer.close(loading);
         }).exec();
   }

   // 名师头
   renderHead(data) {
      let headStr = '<div class=\'course-inner course-inner-default-padding\'>\n' +
         '               <div class=\'course-img-wrap course-default-img-wrap\'>\n' +
         '                  <img src="' + (data.photo ? dsf.url.getWebPath(JSON.parse(data.photo)[0].relativePath) : '/dsfa/res/dsf_styles/themes/nc/404.png') + '" alt="">\n' +
         '               </div>\n' +
         '               <div class=\'course-info-wrap course-info-wrap-default-margin\' style="margin-left: 375px;">\n' +
         '                  <h3 class=\'course-info-title\'>\n' +
         '                     <!-- <span class=\'course-ipt\'>必修</span> -->\n' +
         '                     <span class="course-title">' + (data.name ? data.name : '暂无') + '</span>\n' +
         '                     <i class="d-icon d-fx"></i>\n' +
         '                  </h3>\n' +
         '                  <p class="famous-teacher-job">\n' +
         '                     ' + (data.job_text ? data.job_text : '暂无') + '  '+ ((data.zj_text ? data.zj_text : '')) +'\n' +
         '                  </p>\n' +
         '                  <ul class="famous-teacher-course">\n' +
         '                     <li>\n' +
         '                        <b>' + (data.courseNum ? data.courseNum : '暂无') + ' </b> 门课程\n' +
         '                     </li>\n' +
         '                     <li>\n' +
         '                        <b>' + (data.dyrs ? data.dyrs : '暂无') + ' </b> 人订阅\n' +
         '                     </li>\n' +
         '                  </ul>\n' +
         '                  <button class="sing-read-btn">立即订阅</button>\n' +
         '               </div>\n' +
         '            </div>';

      this._handlers['courseHead'].html(headStr);
   }
   // 查询订阅
   inquireSubscribe(data) {
      let sourceUrl = dsf.url.getWebPath('dsfa/subscribe/queryTotalByYwid'),
          params = {
             ywlxValue: 'ms',
             ywid: data.nc_szk_id
          };
      dsf.http.request(sourceUrl, params, "GET")
          .done(function (res) {
             if (res.success&&res.state == '20000') {
                $('.famous-teacher-course li:nth-of-type(2) b').html(res.data);
             } else {
                dsf.layer.message(res.message, false);
             }
          })
          .error(function (err) {
             dsf.layer.message('接口异常,请稍后重试', false);
          })
          .always(function () {
          }).exec();

   }
   // 订阅
   getSubscribe(data) {
      $('.sing-read-btn').on('click', function () {
      	console.log(111);
         let singText = $('.sing-read-btn').html();
         let dyloading = dsf.layer.loadding(),
             sourceUrl = dsf.url.getWebPath('dsfa/subscribe/saveOrCancel'),
             params = {
                ywlxValue: 'ms',
                ywlxText: '新增',
                ywid: data.nc_szk_id
             },
             _this = this;
         dsf.http.request(sourceUrl, params, "POST")
             .done(function (res) {
             	console.log(res);
                if (res.success&&res.state == '20000') {
                   if (res.data.isDo) {
                      dsf.layer.message('订阅成功');
                      $('.sing-read-btn').html('取消订阅');
                   } else {
                      dsf.layer.message('取消订阅成功');
                      $('.sing-read-btn').html('立即订阅');
                   }
                   _this.getCourse();
//                 _this.inquireSubscribe(data);
                } else {
                   dsf.layer.message(res.message, false);
                }
             })
             .error(function (err) {
                dsf.layer.message('接口异常,请稍后重试', false);
             })
             .always(function () {
                dsf.layer.close(dyloading);
             }).exec();

      })
   }

   //  擅长领域
   renderArea(data) {
      if (data) {
         let tagsArr = data.split('^');
         let tags = '';
         for (let i = 0; i < tagsArr.length; i++) {
            tags += '<button class="famous-teacher-item-btn">' + tagsArr[i] + '</button>'
         }
         let areaStr = '<h3 class="famous-com-title"><span>擅长领域</span></h3>\n' +
            '         <div class="famous-teacher-item-detail">\n' +
            '            ' + tags + '\n' +
            '         </div>';
         this._handlers['courseArea'].html(areaStr);
      }
   }
   // 简介
   renderIntro(data) {
      let introStr = '<h3 class="famous-com-title"><span>简介</span></h3>\n' +
         '         <div class="famous-teacher-item-detail">\n' +
         '            <div class="famous-teacher-item-desc">\n' +
         '               ' + data + '\n' +
         '            </div>\n' +
         '         </div>';

      this._handlers['courseIntro'].html(introStr);
   }

   renderPage(data) {
      let course  = data.course;
      if (course.length > 0) {
         let cStr = '';
         for (let i = 0; i < course.length; ++i) {
            let techStr = '';
            let item = course[i];
            if (!!item['SKJS'] && item['SKJS'].length !== 0) {
               for (let k = 0; k < item['SKJS'][k].length; ++k) {
                  techStr += "<p class='item-sub-title'>" +
                     "           <i class='icon-person'></i>" +
                     "           <span>" + item['SKJS'][k]['JSMC'] + '-' + item['SKJS'][k]['JOB'] + "</span>" +
                     "        </p>";
               }
            }
            cStr += "<div class='item'>" +
               "           <div class='item-org'>" +
               "              <span class='item-new' style='display:" + (item['SFNEW'] == 1 ? 'inline-block' : 'none') + "'>new</span>" +
               "              <span class='item-score'>" + (!!item['kcpf'] ? item['kcpf'] : '') + "</span>" +
               "              <figure class='img-wrap'>" +
               "                 <img src='" + (!!item['cover'] ? dsf.url.getWebPath(JSON.parse(item['cover'])[0]['relativePath']) : '/dsfa/res/dsf_styles/themes/nc/404.png') + "' alt=''>" +
               "                 <span class='item-time'>" +
               "                    <i class='icon-time'></i>" +
               "                    <b>" + (!!item['kcsc'] ? item['kcsc'] : '') + "</b>" +
               "                 </span>" +
               "              </figure>" +
               "              <div class='item-desc'>" +
               "                 <p class='item-desc-title'>" +
               "                    <dsp class='title-wrap'>" +
               "                       <span class='item-title-imp' style='display:" + (item['SFBX'] == 1 ? 'inline-block' : 'none') + ";'>必修</span>" +
               "                       <b>" + (!!item['title'] ? item['title'] : '') + "</b>" +
               "                    </dsp>" +
               "                 </p>" +
               "                 " + techStr +
               "                 <p class='item-state'>" +
               "                    <span>" +
               "                       <i class='icon-study-time'></i>" +
               "                       <b>" + (!!item['kcxs'] ? item['kcxs'] : 0) + "学时</b>" +
               "                    </span>" +
               "                    <span>" +
               "                       <i class='icon-see'></i>" +
               "                       <b>" + (!!item['gkcs'] ? item['gkcs'] : '') + "</b>" +
               "                    </span>" +
               "                 </p>" +
               "              </div>" +
               "           </div>" +
               "           <div class='item-clone' style='top:8px'>" +
               "              <span class='item-new' style='display:" + (item['SFNEW'] == 1 ? 'inline-block' : 'none') + "'>new</span>" +
               "              <span class='item-score'>" + (!!item['kcpf'] ? item['kcpf'] : '') + "</span>" +
               "              <figure class='img-wrap' style='height:200px;'>" +
               "                 <img src='" + (!!item['cover'] ? dsf.url.getWebPath(JSON.parse(item['cover'])[0]['relativePath']) : '/dsfa/res/dsf_styles/themes/nc/404.png') + "' alt=''>" +
               "                 <i class='icon-voice'></i>" +
               "              </figure>" +
               "              <div class='item-desc'>" +
               "                 <p class='item-desc-title'>" +
               "                    <dsp class='title-wrap clone-margin'>" +
               "                       <span class='item-title-imp' style='display:none;'>必修</span>" +
               "                       <b>" + (!!item['title'] ? item['title'] : '') + "</b>" +
               "                    </dsp>" +
               "                    <span class='toggle-join'>加入在学</span>" +
               "                 </p>" +
               "                 <p class='item-sub-title'>" +
               "                    <i class='icon-person'></i>" +
               "                    <span>" + (!!item['xm'] ? item['xm'] : '') + "</span>" +
               "                 </p>" +
               "                 <p class='item-state clone-span-wrap'>" +
               "                    <span>" +
               "                       <i class='icon-study-time'></i>" +
               "                       <b>" + (!!item['kcxs'] ? item['kcxs'] : 0) + "学时</b>" +
               "                    </span>" +
               "                    <span>" +
               "                       <i class='icon-see'></i>" +
               "                       <b>" + (!!item['gkcs'] ? item['gkcs'] : 0) + "</b>" +
               "                    </span>" +
               "                    <span>" +
               "                       <i class='icon-zan'></i>" +
               "                       <b>" + (!!item['KCXS'] ? item['KCXS'] : 0) + "</b>" +
               "                    </span>" +
               "                 </p>" +
               "              </div>" +
               "           </div>" +
               "        </div>";
            this.$course.html(cStr);
         }
         this.bindDetail(data);
      } else {
         this.noData();
      }
   }
   bindDetail(data) {
      // 跳转课程
      $('.course-wrap').find('.item-clone').each(function (index) {
         let _this = $(this);
         _this.on('click',function () {
            let courseUrl = dsf.url.getWebPath('nc/pc/course/views/course.html?type=2&id='+data[index].nc_zyb_id);
            window.open(courseUrl);
         })
      });
   }
   noData() {
      this.$course.html("<img style='position: relative' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({
         'text-align': 'center'
      });
   }

}
