  recentNewslist(){
  	let _this=this;
	let loading = dsf.layer.loadding();
		let url = dsf.url.getWebPath("nc/xxgl/xys/findXys");
    dsf.http.request_sync(
    	url,
    	_this.parms, 
    	"get"
    )
    .done(function (data) {
    	if(data.state==20000){
    		_this.recent_newslist = data.data.info;
    		_this.parms.total = data.data.total || 0
    		_this.showlist();
    	}
    })
    .error(function (err) {
      console.log(err);
    })
    .always(function () {
    	dsf.layer.close(loading)
    }).exec();
  	
  }
  geturls(cover){
		let urls ='';
		if(cover){
			let cov = JSON.parse(cover);
			if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
		}else{
			urls="res/dsf_styles/themes/nc/head_logo.png"
		}
		return urls;
  }
