import dome from '../templates/Nmtel.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';
import {
    relyFiles
} from '../../../core/relyfiles';
import {
    Action,
    UrlSetting
} from '../../../core/pageAction';
import {
    PageEvent
} from '../../../core/ControlEvent';
@map("联系方式", 'nc.teas.nctellist', 'Nmtel')

@relyFiles([
    'res/libs/jquery-ui/jquery-ui.min.css',
    'res/libs/jquery-ui/jquery-ui.min.js'
])
export class Nmtel extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this._desingerClass = ControlEditor;
		this.$useVdom = true;
		
		this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
		this.parms={
			pageNum:1,
			pageSize:20,
			namespace:'nc.contact_way',
			pageName:'list'
		}
		this.top='20px'
		this.left='20px'
//		this.$name = '标题';
//		this.$title="师资列表~";
//		this.$id="666";
		this.$arr = [];
//		this.$ratio = 2.051;
	}
	initTemplate() {
		return dome(this);
	}
	updated() {
      let _this = this;
    }
	
	
 	inserted(){
 	  if (this._root._isDesign) {
 	  	 this.$arr=[
 	  	 	{
 	  	 		title: "自治区党委组织部干教处",
 	  	 		contents:[
 	  	 			{content:'15881141233'}
 	  	 		]
 	  	 	}
 	  	 ]
 	  	 this.domUpdate();
      } else {
         this.showlist();
         this.isdragged();
         this.changewhere()
         
      }
 	}
   	updated() {
      let _this = this;
    }
// 	fun(){
// 		let _this = this;
// 		_this.inp = _this._handlers['inp'];
// 		this.$title = _this.inp.val()
//		this.domUpdate();
// 	}
// 	相对顶部距离
	set wheretop(v) {
      this.top = v;
      this.domUpdate();
    }
    get wheretop() {
      return this.top;
    }
// 相对左部距离
	set whereleft(v) {
      this.left = v;
      this.domUpdate();
    }
    get whereleft() {
      return this.left;
    }

 	
 	
 	//获取图片地址
    getImageSrc(cover){
      let _this = this;
      if(cover){
          return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath)
      }else{
          return _this.$defaultImgUrl;
      }
    }
	showlist(){
		var loadshow = dsf.layer.loadding();
	  	let _this = this;
		var loadshow = dsf.layer.loadding();
	    let url = dsf.url.getWebPath("meta/list/data")
	    dsf.http.request(url,_this.parms,"get")
	   .done(function (d) {
	   	  if(d.success && d.state==20000){
	   	  	_this.$arr = d.data;
	   	  	_this.domUpdate();
	   	  	console.log(_this.$arr);
	   	  }else{
	   	  	dsf.layer.message(d.message, false)
	   	  }
	   })
	   .error(function (err) {
	      console.log(err);
	      dsf.layer.message(err.message, false)
	   })
	   .always(function () {
	      dsf.layer.close(loadshow);
	   }).exec();
    }
	isdragged(){
		$('.ds_nc_nmtel').draggable()
	}
	changewhere(){
		$('.ds_nc_nmtel').addClass("ds_nc_nmtel_fixe");
		$('.ds_nc_nmtel').css({
			top:this.top,
            left:this.left,
            'z-index':10010
        });
	}
	
	
	//跳转页面
//	gotopage(d){
//		dsf.openUrl(1,d)
//	}
//  funin(d){
//  	console.log('移入'+d);
//  }
//  funout(d){
//  	console.log('移出'+d);
//  }
}
