   //是否显示菜单
   isShowMenusFun() {
      if (this.defaultData.isShowMenu) {
         this._handlers['comMenus'].removeClass("none");
      } else {
         this._handlers['comMenus'].addClass("none");
      }
   }
   //是否显示操作按钮
   isShowChooseBtnFun() {
      if (this.defaultData.isShowChooseBtn) {
         this._handlers['comHandleBtn'].removeClass("none");
      } else {
         this._handlers['comHandleBtn'].addClass("none");
      }
      this._handlers['comHandleBtn'].html(this.defaultData.btnText);
      let that = this;
      this._handlers['comHandleBtn'].click(function () {
         if (!userId) {
            window.parent.openLogin();
         } else {
            let path = dsf.url.getWebPath(that.defaultData.btnUrl);
            dsf.openUrl(1, path);
         }
      })
   }
   //是否显示更多按钮
   isShowMoreBtnFun() {
      if (this.defaultData.isShowMoreBtn) {
         this._handlers['comMoreBtn'].removeClass("none");
      } else {
         this._handlers['comMoreBtn'].addClass("none");
      }
      let that = this;
      this._handlers['comMoreBtn'].click(function (evt) {
         let userId = dsf.getCookie('userId');
         if (!userId) {
            window.parent.openLogin();
            evt.preventDefault();
         }
         // else {
         //    let path = dsf.url.getWebPath(that.defaultData.moreBtnUrl);
         //    dsf.openUrl(1, path)
         // }
      })
   }
    
    
