      let id = dataBanner[idx]['id'],
         path = dsf.url.getWebPath('nc/mhsy/views/xwxq.html?id=' + id),
         userId = dsf.getCookie('userId');
      if (!userId) {
         window.parent.openLogin();
         return;
      } else {
         dsf.openUrl(1, path);
      }
