import dome from '../templates/NcClassRoomr.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("在学课堂右", 'nc.teas.ncclassroombox', 'NcClassRoomr')
export class NcClassRoomr extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);

      this._desingerClass = ControlEditor;
      this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
      this.hrefsrc = '';
      this.btnColor = "#D40000"; //默认加号按钮颜色;
      this.dividerColor = "#D40000"; // 默认分隔条颜色;
      this.labelAndNameColor = "#D40000" //默认的鼠标移入颜色;
      this.parms = {
         words: '',
         pageNum: '1',
         pageSize: '10',
         userid: ''
      }
      this.sftjsj = 1
      this.newstextlist = [];

      this.roomlistId = 'roomlist__' + parseInt(Math.random() * 99999999);
      this.btnId = "btn__" + parseInt(Math.random() * 99999999);
      this.jsHeadId = "title__" + parseInt(Math.random() * 99999999);
   }

   initTemplate() {
      return dome(this);
   }

   createElement() {
      super.createElement();
      let _this = this;
      _this.parms.userid = dsf.getCookie('userId');
      let url = dsf.url.getWebPath("nc/kjk/frontuse/getXyZzxxKc");
      dsf.http.request_sync(
         url,
         _this.parms,
         "get"
      )
         .done(function (data) {
            if (data.state == 20000) {
               _this.newstextlist = data.data;
               _this.sftjsj = data.sftjsj;

            }
         })
         .error(function (err) {
            console.log(err);
         })
         .always(function () {
         }).exec();
   }

   renderContext(refresh) {
   }

   //renderComplete(){
   //	console.log(3);
   //}
   geturls(cover) {
      let urls = '';
      if (cover) {
         let cov = JSON.parse(cover);
         if ($.isArray(cov)) {
            urls = cov[0].relativePath;
         }
      } else {
         urls = "res/dsf_styles/themes/nc/404.png"
      }
      return urls;
   }
   nc_classroomlist() {
      let _this = this, shtmlbefore = "", shtml = "", sd = this.newstextlist, isact = '', isxindexact = '';
      _this.$roomlist = _this._handlers['roomlist'];
      if (_this.sftjsj == 0) {
         shtmlbefore = '<p style="text-align: center; padding: 16px;">您暂无在学课程,为您推荐以下课程</p>'
      } else {
         shtmlbefore = ""
      }
      if (sd.length == 0) {
         $('.ds_nc_roombigbox .roomlist').html(shtmlbefore + '<div style="text-align: center; margin-top: 18px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"></div>');
      } else {
         for (var i = 0, len = sd.length; i < len; i++) {
            let urls = _this.geturls(sd[i].cover)
            shtml += `<div class="rrow jsrrow "  id="` + sd[i]._id + `">
									<span class="lintnum">`+ (i + 1) + `</span>
									<div class="roomcon roomconact">
										<div class="ptext"><p class="ell2" title="` + sd[i].title + `"><b style="display: ` + (sd[i].sfnew == 1 ? '' : 'none') + `">new</b><i style="display: ` + (sd[i].sfbx == 1 ? '' : 'none') + `">必修</i>` + sd[i].title + `</p></div>
										<div class="videobox">
											<div class="vboxcon">
												<img src="`+ dsf.url.getWebPath(urls) + `" onerror='onerror=null;src="${this.$defaultImgUrl}"'/>
												<h4></h4>
												<h5>`+ sd[i].kcfs + `</h5>
												<h6><i></i>`+ (sd[i].kcsc == null ? "" : sd[i].kcsc) + `</h6>
											</div>
										</div>
									</div>
								</div>`;
         }
         _this.$roomlist.html(shtmlbefore + shtml);
         _this.$roomlist.find('.roomcon').click(function () {
            let id = $(this).parents('.rrow').attr('id');
            let urls = dsf.url.getWebPath('nc/pc/course/views/course.html?id=' + id)
            dsf.openUrl(1, urls)
         })
      }

   }
   messmore() {
      let _this = this;
      _this.$jsmess = _this._handlers['jsmess'];
      _this.$jsmess.click(function () {
         let urls = dsf.url.getWebPath(_this.hrefsrc)
         dsf.openUrl(1, urls)

         //       let urls = dsf.url.getWebPath(_this.hrefsrc);
         //       window.parent.location.href = window.parent.location.href.split('?')[0] + '?hasRead=0&type=1&selItem=2&path=' + dsf.Base64.encode(urls);
      })
   }
   renderReady() {//组件加载完成后执行
      super.renderReady();
      this.nc_classroomlist();
      this.messmore();

   }
   initEvent() {
      console.log(222);
   }
   changeBtnColor() {
      this._handlers["btnC"].html(`
        .${this.btnId}{
           background:${this.btnColor} !important;
        }
     `);
   }
   changeDividerColor() {
      // this._handlers["jsHead"].css({"borderBottom":"1px solid " + this.dividerColor})
      this._handlers["divideC"].html(`
       .${this.jsHeadId}{
          background:${this.dividerColor} !important;
       }
     `);
   }
   changeLabelAndNameColor() {
      this._handlers.labelAndName.html(`
         .${this.roomlistId} .rrow:hover .ptext{
            color: ${this.labelAndNameColor} !important;
         }
         .${this.roomlistId} .rrow:hover span{
            background-color: ${this.labelAndNameColor} !important;
         }
         .${this.roomlistId} .rrow:hover .ptext .ell2 b {
            background-color: ${this.labelAndNameColor} !important;
         }
         .${this.roomlistId} .rrow:hover .videobox .vboxcon h4 {
            border-color: ${this.labelAndNameColor} !important;
         }
      `);

   }
}

