   postData () {
      let loading = dsf.layer.loadding();
      let url = 'nc/xxgl/xys/findXys';
      if (this.defaultData.urlAddress) url = this.defaultData.urlAddress;
      let sourceUrl = dsf.url.getWebPath(url);
      let params = {
         pageNum: 1,
         pageSize: 200,
         words: ''
      };
      dsf.http.request(
          sourceUrl, params, 'GET'
      ).done(response => {
         if (response.state === 20000) {
            // 请求成功
            this.postDataSuccess(response.data.info);
         } else {
            // 请求失败
            dsf.layer.message(response.message, false);
         }
      }).error(response => {
         // 请求错误
         dsf.layer.message('请求异常', false);
      }).always(response => {
         dsf.layer.close(loading);
      }).exec();
   }

