import dome from "../templates/NcAssignment.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("学习任务", "nc.teas.ncassignment", "NcAssignment")
export class NcAssignment extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
		this.$useVdom = true;
		
    this.sourceUrl = "";
    this.iscl = true;
    this.listColor = "#D60C0C"; //分隔条颜色
    this.numColor = "#D60C0C"; //数字颜色
    this.tabs = []; //选项卡
    //默认字段
    this.defaulData = {
      year: "1",
      wcztbcount: "2",
      ztbcount: "3",
      wckccount: "4",
      kccount: "5",
      wczxscount: "6",
      zxscount: "",
      xxkccount:"8",
			wcxxkccount:"9",
			xxkcxscount:"10",
			wcxxkcxscount:"11"
    };
    this.isbtn = false; 
    this.btnssrc = ''; //点击按钮跳转的链接
    
    //  this.assignmentList = [
    //    {
    //      img: "/themes/nc/assignment/naindu.png",
    //      value: "2019",
    //      text: "学习年度",
    //    },
    //    {
    //      img: "/themes/nc/assignment/zhuantiban.png",
    //      value: "1/2",
    //      text: "必修专题班",
    //    },
    //    {
    //      img: "/themes/nc/assignment/kecheng.png",
    //      value: "12/20",
    //      text: "必修课程",
    //    },
    //    {
    //      img: "/themes/nc/assignment/xueshi.png",
    //      value: "1/2",
    //      text: "总学时",
    //    },
    //  ];
  }
  //兼容老版本
  //   renderReady() {

  //   }
  initTemplate() {
    return dome(this);
  }
  
//20200619新增------------
		set isbtnssrcfun(v) {
      this.isbtn = v;
      this.isshowExambtn();
      this.domUpdate();
    }
    get isbtnssrcfun() {
      return this.isbtn;
    }
    
		set btnsrc(v) {
      this.btnssrc = v;
      this.domUpdate();
    }
    get btnsrc() {
      return this.btnssrc;
    }
    
    
//   _this._handlers['ds_nc_newbanner']
//  gotopage(){
//  	
//  	if(this.btnssrc!=undefined && this.btnssrc!=''){
//  		var ur = dsf.url.getWebPath(this.btnssrc);
//  		console.log(ur);
//	    	dsf.openUrl(1,ur)
//  	}
//  }
    
//-----------------------end
  
  

  renderContext() {
    super.renderContext();

    //  this._handlers.assignList.css({
    //    color: this.numColor,
    //  })

    //  dom.length &&
    //    dom.forEach((item) => {
    //      console.log(item);
    //      $(item)[0].style.color = this.numColor;
    //    });
    //增加默认值兼容老版本
    if (!this.tabs.length) {
      this.tabs = [
        {
          text: "学习年度",
          img: "/res/dsf_styles/themes/nc/assignment/naindu.png",
          count1: "year",
          count2: "",
          httpsrc:''
        },
        {
          text: "必修专题班",
          img: "/res/dsf_styles/themes/nc/assignment/zhuantiban.png",
          count1: "wcztbcount",
          count2: "ztbcount",
          httpsrc:''
        },
        {
          text: "必修课程",
          img: "/res/dsf_styles/themes/nc/assignment/kecheng.png",
          count1: "wckccount",
          count2: "kccount",
          httpsrc:''
        },
        {
          text: "必修课程总学时",
          img: "/res/dsf_styles/themes/nc/assignment/xueshi.png",
          count1: "wczxscount",
          count2: "zxscount",
          httpsrc:''
        },
        {
          text: "选修课程",
          img: "/res/dsf_styles/themes/nc/assignment/xuanxiu.png",
          count1: "wcxxkccount",
          count2: "xxkccount",
          httpsrc:''
        },
        {
          text: "选修课程总学时",
          img: "/res/dsf_styles/themes/nc/assignment/xuanxiutime.png",
          count1: "wcxxkcxscount",
          count2: "xxkcxscount",
          httpsrc:'nc/pc/mine/views/learnTrajectory.html?name=我的'
        },
      ];
    }
    this.isshowExambtn();
    if (this._root._isDesign) {
      this.renderPage(this.defaulData);
    } else {
      this.getAssignData();
      this.tips();
      this.isgotopage();
    }
    //颜色渲染 commonFontColor
    this.changeColor();
  }
  isgotopage(){
  	var _this = this;
  	this._handlers['jsemax'].click(function(){
  		if(_this.btnssrc!=undefined && _this.btnssrc!=''){
    		var ur = dsf.url.getWebPath(_this.btnssrc);
	    	dsf.openUrl(1,ur)
    	}
  	});
  }
  changeColor() {
    if (!this.listColor) {
      this._handlers.leftb.addClass("commonBgColor");
    } else {
      this._handlers.leftb.removeClass("commonBgColor");
      this._handlers.leftb.css({
        "background-color": this.listColor,
      });
    }
  }
  updateDom() {
    let dom = $(".assignment_list>li>dl>dt");
    this.tabs.length &&
      dom.length &&
      this.tabs.forEach((item, index) => {
        let a = $(dom[index]);
        if (!this.numColor) {
          a.addClass("commonFontColor");
        } else {
          a.removeClass("commonFontColor");
          a.css({
            color: this.numColor,
          });
        }
        // dom[index].style.color = this.numColor ? this.numColor : "#2B6BE2";
      });
  }
  getAssignData() {
    let loading = dsf.layer.loadding();
    if (!this.sourceUrl) this.sourceUrl = "nc/ztb/tea/getMyStudentTask";
    let sourceurl = dsf.url.getWebPath(this.sourceUrl);
    let params = {
      userid: "eafe290932464971b0e036c38a92f882",
    };

    dsf.http
      .request(sourceurl, params, "Get")
      .done((res) => {
      	res = {
      		data:{
      			kccount: "0",
						wckccount: "0",
						wcxxkccount: 15,
						wcxxkcxscount: 7.5,
						wcztbcount: "0",
						wczxscount: "0",
						xxkccount: 38,
						xxkcxscount: 19,
						year: "2020",
						ztbcount: "0",
						zxscount: "20"
      		},
      		message: "成功",
					state: 20000,
					success: true
      	}
        if (res.success && res.state == 20000) {
          this.renderPage(res.data);
        } else {
          dsf.layer.message(res.message);
        }
      })
      .error((err) => {
        dsf.layer.message(err);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }
  changeTabsData() {
    if (this._root._isDesign) {
      this.renderPage(this.defaulData);
    } else {
      this.getAssignData();
      this.tips();
    }
  }
  renderPage(data) {
    let html = "";
    this.tabs.length &&
      this.tabs.forEach((item) => {
      	let iscur = '';
      	if(item.httpsrc==''){
      		iscur = ''
      	}else{
      		iscur = 'addcur';
      	}
        html += `
          <li class="`+iscur+`" data-src="`+item.httpsrc+`">\n
            <img src='${dsf.url.getWebPath(item.img)}' alt="">\n
              <dl>\n 
                <dt>${data[item.count1 || "--"]} ${
          item.count2 ? " / " + (data[item.count2] || "--") : ""
        }</dt>\n 
                <dd>${item.text}</dd>\n 
              </dl>\n 
          </li>\n 
        `;
      });
    this._handlers["assignList"].html(html);
    this._handlers["assignList"].find('li').click(function(){
    	
//  	当前document切换页面时,让导航也切换
    	var hsrc = $(this).attr('data-src');
    	var ur = dsf.url.getWebPath(hsrc);
    	if(ur==''){
    		return false;
    	}
    	$(window.parent.document).find("#J_content").attr('src',ur+'&filter=0');
    	$(window.parent.document).find(".main-header .nav-wrap li").removeClass('nav-item-sel-white');
    	$(window.parent.document).find(".main-header .nav-wrap li:nth-child(3)").addClass('nav-item-sel-white');
    })
    this.updateDom();
  }
  tips() {
    let _this = this;
    this._handlers["jstitle_icon"].mouseover(function() {
      _this.$jstipscon = _this._handlers["jstipscon"];
      if (_this.iscl) {
        let yeaer = new Date().getFullYear();
        layer.tips(
          `<span style="color:#333">${yeaer}学年周期为</br>${yeaer}-2-1至${yeaer +
            1}-1-31</span>`,
          _this.$jstipscon,
          {
            tips: [4, "#f9f9f9"],
            time: 4000,
          }
        );
        
        _this.iscl = false;
        setTimeout(function() {
          _this.iscl = true;
        }, 4000);
      }
    });
  }
  isshowExambtn(){
  	if(this.isbtn){
  		$('.btnsbox').show();
  	}else{
  		$('.btnsbox').hide();
  	}
  }
}
