import dome from "../../templates/HdRecommend.ejs";
import { map } from "../../../../decorator/controlmap";
import { ControlEditor } from "../../../../editor/ControlEditor";

@map("首页推荐", "nc.teas.hdrecommend", "HdRecommend")
export class HdRecommend extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$useVdom = true;

    this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
    
    this.$recommendList = [];
    //请求接口参数
    this.parms = {
      type_value: "05",
      pageNo: 1,
      pageSize: 6,
    };
    
  }

  gotoDetail(){
    // var ur = dsf.url.getWebPath(this.detailUrl);
    //   dsf.openUrl(1,ur)
    dsf.layer.message('暂未开放', false)
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
    if (this._root._isDesign) {
      this.defaultData();

    } else {
      // this.postData();
      this.defaultData();
    }
    
  }
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
  }
  initEvent() {}

  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = dsf.url.getWebPath(cov[0].relativePath);
      }
    } else {
      urls = dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png");
    }
    return urls;
  }

  /**
   * 请求数据
   */
  postData () {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('yyzx/pdgl/findZtbGDList');
    dsf.http.request(
        url, _this.parms, 'get'
    ).done(response => {
      if (response.state === 20000) {
        // 请求成功
        _this.$recommendList = response.data;
        _this.domUpdate();
      }else{
        dsf.layer.message(response.message, false)
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }

  defaultData(){
    let _this = this;
    _this.$recommendList = [{
      imgSrc: '/dsfa/res/dsf_styles/themes/img/nc/songdujd.png'
    },{
      imgSrc: '/dsfa/res/dsf_styles/themes/img/nc/dangyuankc.png'
    },{
      imgSrc: '/dsfa/res/dsf_styles/themes/img/nc/read.png'
    },{
      imgSrc: '/dsfa/res/dsf_styles/themes/img/nc/huadiankjl.png'
    }];
    _this.domUpdate();
  }
}
