import dome from '../../templates/Hcteacher.ejs';
import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from '../../../../editor/ControlEditor';
 
@map("华电师资", 'nc.teas.hdteacher', 'Hcteacher')
export class Hcteacher extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this._desingerClass = ControlEditor;
		this.$useVdom = true;
		
		this.parms={
			hasRead: 0,
			pageNum: 1,
			pageSize: 4,
			query: '{"searchValue":""}',
			namespace: 'nc.szk',
			pageName: 'mslist',
		}
		this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
		this.title="师资";
		this.ismorebtn = true;
		this.morebtnsrc = '1.html';
		this.$teacherlist=[];
	}
	initTemplate() {
		return dome(this);
	}
	updated() {
      let _this = this;
    }
	
	
 	inserted(){
 	  if (this._root._isDesign) {
 	  	this.showlist();
      } else {
      	this.showlist();
      }
 	}
   	updated() {
      let _this = this;
    }
 	
	set gtitle(v) {
      this.title = v;
      this.domUpdate();
    }
    get gtitle() {
      return this.title;
    }
    
	set gismorebtn(v) {
      this.ismorebtn = v;
      this.domUpdate();
    }
    get gismorebtn() {
      return this.ismorebtn;
    }
    
	set gmorebtnsrc(v) {
      this.morebtnsrc = v;
      this.domUpdate();
    }
    get gmorebtnsrc() {
      return this.morebtnsrc;
    }
    
 	gotopage(){
 		var ur = dsf.url.getWebPath(this.morebtnsrc);
 		location.href=ur
// 		dsf.openUrl(1,ur)
 	}
 	
 	//获取图片地址
    getImageSrc(cover){
      let _this = this;
      if(cover){
          return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath)
      }else{
          return _this.$defaultImgUrl;
      }
    }
	showlist(){
		var _this = this;
		console.log(_this.parms.pageNum);
//		var loadshow = dsf.layer.loadding();
        let url = dsf.url.getWebPath("meta/list/data")
        dsf.http.request(url,_this.parms,"get")
           .done(function (d) {
              console.log(d);
              if(d.success && d.state==20000){
              	_this.$teacherlist = d.data;
//            	if(_this.$teacherlist.length<_this.parms.pageSize){
//            		_this.parms.pageNum--
//            	}
              	_this.domUpdate();
              }else{
              	dsf.layer.message(d.message, false)
              }
           })
           .error(function (err) {
              console.log(err);
              dsf.layer.message(d.message, false)
           })
           .always(function () {
//            dsf.layer.close(loadshow);
           }).exec();
	}
	newsdetails(id){
		var ur = dsf.url.getWebPath('nc/mhsy/views/xwxq.html?id='+id);
		location.href = ur
//		dsf.openUrl(1,ur)
	}
	teacherpage(choosebtn){
		if(choosebtn=='left'){
			this.parms.pageNum--
			if(this.parms.pageNum<1){
				this.parms.pageNum=1
				this.showlist();
			}else{
				this.showlist();
			}
		}else{
			this.parms.pageNum++
			this.showlist();
		}
	}
	teacherDetails(id){
		let userId = dsf.getCookie('userId');
	    if (!userId) {
	        window.parent.openLogin();
	        return;
	    }
		var ur = dsf.url.getWebPath('nc/pc/teachersDetailnew/views/teachersDetailnew.html?id='+id);
		dsf.openUrl(1,ur)
	}
}
