import dome from '../templates/NcRecoNoviceSaid.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("推荐学员说", 'nc.teas.ncreconovicesaid', 'NcRecoNoviceSaid')

export class NcRecoNoviceSaid extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.tjList = [
            {name:'姓名一',title: '推荐学员说一'},
            {name:'姓名二',title: '推荐学员说二'},
            {name:'姓名三',title: '推荐学员说三'},
            {name:'姓名四',title: '推荐学员说四'},
        ]
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            this.renderNewest(this.tjList);
        } else {
            this.getRecomSaid();
        }
    };

    renderReady() {
        super.renderReady();
    }

    // 推荐学员说
    getRecomSaid() {
        let loading = dsf.layer.loadding();
        let sourceUrl = dsf.url.getWebPath('nc/xxgl/xys/findTjXys');
        dsf.http.request(sourceUrl,{},'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    this.renderNewest(res.data)
                } else {
                    dsf.layer.message('请求失败');
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    renderTop(data) {
        let page = [
            {s:0,e:10},
            {s:10,e:20},
            {s:20,e:30},
            {s:30,e:40},
            {s:40,e:50},
        ];
        let n = -1;
        let topArr = '';
        let _this = this;
        // 换一批点击
        document.onclick = function() {
            n++;
            if (n>4) {
                n = -1;
            }
            topArr = data.slice(page[n].s,page[n].e);
            _this.renderNewest(topArr);
        }
    }

    // 推荐学员说
    renderNewest(data) {
        let newestStr = '';
        if (data&&data.length) {
            for (var i = 0;i < data.length;i++) {
                newestStr += '<li><span>'+ data[i].name +'</span>'+ data[i].title +'</li>';
            }
            this._handlers['newestList'].html(newestStr);
            this.bindDetail(data);
        } else {
            return
        }
    }

    // 跳转学员说详情
    bindDetail(data) {
        $('.news_list').find('li').each(function (index) {
            var _this = $(this);
            _this.on('click',function (e) {
                let jumpUrl = dsf.url.getWebPath('nc/mhsy/views/xysxq.html?id='+data[index].id);
                window.open(jumpUrl,'_self');
            })
        });
    }

}


