import query from "../../templates/JxQueryCertificate.ejs";
import { ControlEditor } from "../../../../editor/ControlEditor";
import { map } from "../../../../decorator/controlmap";

@map("证书查询", "nc.ncctrl.jxquerycertificate", "JxQueryCertificate")
export class JxQueryCertificate extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    //表单宽度
    this.formWidth = 400;
    //表单撑开
    this.formPadding = true;
    //表单背景图
    this.formBg = "";
    //表格数据
    this.listData = [];
    //接口地址
    this.httpUrl = "/nc/zsgl/matchingNumberAndName";
    //没有数据图片
    this.noDataImg = dsf.url.getWebPath(
      "/res/dsf_styles/themes/img/nodata.png"
    );
  }
  initTemplate() {
    return query(this);
  }
  renderContext(refresh) {
    super.renderContext();
    this.root.event.on(PageEvent.READY, (args) => {
      this._handlers.queryFrom.css({
        width: this.formWidth + "px",
      });
      if (!this.formPadding) {
        this._handlers.queryFrom.css({
          padding: 0,
        });
      }
      let htmlHight = $("html").height(),
        formHeight = this._handlers.queryFrom.outerHeight();
      this._handlers.queryTbody.css({
        "min-height": htmlHight - formHeight - 90 + "px",
      });
      this.InitCode();
      if (this.formBg) {
        this._handlers.form_box.css({
          background: `url('${dsf.url.getWebPath(this.formBg)}') no-repeat`,
          "background-size": "100% 100%",
        });
      }
    });
  }
  //验证码获取
  InitCode() {
    var imgUrl = dsf.url.getWebPath("code/image?t=" + new Date().getTime());
    this._handlers.codeImg.attr("src", imgUrl);
  }

  //注册点击查询
  initEvent() {
    this.element.on("click", ".codeImgBox", () => {
      this.InitCode();
    });
    this.element.on("click", ".queryBtnCer", () => {
      let number = this._handlers.number.val();
      // let number = "ZS202041300135";
      let name = this._handlers.name.val();
      // let name = "黄麒源";
      let code = this._handlers.code.val();
      if (!number) {
        dsf.layer.message("证书编号不能为空", false);
        return;
      } else if (!name) {
        dsf.layer.message("学员姓名不能为空", false);
        return;
      } else if (!code) {
        dsf.layer.message("验证码不能为空", false);
        return;
      }
      let REX = /^[ZS]{2}(\d{11}|\d{12}|\d{13})$/;
      console.log(REX.test(number));
      if (!REX.test(number)) {
        dsf.layer.message("请输入正确的证书编号", false);
        return;
      }
      //汉字匹配
      let REX2 = /[\u4e00-\u9fa5]/;
      if (!REX2.test(name)) {
        dsf.layer.message("请输入纯汉字", false);
        return;
      }
      //验证码
      let REX3 = /\d{4}$/;
      if (!REX3.test(code)) {
        dsf.layer.message("验证码错误", false);
        return;
      }
      // 调用接口
      let loadding = dsf.layer.loadding();
      dsf.http
        .request(
          dsf.url.getWebPath(this.httpUrl),
          { number, name, code },
          "GET"
        )
        .done((response) => {
          if (response.state === 20000) {
            let res = response.data;
            res && res.length ? (this.listData = res) : (this.listData = []);
            this.renderHtml();
          } else {
            this.listData = [];
            this.renderHtml();
            dsf.layer.message(response.message, false);
          }
        })
        .error(function(response) {
          dsf.layer.message("加载数据出错", false);
        })
        .always(() => {
          this.InitCode();
          dsf.layer.close(loadding);
        })
        .exec();
    });
  }
  //html渲染
  renderHtml() {
    let html = "";
    if (this.listData.length) {
      this.listData.forEach((item) => {
        html += `
        <tr class="tb-tr">
            <td>${item.zsmc}</td>
            <td>${item.zsbh}</td>
            <td>${item.pxnd}</td>
            <td>${item.xymc}</td>
            <td>${item.xyxb}</td>
            <td>${item.zxs}</td>
            <td>${item.bydate}</td>
          </tr>
        `;
      });
      html = `
      <table>
        <tbody>
          ${html}
        </tbody>
      </table>
      `;
    } else {
      html = `
      <div class="noData">
        <img src="${this.noDataImg}" alt="" />
      </div>
      `;
    }
    this._handlers.queryTbody.html(html);
  }
}
