import dome from "../templates/Newlists.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("新闻列表", "nc.teas.newlists", "Newlists")
export class Newlists extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.errimg = "/dsfa/res/dsf_styles/themes/nc/404.png";
    this.parms = {
      words: "",
      pageNum: 1,
      pageSize: "5",
    };
    this.maintitle = [{ cname: "1" }, { cname: "2" }, { cname: "3" }];
    this.banner_newslists = [
      {
        cover:
          "/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-1.jpg",
        cname: "条目1",
      },
      {
        cover:
          "/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg",
        cname: "条目2",
      },
      {
        cover:
          "/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-3.jpg",
        cname: "条目3",
      },
      {
        cover:
          "/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-4.jpg",
        cname: "条目4",
      },
    ];
    this.common = {};
    this.fontColor = "#C90C0A";
    this.searchColor = "#c90c0a";
    this.titleImg = "res/dsf_styles/themes/nc/icon_means.png";
    this.searchImg = "res/dsf_styles/themes/nc/sousuo02.png";
  }

  initTemplate() {
    return dome(this);
  }
  nofind() {
    let img = event.srcElement;
    img.src = "404.png";
    img.onerror = null;
  }
  getlist() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath("nc/news/findNewsList");

    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          _this.common = data.data.common;
          _this.recentNewslist();
        }
      })
      .error(function(err) {})
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }
  createElement() {
    super.createElement();
    //      20200310做成标题和数据过滤项可配置
    this._handlers.newstitle.html(dsf.url.queryString("gitTitle") || "新闻");
    this.parms.lmId = dsf.url.queryString("newlmld") || "";
    this._handlers.newsinp.attr(
      "placeholder",
      dsf.url.queryString("placeholder") || "请输入"
    );

    let _this = this;
    let url = dsf.url.getWebPath("nc/news/findNewsList");
    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          _this.maintitle = data.data.zd;
          _this.banner_newslists = data.data.lb;
        }
      })
      .error(function(err) {})
      .always(function() {})
      .exec();
  }

  renderContext(refresh) {
    super.renderContext();
    this.changeTitleIcon();
  }
  //切换标题图片
  changeTitleIcon() {
    this._handlers.photoImgLeft.attr(
      "src",
      this.titleImg ? dsf.url.getWebPath(this.titleImg) : ""
    );
    this._handlers.newsserchimg.attr(
      "src",
      this.searchImg ? dsf.url.getWebPath(this.searchImg) : ""
    );
    if (this.titleImg == "" || this.titleImg == undefined) {
      $(".serchbox .leftbox span").css("display", "none");
    } else {
      $(".serchbox .leftbox span").css({ display: "block", float: "left" });
    }
  }
  // 改变标题字体颜色,按钮背景色，标题背景色
  changeColor() {
    $(".titlebox .p0").css("color", this.fontCo);
    $(".titlebox .p1").css("color", this.fontCo);
//  $(".serchbox .leftbox span").css("background", this.fontColor);
//  if (this.searchColor == "") {
//    this._handlers.newsserch.addClass("f_background_color");
//  } else {
//    this._handlers.newsserch
//      .css("background", this.searchColor)
//      .removeClass("f_background_color");
//  }
  }
  showtitle() {
    let _this = this,
      shtml = "",
      sd = this.maintitle;
    _this.$titlebox = _this._handlers["titlebox"];
    if (sd.length == 0) {
      return false;
    }
    for (var i = 0, len = sd.length; i < len; i++) {
      shtml +=
        '<p class="p' +
        i +
        '" id="' +
        sd[i].id +
        '">' +
        (sd[i].cname == undefined ? "--" : sd[i].cname) +
        "</p>";
    }
    this._handlers.titlebox.html(shtml);
    _this.$titlebox.find("p").click(function() {
      let id = $(this).attr("id");
      dsf.openUrl(1, "/dsfa/nc/mhsy/views/xwxq.html?id=" + id);
    });
  }
  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
    } else {
      urls = "res/dsf_styles/themes/nc/404.png";
    }
    return urls;
  }
  newslistsbanner() {
    let _this = this,
      shtml = "",
      sd = this.banner_newslists;
    _this.$ds_nc_newlistsbanner = _this._handlers["ds_nc_newlistsbanner"];

    if (sd.length == 0) {
      _this._handlers["bannerbox"].hide();
    } else {
      _this._handlers["bannerbox"].show();
      for (var i = 0, len = sd.length; i < len; i++) {
        let urls = _this.geturls(sd[i].cover);
        shtml +=
          '<div class="n_banner_item_box">' +
          '<div class="n_banner_item" id="' +
          sd[i].id +
          '">' +
          '<img src="' +
          dsf.url.getWebPath(urls) +
          '" onerror=\'onerror=null;src="' +
          dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") +
          "\"'/>" +
          "<p>" +
          sd[i].cname +
          "</p>" +
          "</div>" +
          "</div>";
      }
      _this.$ds_nc_newlistsbanner.html(shtml);
      _this.$ds_nc_newlistsbanner.find(".n_banner_item").click(function() {
        let id = $(this).attr("id");
        dsf.openUrl(1, "/dsfa/nc/mhsy/views/xwxq.html?id=" + id);
      });
    }
  }
  recentNewslist() {
    let _this = this,
      shtml = "",
      sd = this.common.info;
    _this.$newslistbox = _this._handlers["newslistbox"];
    if (sd.length == 0) {
      _this.$newslistbox.html(
        "<div style='text-align: center; margin: 20px;'><img src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>"
      );
      $(".pagebox").hide();
      return false;
    }
    for (var i = 0, len = sd.length; i < len; i++) {
      let urls = _this.geturls(sd[i].cover);
      shtml +=
        '<div class="news_item" id="' +
        sd[i].id +
        '">' +
        '<div class="leftimgbox">' +
        '<img src="' +
        dsf.url.getWebPath(urls) +
        '" onerror=\'onerror=null;src="' +
        dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") +
        "\"'/>" +
        "</div>" +
        '<div class="rightconbox">' +
        '<p class="ell" title="' +
        (sd[i].cname == undefined ? "" : sd[i].cname) +
        '">' +
        (sd[i].cname == undefined ? "" : sd[i].cname) +
        "</p>" +
        '<h6 class="ell3">' +
        (sd[i].abstract == undefined ? "" : sd[i].abstract) +
        "</h6>" +
        "<h5><i></i><span>" +
        (sd[i].djcs == null ? "" : sd[i].djcs) +
        "</span></h5>" +
        "<em>" +
        (sd[i].ds_create_time == null ? "" : sd[i].ds_create_time) +
        "</em>" +
        "</div>" +
        "</div>";
    }
    $(".pagebox").show();
    _this.$newslistbox.html(shtml);
    _this.$newslistbox.find(".leftimgbox,p").click(function() {
      let id = $(this)
        .parents(".news_item")
        .attr("id");
      dsf.openUrl(1, "/dsfa/nc/mhsy/views/xwxq.html?id=" + id);
    });
  }
  newsserch() {
    let _this = this;
    _this.$newslistbox = _this._handlers["newsserch"];
    _this.$newsinp = _this._handlers["newsinp"];
    _this.$newslistbox.click(function() {
      _this.parms.words = _this.$newsinp.val();
      _this.parms.pageNum = 1;
      _this.getlist();
      _this.getPage();
    });
    //enter
    _this.$rightbox = _this._handlers["rightbox"];
    _this.$rightbox.keyup(function() {
      if (event.keyCode == 13) {
        _this.parms.words = _this.$newsinp.val();
        _this.parms.pageNum = 1;
        _this.getlist();
        _this.getPage();
      }
    });
  }
  getPage() {
    let _this = this;

    console.log(dsf.config.defaultTheme);

    layui.use(["laypage", "layer"], function() {
      var laypage = layui.laypage,
        layer = layui.layer;
      laypage.render({
        elem: "demo2",
        limit: _this.parms.pageSize,
        count: _this.common.total,
        groups: 4,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ["prev", "page", "next", "count"],
        jump: function(obj, first) {
          if (!first) {
            _this.parms.pageNum = obj.curr;
            _this.getlist();
          }
        },
      });
    });
  }
  renderReady() {
    super.renderReady();
    var _this = this;

    this.showtitle();
    this.newslistsbanner();
    this.newsserch();
    let w = 0;
    setTimeout(function() {
      w = _this._handlers.bannerbox.width();

      let h = (w / 4) * 3;
      layui.use(["carousel", "form"], function() {
        var carousel = layui.carousel,
          form = layui.form;
        carousel.render({
          elem: "#test2",
          interval: 1800,
          height: "600px",
          width: "100%",
          arrow: "none",
        });
      });
    }, 500);
    _this.getlist();
    _this.getPage();

    this.fontColor = this.fontColor === undefined ? "#C90C0A" : this.fontColor;
    this.titleImg =
      this.titleImg === undefined
        ? "res/dsf_styles/themes/nc/book.png"
        : this.titleImg;
    this.searchImg =
      this.searchImg === undefined
        ? "res/dsf_styles/themes/nc/sousuo02.png"
        : this.searchImg;
    this.searchColor =
      this.searchColor == undefined ? "#c90c0a" : this.searchColor;
    this.changeColor();
    this.changeTitleIcon();
  }

  initEvent() {}
}
