import dome from '../templates/NcBottomBar.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("底栏", 'nc.teas.ncbottombar', 'NcBottomBar')

export class NcBottomBar extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.years = '2019';
        this.recordNum = '沪ICP备18014503号-1';
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        this._handlers.setYear.find('span').html(this.years);
        this._handlers.setRecoreNum.find('span').html(this.recordNum);
    };

}
