function cancelAllEdit(exclude) {
  let ctrls = $(document).find(".ds_control");
  ctrls.each((i, el) => {
    var c = $.data(el, "Object");
    if (exclude != c) {
      if (c._desinger) {
        c._desinger.cancelEdit();
      }
    }
  })
  this._selectedList = [];
}

//拖动排序
function layoutChange(target, mouse) {
  let box = null;
  let ctrl = target.closest(".ds_control");
  if (target.hasClass("drop-ignore")) {
    return;
  }
  // console.log(target.get(0).tagName);
  // console.log(target.hasClass("ds_container"));
  //如果不是容器，则取组件所在容器
  if (!target.hasClass("ds_container")) {
    // console.log(target.get(0))
    box = target.closest(".ds_container");
    if (box.hasClass("ds_container")) {
      if (!target.hasClass("ds_drop_proxy")) {
        let control = target.closest(".ds_control");
        let position = control.offset();
        let offset = { x: 0, y: 0 };
        let height = control.height();
        offset.x = mouse.x - position.left;
        offset.y = mouse.y - position.top;
        offset.x = offset.x < 0 ? 0 : offset.x;
        offset.y = offset.y < 0 ? 0 : offset.y;
        let proxy = showProxy();
        // let last = box.children(".ds_control").last();
        if (offset.y < height / 2) {
          control.before(proxy);
        } else {
          control.after(proxy);
        }
      }
    }

  } else if (target.hasClass("ds_container")) {
    box = target;
    let proxy = showProxy();
    box.append(proxy);
  }
}


//计算亮点距离
function getDistance(p1, p2) {
  if (!p1 || !p2) {
    return 0;
  }
  let x_len = Math.abs(p2.x - p1.x);
  let y_len = Math.abs(p2.y - p1.y);
  let len = Math.sqrt(Math.pow(x_len, 2) + Math.pow(y_len, 2));
  return len;
}


//动态创建控件类型
function createNewControl(ctrlType, callback) {
  // console.log(Controls);
  let ctrl = new dsf.Controls[ctrlType](null, false);


  if (ctrl.label != undefined && ctrl.isPostSupport) {
    ctrl.label = "";
  }
  if (ctrl.relyFiles && ctrl.relyFiles) {
    dsf.Import(ctrl.relyFiles, (a, b, c) => {
      callback(ctrl);
      fn();
    });
  } else {
    callback(ctrl);
    fn();
  }
  //如果组件添加了基础设置，则从工具箱拖动到页面时自动弹出设置
  function fn() {
    if (ctrl.baseSetting && ctrl.baseSetting.settingHtmlPath) {
      dsf.layer.openDialog({
        title: ctrl.baseSetting.title,
        content: dsf.url.getAbsolutePath(ctrl.baseSetting.settingHtmlPath),
        args: {
          owner: ctrl
        },
        area: [ctrl.baseSetting.width, ctrl.baseSetting.height],
        btn: [{
          text: "完成编辑",
          handler: function(index, layero) {
            let frame = layero.find("iframe");
            let win = frame.get(0).contentWindow;
            if (win) {
              let result = win.getDialogResult();
              $.extend(ctrl, result);
              ctrl.render();
            }
          }
        }, {
          text: "取消",
          handler: function() {
            return true;
          }
        }]
      });
    }
  }
}

