function moveControl(control) {
  let proxy = $(".ds_drop_proxy");
  let index = null;
  let box = this.children[0];
  let oldParent = control.parent;
  oldParent.removeChild(control, false);
  let handler = "";
  if (proxy.length > 0) {
    // index = proxy.index();
    box = proxy.parent();
    let nextEl = proxy.next();
    if (nextEl.length > 0) {
      let nextCtrl = nextEl.data("Object");
      if (nextCtrl) {
        index = nextCtrl.index;
      }
    } else {
      index = oldParent.children.length;
    }
    handler = box.attr("handler")
    while (!box.data("Object")) {
      box = box.parent();
    }
    box = box.data("Object");
  }
  cancelAllEdit.call(this);
  if (box instanceof dsf.Controls.LayoutControl) {
    box.addChild(control, index, handler);
  } else {
    box.addChild(control, index);
  }
  let old_scopeLevel = control.$scopeLevel;
  this.isOneToMany(control) ? control.$scopeLevel = 1 : control.$scopeLevel = 0;
  if (control.$scopeLevel != old_scopeLevel) {
    if (control.metadata) {
      control.metadata_fullcode = "";
    }
  }
  console.log(control.$scopeLevel)
}

