function createAttrbutesEditor(control, attrs) {
  let _this = this;
  let root = $("<DIV class='ds_attr_root'/>");
  let form = $("<form class='layui-form' lay-filter='attr_form' action=''/>").appendTo(root);
  let collapse = $("<div class='layui-collapse lay-accordion' lay-filter='controls_attrs'/>").appendTo(form);

  function fn(attrs, content) {
    for (let i = 0; i < attrs.length; i++) {
      // 配置class属性用于添加class，支持Array/String
      let _class = "";
      if (attrs[i].class) {
        let attrClass = attrs[i].class;
        if ($.isArray(attrClass)) {
          for (let j in attrClass) {
            _class += " " + attrClass[j];
          }
        } else if (typeof attrClass) {
          _class = " " + attrClass;
        } else {
          console.error('设置属性值[class]类型错误');
        }
      }
      // 配置了隐藏属性，判断是否满足隐藏，添加隐藏class
      if (attrs[i].hidden) {

		if((typeof attrs[i].hidden) === "boolean"){
			attrs[i].hidden && (_class += " ds_item_hidden");
		}else{
			let isReverse = attrs[i].hidden.slice(0, 1) === '!';
			if (isReverse) {
			  attrs[i].hidden = attrs[i].hidden.slice(1);
			}
			let _idx = attrs[i].hidden.indexOf("!=");
			let array = attrs[i].hidden.split(_idx != -1 ? "!=" : "==");
			let _dA = array[0].split('.');
			let state = control;
			for (let k in _dA) {
			  if (_dA[k].indexOf('[') != -1) {
			    let _leftIndex = _dA[k].indexOf('[');
			    let _rightIndex = _dA[k].indexOf(']')
			    state = state[_dA[k].slice(0, _leftIndex)][_dA[k].slice(_leftIndex + 1, _rightIndex)];
			  } else {
			    state = state[_dA[k]];
			  }
			}
			if (isReverse) {
			  state = !state;
			}
			if (array.length > 1) {
			  if (array[1] == 'false' || array[1] == 'null' || array[1] == 'undefined') {
			    array[1] = eval(array[1]);
			  }
			  if (_idx != -1) {
			    if (state != array[1]) {
			      _class += " ds_item_hidden";
			    }
			  } else if (state == array[1]) {
			    _class += " ds_item_hidden";
			  }
			} else if (state) {
			  _class += " ds_item_hidden";
			}
		}
      }
      let item = $("<div class='layui-form-item ds_attr_item" + _class + "'/>");
      let helper = (attrs[i].helper && attrs[i].helper.url) ? `<a href='${attrs[i].helper.url}' target='view_window' style='padding-left:8px' class='iconfont icon-color icon-093info ${attrs[i].helper.icon}' title='${attrs[i].helper.title}'></a>` : "";
      let label = $("<label>" + attrs[i].text + helper + "</label>");
      let attachment = attrs[i].attachment ? $("<a href='" + attrs[i].attachment.url + "' target='view_window' class='ds_attr_attachment'>" + attrs[i].attachment.name + "</a>") : "";
      let editor = null;
      if (attrsEditor[attrs[i].showType]) {
        editor = new attrsEditor[attrs[i].showType](control, attrs[i]);
      } else {
        editor = new attrsEditor.text(control, attrs[i]);
      }
      item.append(label);
      item.append(attachment);
      item.append(editor.createDom());
      content.append(item);
      if (attrs[i].isShow != undefined) {
        if (typeof(attrs[i].isShow) == "boolean") {
          item.css("display", attrs[i].isShow ? "block" : "none");
        } else if (typeof(attrs[i].isShow) == "string") {
          var isShowResult = dsf.Express.eval(attrs[i].isShow, _this);
          item.css("display", isShowResult ? "block" : "none");
        }
      }

      // dsf.Express.eval()
    }
  }
  for (let i = 0; i < attrs.length; i++) {
    let group = attrs[i];
    let item = $("<div class='layui-colla-item'>").appendTo(collapse);
    let title = $("<h2 class='layui-colla-title'>" + group.name + "</h2>").appendTo(item);
    let content = $('<div class="layui-colla-content layui-show">').appendTo(item);
    fn(group.attributes, content);
  }

  return root;
}

