import dome from "../templates/Ncstraight.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("学霸列", "nc.teas.ncstraight", "Ncstraight")
export class Ncstraight extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.btn1src = "";
    this.btn2src = "";
    this.btn3src = "";
    this.backgroundColor = null;
    this.parms = {
      ztbid: "9f7f9f3faf5945c08c4dba23e6e85684",
      pageNo: 1,
      pageSize: 5,
    };
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    //  let _this=this;
    //		if(parent.parms!=undefined){
    //			this.parms.ztbid = parent.parms.id
    //		}
    console.log(this.parms);
    if (this._root._isDesign) {
    } else {
      this.parms.ztbid = parent.rparms.ztbid;
    }
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-16 11:09:27
   * @LastEditors: OBKoro1
   * @LastEditTime: 颜色值
   */
  setColor() {
    var pattern = /^#[0-9a-fA-F]{6}$/;
    if (!this.backgroundColor.match(pattern)) {
      alert("请输入正确的16进制颜色值");
      return;
    }
    this._handlers.bannerColor.css({
      backgroundColor: this.backgroundColor,
    });
  }

  renderContext(refresh) {
    console.log("titlebox", "refresh");
  }
  geturls(cover) {
    let urls = "";

    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
    } else {
      urls = "res/dsf_styles/themes/nc/head_logo.png";
    }
    return urls;
  }
  showlist() {
    let _this = this;
    let url = dsf.url.getWebPath("nc/ztb/tea/findTodayLearnList");
    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          let shtml = "",
            sd = data.data.records,
            num = "";
          _this.$todaybox = _this._handlers["todaybox"];
          if (sd.length == 0) {
            shtml =
              '<div style="text-align: center; padding: 30px 0;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"></div>';
          } else {
            for (var i = 0, len = sd.length; i < len; i++) {
              let urls = _this.geturls(sd[i].photo);
              if (i < 3) {
                num = "";
              } else {
                num = i + 1;
              }
              shtml +=
                `<div class="todayitem todayitem` +
                i +
                `">
			        			<p class="p1">` +
                num +
                `</p>
			        			<p class="p2"><img src="` +
                dsf.url.getWebPath(urls) +
                `" onerror="onerror=null;src='` +
                dsf.url.getWebPath("res/dsf_styles/themes/nc/head_logo.png") +
                `'"  /></p>
			        			<p class="p3">` +
                (sd[i].name == null ? "" : sd[i].name) +
                `</p>
			        			<p class="p4">` +
                (sd[i].bw == null ? "" : sd[i].bw) +
                `</p>
			        			<p class="p5">` +
                sd[i].times +
                `</p>
			        		</div>`;
            }
          }
          _this.$todaybox.html(shtml);
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {})
      .exec();
  }
  clquestion() {
    let _this = this;
    let iscl = true;
    _this.$jsquestion = _this._handlers["jsquestion"];
    _this.$jsquestion.click(function() {
      if (iscl) {
        layer.tips(
          '<span style="color:#333">当日学习总时长排列前五名的学员</span>',
          _this.$jsquestion,
          {
            tips: [2, "#fff"],
            time: 4000,
          }
        );
        let top = parseInt($(".layui-layer-tips").css("top")) - 15;
        $(".layui-layer-tips").css("top", top + "px");
        iscl = false;
        setTimeout(function() {
          iscl = true;
        }, 4000);
      }
    });
  }
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
    this.showlist();
    this.clquestion();
  }
  initEvent() {}
}
