import dome from "../templates/Ncdoclist.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";

@map("文档列", "nc.teas.ncdoclist", "Ncdoclist")
export class Ncdoclist extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.listColor = "#D60C0C"; //分隔条颜色
    this.moresrc = "";
    this.parms = {
      ztbid: "3f0bdc9c047a43a3b7d98907f7609d98",
    };
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    if (this._root._isDesign) {
    } else {
      this.parms.ztbId = parent.rparms.ztbid || "";
    }
  }

  renderContext(refresh) {
    super.renderContext();
    // $(".nc_doclist .titlebox i")[0].style.background = this.listColor
    //   ? this.listColor
    //   : "#2B6BE2";
    this.changeColor();
    this.showBtn()
  }
  changeColor() {
    let dom = $($(".nc_doclist .titlebox i")[0]);
    if (!this.listColor) {
      dom.addClass("commonBgColor");
    } else {
      dom.removeClass("commonBgColor");
      dom.css({
        "background-color": this.listColor,
      });
    }
  }
  showlist() {
    let _this = this;

    let url = dsf.url.getWebPath("nc/jxgl/zlsc/findXxZlByZtbId");
    dsf.http
      .request_sync(url, _this.parms, "get")
      .done(function(data) {
        if (data.state == 20000) {
          let shtml = "",
            sd = data.data;
          _this.$doclist = _this._handlers["doclist"];
//        sd=[
//        	{'type':'doc',"name":"1这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"2这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"3这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"4这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"5这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"6这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"7这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"8这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"9这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"10这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"11这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	{'type':'doc',"name":"12这是一段这是一段这是一段这是一段这是一段这是一段这是一段"},
//        	]
          if (sd.length == 0) {
            shtml =
              '<div style="text-align: center; padding: 30px 0;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"></div>';
          } else {
            var iconNum = 1;
            
            
            sd=sd.slice(0,8);
            for (var i = 0, len = sd.length; i < len; i++) {
              if (sd[i].type == "txt") {
                iconNum = 1;
              } else if (sd[i].type == "doc") {
                iconNum = 2;
              } else if (sd[i].type == "docx") {
                iconNum = 3;
              } else if (sd[i].type == "xls") {
                iconNum = 4;
              } else if (sd[i].type == "xlsx") {
                iconNum = 5;
              } else if (sd[i].type == "ppt") {
                iconNum = 6;
              } else if (sd[i].type == "pptx") {
                iconNum = 7;
              } else if (sd[i].type == "pdf") {
                iconNum = 8;
              }
              shtml +=
                `<div class="stuspeakitem jsstuspeakitem" id="` +
                sd[i].fileid +
                `">
												<span class="icon` +
                iconNum +
                `"></span><p class="ell" title="` +
                sd[i].name +
                `">` +
                sd[i].name +
                `</p><i class="ylook">预览</i>
											</div>`;
            }
          }
          _this.$doclist.html(shtml);
          _this.$doclist
            .find(".jsstuspeakitem")
            .find("p,span")
            .click(function() {
              let id = $(this)
                .parents(".jsstuspeakitem")
                .attr("id");
              let newpath = dsf.url.getWebPath("file/download?files=" + id);
              window.open(newpath);
            });
          _this.$doclist
            .find(".jsstuspeakitem")
            .find(".ylook")
            .click(function() {
              let id = $(this)
                .parents(".jsstuspeakitem")
                .attr("id");
              var ur = dsf.url.getWebPath("preview/file?fileId=" + id);
              dsf.openUrl(1, ur);
            });
        }
      })
      .error(function(err) {
      })
      .always(function() {})
      .exec();
  }
  morecl() {
    let _this = this;
    _this.$jsstumore = _this._handlers["jsstumore"];
    _this.$jsstumore.click(function () {
      let urls = dsf.url.getWebPath(_this.moresrc+'?ztb_id='+(parent.rparms.ztbid || "") );
      dsf.openUrl(1, urls);
    });
  }
  //  是否显示更多按钮
  showBtn() {
    if (this.showMoreBtn) {
      this._handlers.jsstumore.css('display', 'block');
    } else {
      this._handlers.jsstumore.css('display', 'none');
    }
  }
handleShowMoreBtn() {
    this.showBtn()
}
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
    this.showlist();
    this.morecl();
    this.showBtn();
  }
  initEvent() {}
}
