import dome from '../templates/NcTeasBanner.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';
import {relyFiles} from "../../../core/relyfiles";
@relyFiles([
  'res/libs/swiper/js/swiper.min.js',
  'res/libs/swiper/css/swiper.min.css'
])
@map("名师轮播图", 'nc.teas.ncteasbanner', 'NcTeasBanner')
export class NcTeasBanner extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;

    this.mainTitle = '主标题';
    this.subTitle = '副标题';
    this.showSubTitle = true;
    this.switchIcon = false;
    this.fontCo = '#333';
    this.iconnum = '1';

    this.teachers=[];
    this._dataUrl="/dsfa/nc/szk/ms/findIndexMs";
    this.req();
  }

  get dataUrl(){
    return this._dataUrl
  }
  set dataUrl(url){
    this._dataUrl=url;
    this.req();
  }

  req(){
    let loading = dsf.layer.loadding(),_this=this;
    dsf.http.request(this._dataUrl,{},"GET")
        .done(function(response) {
          if (response.success) {
            _this.teachers=response.data;
            _this.teachers.forEach(function (teacher) {
              if(teacher.photo){
                teacher.photo=JSON.parse(teacher.photo);
                teacher.photo= dsf.url.getAbsolutePath(teacher.photo[0]['relativePath']);
              }
            });
            _this.render();
          } else {
            dsf.layer.message("加载数据出错", false)
          }
        })
        .error(function(response) {
          dsf.layer.message("加载数据出错", false)
        }).always(function(){
      dsf.layer.close(loading)
    }).exec();
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
    this._handlers.setMainTitle.html(this.mainTitle);
    this._handlers.setSubTitle.html(this.subTitle);
    this.changeColor();
    this.changeTitleIcon();
    this.showSub();
    this.changeTitle()
  }

  renderReady(){//组件加载完成后执行
    super.renderReady();
    window.Swiper&&new window.Swiper('.ds_nc_teasbanner-swiper-container', {
      spaceBetween: 20,
      slidesPerView : 2,
      loop:true,
      autoplay:true,
      paginationClickable: true,
      pagination: {
        el: '.swiper-pagination',
        clickable: true,
      },
    });
    $(this._handlers.wrapper).on("click",".swiper-slide",function() {
      let id=$(this).attr('data-teas-id');
      let userId = dsf.getCookie('userId');
    	if (!userId) {
      	window.parent.openLogin();
      	return;
    	}

      let teacherUrl = dsf.url.getWebPath('nc/pc/teachersDetailnew/views/teachersDetailnew.html?id='+id);
      dsf.openUrl(1,teacherUrl);
    });
    }
	// 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
    changeTitle(){
			let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
		}
}

