import dome from "../templates/NcFloatmenu.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("浮动菜单", "nc.teas.ncfloatmenu", "NcFloatmenu")
export class NcFloatmenu extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$useVdom = true;
    this.$qrcodeurl = "nc/1.html"; //二维码的链接
    this.$tel = "15881141234";
    this.$feedbackurl = "nc/2.html"; //用户反馈的链接

    this.iswhere = "0"; //1左  2右
    this.$spacingnum = "30px"; //边距距离

    this.$ismainshow = "1,2,3,4";
    this.$textarr = ["扫码下载1", "联系客服2", "学员反馈3", "回到顶部3"];
  }
  initTemplate() {
    return dome(this);
  }
  renderContext(refresh) {
    super.renderContext();
    //		预览时
    this.mainshow();
    this.changewhere();
  }
  updated() {
    let _this = this;
  }

  inserted() {
    if (this._root._isDesign) {
    } else {
    }
  }
  updated() {
    let _this = this;
  }

  userfeedback() {
    let _this = this;
    dsf.layer.openDialog({
      title:_this.$textarr[2],
      area: ["1200px", "600px"],
      content: dsf.url.getWebPath(_this.$feedbackurl),
      dialogLoaded: function(layero, index, win) {},
    });
  }
  contenttop() {
  	console.log('');
  	
    window.top.$('html,body').animate({scrollTop : '0px'}, 400);
    scrollTo(0,0);//兼容在阿里学堂(iframe自身有滚动条的)项目中
    // var scroll_top = window.parent.document.scrollingElement;
	  // $(scroll_top).animate({
	  //   scrollTop : '0px'
	  // }, 400);
  }

  //二维码的链接
  set qrcodeurl(v) {
    this.$qrcodeurl = v;
    this.domUpdate();
  }
  get qrcodeurl() {
    return this.$qrcodeurl;
  }
  //联系电话
  set tel(v) {
    this.$tel = v;
    this.domUpdate();
  }
  get tel() {
    return this.$tel;
  }
  //联系电话
  set feedbackurl(v) {
    this.$feedbackurl = v;
    this.domUpdate();
  }
  get feedbackurl() {
    return this.$feedbackurl;
  }
  //模块边距
  set spacingnum(v) {
    this.$spacingnum = v;
    this.changewhere();
    this.domUpdate();
  }
  get spacingnum() {
    return this.$spacingnum;
  }
  //	菜单名称

  set maintext(v) {
    v = v.split(",");
    this.$textarr = v;
    this.domUpdate();
  }
  get maintext() {
    return this.$textarr.toString();
  }
  //	显示哪几个菜单
  set ismainshow(v) {
    this.$ismainshow = v;
    this.mainshow();
    this.domUpdate();
  }
  get ismainshow() {
    return this.$ismainshow;
  }

  mainshow() {
    let sd = this.$ismainshow.split(",");
    console.log(sd);
    this.root.event.on(PageEvent.READY, (args) => {
      this._handlers["menucontent"].find("ul li").hide();
      if (sd && sd.length > 0) {
        for (var i = 0, len = sd.length; i < len; i++) {
          this._handlers["menucontent"].find("ul .li_" + sd[i]).show();
        }
      }
    });
  }
  changewhere() {
    this.root.event.on(PageEvent.READY, (args) => {
      console.log("===================================");
      if (this._root._isDesign) {
      } else {
        var menucontent = this._handlers.menucontent;
        console.log(menucontent, "_this.$menucontent");
        // debugger;
        //	    	预览时
        if (this.iswhere == 1) {
          menucontent.addClass("iswhere_left");
          menucontent.css({
            left: this.$spacingnum,
          });
        } else if (this.iswhere == 2) {
          menucontent.addClass("iswhere_right");
          menucontent.css({
            right: this.$spacingnum,
          });
        }
      }
    });
  }
  getImageSrc() {
    var qrPath = dsf.url.getWebPath(this.$qrcodeurl);
    qrPath = encodeURIComponent(qrPath);
    var qrCodeUrl = dsf.url.getWebPath("nc/ncqrcode/buildQrCode") + "?rexdirect=" + qrPath; //固定写法
    return qrCodeUrl;
  }
  //	renderReady() {
  //		this.changewhere();
  //	}
}
