import dom from "../../templates/NctrainClass.ejs";
import { ControlEditor } from "../../../../editor/ControlEditor";
import { map } from "../../../../decorator/controlmap";

@map("线下培训班", "nc.teas.nctrainclass", "NctrainClass")
export class NctrainClass extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.$showNumber = 4;
    this.$sourceUrl = null;
    this.$moreSrc = null;
    this._desingerClass = ControlEditor;

    this.randomClass = "ds_nc_OnStudy__" + parseInt(Math.random() * 999999);
    this.old_conTitleBarColor = "#d40000";
    this.old_wrapColor = "#d40000";
    this.old_itemBxColor = "#d40000";
    this.old_endTimeColor = "#C90C0A";
    this.old_studyBtnColor = "#D40000";
    this.styleMap = {};
  }

  set sourceUrl(val) {
    this.$sourceUrl = val;
  }

  get sourceUrl() {
    return this.$sourceUrl;
  }

  set moreSrc(val) {
    this.$moreSrc = val;
  }

  get moreSrc() {
    return this.$moreSrc;
  }

  get showNumber() {
    return this.$showNumber;
  }

  set showNumber(val) {
    return (this.$showNumber = val);
  }

  initTemplate() {
    return dom(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    let that = this;
    super.renderContext();
    that.onStudyWrap = that._handlers["onStudyWrap"];
    that.onStudy = that._handlers["onStudy"];
    if (!this._root._isDesign) {
      let mStr =
        "<a href='javascript:void(0)' style='color:#fff;'>\
         <i class='icon iconfont icon-hao'></i>\
         </a>";
      that._handlers["moreHandle"].html(mStr);
      that._handlers["moreHandle"].click(function() {
        if (that.$moreSrc.trim() !== "") {
          const ur = dsf.url.getWebPath(that.$moreSrc);
          dsf.openUrl(1, ur);
        }
        //          window.parent.location.href = window.parent.location.href.split('?')[0] + '?hasRead=0&type=2&selItem=2&path=' + dsf.Base64.encode(path);
      });
    }
    // **************
    this.conTitleBarColor !== void 0
      ? this.setConTitleBarColor(this.conTitleBarColor)
      : this.setConTitleBarColor(this.old_conTitleBarColor);
    this.wrapColor !== void 0
      ? this.setWrapColor(this.wrapColor)
      : this.setWrapColor(this.old_wrapColor);
    this.itemBxColor !== void 0
      ? this.setItemBxColor(this.itemBxColor)
      : this.setItemBxColor(this.old_itemBxColor);
    this.endTimeColor !== void 0
      ? this.setEndTimeColor(this.endTimeColor)
      : this.setEndTimeColor(this.old_endTimeColor);
    this.studyBtnColor !== void 0
      ? this.setStudyBtnColor(this.studyBtnColor)
      : this.setStudyBtnColor(this.old_studyBtnColor);
    this.updataStyle();
  }





  /********** json事件——颜色设置 *************/
  mapObj(obj) {
    if (!obj) {
      return;
    }
    let arr = [];
    for (let item in obj) {
      console.log(item);
      arr.push(obj[item]);
    }
    return arr;
  }
  updataStyle() {
    //  this._handlers.onStudyStyle.html(Object.values(this.styleMap).join(""));
    this._handlers.onStudyStyle.html(this.mapObj(this.styleMap).join("")); //兼容IE11处理
  }
  setConTitleBarColor(v) {
    if (v.trim() !== "") {
      this.styleMap.conTitleBarColor = `.${this.randomClass} .com-title b{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.conTitleBarColor = "";
    }
  }
  setWrapColor(v) {
    if (v.trim() !== "") {
      this.styleMap.wrapColor = `.${this.randomClass} .com-icon-wrap{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.wrapColor = "";
    }
  }
  setItemBxColor(v) {
    if (v.trim() !== "") {
      this.styleMap.itemBxColor = `.${this.randomClass} .item-bx{
            color: ${v} !important;
            border-color: ${v} !important;
         }`;
    } else {
      this.styleMap.itemBxColor = "";
    }
  }
  setEndTimeColor(v) {
    if (v.trim() !== "") {
      this.styleMap.endTimeColor = `.${this.randomClass} .item-end-time{
            color: ${v} !important;
         }`;
    } else {
      this.styleMap.endTimeColor = "";
    }
  }
  setStudyBtnColor(v) {
    if (v.trim() !== "") {
      this.styleMap.studyBtnColor = `.${this.randomClass} .item-study-btn{
            background-color: ${v} !important;
         }`;
    } else {
      this.styleMap.studyBtnColor = "";
    }
  }

  changeConTitleBarColor() {
    this.setConTitleBarColor(this.conTitleBarColor);
    this.updataStyle();
  }
  changeWrapColor() {
    this.setWrapColor(this.wrapColor);
    this.updataStyle();
  }
  changeItemBxColor() {
    this.setItemBxColor(this.itemBxColor);
    this.updataStyle();
  }
  changeEndTimeColor() {
    this.setEndTimeColor(this.endTimeColor);
    this.updataStyle();
  }
  changeStudyBtnColor() {
    this.setStudyBtnColor(this.studyBtnColor);
    this.updataStyle();
  }
}
function studyState(state, id) {
  let text = "";
  if (state !== 4) {
    //封闭式
    if (state == 0) {
      text = "报名";
    } else if (state == 1) {
      text = "开始学习";
    } else if (state == 2) {
      text = "继续学习";
    } else if (state == 3) {
      text = "已结业";
    }
    return (
      "<button class='item-study-btn btnToCourse " +
      (state == 3 || state == 4 ? "item-state-bg" : "") +
      "' data-state='" +
      state +
      "' data-id='" +
      id +
      "'>" +
      "        <a  class='isBeginStudy' href='javascript:void(0);' style='color:#fff;'>" +
      text +
      "</a>" +
      "     </button>"
    );
  } else {
    return "";
  }
}
