import dome from '../templates/NcNoviceSaidDetail.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("学员说详情", 'nc.teas.ncnovicesaiddetail', 'NcNoviceSaidDetail')

export class NcNoviceSaidDetail extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            this.renderdefaultPage();
        } else {
            this.getDetail();
        }
    };

    renderReady() {
        super.renderReady();
    }

    // 详情尾点击事件
    buttonsClick() {
        // var buttons = $('.buttons_edit li');
        let _this = this;
        $('.favorite_btn').click(function () {
            dsf.layer.message('点击了收藏');
            return
            _this.favoriteClick();
        });
        $('.like_btn').click(function () {
            dsf.layer.message('点击了赞');
            return
            _this.likeClick();
        });
        $('.share_btn').click(function () {
            dsf.layer.message('点击了分享');
            return
            _this.shareClick();
        })
    }
    // 收藏
    favoriteClick() {
        let loading = dsf.layer.loadding(),
            url = '',
            params = {};
        let sourceUrl = dsf.url.getWebPath(url);
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {

                } else {
                    dsf.layer.message('请求失败');
                }
            })
            .error((err) => {
                dsf.layer.message('请求错误');
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }
    // 点赞
    likeClick() {
        let loading = dsf.layer.loadding(),
            url = '',
            params = {};
        let sourceUrl = dsf.url.getWebPath(url);
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    // this.renderPage(res.data);
                } else {
                    dsf.layer.message('请求失败');
                }
            })
            .error((err) => {
                dsf.layer.message('请求错误');
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }
    // 分享
    shareClick() {
        let loading = dsf.layer.loadding(),
            url = '',
            params = {};
        let sourceUrl = dsf.url.getWebPath(url);
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    // this.renderPage(res.data);
                } else {
                    dsf.layer.message('请求失败');
                }
            })
            .error((err) => {
                dsf.layer.message('请求错误');
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    getDetail() {
        let loading = dsf.layer.loadding();
        let sourceUrl = dsf.url.getWebPath('nc/xxgl/xys/findXysDetail');
        let params = {
            id: dsf.url.queryString('id') || 'f67ea8231b2c4d7e9e067ce2d250e1c7'
        };
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    this.renderPage(res.data);
                } else {
                    dsf.layer.message('请求失败');
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    // 详情DOM
    renderPage(data) {
        let detailStr = '';
        if (data) {
            detailStr = '<h5 class="news_title">'+ data.title +'</h5>\n' +
                '        <div class="news_info">\n' +
                '            <span>'+ (data.ds_update_time?data.ds_update_time:'暂无') +'</span>\n' +
                '            <span><img src="'+ (data.photo? dsf.url.getWebPath((JSON.parse(data['photo'])[0]['relativePath'])) :'/dsfa/res/dsf_styles/themes/nc/head_logo.png') +'" alt="">'+ (data.name?data.name:'暂无') +'</span>\n' +
                '            <span>来源：'+ (data.unit_text?data.unit_text:'暂无') +'</span>\n' +
                '            <span><i></i>'+ (data.llcs?data.llcs:'暂无') +'</span>\n' +
                '        </div>\n' +
                '        <div class="news_contnet">\n' +
                '            '+ data.content +'\n' +
                '        </div>';
        } else {
            detailStr = "<div class='have_not_data'>暂无数据</div>";
            this._handlers['newsWrap'].css({'text-align': 'center'});
        }
        this._handlers['newsWrap'].html(detailStr);
        this.buttonsClick();
    }
    // 默认详情DOM
    renderdefaultPage() {
        let list = '<h5 class="news_title">今年以来习近平总书记国内考察纪实</h5>\n' +
            '        <div class="news_info">\n' +
            '            <span>2019-08-09</span>\n' +
            '            <span>来源：人民网</span>\n' +
            '            <span><i></i>10254</span>\n' +
            '        </div>\n' +
            '        <div class="news_contnet">\n' +
            '            今年是中朝建交70周年。在这个历史性时刻，应朝鲜劳动党委员长、国务委员会委员长金正恩同志邀请，我怀着“传承友谊、续写新篇”的美好愿望，即将对朝鲜民主主义人民共和国进行国事访问。回想当年，两党两国老一辈领导人怀着共同的理想信念和深厚的革命友谊，携手缔造了中朝传统友谊，为我们留下了共同的宝贵财富。中朝几代领导人一直保持着密切交往，就传承中朝传统友谊、造福两国人民深入沟通、真诚合作，书写了国际关系史上的佳话。长期以来，在中朝两党坚强领导下，不论是在共同反对外来侵略、争取国 家独立和民族解放的斗争中，还是在开展社会主义革命和建设事业中，两国人民都彼此信赖，相互支持，相互帮助，结下了深厚友情，可以说是“历久弥坚金不换”。 亲望亲好，邻望邻好。作为好同志、好邻居，无论国际风云如何变幻，中国党和政府巩固发展中朝友好合作关系的坚定立场都没有变也不会变，中方将坚定支持金正恩委员长带领朝鲜党和人民贯彻落实新战略路线，集中精力发展经济、改善民生，推动朝鲜社会主义建设取得新的更大成就。\n' +
            '        </div>\n' +
            '        <ul class="buttons_edit">\n' +
            '            <li class="favorite_btn"><i class="layui-icon layui-icon-star"></i>12</li>\n' +
            '            <li class="like_btn"><i class="layui-icon layui-icon-praise"></i>9.6万</li>\n' +
            '            <li class="share_btn"><i class="layui-icon layui-icon-share"></i>分享</li>\n' +
            '        </ul>';
        this._handlers['newsWrap'].html(list);
    };
}
