   renderReady() {//组件加载完成后执行
      super.renderReady();
   }
   loadData(args) { // 数据
      let _this = this, str = "", param = {}, item = [];
      param = $.extend({}, args, this.pageConfig)
      dataRequst.call(this, this.requestUrl, param, "GET", function (args) {
         console.log('数据==>', args)
         _(args.data).forEach(val => {
            str += createHtml.call(_this, val)
         });
         item = _(args.data);
         _this.informationListWrap.html(str);
         _this.informationListWrap.on('click', '.ds_nc_listitem', item, function () {
            // _this.clickListItem(item['__wrapped__'][$(this).index()])
            let listItem = item['__wrapped__'][$(this).index()];
            if (!_this.detailurlfun || !_this.detailurlfun.includes('id=') || !_this.detailurlfun.includes('type=')) { // 设计器未动态设计id或type
               _this.detailurlfun = `${_this.detailurlfun}?id=${listItem['_id']}&type=${listItem['nc_news_matchCmDataSource.cms_cm_code']}`;
               _this.clickDetail()
            } else {
               _this.clickListItem(listItem)
            }
         });
      })
   }
   // 点击列表 跳转详情页面
   clickListItem(data) {
      let userId = dsf.getCookie("userId");
      if (!userId) {
         window.parent.openLogin();
         evt.preventDefault();
         return
      }
      this.listItem = data;
      let v = dsf.Express.replace(this.detailurlfun, this.listItem)
      v = dsf.url.getAbsolutePath(v);
      v = dsf.url.analysis(v)
      // dsf.openUrl(1, `nc/pc/menusDetail/views/menusDetail.html?deUrl = '${v}'`);
      let url = dsf.url.getWebPath(`nc/pc/menusDetail/views/menusDetail.html?deUrl=${dsf.Base64.encode(v)}`);
      dsf.openUrl(1, url);
   }
   // 无配置项跳转详情
   clickDetail() {
      let userId = dsf.getCookie("userId");
      if (!userId) {
         window.parent.openLogin();
         evt.preventDefault();
         return
      }
      // let url = dsf.url.getWebPath(this.detailurlfun);
      let url = dsf.url.getWebPath(`nc/pc/menusDetail/views/menusDetail.html?deUrl=${dsf.Base64.encode(this.detailurlfun)}`);
      dsf.openUrl(1, url);
   }

   // 配置项----------------------------------------------------------
   // 是否显示菜单
   isshowBarfun() {
      let _this = this;
      _this.$jsbarbox = _this._handlers["jsbarbox"];
      if (this.sdata.isshowBar) {
         _this.$jsbarbox.removeClass("none");
         _this._handlers.jsbarbox.find("li.act").removeClass("actv");
         if (_this.sdata.issBarcoloract != "") {
            _this._handlers.jsbarbox.find("li.act").css({
               color: _this.sdata.issBarcoloract,
               "border-bottom-color": _this.sdata.issBarcoloract,
            }); //选中色
         } else {
            _this._handlers.jsbarbox.find("li.act").addClass("actv");
         }
      } else {
         _this.$jsbarbox.hide();
      }
   }
