// 数据请求封装方法
function dataRequst(url, args, queryway, callback) {
   let loadding = dsf.layer.loadding();
   dsf.http.request(url, args, queryway, callback)
      .done(function (response) {
         if (response.success) {
            if (callback) callback(response)
         } else {
            dsf.layer.message("请求失败,请稍后再试", false)
         }
      })
      .error(function (err) {
         dsf.layer.message("请求失败,请稍后再试", false)
      })
      .always(function () {
         dsf.layer.close(loadding);
      }).exec();
}
// 创建列表dom字符串
function createHtml(item) {
   let str = "";
   str =
      '<li class="ds_nc_listitem" data-id=' + item['nc_news_matchCmDataSource.dsfa_cms_content_id'] + '>' +
      '<i class="d-icon d-nmg"></i>' +
      '<span class="item_font">' + item['nc_news_matchCmDataSource.cname'] + '</span>' +
      '</li>'
   return str
}
