import dome from '../templates/NcIndexZtbBanner.ejs';
import { relyFiles } from '../../../core/relyfiles';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("首页专题班", 'nc.teas.ncindexztbbanner', 'NcIndexZtbBanner')
@relyFiles([
   'res/libs/swiper/css/swiper.min.css',
   'res/libs/swiper/js/swiper.min.js'
])
export class NcIndexZtbBanner extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this.$sourceUrl = null;
      this.$showNum = 3;
      this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
      this.$defaultHead = '/dsfa/res/dsf_styles/themes/nc/head_logo.png';
      this.defaultUrl = dsf.url.getWebPath('teas/tempdata/OnStudyList.json');
      this._desingerClass = ControlEditor;

      this.mainTitle = '主标题';
      this.subTitle = '副标题';
      this.showMainTitle = false;
      this.showSubTitle = true;
      this.switchIcon = false;
      this.fontCo = '#333';
      this.iconnum = '1';
   }

   set sourceUrl(val) {
      this.$sourceUrl = val;
   }
   get sourceUrl() {
      return this.$sourceUrl;
   }

   set showNum(val) {
      this.$showNum = val;
   }
   get showNum() {
      return this.$showNum;
   }


   set changeShowSub(v) {
      this.showSubTitle = v;
      this.showSub();
   }
   get changeShowSub() {
      return this.showSubTitle;
   }

   set changeShowMain(v) {
      this.showMainTitle = v;
   }
   get changeShowMain() {
      return this.showMainTitle;
   }

   set changeIcon(v) {
      this.switchIcon = v;
      this.changeTitleIcon();
   }
   get changeIcon() {
      return this.switchIcon;
   }
   // 改变字体颜色
   changeColor() {
      $('.module_title').css('color', this.fontCo);
   }
   showMain() {
      if (this.showMainTitle) {
         this._handlers['title'].css('display', 'block');
         this._handlers.setMainTitle.html(this.mainTitle);
      } else {
         this._handlers['title'].css('display', 'none');
      }
   }
   // 是否显示副标题
   showSub() {
      if (this.showSubTitle) {
         this._handlers.setSubTitle.css('display', 'block');
         this._handlers.setSubTitle.html(this.subTitle);
      } else {
         this._handlers.setSubTitle.css('display', 'none');
      }
   }

   // 切换标题icon
   changeTitleIcon() {
      let leftImageUrl = {
         1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
         2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
      };
      let rightImageUrl = {
         1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
         2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
      };
      
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

      super.renderContext();
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));

      if (this.switchIcon) {
         this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
         this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
      } else {
         this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
         this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
      }
   }

   handleShowSubTitle() {
      this.showSub();
   }

   handleShowMainTitle() {
      this.showMain();
   }

   handleChangeIcon() {
      this.changeTitleIcon()
   }

   initTemplate() {
      return dome(this);
   }

   renderContext() {
      super.renderContext();
      this.showMain();
      this.showSub();
      this.changeColor();
      this.changeTitleIcon();
      this.changeTitle();
      if (!this._root._isDesign) {
         this.getZtBannerList();
      } else {
         this._handlers['ztWrapper'].css('width', '100%');
         var swiper = new Swiper('.zt_swiper-container', {
            slidesPerView: 3,
            spaceBetween: 30,
            centeredSlides: true,
            loop: true
         });
      }
   }

   getZtBannerList() {
      let that = this;
      if (!that.$sourceUrl) that.$sourceUrl = 'yyzx/pdgl/findZtbGDList';
      that.$sourceUrl = dsf.url.getWebPath(that.$sourceUrl);
      let params = {
         title: '',
         type_value: '05',
         pageNo: 1,
         pageSize: this.$showNum
      };
      let loading = dsf.layer.loadding();
      dsf.http.request(that.$sourceUrl, params, "GET")
         .done(function (res) {
            if (res.success) {
               if (res.data) {
                  that.renderPage(res.data)
               }
            } else {
               dsf.layer.message('专题班:' + res.message, false);
               that.noData();
            }
         })
         .error(function (err) {
            console.log(err)

            dsf.layer.message(err.message);
         })
         .always(function () {
            dsf.layer.close(loading);
         }).exec();
   }

   renderPage(data) {
      let that = this;
      let bStr = '';
      if (data.length !== 0) {
         for (var i = 0; i < data.length; ++i) {
            let item = data[i];
            // let imgUrl = !!item['cover'] ? dsf.url.getWebPath(JSON.parse(item['cover'])[0]['relativePath']) : this.$defaultImgUrl;
            let imgStr = `<img class='inner-l-cover' src="${!!item['cover'] ? dsf.url.getWebPath((JSON.parse(item['cover'])[0]['relativePath'])) : this.$defaultImgUrl}" onerror='onerror=null;src="${this.$defaultImgUrl}"' alt=''/>`
            let courseTitStr = '';
            if (item.kcm && item.kcm.length > 0) {
               for (let i = 0; i < item.kcm.length; ++i) {
                  courseTitStr += "<p class='inner-r-desc'>" + item['kcm'][i]['NAME'] + "</p>"
               }
               courseTitStr = "<div class='kcm-wrap'>" + courseTitStr + "</div>";
            }
            let descSubString = '暂无';
            if (!!item['abstract']) {
               if (item['abstract'].length > 75) {
                  descSubString = item['abstract'].substring(0, 75) + '...';
               } else {
                  descSubString = item['abstract'];
               }
            }
            let avatarStr = '';
            if (!!item['xytuList'] && item['xytuList'].length > 0) {
               item['xytuList'] = item['xytuList'].slice(0, 5);
               for (let i = 0; i < item['xytuList'].length; ++i) {
                  let imgItem = item['xytuList'][i];
                  if (i % 2 == 0) {
                     console.log(i)
                  }
                  let pSrc = !!imgItem.photo ? dsf.url.getWebPath(JSON.parse(imgItem.photo)[0].relativePath) : that.$defaultHead;
                  avatarStr += "<div class='inner-r-bt-head-warp' style='top:" + (i % 2 == 0 ? '0;' : '-5px') + ";left:" + (i !== 0 ? -i * 10 + 'px' : '0') + "'>" +
                     "              <img src='" + pSrc + "' alt=''>" +
                     "           </div>";
               };

            } else {
               avatarStr = "<div class='inner-r-bt-head-warp'>" +
                  "              <img src='" + that.$defaultHead + "' alt=''>" +
                  "           </div>";
            }
            let lStr = "<div class='inner-l'>" +
               "        <div class='inner-l-top'>" +
               "           " + imgStr +
               "           <img src='/dsfa/res/dsf_styles/themes/nc/i_course_logo.png' alt='' class='inner-l-logo'>" +
               "        </div>" +
               "        <ul class='inner-l-desc-wrap'>" +
               "           <li>" +
               "              <span class='l-desc-zbDw'>主办单位：" + (!!item['zbdw'] ? item['zbdw'] : '暂无') + "</span>" +
               "           </li>" +
               "           <li>" +
               "              <span class='l-desc-cbDw'>承办单位：" + (!!item['cjdw'] ? item['cjdw'] : '暂无') + "</span>" +
               "           </li>" +
               "           <li>" +
               "              <span class='l-desc-con' title='" + (!!item['abstract'] ? item['abstract'] : '') + "'>" + (descSubString) + "</span>" +
               "           </li>" +
               "           <li>" +
               "              <span class='l-desc-get-more J_detail' data-id='" + item['nc_zyb_id'] + "'>了解详情<i class='icon iconfont icon-youjiantou'></i></span>" +
               "           </li>" +
               "        </ul>" +
               "  </div>";
            let rStr = "<div class='inner-r'>" +
               "        <h3 class='inner-r-title'>" + (!!item['title'] ? item['title'] : '') + "</h3>" +
               "         " + courseTitStr +
               "        <ul class='inner-r-sing-info'>" +
               "           <li>必修课程: " + (!!item['bxcount'] ? item['bxcount'] : 0) + "</li>" +
               "           <li>必修学时: " + (!!item['bxxs'] ? item['bxxs'] : 0) + "</li>" +
               "           <li>选修课程: " + (!!item['xxcount'] ? item['xxcount'] : 0) + "</li>" +
               "           <li>选修学时: " + (!!item['xxxs'] ? item['xxxs'] : 0) + "</li>" +
               "           <li style='width:100%'>开班时间: " + (item['pxrq_sdate'] + ' 至 ' + item['pxrq_edate']) + "</li>" +
               "        </ul>" +
               "        <div class='inner-r-bottom-head'>" +
               avatarStr +
               "           <span class='inner-r-num'>学员人数: " + (!!item['studentNum'] ? item['studentNum'] : 0) + "</span>" +
               "           <button class='inner-r-sing-up J_singUp' data-id='" + item['nc_zyb_id'] + "' data-state='" + item['STATE'] + "'>" + (item['STATE'] == 0 ? '立即报名' : item['STATE'] == 1 ? '开始学习' : item['STATE'] == 2 ? '继续学习' : item['STATE'] == 3 ? '已通过' : '') + "</button>" +
               "        </div>" +
               "     </div>";
            bStr += "<div class='swiper-slide'>" +
               "        <div class='com'>" + lStr + rStr + "</div>" +
               "     </div>";
         }

         bStr = "<div class='zt_swiper-container'><div class='swiper-wrapper'>" + bStr + "</div></div>";
         that._handlers['ztWrapper'].html(bStr);
         var swiper = new Swiper('.zt_swiper-container', {
            slidesPerView: 3,
            spaceBetween: 30,
            slideToClickedSlide: true,
            centeredSlides: true,
            loop: data.length == 1 ? false : true,
            autoplay: {
               delay: 100000 * 3,
               stopOnLastSlide: false,
               disableOnInteraction: true,
            }
         });
         $('.J_detail').click(function () {
            let id = $(this).attr('data-id'),
               userId = dsf.getCookie('userId');
            if (userId) {
               let path = dsf.url.getWebPath('nc/pc/stylecenterindex/views/stylecenterindex.html?id=' + id);
               window.open(path);
            } else {
               window.parent.openLogin();
            }
         })
         $('.J_singUp').click(function () {
            let id = $(this).attr('data-id'),
               state = $(this).attr('data-state'),
               userName = dsf.getCookie('user_name'),
               userId = dsf.getCookie('userId');
            if (userId) {
               if (state == 0) {
                  dsf.layer.confirm("您确定要报名吗?", () => {
                     that.courseSingUp(id, state, userName, userId);
                  }, () => {
                     console.log('取消报名')
                  })
               } else {
                  let path = dsf.url.getWebPath('nc/pc/stylecenterindex/views/stylecenterindex.html?id=' + id);
                  window.open(path);
               }
            } else {
               window.parent.openLogin();
            }
         })
      } else {
         that.noData();
      }
   }
   courseSingUp(id, state, userName, userId) {
      let params = {
         nc_zyb_id: id,
         nc_students_id: userId
      };
      let that = this;
      let loading = dsf.layer.loadding();
      let singUrl = dsf.url.getWebPath('ztb/xymd/addXymdBm');
      dsf.http.request(singUrl, params, "POST")
         .done(function (res) {
            if (res.success) {
               if (res.data) {
                  dsf.layer.message('报名成功', true);
                  let t = setTimeout(() => {
                     that.getZtBannerList();
                     clearTimeout(t);
                  }, 1000)
               }
            } else {
               dsf.layer.message(res.message, false);
            }
         })
         .error(function (err) {
            console.log(err)
            dsf.layer.message(err.message, false);
         })
         .always(function () {
            dsf.layer.close(loading);
         }).exec();
   }

   noData() {
      var bStr = "<div class='zt_swiper-container'><div class='swiper-wrapper'><img style='position: relative;width:200px;height:180px;margin:auto;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div></div>";
      this._handlers['ztWrapper'].html(bStr).css({
         'text-align': 'center'
      });
   }
	changeTitle(){
		let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

				super.renderContext();
				
        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
        console.log(this.iconnum);
	}

}


