   baractNum() {
      let _this = this;
      _this.$jsbarbox = _this._handlers["jsbarbox"];
      _this.$jsbarbox.find('li:nth-child(' + _this.$baractnum + ')').click();
   }

   //配置项----------------------------------------------------------end
   gettex(text) {
      var shtml = "";
      if (text) {
         var arr = text.split("^");
         for (var i = 0, len = arr.length; i < len; i++) {
            shtml += "<span>" + arr[i] + "</span>";
         }
      }
      return shtml;
   }
   geturls(cover) {
      let urls = "";
      if (cover) {
         let cov = JSON.parse(cover);
         if ($.isArray(cov)) {
            urls = cov[0].relativePath;
         }
      } else {
         urls = "res/dsf_styles/themes/nc/404.png";
      }
      return urls;
   }

