   /**
    * 请求数据
    */
   postData() {
      let loading = dsf.layer.loadding();
      let _this = this;
      let url = dsf.url.getWebPath("nc/kjk/frontuse/getKcHomePageSixList");
      dsf.http.request(
         url, _this.parms, 'get'
      ).done(response => {
         if (response.state === 20000) {
            // 请求成功
            this.postDataSuccess(response.data);
         } else {
            // 请求失败
            _this.$jscourselist = _this._handlers['jscourselist'];
            _this.$jscourselist.html('<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>');
         }
      }).error(response => {
         // 请求错误
         dsf.layer.message('请求异常', false);
      }).always(response => {
         dsf.layer.close(loading);
      }).exec();
   }

   /**
    * 请求成功处理
    * @param tabId
    * @param data [
    *    {CKL, CODE, COVER: '[
    *      {originalFileName, name, suffix, size, contentType, relativePath, absolutePath, uploadDate, id}
    *    ]', DZL, KCFS, KCSC, KCXS, LABEL_TEXT, NC_ZYB_ID, SFBX, SFJRZX, SFNEW, SFXX, SKJS: [
    *      {ROWNUM, JOB, JSMC},
    *      ......
    *    ], SKJSUNIT, TITLE, fbrq, _id}
    *    ......
    * ]
    */
   postDataSuccess(data) {
      let _this = this;
      let shtml = [], isaddHtml = '';
      this.$jscourselist = this._handlers.jscourselist;
      if (data.length > 0) {
         data.forEach(v => {
            let urls = _this.geturls(v.COVER);
            if (v.SFJRZX == 0) {
               isaddHtml = `<span class="jsadd act">加入在学</span>`;
            } else {
               isaddHtml = ``;
            }
            shtml.push(
               `<div class="aitem" id="${v.NC_ZYB_ID}">
            <div class="aimgbox">
				      <img src="${dsf.url.getWebPath(urls)}" data-adaptive-background="1" data-description="grandpa"
				        onerror="onerror=null;this.src='${dsf.url.getWebPath('res/dsf_styles/themes/nc/404.png')}'"/>
							<div class="imgtext">
							  <div class="choosebox">
								  <span class="choose1" style="display: ${+v.KCFS ? 'inline-block' : 'none'}">
								    ${+v.KCFS ? v.KCFS : ''}
								  </span>
									<span class="choose2" style="display: ${v.SFBX == '1' ? 'inline-block' : 'none'}">必</span>
									<span class="choose3" style="display: ${v.SFNEW == 1 ? 'inline-block' : 'none'}">新</span>
							  </div>
								<div class="timecenter">
									<b class="iconfont icon1 icon-shijian"/>
									<b>${!!v.KCSC ? v.KCSC : ''}</b>
								</div>
							</div>
						</div>
						<div class="item-foot">
							<div class="ctitle ell2">${!!v.TITLE ? v.TITLE : ''}</div>
							<div class="cteacher">
							  <i class="iconfont icon-touxiang"/><span class="ell">${!!v.SKJSUNIT ? v.SKJSUNIT : ''}</span>
              </div>
							<div class="cstyle-hour">
								<p class="p1"><i/><span>${!!v.fbrq ? v.fbrq : ''}</span><p>
								<p class="p2"><i class="iconfont icon-yanjing"/><span>${!!v.CKL ? v.CKL : 0}</span><p>
							</div>
							<div class="clabel">${_this.gettex(v.LABEL_TEXT)}</div>
            </div>
            <div class="hbox">
              <p class="ell2">${!!v.TITLE ? v.TITLE : ''}</p>
              <div class="btnbox">
                <span class="jsstyle">马上学习</span>
                ${isaddHtml}
              </div>
            </div>
          </div>`);
         });
      } else {
         shtml = ['<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>'];
      }
      this.$jscourselist.html(shtml.join(''));
      //标签色
      this.$jscourselist.find('.clabel span').css({
         color: this.plancoursedata.labelcolor,
         border: '1px solid ' + this.plancoursedata.labelcolor
      });
      //移入背景图
      this.$jscourselist.find('.hbox').css({
         'background': 'url(' + dsf.url.getWebPath(this.plancoursedata.hoverbg) + ') no-repeat',
         'background-size': '100% 100%'
      });
      //移入背景色
      this.$jscourselist.find('.btnbox span.act').css({
         background: this.plancoursedata.btncolor
      });
      // 马上学习
      let $aitem = this.$jscourselist.find('.aitem');
      $aitem.find('.jsstyle').click(function () {
         let id = $(this).parents('.aitem').attr('id');
         let userId = dsf.getCookie('userId');
         if (!userId) {
            window.parent.openLogin();
            return;
         }
         _this.checkUserAuth(id);
      });
      // 加入学习
      $aitem.find('.jsadd').click(function () {
         let id = $(this).parents('.aitem').attr('id');
         let userId = dsf.getCookie("userId");
         if (!userId) {
            window.parent.openLogin();
            return;
         }
         _this.addStyleClass(id);
      });
   }

