import dome from '../templates/NcATeachers.ejs';
import {
   map
} from '../../../decorator/controlmap';
import {
   ControlEditor
} from '../../../editor/ControlEditor';

@map("首页学堂师资", 'nc.teas.ateachers', 'NcATeachers')
export class NcATeachers extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.$useVdom = true;

      this.$test = [];
      this.sdata = {
         titleicon: '/res/dsf_styles/themes/styleClass/teachers.png', //标题图片
         titleText: "师资",
         titleTextcolor: "",
         issBarcoloract: "#FF6A00", //菜单选中色

         borderstyle: "#fdc8c8 2px dotted", //边框样式
         gtitlebg: "#fff", //头部整栏背景
         titletxtbgcolor: '#da0000',
         titletxtbgl: "/res/dsf_styles/themes/nc/nm/tit-left.png", //标题文字背景
         titletxtbgr: "/res/dsf_styles/themes/nc/nm/tit-right.png", //标题文字背景
         morebtnbg: "#fff,/res/dsf_styles/themes/nc/nm/more01.png",//更多按钮的背景
         moretext: '更多',

         isshowChooseBtn: true, //是否显示操作按钮
         Btntext: "按钮名称", //操作按钮文本
         Btnurl: "", //操作按钮链接

         ismoreBtn: true, //是否显示更多按钮
         moreBtnUrl: "nc/kck/mhkc/views/kclb.html", //更多按钮链接
         moreBtnColor: "", //更多按钮颜色
      }
      //    主要内容
      this.parms = {
         pageNum: 1,
         pageSize: 10,
         namespace: 'nc.szk',
         pageName: 'mslist'
      }

      this.$pageSize = 10;


      //		点击某一项需跳转的页面路由
      this.$detailUrl = 'nc/pc/teachersDetailnew/views/teachersDetailnew.html';
      this.$baractnum = 1;
   }

   set pageSize(val) {
      this.$paseSize = val;
      this.parms.pageSize = this.$paseSize;
   }

   get pageSize() {
      return this.$pageSize;
   }

   initTemplate() {
      return dome(this);
   }

   createElement() {
      super.createElement();
   }

   renderContext(refresh) {
      super.renderContext();
      if (this._root._isDesign) {	//配置页面

         if (this.sdata.titleicon == "") {
            this._handlers.jstitleicon.parents(".titimgbox").hide();
         } else {
            this._handlers.jstitleicon.parents(".titimgbox").show();
            this._handlers.jstitleicon.attr("src", dsf.url.getWebPath(this.sdata.titleicon));
         }
         this._handlers.jstitletext.find("span").text(this.sdata.titleText);
         //    文字显示区域
         this._handlers.jstitletext.find("span").css({
            "color": this.sdata.titleTextcolor,
            "background": this.sdata.titletxtbgcolor,
         })


         if (this.sdata.titletxtbgl == '' || this.sdata.titletxtbgr == '') {//如果没有配置图片就去掉边距
            this._handlers.jstitletext.find("span").css('padding', 0)
            this._handlers.jstitletext.css('padding', 0)
         }
         this._handlers.jstitletext.css({
            "background": ' url(' + dsf.url.getWebPath(this.sdata.titletxtbgl) + ') no-repeat,'
               + 'url(' + dsf.url.getWebPath(this.sdata.titletxtbgr) + ') no-repeat 100% 0',
         });
         this._handlers.jstitlebox.css({
            "border": this.sdata.borderstyle,
            "background": this.sdata.gtitlebg,
         });
         // let morearr=this.sdata.morebtnbg.split(',');
         let morearr = this.sdata.morebtnbg ? this.sdata.morebtnbg.split(',') : [];
         // this._handlers.jsmorebtn.css({
         // 	"color": this.sdata.moreBtnColor,
         // 	"background": morearr[0] +' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
         // 	"background-size":'100% 100%'
         // });
         if (morearr.length > 1) {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
               "background-size": '100% 100%'
            });
         } else {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath('/res/dsf_styles/themes/nc/nm/more01.png') + ') no-repeat',
               "background-size": '100% 100%'
            });
         }
      } else {             //预览时
         if (this.sdata.titleicon == "") {
            this._handlers.jstitleicon.parents(".titimgbox").hide();
         } else {
            this._handlers.jstitleicon.parents(".titimgbox").show();
            this._handlers.jstitleicon.attr("src", dsf.url.getWebPath(this.sdata.titleicon));
         }
         this._handlers.jstitletext.find("span").text(this.sdata.titleText);
         //    文字显示区域
         this._handlers.jstitletext.find("span").css({
            "color": this.sdata.titleTextcolor,
            "background": this.sdata.titletxtbgcolor,
         })


         if (this.sdata.titletxtbgl == '' || this.sdata.titletxtbgr == '') {//如果没有配置图片就去掉边距
            this._handlers.jstitletext.find("span").css('padding', 0)
            this._handlers.jstitletext.css('padding', 0)
         }
         this._handlers.jstitletext.css({
            "background": ' url(' + dsf.url.getWebPath(this.sdata.titletxtbgl) + ') no-repeat,'
               + 'url(' + dsf.url.getWebPath(this.sdata.titletxtbgr) + ') no-repeat 100% 0',
         });
         this._handlers.jstitlebox.css({
            "border": this.sdata.borderstyle,
            "background": this.sdata.gtitlebg,
         });
         // let morearr=this.sdata.morebtnbg.split(',');
         let morearr = this.sdata.morebtnbg ? this.sdata.morebtnbg.split(',') : [];
         // this._handlers.jsmorebtn.css({
         // 	"color": this.sdata.moreBtnColor,
         // 	"background": morearr[0] +' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
         // 	"background-size":'100% 100%'
         // });
         if (morearr.length > 1) {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath(morearr[1]) + ') no-repeat',
               "background-size": '100% 100%'
            });
         } else {
            this._handlers.jsmorebtn.css({
               "color": this.sdata.moreBtnColor,
               "background": morearr[0] + ' url(' + dsf.url.getWebPath('/res/dsf_styles/themes/nc/nm/more01.png') + ') no-repeat',
               "background-size": '100% 100%'
            });
         }

         this.isshowChooseBtnfun();
         this.isshowMoreBtnfun();

         if (this._root._isDesign) {
            this.teacherListDemo();
         } else {
            this.teacherList();
         }
      }
   }
   renderReady() { //组件加载完成后执行
      super.renderReady();
   }
   initEvent() { }


   // 配置项----------------------------------------------------------
   // 是否显示菜单
   isshowBarfun() {
      let _this = this;
      _this.$jsbarbox = _this._handlers["jsbarbox"];
      if (this.sdata.isshowBar) {
         console.log(1);
         //			兼容
         _this.$jsbarbox.removeClass("none");
         _this._handlers.jsbarbox.find("li.act").removeClass("actv");
         if (_this.sdata.issBarcoloract != "") {
            _this._handlers.jsbarbox.find("li.act").css({
               color: _this.sdata.issBarcoloract,
               "border-bottom-color": _this.sdata.issBarcoloract,
            }); //选中色
         } else {
            _this._handlers.jsbarbox.find("li.act").addClass("actv");
         }
      } else {
         _this.$jsbarbox.hide();
      }
   }
   //是否显示操作按钮
   isshowChooseBtnfun() {
      console.log(this.sdata.isshowChooseBtn);
      let _this = this;
      _this.$jschoosebtn = _this._handlers["jschoosebtn"];
      if (this.sdata.isshowChooseBtn) {
         _this.$jschoosebtn.removeClass("none");
      } else {
         _this.$jschoosebtn.addClass("none");
      }
      _this.$jschoosebtn.click(function () {
         let url = dsf.url.getWebPath(_this.sdata.Btnurl);
         dsf.openUrl(1, url);
         // window.location.href = dsf.url.getAbsolutePath(url);
      });
   }
   //是否显示更多按钮
   isshowMoreBtnfun() {
      let _this = this;
      _this.$jsmorebtn = _this._handlers["jsmorebtn"];
      if (this.sdata.ismoreBtn) {
         _this.$jsmorebtn.removeClass("none");
      } else {
         _this.$jsmorebtn.addClass("none");
      }
      _this._handlers["jsmorebtn"].click(function (evt) {
         let userId = dsf.getCookie("userId");
         if (!userId) {
            window.parent.openLogin();
            evt.preventDefault();
         }
         //  else {
         // 	let path = dsf.url.getWebPath(_this.sdata.moreBtnUrl);
         // 	dsf.openUrl(1, path)
         // }
      });
   }


   set detailurlfun(v) {
      this.$detailUrl = v;
      this.domUpdate();
   }
   get detailurlfun() {
      return this.$detailUrl;
   }
   set labelcolor(v) {
      this.plancoursedata.labelcolor = v;
      this.domUpdate();
   }
   get labelcolor() {
      return this.plancoursedata.labelcolor;
   }

   set btncolor(v) {
      this.plancoursedata.btncolor = v;
   }
   get btncolor() {
      return this.plancoursedata.btncolor;
   }


   set baract(v) {
      this.$baractnum = v;
      this.baractNum()
      this.domUpdate();
   }
   get baract() {
      return this.$baractnum;
   }
   //新增配置项
   set gtitheight(v) {
      this.sdata.titheight = v;
      this.domUpdate();
   }
   get gtitheight() {
      return this.sdata.titheight;
   }

   set gtitleborder(v) {
      this.sdata.borderstyle = v;
      this.domUpdate();
   }
   get gtitleborder() {
      return this.sdata.borderstyle;
   }

   set gtitlebg(v) {
      this.sdata.gtitlebg = v;
      this.domUpdate();
   }
   get gtitlebg() {
      return this.sdata.gtitlebg;
   }


   set gtitletxtbgcolor(v) {
      this.sdata.titletxtbgcolor = v;
      this.domUpdate();
   }
   get gtitletxtbgcolor() {
      return this.sdata.titletxtbgcolor;
   }


   set gtitletxtbgl(v) {
      this.sdata.titletxtbgl = v;
      this.domUpdate();
   }
   get gtitletxtbgl() {
      return this.sdata.titletxtbgl;
   }

   set gtitletxtbgr(v) {
      this.sdata.titletxtbgr = v;
      this.domUpdate();
   }
   get gtitletxtbgr() {
      return this.sdata.titletxtbgr;
   }

   set gmorebtnbg(v) {
      this.sdata.morebtnbg = v;
      this.domUpdate();
   }
   get gmorebtnbg() {
      return this.sdata.morebtnbg;
   }

   set gmoretext(v) {
      this.sdata.moretext = v;
      this.domUpdate();
   }
   get gmoretext() {
      return this.sdata.moretext;
   }

   baractNum() {
      let _this = this;
      _this.$jsbarbox = _this._handlers["jsbarbox"];
      _this.$jsbarbox.find('li:nth-child(' + _this.$baractnum + ')').click();
   }

   //配置项----------------------------------------------------------end


   geturls(cover) {
      let urls = '';
      if (cover) {
         let cov = JSON.parse(cover);
         if ($.isArray(cov)) {
            urls = cov[0].relativePath;
         }
      } else {
         urls = "res/dsf_styles/themes/nc/file-nopeo.png"
      }
      return urls;
   }
   teacherList() {
      let loading = dsf.layer.loadding();
      let _this = this;
      let url = dsf.url.getWebPath("meta/list/data");
      dsf.http.request_sync(
         url,
         _this.parms,
         "get"
      )
         .done(function (data) {
            console.log(data);
            if (data.state == 20000) {
               let sd = data.data,
                  shtml = '';
               _this.$jsteacherlist = _this._handlers['jsteacherlist'];
               console.log(sd);
               if (sd.length > 0) {
                  for (var i = 0, len = sd.length; i < len; i++) {
                     let urls = _this.geturls(sd[i]['nc_szk_mslbsjy.photo'])
                     shtml += `<div class="aitem" id="` + sd[i]['nc_szk_mslbsjy.nc_szk_id'] + `">
								   	 <img src="` + dsf.url.getWebPath(urls) + `" onerror="onerror=null;src='` + dsf.url.getWebPath('res/dsf_styles/themes/nc/file-nopeo.png') + `'" data-adaptive-background="1" data-description="grandpa" >
								   	 <div class="tea-text">
								   	 	<p>` + (!!sd[i]['nc_szk_mslbsjy.name'] ? sd[i]['nc_szk_mslbsjy.name'] : " ") + `</p>
								   	 	<div class="ftext ell9">
								   	 		 ` + (!!sd[i]['nc_szk_mslbsjy.description'] ? sd[i]['nc_szk_mslbsjy.description'] : "&nbsp") + `
								   	 	</div>
								   	 </div>
								   </div>`;
                  }
               } else {
                  shtml += '<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>';
               }
               _this.$jsteacherlist.html(shtml);
               _this.$jsteacherlist.find('.aitem').click(function () {
                  let id = $(this).attr('id');
                  var ur = dsf.url.getWebPath('nc/pc/main/views/main.html');
                  let userId = dsf.getCookie('userId');
                  if (!userId) {
                     window.parent.openLogin();
                     return;
                  }
                  //                dsf.openUrl(1,  _this.$detailUrl+'?id=' + id)
                  dsf.openUrl(1, dsf.url.getWebPath(_this.$detailUrl + '?id=') + id)
               })
            }
         })
         .error(function (err) {
            console.log(err);
         })
         .always(function () {
            dsf.layer.close(loading)
         }).exec();
   }
   teacherListDemo() {
      let shtml = '';
      for (var i = 0, len = 5; i < len; i++) {
         shtml += `<div class="aitem">
				   	 <img src="/dsfa/res/dsf_styles/themes/nc/file-nopeo.png" alt="">
				   	 <div class="tea-text">
				   	 	<p>刘孝成</p>
				   	 	<div class="ftext ell9">
				   	 		 金融学博士金融学博士金融学博士金融学博士金融学博士金融学博士金融学博士金融学博士
				   	 	</div>
				   	 </div>
				   </div>`;
      }
      this._handlers.jsteacherlist.html(shtml);
   }
}