  /**
   * 请求数据
   */
  postData () {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('yyzx/pdgl/findZtbGDList');
    dsf.http.request(
        url, _this.parms, 'get'
    ).done(response => {
      if (response.state === 20000) {
        // 请求成功
        this.postDataSuccess(response.data);
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }

  /**
   * 请求成功处理
   * @param tabId
   * @param data [
   *    {CKL, CODE, COVER: '[
   *      {originalFileName, name, suffix, size, contentType, relativePath, absolutePath, uploadDate, id}
   *    ]', DZL, KCFS, KCSC, KCXS, LABEL_TEXT, NC_ZYB_ID, SFBX, SFJRZX, SFNEW, SFXX, SKJS: [
   *      {ROWNUM, JOB, JSMC},
   *      ......
   *    ], SKJSUNIT, TITLE, fbrq, _id}
   *    ......
   * ]
   */
  postDataSuccess (data) {
    let _this = this;
    let shtml = [];
    this.$jsspelist = this._handlers["jsspelist"];
    if (data.length > 0) {
      data.forEach(v => {
        let urls = this.geturls(v.cover);
        let btnshtml = "";
        //							0 未报名
        //							1 已报名
        //							2 学习中
        //							3 已通过
        if (v.STATE === '0') {
          btnshtml = `<span class="jsadd act" state="${v.STATE}">加入在学</span>`;
        } else if (v.STATE === '1') {
          btnshtml = `<span class="jsadd act" state="${v.STATE}">开始学习</span>`;
        } else if (v.STATE === '2') {
          btnshtml = `<span class="jsadd act" state="${v.STATE}">继续学习</span>`;
        } else if (v.STATE === '3') {
          btnshtml = `<span class="jsadd act" state="${v.STATE}">通过学习</span>`;
        } else if (v.STATE === '4') {
          btnshtml = ``;
        }
        shtml.push(
          `<div class="aitem" id="${v.nc_zyb_id}">
            <div class="aimgbox">
							<img src="${dsf.url.getWebPath(urls)}" data-adaptive-background="1" data-description="grandpa"
							  onerror="onerror=null;this.src='${dsf.url.getWebPath('res/dsf_styles/themes/nc/404.png')}'"/>
							<div class="imgtext">
							  <div class="choosebox">
							    <span class="choose2" style="display: ${v.sfbx === 1 ? 'display:inline-block' : 'none'}">必</span>
                  <span class="choose3" style="display: ${v.isnew === 1 ? 'display:inline-block' : 'none'}">新</span>
								</div>
                <div class="timecenter">
                  <b class="iconfont icon1 icon-shijian"/>
                  <b>
                    ${!!v.pxrq_sdate ? v.pxrq_sdate.substr(5, 2) + '.' + v.pxrq_sdate.substr(8, 2) : ''}
                    -
                    ${!!v.pxrq_edate ? v.pxrq_edate.substr(5, 2) + '.' + v.pxrq_edate.substr(8, 2) : ''}
                  </b>
								</div>
              </div>
            </div>
            <div class="item-foot">
              <div class="ctitle ell2">${!!v.title ? v.title : ''}</div>
              <div class="cclass-hour">
								<p><span>必修课程</span><i>${!!+v.bxcount ? v.bxcount : ''}</i></p>
								<p><span>必修学时</span><i>${!!+v.bxxs ? v.bxxs : ''}</i></p>
								<p><span>学员人数</span><i>${v.studentNum ? v.studentNum : '0'}</i></p>
              </div>
            </div>
            <div class="hbox">
              <p class="ell2">${!!v.title ? v.title : ''}</p>
              <div class="btnbox">
								<span class="jstodoStyle">马上学习</span>
								${btnshtml}
              </div>
            </div>
          </div>`);
      });
    } else {
      shtml = ['<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>'];
    }
    this.$jsspelist.html(shtml.join(''));

    //移入背景图
    this.$jsspelist.find('.hbox').css({
      'background': `url(${dsf.url.getWebPath(this.plandata.hoverbg)}) no-repeat`,
      'background-size': '100% 100%'
    });
    //移入背景色
    this.$jsspelist.find('.btnbox span.act').css({
      background: this.plandata.btncolor,
    });

    let $aitem = this.$jsspelist.find('.aitem');
    $aitem.find('.jstodoStyle').click(function() {
      let id = $(this).parents('.aitem').attr('id');
      let userId = dsf.getCookie("userId");
      if (!userId) {
        window.parent.openLogin();
        return;
      }
      //						dsf.openUrl(1, '/dsfa/nc/pc/stylecenterindex/views/stylecenterindex.html?id=' + id)
      //						dsf.openUrl(1, _this.detailUrl+'/dsfa/nc/pc/stylecenterindex/views/stylecenterindex.html?id=' + id)
      let path = dsf.url.getWebPath(_this.$detailUrl + '?id=' + id);
      dsf.openUrl(1, path);
    });
    $aitem.find('.jsadd').click(function() {
      let id = $(this).parents('.aitem').attr('id'),
          state = $(this).attr('state'),
          userName = dsf.getCookie('user_name'),
          userId = dsf.getCookie('userId');
      if (userId) {
        if (state === '0') {
          dsf.layer.confirm(
              "您确定要报名吗?",
              () => {
                _this.courseSingUp(id, state, userName, userId);
              },
              () => {
                console.log("取消报名");
              }
          );
        } else {
          let path = dsf.url.getWebPath(_this.$detailUrl + "?id=" + id);
          dsf.openUrl(1, path);
        }
      } else {
        window.parent.openLogin();
      }
    });
  }

