  courseSingUp(id, state, userName, userId) {
    //报名成功后刷新列表
    let params = {
      nc_zyb_id: id,
      nc_students_id: userId,
    };
    let that = this;
    let loading = dsf.layer.loadding();
    let singUrl = dsf.url.getWebPath("ztb/xymd/addXymdBm");
    dsf.http
      .request(singUrl, params, "POST")
      .done(function(res) {
        if (res.success) {
          if (res.data) {
            dsf.layer.message(res.message, true);
            let t = setTimeout(() => {
              if (this._root._isDesign) {
                _this._postData();
              } else {
                _this.postData();
              }
              clearTimeout(t);
            }, 1000);
          }
        } else {
          dsf.layer.message(res.message, false);
        }
      })
      .error(function(err) {
        console.log(err);
        dsf.layer.message(err.message, false);
      })
      .always(function() {
        dsf.layer.close(loading);
      })
      .exec();
  }

