import dome from '../templates/Ncclasstuttons.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("按钮组", 'nc.teas.ncclasstuttons', 'Ncclasstuttons')
export class Ncclasstuttons extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
		this.btn1src='';
		this.btn2src='';
		this.btn3src='';
		this.parms={
  		ztbid:'3f0bdc9c047a43a3b7d98907f7609d98',
  	}
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    let _this=this;
    if (this._root._isDesign) {
		} else {
			this.parms.ztbid = parent.rparms.ztbid
		}
  }

  renderContext(refresh) {
  	let _this=this;
  	_this.$righttopbox = _this._handlers['righttopbox'];
  	_this.$righttopbox.find('.righttopitem p').click(function(){
  		let ind=$(this).parents('.righttopitem').index();
  		if(ind==0){
  			window.parent.rankingshade(_this.parms.ztbid);
  		}else if(ind==1){
  			window.parent.showquestion(_this.parms.ztbid);
  		}else if(ind==2){
  			window.parent.peopleshade();
//			let urls = dsf.url.getWebPath(_this.btn3src);
//				dsf.openUrl(1,urls)
  		}
  	})
  }

	renderReady(){//组件加载完成后执行
		super.renderReady();

	}
  initEvent() {
  }

}

