import dome from '../templates/NcLearnFile.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("学习档案", 'nc.teas.nclearnfile', 'NcLearnFile')

export class NcLearnFile extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.timeLine = [
            {
                year: '2019',
                task: {
                    xs: '120',
                    kcxs: {
                        num: 55,
                        total: 50
                    },
                    bxztb: {
                        num: 3,
                        total: 3
                    },
                    bxb: {
                        num: 3,
                        total: 3
                    },
                },
                detail: {
                    ztb: {
                        num: 10,
                        total: 65
                    },
                    kc: {
                        num: 50,
                        total: 55
                    },
                    hd: 2,
                    zs: 7,
                },
                grpxbg: 0
            },
            {
                year: '2018',
                task: {
                    xs: '120',
                    kcxs: {
                        num: 55,
                        total: 50
                    },
                    bxztb: {
                        num: 3,
                        total: 3
                    },
                    bxb: {
                        num: 3,
                        total: 3
                    },
                },
                detail: {
                    ztb: {
                        num: 10,
                        total: 65
                    },
                    kc: {
                        num: 50,
                        total: 55
                    },
                    hd: 2,
                    zs: 7,
                },
                grpxbg: 1
            },
        ]
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            this.renderDefaultPage(this.timeLine);
        } else {
            this.getLearnFile();
        }
    };

    getLearnFile() {
        let loading = dsf.layer.loadding();
        let sourceurl = dsf.url.getWebPath('nc/xyda/displayXd');
        let params = {};
        dsf.http.request(sourceurl,params,'GET')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    this.renderhead(res.data.head);
                    this.renderPage(res.data.list);
                } else {
                    dsf.layer.message(JSON.stringify(res));
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    renderhead(data) {
        let headStr = '<div class="file_header">\n' +
            '            <h4>学习档案</h4>\n' +
            '            <div class="learn_time">\n' +
            '                已经陪伴<span class="learn_day">'+ data.day +'</span>天\n' +
            '                <img src="/dsfa/res/dsf_styles/themes/nc/learnFile/dan.png" alt="">\n' +
            '            </div>\n' +
            '            <ul class="learn_info">\n' +
            '                <li>专题班总计：<span>'+ data.ztb_total +'</span>个</li>\n' +
            '                <li>学时总计：<span>'+ data.time_total +'</span>学时</li>\n' +
            '                <li>学习时长总计：<span>'+ data.study_total_hour +'</span>小时<span>'+ data.study_total_minute +'</span>分钟</li>\n' +
            '            </ul>\n' +
            '        </div>';
        this._handlers['learnFile_head'].html(headStr);
    }

    renderPage(data) {
        let timeLineStr = '';
        for (let i = 0;i < data.length;i++) {
            let item = data[i];
            timeLineStr += '<li class="layui-timeline-item" style="padding: 40px 0 110px 16px;">\n' +
                '            <h5 class="layui-timeline-title line_time">'+ item.year +'</h5>\n' +
                '            <div class="layui-timeline-content layui-text">\n' +
                '                <div class="task">\n' +
                '                    <span class="task_title">任务</span>\n' +
                '                    <ul class="task_info">\n' +
                '                        <li>获得<span>'+ item.task.study_total_qian +''+ (item.task.study_total_qian>0?'/':'') +' '+ item.task.study_total_hou +'</span>学时</li>\n' +
                '                        <li style="display: '+ (item.task.kc_state==1?'block':'none') +'"><span>'+ item.task.kc_xs_qian +'</span>/'+ item.task.kc_xs_hou +'课程学时</li>\n' +
                '                        <li><span>'+ item.task.compulsory_ztb +'</span>/'+ item.task.compulsory_ztb_total +'个必修专题班</li>\n' +
                '                        <li><span>'+ item.task.compulsory_counrse +'</span>/'+ item.task.compulsory_counrse_total +'门必修课程</li>\n' +
                '                    </ul>\n' +
                '                    <div class="task_tags">\n' +
                '                        <span class="'+(item.task.state==1?'passing':'not_passing')+'">'+ (item.task.state==1?'通过':'未通过') +'</span>\n' +
                '                    </div>\n' +
                '                    <span class="triangle"></span>\n' +
                '                    <span class="time_node"></span>\n' +
                '                </div>\n' +
                '                <div class="detail">\n' +
                '                    <span class="detail_title">详情</span>\n' +
                '                    <ul class="detail_info">\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/ztb.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.information.ztb_count +'/</span><span>'+ item.information.ztb_hour +'</span>学时</dt>\n' +
                '                                <dd>专题班</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/kc.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.information.kc_count +'/</span><span>'+ item.information.kc_hour +'</span>学时</dt>\n' +
                '                                <dd>课程</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/hd.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.information.activity +'</span>个</dt>\n' +
                '                                <dd>活动</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/zs.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.information.certificate +'</span>个</dt>\n' +
                '                                <dd>证书</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/pxbg.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span></span><span>'+ (item.information.report==0?'未生成':'查看') +'</span></dt>\n' +
                '                                <dd>个人培训报告</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                    </ul>\n' +
                '                    <span class="triangle"></span>\n' +
                '                </div>\n' +
                '            </div>\n' +
                '        </li>';
        }

        this._handlers['timeLine_list'].html(timeLineStr);

    }

    renderDefaultPage(data) {
        let timeLineStr = '';
        for (let i = 0;i < data.length;i++) {
            let item = data[i];
            timeLineStr += '<li class="layui-timeline-item" style="padding: 40px 0 110px 16px;">\n' +
                '            <h5 class="layui-timeline-title line_time">'+ item.year +'</h5>\n' +
                '            <div class="layui-timeline-content layui-text">\n' +
                '                <div class="task">\n' +
                '                    <span class="task_title">任务</span>\n' +
                '                    <ul class="task_info">\n' +
                '                        <li>获得<span>'+ item.task.xs +'</span>学时</li>\n' +
                '                        <li><span>'+ item.task.kcxs.num +'</span>/'+ item.task.kcxs.total +'课程学时</li>\n' +
                '                        <li><span>'+ item.task.bxztb.num +'</span>/'+ item.task.bxztb.total +'个必修专题班</li>\n' +
                '                        <li><span>'+ item.task.bxb.num +'</span>/'+ item.task.bxb.total +'门必修班</li>\n' +
                '                    </ul>\n' +
                '                    <div class="task_tags">\n' +
                '                        <span class="'+(item.grpxbg?'passing':'')+'">通过</span>\n' +
                '                        <span class="'+(item.grpxbg?'':'not_passing')+'">未通过</span>\n' +
                '                    </div>\n' +
                '                    <span class="triangle"></span>\n' +
                '                    <span class="time_node"></span>\n' +
                '                </div>\n' +
                '                <div class="detail">\n' +
                '                    <span class="detail_title">详情</span>\n' +
                '                    <ul class="detail_info">\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/ztb.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.detail.ztb.num +'/</span><span>'+ item.detail.ztb.total +'</span>学时</dt>\n' +
                '                                <dd>专题班</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/kc.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.detail.kc.num +'/</span><span>'+ item.detail.kc.total +'</span>学时</dt>\n' +
                '                                <dd>课程</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/hd.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.detail.hd +'</span>个</dt>\n' +
                '                                <dd>活动</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/zs.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span>'+ item.detail.zs +'</span>个</dt>\n' +
                '                                <dd>证书</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                        <li>\n' +
                '                            <div class="img_wrap"><img src="/dsfa/res/dsf_styles/themes/nc/learnFile/pxbg.png" alt=""></div>\n' +
                '                            <dl>\n' +
                '                                <dt><span></span><span>未生成</span></dt>\n' +
                '                                <dd>个人培训报告</dd>\n' +
                '                            </dl>\n' +
                '                        </li>\n' +
                '                    </ul>\n' +
                '                    <span class="triangle"></span>\n' +
                '                </div>\n' +
                '            </div>\n' +
                '        </li>';
        }

        this._handlers['timeLine_list'].html(timeLineStr);

    }

}


