import dome from "../templates/NcHistoryRecord.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("历史记录", "nc.teas.nchistiryrecord", "NcHistoryRecord")
export class NcHistoryRecord extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.sourceUrl = "";
    this.barcolor = "#D60C0C";
    this.countcolor = "#D60C0C";
    this.viewMore = "#D60C0C";
    this.playurl = "/res/dsf_styles/themes/nc/bofang.png";
  }
  initTemplate() {
    return dome(this);
  }

  renderContext() {
    super.renderContext();
    if (this._root._isDesign) {
      // this._handlers['bannerList'].css('height', '300px');
    } else {
      this.getRecords();
    }
  }

  changeColor() {
    this._handlers.barcolor.css("background-color", this.barcolor);
    this._handlers.countcolor.css("color", this.countcolor);
    this._handlers.playurl.attr("src", dsf.url.getWebPath(this.playurl));
    this._handlers.viewMore.css("color", this.viewMore);
  }

  getRecords() {
    let loading = dsf.layer.loadding();
    this.bannerList = [];
    if (!this.sourceUrl) this.sourceUrl = "nc/kjk/frontuse/getXyHistoryKc";
    let sourceurl = dsf.url.getWebPath(this.sourceUrl);
    let params = {
      pageNum: 1,
      pageSize: 8,
    };
    dsf.http
      .request(sourceurl, params, "Get")
      .done((res) => {
        if (res.success && res.state == 20000) {
          if (res.cnt) {
            $(".class_total")
              .find("span")
              .html(res.cnt);
            this.hiddenMore(res.cnt);
          }
          this.renderPage(res.data);
        } else {
          dsf.layer.message(JSON.stringify(res));
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }
  // 渲染DOM
  renderPage(data) {
    let _this = this;
    if (data && data.length > 0) {
      let recordStr = "";
      for (let i = 0; i < data.length; i++) {
        let item = data[i];
        recordStr +=
          "<li>\n" +
          '            <img class="item_cover" src="' +
          (item.cover
            ? dsf.url.getWebPath(JSON.parse(item.cover)[0].relativePath)
            : "/dsfa/res/dsf_styles/themes/nc/404.png") +
          '" onerror="this.src=' +
          "/dsfa/res/dsf_styles/themes/nc/404.png" +
          ';this.onerror=null" alt="">\n' +
          "            <p>" +
          item.title +
          "</p>\n";
        if (this.playurl) {
          recordStr +=
            '<img class="play_btn" handler="playurl" src="' +
            dsf.url.getWebPath(this.playurl) +
            '" alt="">\n';
        }
        recordStr += "</li>";
      }

      _this._handlers["recordList"].html(recordStr);
      $(".view_more").on("click", function() {
        //              let courseUrl = dsf.url.getWebPath('nc/kck/mhkc/views/mhkclb.html');//门户课程
        //              window.open(courseUrl);
        //var ur = dsf.url.getWebPath('nc/pc/mine/views/learnTrajectory.html?a=1');
        //dsf.openUrl(1,ur)

        var elid = $(window.parent.document).find("#J_content");
        $(elid).attr(
          "src",
          dsf.url.getWebPath(
            "nc/pc/mine/views/learnTrajectory.html?name=" + encodeURI("在学")
          )
        );
      });
      $(".record_list")
        .find("li")
        .each(function(index) {
          let _this = $(this);
          _this.on("click", function() {
            let courseUrl = dsf.url.getWebPath(
              "nc/pc/course/views/course.html?type=2&id=" + data[index].kcid
            );
            window.open(courseUrl);
          });
        });
    } else {
      _this.notList();
      $(".jump_course").on("click", function() {
        //              let courseUrl = dsf.url.getWebPath('nc/kck/mhkc/views/mhkclb.html');
        //              window.open(courseUrl);
        var elid = $(window.parent.document).find("#J_content");
        $(elid).attr(
          "src",
          dsf.url.getWebPath(
            "nc/pc/mine/views/learnTrajectory.html?name=" + encodeURI("在学")
          )
        );
      });
    }
  }

  // 无数据的
  notList() {
    let noStr =
      '<div class="not_record">\n' +
      '            <img src="/dsfa/res/dsf_styles/themes/nc/c_icon_score.png" alt="">\n' +
      '            <p>您还没有学习记录，去<span class="jump_course">课程</span>看看</p>\n' +
      "        </div>";
    this._handlers["record_wrap"].html(noStr);
  }

  // 不显示更多
  hiddenMore(cnt) {
    if (cnt <= 8) {
      $(".view_more").css("display", "none");
    } else {
      return;
    }
  }

  renderReady() {
    super.renderReady();
    this.barcolor = this.barcolor === undefined ? "#D60C0C" : this.barcolor;
    this.countcolor =
      this.countcolor === undefined ? "#D60C0C" : this.countcolor;
    this.playurl =
      this.playurl === undefined
        ? "/res/dsf_styles/themes/nc/bofang.png"
        : this.playurl;
    this.changeColor();
  }
}
