import dome from "../templates/NcChannelPortal.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("频道门户", "nc.teas.ncchannelportal", "NcChannelPortal")
export class NcChannelPortal extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.pageSize = 3; // 一页显示的数目
    this.curr = 1;
    this.count = "";
    this.fontColor = "#ea4d4d";
    this.channerID = "";
  }

  initTemplate() {
    return dome(this);
  }

  renderContext() {
    super.renderContext();
    if (!this._root._isDesign) {
      this.getChannelID();
      this.getDetail();
    }
    this.changeColor();
  }
  renderReady() {
    super.renderReady();
    this.switchTab();
  }

  getChannelID() {
    let chaID = window.parent.document.getElementById("channel_frame")
      .contentWindow.location.search;
    this.channerID = chaID.substring(4);
    if (!this.channerID) {
      this.channerID = dsf.url.queryString("id");
    }
  }
  changeColor() {
    let lay = $(".layui-this");
    console.log(this.fontColor);
    if (this.fontColor) {
      if (lay.length) {
        lay.removeClass("commonBorderColorAfter");
      }
      $(
        ".learn_btn,.item_tag,.pagination .layui-laypage .layui-laypage-curr .layui-laypage-em"
      ).css({
        background: this.fontColor + "!important",
      });
      $(".isNew").css({
        border: "1px solid " + this.fontColor,
        color: this.fontColor,
      });
      $(
        `<style>.layui-this:after{border-color:${this.fontColor} !important}
        .dsf_nc_channerPortal .content_wrap .layui-tab .layui-tab-title .layui-this{color:${this.fontColor}!important}</style>`
      ).appendTo("head");
    } else {
      if (lay.length) {
        lay.addClass("commonBorderColorAfter");
      }
      $(
        ".learn_btn,.item_tag,.pagination .layui-laypage .layui-laypage-curr .layui-laypage-em"
      ).css({
        background: "",
      });
      $(
        ".dsf_nc_channerPortal .content_wrap .layui-tab .layui-tab-title .layui-this"
      ).css({
        color: "!important",
      });
    }
  }
  // tab事件
  switchTab() {
    let _this = this;
    layui.use("element", function() {
      var element = layui.element;
      //一些事件监听
      element.on("tab(portal_tab)", function(data) {
        switch (data.index) {
          case 0:
            _this.getDetail();
            break;
          case 1:
            _this.getList();
            break;
          case 2:
            _this.getSource();
            break;
          default:
            _this.getDetail();
        }
      });
    });
  }

  // 简介
  getDetail() {
    let loading = dsf.layer.loadding();
    let url = "yyzx/pdgl/pdid";
    let sourceUrl = dsf.url.getWebPath(url);
    let params = {
      id: dsf.url.queryString("id") || "8077b9ac6a214dd4866850979e76a5c0",
    };
    dsf.http
      .request(sourceUrl, params, "Get")
      .done((res) => {
        if (res.success && res.state == 20000) {
          this.renderHead(res.data);
          this.renderIntro(res.data);
          this.getFavorite(res.data);
          this.getLike(res.data);
          this.getSubscribe(res.data);
        } else {
          dsf.layer.message(JSON.stringify(res));
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }
  // 页面头部
  renderHead(data) {
    var tags = "";
    if (
      data.label_text != null &&
      data.label_text != undefined &&
      data.label_text.length > 0
    ) {
      for (let i = 0; i < data.label_text.length; i++) {
        tags +=
          "<li>\n" + "      <b>" + data.label_text[i] + "</b>\n" + "     </li>";
      }
    }
    let headStr =
      "<div class='course-inner course-inner-default-padding'>\n" +
      "                        <div class='course-img-wrap course-default-img-wrap'>\n" +
      '                            <img src="' +
      (data.cover
        ? dsf.url.getWebPath(JSON.parse(data.cover)[0].relativePath)
        : "/dsfa/res/dsf_styles/themes/nc/404.png") +
      '" onerror="this.src=' +
      "/dsfa/res/dsf_styles/themes/nc/404.png" +
      ';this.onerror=null" alt="">\n' +
      "                        </div>\n" +
      "                        <div class='course-info-wrap course-info-wrap-default-margin' style=\"margin-left: 375px;\">\n" +
      "                            <h3 class='course-info-title'>\n" +
      '                                <span class="course-title">' +
      data.title +
      "</span>\n" +
      '                                <i class="d-icon d-fx"></i>\n' +
      "                            </h3>\n" +
      '                            <p class="famous-teacher-job portal_info">\n' +
      "                                <span>共&nbsp;" +
      data.count +
      "&nbsp;门</span>\n" +
      "                                <span>发布&nbsp;&nbsp;" +
      data.ds_update_time.slice(0, 10) +
      "</span>\n" +
      "                                <span><i></i>" +
      data.djs +
      "</span>\n" +
      "                            </p>\n" +
      '                            <ul class="famous-teacher-course portal_tags">\n' +
      "                                " +
      tags +
      "\n" +
      "                            </ul>\n" +
      '                            <div class="info_bar">\n' +
      '                                <div class="num_bar">\n' +
      "                                    <span><i></i><span>" +
      data.scs +
      "</span></span>\n" +
      "                                    <span><i></i><span>" +
      data.dzs +
      "</span></span>\n" +
      "                                    <span><i></i><span>" +
      data.dys +
      "</span></span>\n" +
      "                                </div>\n" +
      '                                <button class="sing-read-btn learn_btn" style="display: ' +
      (data.sfsq == 1 ? "block" : "none") +
      ';">' +
      (data.sfzx ? "学习中" : "开始学习") +
      "</button>\n" +
      "                            </div>\n" +
      "                        </div>\n" +
      "                    </div>";
    this._handlers["courseHead"].html(headStr);
    this.favorite(data);
    this.bindLike(data);
    this.bindSubscribe(data);
    this.startLearn(data);
  }
  // 查询收藏数
  getFavorite(data) {
    let sourceUrl = dsf.url.getWebPath("dsfa/collect/queryTotalByYwid");
    let params = {
      ywlxValue: "pd",
      ywid: data.nc_zyb_id,
    };
    dsf.http
      .request(sourceUrl, params, "GET")
      .done((res) => {
        if (res.success && res.state == 20000) {
          $(".num_bar>span:nth-of-type(1)>span").html(res.data);
        } else {
          dsf.layer.message(res.message);
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {})
      .exec();
  }
  // 收藏点击
  favorite(data) {
    var _this = this;
    $(".num_bar>span:nth-of-type(1)>i").on("click", function() {
      let scloading = dsf.layer.loadding();
      let url = "dsfa/collect/saveOrCancel";
      let sourceUrl = dsf.url.getWebPath(url);
      let params = {
        ywid: data.nc_zyb_id,
        ywlxValue: "pd",
        ywlxText: "新增",
      };
      dsf.http
        .request(sourceUrl, params, "POST")
        .done((res) => {
          if (res.success && res.state == 20000) {
            if (res.data.isDo) {
              dsf.layer.message("收藏成功");
            } else {
              dsf.layer.message(" 取消收藏成功");
            }
            _this.getFavorite(data);
          } else {
            dsf.layer.message(res.message);
          }
        })
        .error((err) => {
          dsf.layer.message("接口异常,请稍后重试", false);
        })
        .always(() => {
          dsf.layer.close(scloading);
        })
        .exec();
    });
  }
  // 查询点赞
  getLike(data) {
    let sourceUrl = dsf.url.getWebPath("dsfa/tags/queryTotalByYwid");
    let params = {
      ywlxValue: "pd",
      ywid: data.nc_zyb_id,
    };
    dsf.http
      .request(sourceUrl, params, "GET")
      .done((res) => {
        if (res.success && res.state == 20000) {
          $(".num_bar>span:nth-of-type(2)>span").html(res.data);
        } else {
          dsf.layer.message(res.message);
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {})
      .exec();
  }
  // 点赞点击
  bindLike(data) {
    var _this = this;
    $(".num_bar>span:nth-of-type(2)>i").on("click", function() {
      let dzloading = dsf.layer.loadding();
      let url = "dsfa/tags/saveOrCancel";
      let sourceUrl = dsf.url.getWebPath(url);
      let params = {
        ywid: data.nc_zyb_id,
        ywlxValue: "pd",
        ywlxText: "新增",
      };
      dsf.http
        .request(sourceUrl, params, "POST")
        .done((res) => {
          if (res.success && res.state == 20000) {
            if (res.data.isDo) {
              dsf.layer.message("点赞成功");
            } else {
              dsf.layer.message("取消点赞成功");
            }
            _this.getLike(data);
          } else {
            dsf.layer.message(res.message);
          }
        })
        .error((err) => {
          dsf.layer.message("接口异常,请稍后重试", false);
        })
        .always(() => {
          dsf.layer.close(dzloading);
        })
        .exec();
    });
  }
  // 查询订阅
  getSubscribe(data) {
    let sourceUrl = dsf.url.getWebPath("dsfa/subscribe/queryTotalByYwid");
    let params = {
      ywlxValue: "pd",
      ywid: data.nc_zyb_id,
    };
    dsf.http
      .request(sourceUrl, params, "GET")
      .done((res) => {
        if (res.success && res.state == 20000) {
          $(".num_bar>span:nth-of-type(3)>span").html(res.data);
        } else {
          dsf.layer.message(res.message);
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {})
      .exec();
  }
  // 订阅点击
  bindSubscribe(data) {
    let _this = this;
    $(".num_bar>span:nth-of-type(3)>i").on("click", function() {
      let dyloading = dsf.layer.loadding();
      let url = "dsfa/subscribe/saveOrCancel";
      let sourceUrl = dsf.url.getWebPath(url);
      let params = {
        ywid: data.nc_zyb_id,
        ywlxValue: "pd",
        ywlxText: "新增",
      };
      dsf.http
        .request(sourceUrl, params, "POST")
        .done((res) => {
          if (res.success && res.state == 20000) {
            if (res.data.isDo) {
              dsf.layer.message("订阅成功");
            } else {
              dsf.layer.message("取消订阅成功");
            }
            _this.getSubscribe(data);
          } else {
            dsf.layer.message(res.message);
          }
        })
        .error((err) => {
          dsf.layer.message("接口异常,请稍后重试", false);
        })
        .always(() => {
          dsf.layer.close(dyloading);
        })
        .exec();
    });
  }
  // 开始学习
  startLearn(data) {
    $(".learn_btn").on("click", function() {
      let courseUrl = dsf.url.getWebPath(
        "nc/pc/course/views/course.html?type=1&id=" + data.nc_zyb_id
      );
      window.open(courseUrl);
    });
  }

  // 简介DOM
  renderIntro(data) {
    if (data) {
      this._handlers["intro_container"].html(data.content);
    } else {
      let notDataStr =
        "<img style='width:200px;height:180px;margin:0 auto;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>";
      this._handlers["intro_container"]
        .html(notDataStr)
        .css({ "text-align": "center", padding: "80px 0" });
    }
  }

  // 列表
  getList() {
    let loading = dsf.layer.loadding();
    let url = "yyzx/pdgl/pdlbid";
    let sourceUrl = dsf.url.getWebPath(url);
    let params = {
      id: dsf.url.queryString("id") || "3d8ce0dcae154e358ddefe0c49450204",
      pageNo: this.curr,
      pageSize: this.pageSize,
    };
    dsf.http
      .request(sourceUrl, params, "Get")
      .done((res) => {
        if (res.success && res.state == 20000) {
          this.renderList(res.data);
          this.count = res.data.count;
          this.renderPagination();
        } else {
          dsf.layer.message(JSON.stringify(res));
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }
  // 渲染分页
  renderPagination() {
    let laypagenation = layui.laypage;
    let _this = this;
    //执行一个laypage实例
    laypagenation.render({
      elem: "portal_pagenation",
      count: _this.count,
      limit: _this.pageSize,
      curr: _this.curr,
      theme: this.fontColor,
      layout: ["prev", "page", "next", "last"],
      prev: "<i class='iconfont icon-left'></i>",
      next: "<i class='iconfont icon-right'></i>",
      jump: (obj, first) => {
        if (!first) {
          _this.curr = obj.curr;
          _this.getList();
        }
      },
    });
  }
  // 列表DOM
  //  + (!!data['bmrq_sdate'] ? data['bmrq_sdate'] : '') +
  renderList(list) {
    let listStr = "",
      data = list.records;
    if (data && data.length > 0) {
      for (let i = 0; i < data.length; i++) {
        listStr +=
          '<li class="portal_item">\n' +
          '         <img src="' +
          (data[i].cover
            ? dsf.url.getWebPath(JSON.parse(data[i].cover)[0].relativePath)
            : "/dsfa/res/dsf_styles/themes/nc/404.png") +
          '" onerror="this.src=' +
          "/dsfa/res/dsf_styles/themes/nc/404.png" +
          ';this.onerror=null" alt="">\n' +
          '         <div class="item_content">\n' +
          '             <div class="content_header">\n' +
          '                 <span class="' +
          (data[i].sfnew ? "isNew" : "") +
          '">new</span>\n' +
          "                 <h6>" +
          data[i].title +
          "</h6>\n" +
          "                 <span><i></i></span>\n" +
          "             </div>\n" +
          '             <p class="name_posi"><span>' +
          (!!data[i].skjs ? data[i].skjs : "") +
          "</span><span>" +
          (!!data[i].jsdwzw ? "-" + data[i].jsdwzw : "") +
          "</span></p>\n" +
          '             <div class="item_num">\n' +
          "                 <span><i></i>" +
          data[i].xs +
          "学时</span>\n" +
          "                 <span><i></i>" +
          data[i].djs +
          "</span>\n" +
          '             <div class="btns_wrap" style="display: ' +
          (list.sfsq == 1 ? "none" : "block") +
          '">\n' +
          '                 <button class="' +
          (data[i].type_value == "02" ? "write_btn" : "") +
          '">撰写</button>\n' +
          '                 <button class="' +
          (data[i].type_value == "03" ? "answer_btn" : "") +
          '">作答</button>\n' +
          '                 <button class="' +
          (data[i].type_value == "04" ? "exam_btn" : "") +
          '">考试</button>\n' +
          '                 <button class="' +
          (data[i].type_value == "05" ? "join_btn" : "") +
          '">加入学习</button>\n' +
          "             </div>\n" +
          "             </div>\n" +
          "         </div>\n" +
          "     </li>";
      }
      this._handlers["list_wrap"].html(listStr);
      this.bindDetail(list);
      this.bindDetailImg(list);
      this.joinLearn(data);
    } else {
      let notDataStr =
        "<img style='width:200px;height:180px;margin:0 auto;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>";
      this._handlers["list_container"]
        .html(notDataStr)
        .css({ "text-align": "center", padding: "80px 0" });
    }
  }
  // 加入学习
  joinLearn(data) {
    $(".join_btn").each(function(index) {
      $(this).on("click", function() {
        let leloading = dsf.layer.loadding();
        let url = "zxgl/add";
        let sourceUrl = dsf.url.getWebPath(url);
        let params = {
          relid: data[index].relid,
        };
        dsf.http
          .request(sourceUrl, params, "GET")
          .done((res) => {
            if (res.success && res.state == 20000) {
              dsf.layer.message("已加入在学");
              // $('.join_btn')[index].html('已加入在学');
            } else {
              dsf.layer.message(res.message);
            }
          })
          .error((err) => {
            dsf.layer.message("接口异常,请稍后重试", false);
          })
          .always(() => {
            dsf.layer.close(leloading);
          })
          .exec();
      });
    });
  }

  // 跳转频道详情
  bindDetail(list) {
    let data = list.records;
    $(".portal_list>.portal_item>img").each(function(index) {
      $(this).on("click", function(e) {
        if (list.sfsq == 1) {
          if (data[index].type_value == "02") {
            dsf.layer.message("暂无撰写页面");
          } else if (data[index].type_value == "03") {
            dsf.layer.message("暂无作答页面");
          } else if (data[index].type_value == "04") {
            dsf.layer.message("暂无试卷页面");
          } else if (data[index].type_value == "05") {
            // let url = '/dsfa/nc/mhsy/views/pdinfo.html?id='+data[index].nc_zyb_id;
            // window.open(url,'_self');
            // 课程
            let courseUrl = dsf.url.getWebPath(
              "nc/pc/course/views/course.html?type=2&id=" + data[index].relid
            );
            window.open(courseUrl);
          } else {
            return;
          }
        } else {
          dsf.layer.message("该频道暂未授权");
          return;
        }
      });
    });
  }
  bindDetailImg(list) {
    let data = list.records;
    $(".portal_list>.portal_item h6").each(function(index) {
      $(this).on("click", function(e) {
        if (list.sfsq == 1) {
          if (data[index].type_value == "02") {
            dsf.layer.message("暂无撰写页面");
          } else if (data[index].type_value == "03") {
            dsf.layer.message("暂无作答页面");
          } else if (data[index].type_value == "04") {
            dsf.layer.message("暂无试卷页面");
          } else if (data[index].type_value == "05") {
            // let url = '/dsfa/nc/mhsy/views/pdinfo.html?id='+data[index].nc_zyb_id;
            // window.open(url,'_self');
            // 课程
            let courseUrl = dsf.url.getWebPath(
              "nc/pc/course/views/course.html?type=2&id=" + data[index].relid
            );
            window.open(courseUrl);
          } else {
            return;
          }
        } else {
          dsf.layer.message("该频道暂未授权");
          return;
        }
      });
    });
  }

  // 相关资源
  getSource() {
    let loading = dsf.layer.loadding();
    let url = "nc/zyb/xg/pdxg";
    let sourceUrl = dsf.url.getWebPath(url);
    let params = {
      id: dsf.url.queryString("id") || "4e3d5bf1f78d490180901c5673ce6a9f",
    };
    dsf.http
      .request(sourceUrl, params, "Get")
      .done((res) => {
        if (res.success && res.state == 20000) {
          this.renderSource(res.data);
        } else {
          dsf.layer.message(JSON.stringify(res));
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }

  // 相关资源DOM
  renderSource(list) {
    let data = list.pdxglist;
    if (data && data.length > 0) {
      let sourceStr = "";
      for (let i = 0; i < data.length; i++) {
        sourceStr +=
          '<li id="' +
          data[i].nc_zyb_id +
          '">\n' +
          '           <span class="item_tag">' +
          data[i].type_text +
          "</span>\n" +
          '           <img src="' +
          (data[i].cover
            ? dsf.url.getWebPath(JSON.parse(data[i].cover)[0].relativePath)
            : "/dsfa/res/dsf_styles/themes/nc/404.png") +
          '" onerror="this.src=' +
          "/dsfa/res/dsf_styles/themes/nc/404.png" +
          ';this.onerror=null" alt="">\n' +
          '           <p class="item_title">' +
          data[i].title +
          "</p>\n" +
          "         </li>";
      }
      this._handlers["sourceList"].html(sourceStr);
      this.sourceBind(list);
    } else {
      let notDataStr =
        "<img style='width:200px;height:180px;margin:0 auto;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>";
      this._handlers["source_wrap"]
        .html(notDataStr)
        .css({ "text-align": "center", padding: "80px 0" });
    }
  }

  // 相关资源跳转
  sourceBind(list) {
    let data = list.pdxglist;
    $(".source_list>li").each(function(index) {
      let _id = $(this).attr("id");
      $(this).on("click", function(e) {
        if (list.sfsq == 1) {
          if (data[index].type_value == "00") {
            // window.open()
            // 跳转课程
            let courseUrl = dsf.url.getWebPath(
              "nc/pc/course/views/course.html?type=2&id=" + _id
            );
            window.open(courseUrl);
          } else if (data[index].type_value == "01") {
            // 频道
            let url = dsf.url.getWebPath("nc/mhsy/views/pdinfo.html?id=" + _id);
            window.open(url, "_self");
          } else if (data[index].type_value == "05") {
            // 专题班
            let ztbUrl = dsf.url.getWebPath(
              "nc/pc/stylecenterindex/views/stylecenterindex.html?id=" + _id
            );
            window.open(ztbUrl);
          } else {
            return;
          }
        } else {
          dsf.layer.message("该频道暂未授权");
          return;
        }
      });
    });
  }
}
