  exam() {
    let _this = this;
    console.log(this.curksid);
    let urlone = dsf.url.getWebPath("exam/api/ksgl/kssz/append");
    let id = $(this)
      .parents(".hrightbox")
      .attr("id"); //专题班id
    let ksid = $(this)
      .parents(".hrightbox")
      .attr("ksid"); //考试id
    let userid = dsf.getCookie("userId"); //用户id
    let user_name = dsf.getCookie("user_name"); //用户名称
    let arr = [];
    arr.push({ exam_user_id: userid, exam_user_name: user_name });
    let param = {};
    param["examId"] = _this.curksid;
    param["examinees"] = JSON.stringify(arr);
    console.log(param);
    dsf.http
      .request_sync(urlone, param, "post")
      .done(function(data) {
        if (data.success) {
          let urltwo = dsf.url.getWebPath("exam/api/sjgl/url");
          let parmstwo = {
            examId: _this.curksid,
            userId: userid,
            deviceType: "pc",
            businessId: _this.parms.ztbid,
            entryType: 2,
          };
          let url = dsf.url.getWebPath("exam/api/sjgl/url");
          dsf.http
            .request_sync(url, parmstwo, "get")
            .done(function(data) {
              if (data.success) {
                if (data.data == null || data.data == undefined) {
                  layui.use("layer", function() {
                    layer.msg("暂无跳转链接", { icon: 0, time: 2000 });
                  });
                } else {
                  dsf.openUrl(1, dsf.url.getWebPath(data.data));
                }
              } else {
                layui.use("layer", function() {
                  layer.msg(data.message, { icon: 0, time: 2000 });
                });
              }
            })
            .error(function(err) {
              console.log(err);
            })
            .always(function() {})
            .exec();
        }
      })
      .error(function(err) {
        console.log(err);
      })
      .always(function() {})
      .exec();
  }
