import dome from '../templates/NcIndexBanner.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("首页banner", 'nc.teas.ncindexbanner', 'NcIndexBanner')

export class NcIndexBanner extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.sourceUrl = '';
      this.stylePos = 'center';
      this.bannerUrl = [
         '/themes/nc/banner/img1.jpeg',
         '/themes/nc/banner/img2.jpg',
      ];
      this.$ratio = 2.051;
      this.$imgHeight = 0;
      this.$defaultImgUrl = "/dsfa/res/dsf_styles/themes/nc/404.png";
   }

   set ratio(v) {
      this.$ratio = v;
      if (this.element) {
         this.renderContext();
      }

   }
   get ratio() {
      return this.$ratio;
   }


   set imgHeight(val) {
      this.$imgHeight = val;
   }
   get imgHeight() {
      return this.$imgHeight;
   }


   initTemplate() {
      return dome(this);
   }



   renderContext() {
      super.renderContext();
      if (this._root._isDesign) {
         this.renderdefaultPage(this.bannerUrl);
      } else {
         this.getBanner();
      }
   };
   set bannerSourceUrl(val) {
      this.sourceUrl = val;
   }
   get bannerSourceUrl() {
      return this.sourceUrl;
   }

   changePos() {
      if (this.stylePos == 'left') {
         $('.layui-carousel-ind').css('text-align', 'left');
      } else if (this.stylePos == 'right') {
         $('.layui-carousel-ind').css('text-align', 'right');
      } else {
         $('.layui-carousel-ind').css('text-align', 'center');
      }
   }

   getBanner() {
      let loading = dsf.layer.loadding();
      if (!this.sourceUrl) this.sourceUrl = 'nc/lbt/sellByCount';
      let sourceurl = dsf.url.getWebPath(this.sourceUrl);
      let params = {
         count: 4
      };
      dsf.http.request(sourceurl, params, 'Get')
         .done((res) => {
            if (res.success && res.state == 20000) {
               this.renderPage(res.data);
            } else {
               dsf.layer.message(JSON.stringify(res));
            }
         })
         .error((err) => {
            dsf.layer.message('接口异常,请稍后重试', false);
         })
         .always(() => {
            dsf.layer.close(loading)
         }).exec();
   }

   renderReady() {
      super.renderReady();
   }

   // 渲染banner轮播
   renderPage(data) {
      let _this = this;
      let imgH = 0;
      let size = _this.getImageSize();
      if (this.$imgHeight && this.$imgHeight > 0) {
         imgH = this.$imgHeight;
      } else {
         imgH = size.height;
      }
      let bannerStr = '';
      for (let i = 0; i < data.length; i++) {
         let item = data[i];
         let imgStr = `<img style='height:${imgH}px' src="${!!item['pcphoto'] ? dsf.url.getWebPath(item.pcphoto.relativePath) : _this.$defaultImgUrl}" onerror='onerror=null;src="${_this.$defaultImgUrl}"' alt=''/>`
         bannerStr += '<li idx="' + i + '" >' + imgStr + '</li>'
      }

      this._handlers['bannerList'].html(bannerStr);
      layui.use('carousel', function () {
         var carousel = layui.carousel;
         //建造实例
         carousel.render({
            elem: '#banner',
            width: '100%',
            arrow: 'hover',
            height: imgH + 'px',
            indicator: 'inside',
            interval: 3500,
         });
         carousel.on('change(bannerClick)', function (res) {
            _this.event.trigger(ncModelEvent.bannerClick, { ui: _this, data: res });
         });
      });
      this._handlers['bannerList'].on('click', 'li', function (evt) {
         let ix = $(this).attr('idx');
         let _id = data[ix].nc_yygl_lbt_id
         //         10 不可以跳页面
         let userId = dsf.getCookie('userId');
         if (!userId) {
            window.parent.openLogin();
            return;
         } else {
            //登录后
            if (data[ix].ljlx_value != '10' && data[ix].lsdz != null && data[ix].lsdz != undefined && data[ix].lsdz != 0) {
               window.open(data[ix].lsdz);
            }
         }
      })
   }

   renderdefaultPage(data) {
      let banner = '';
      for (let i = 0; i < data.length; i++) {
         let item = data[i];
         banner += '<li><img src="' + dsf.url.getWebPath("res/dsf_styles/" + item) + '" alt=""></li>'
      }
      this._handlers['bannerList'].html(banner);
      let _this = this;
      layui.use('carousel', function () {
         var carousel = layui.carousel;
         //建造实例
         let size = _this.getImageSize();
         carousel.render({
            elem: '#banner',
            width: '100%',
            arrow: 'always',
            height: size.height + 'px',
            indicator: 'inside',
            interval: 3500,
         });
      });
   }

   getImageSize() {
      let w = this.element.width();
      let h = w / this.ratio;
      return {
         width: w,
         height: h
      }
   }
}