import dome from '../templates/Ncsdhdemo.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';
 
@map("组件测试", 'nc.teas.sdhdemo', 'Ncsdhdemo')
export class Ncsdhdemo extends dsf.Controls.Control {
	constructor(id, isPart) {
		super(id, isPart);
		this._desingerClass = ControlEditor;
		this.$useVdom = true;
		
		this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
		this.$name = '标题';
		this.$title="师资列表~";
		this.$id="666";
		this.$arr = [];
		this.$ratio = 2.051;
	}
	initTemplate() {
		return dome(this);
	}
	updated() {
      let _this = this;
    }
	
	
 	inserted(){
 	  if (this._root._isDesign) {
      } else {
         this.showlist();
      }
 	}
   	updated() {
      let _this = this;
    }
 	fun(){
 		let _this = this;
 		_this.inp = _this._handlers['inp'];
 		this.$title = _this.inp.val()
		this.domUpdate();
 	}
 	
	set name(v) {
		console.log(111);
      this.$name = v;
      this.domUpdate();
   }
// get name() {
// 		console.log(222);
//    return this.$name;
// }
 	
 	
 	//获取图片地址
    getImageSrc(cover){
      let _this = this;
      if(cover){
          return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath)
      }else{
          return _this.$defaultImgUrl;
      }
    }
	showlist(){
	  	let _this = this;
		var loadshow = dsf.layer.loadding();
	    let url = dsf.url.getWebPath("nc/yygl/yqlj/sellAllYqlj")
	    dsf.http.request(url,null,"get")
	   .done(function (res) {
	   	  console.log(res);
	      _this.$arr = res.data.list;
	      console.log(_this.$arr);
	      _this.domUpdate();
	   })
	   .error(function (err) {
	      console.log(err);
	      dsf.layer.message(err.message, false)
	   })
	   .always(function () {
	      dsf.layer.close(loadshow);
	   }).exec();
    }
	//跳转页面
	gotopage(d){
		dsf.openUrl(1,d)
	}
    funin(d){
    	console.log('移入'+d);
    }
    funout(d){
    	console.log('移出'+d);
    }
}
