import dome from '../templates/NcZtbList.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("专题班列表", 'nc.teas.ztblist', 'NcZtbList')

export class NcZtbList extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.pageSize = 3;  // 一页显示的数目
        this.curr = 1;
        this.title = '';
        this.count = '';
        this.showPagenation = true;
        this.ztbList = [
            {
                img: '/themes/nc/404.png',
                value: '2019',
                title: '深入学习贯彻习近平新时代中国特色社会主义思想',
                trainDate: '2019-05-29',
                endTrainDate: '2019-07-02',
                applyDate: '2019-04-28',
                endApplyDate: '2019-05-14',
                compulsory: {num: '47',time: '20'},
                elective: {num: '50',time: '58.5'},
                organizer: '中国干部网络学院',
                organizer_Undertake: '浦东分院',
                studentNum: '258912',
                isCompu: 1,
                isOnline: 0,
                isLearn: 0,
                isApply: 1,
                tags: ['中央精神','中央精神']
            },
        ];
    }

    initTemplate() {
        return dome(this);
    }
    set pageNum(val) {
        this.pageSize = val;
    }
    get pageNum() {
        return this.pageSize;
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            this.renderdefaultPage(this.ztbList);
        } else {
            this.getListData();
        }
    };

    getListData() {
        let loading = dsf.layer.loadding();
        let url = 'yyzx/pdgl/findZTBList';
        let sourceUrl = dsf.url.getWebPath(url);
        let params = {
            type_value: '05',
            title: this.title,
            pageNo: this.curr,
            pageSize: this.pageSize,
        };
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    if (res.data.records) {
                        this.ztbList = res.data.records;
                        this.renderPage(this.ztbList);
                        this.getDetail(this.ztbList);
                    }
                    if (res.data.count) {
                        this.count = res.data.count;
                    }
                    this.renderPagination();
                } else {
                    dsf.layer.message(JSON.stringify(res));
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    //  渲染分页
    renderPagination() {
		console.log('渲染分页');
		let _this = this;
		layui.use(['laypage', 'layer'], function(){
			let laypage = layui.laypage,layer = layui.layer;
			//执行一个laypage实例
			laypage.render({
			    "elem": 'ztb_pagenation',
			    "count": _this.count,
			    "limit": _this.pageSize,
			    "curr": _this.curr,
				"prev": "<i class='iconfont icon-left'></i>",
	            "next": "<i class='iconfont icon-right'></i>",
	            "layout": ['prev','page','next', 'count'],
			    "jump": (obj, first) => {
			        if(!first){
			            _this.curr = obj.curr;
			            _this.getListData();
			        }
			    }
			});
			
		})
    }

    // 列表DOM
    renderPage(data) {
        let listStr = '';
        if (data.length>0) {
        	$('.pagination.pages').show();
            for (let i = 0;i < data.length;i++) {
                let tag = '';
                let item = data[i];
                if (item.label_text&&item.label_text.length>0) {
                    let tag = '';
		            let item = data[i];
		            if(item.tags!=undefined && item.tags!=null){
		            	for (let labels of item.tags) {
		                	tag += '<span>'+ labels +'</span>'
		            	}
		            }
                }
                listStr += '<li class="list_item">\n' +
                    '            <img class="course_poster" src="'+ (item.cover? dsf.url.getWebPath((JSON.parse(item['cover'])[0]['relativePath'])) :'/dsfa/res/dsf_styles/themes/nc/404.png') +'" onerror=\'onerror=null;src="' + dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") + '"\' />\n' +
                    '            <ul class="course_info">\n' +
                    '                <li class="course_type">\n' +
                    '                    <span class="'+ (item.sfbx==1?'type_bx':'') +'">必修</span><span>线下</span><span>线上</span>\n' +
                    '                </li>\n' +
                    '                <li>\n' +
                    '                    <h5 class="course_title">'+ item.title +'</h5>\n' +
                    '                </li>\n' +
                    '                <li class="fix_date">\n' +
                    '                    <p class="fix_width">培训日期：'+ item.pxrq_sdate +' 至 '+ item.pxrq_edate +'</p>\n' +
                    '                    <p class="'+ (item.ztblx_value != 2?'apply_date':'') +'">报名日期：'+ item.bmrq_sdate +' 至 '+ item.bmrq_edate +'</p>\n' +
                    '                </li>\n' +
                    '                <li class="fix_margin">\n' +
                    '                    <p class="fix_width">必&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;修：'+ item.bxcount +'门&nbsp;&nbsp;&nbsp;&nbsp;   '+ item.bxxs +'学时</p>\n' +
                    '                    <p>选&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;修：'+ item.xxcount +'门&nbsp;&nbsp;&nbsp;&nbsp;   '+ item.xxxs +'学时</p>\n' +
                    '                </li>\n' +
                    '                <li class="fix_margin">\n' +
                    '                    <p class="fix_width">主办单位：'+ (item.zbdw?item.zbdw:'暂无') +'</p>\n' +
                    '                    <p>承办单位：'+ (item.cjdw?item.cjdw:'暂无') +'</p>\n' +
                    '                </li>\n' +
                    '                <li class="fix_margin">\n' +
                    '                    <p>学员人数：<span class="textstyle">'+ (item.studentNum?item.studentNum:'0') +'<span> <img class="hot_icon" src="/dsfa/res/dsf_styles/themes/nc/ztb/huo.png" alt=""></p>\n' +
                    '                </li>\n' +
                    '                <li class="course_tag">\n' +
                    '                    '+ tag +'\n' +
                    '                    <div class="operate" id="'+ item.nc_zyb_id +'">\n' +
                    '                        <button class="'+ (item.STATE == 0?'apply':'') +'">报名</button>\n' +
                    '                        <button class="'+ (item.STATE == 1?'hadApply':'') +'">开始学习</button>\n' +
                    '                        <button class="'+ (item.STATE == 2?'learn':'') +'">继续学习</button>\n' +
                    '                        <button class="'+ (item.STATE == 3?'hadPassed':'') +'">已结业</button>\n' +
                    '                        <button class="'+ (item.STATE == 4?'hadClosed':'') +'">封闭式</button>\n' +
                    '                    </div>\n' +
                    '                </li>\n' +
                    '            </ul>\n' +
                    '        </li>'
            }
            this._handlers['ztbList'].html(listStr);
            this.bindApply(data);
            this.bindDetail(data);
        } else if(data.length == 0) {
//          let noStr = "<img style='position: absolute;width:200px;height:180px;top:50%;left: 50%;margin:-90px 0 0 -100px;' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>";
//          this._handlers['ztbWrap'].html(noStr).css({'text-align': 'center','height':'100%'});
			this._handlers['ztbList'].html("<div style='text-align: center; margin: 20px;'><img src='/dsfa/res/dsf_styles/themes/img/nodata.png'></div>");
            $('.pagination.pages').hide();
        }
    }
    // 默认列表DOM
    renderdefaultPage(data) {
        let list = '';
        for (let i = 0;i < data.length;i++) {
            let tag = '';
            let item = data[i];
            if(item.tags!=undefined && item.tags!=null){
            	for (let labels of item.tags) {
                	tag += '<span>'+ labels +'</span>'
            	}
            }
//          list += '<li class="list_item">\n' +
//              '            <img class="course_poster" src="/dsfa/res/dsf_styles/themes/nc/404.png">\n' +
//              '            <ul class="course_info">\n' +
//              '                <li class="course_type">\n' +
//              '                    <span class="'+(item.isCompu?'type_bx':'')+'">必修</span><span class="'+(item.isOnline?'':'type_xs')+'">线下</span><span class="'+(item.isOnline?'type_xx':'')+'">线上</span>\n' +
//              '                </li>\n' +
//              '                <li>\n' +
//              '                    <h5 class="course_title">'+item.title+'</h5>\n' +
//              '                </li>\n' +
//              '                <li class="fix_date">\n' +
//              '                    <p class="fix_width">培训日期：'+ item.trainDate +' 至 '+ item.endTrainDate +'</p>\n' +
//              '                    <p>报名日期：'+ item.applyDate +' 至 '+ item.endApplyDate +'</p>\n' +
//              '                </li>\n' +
//              '                <li class="fix_margin">\n' +
//              '                    <p class="fix_width">必&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;修：'+ item.compulsory.num +'门   '+ item.compulsory.time +'学时</p>\n' +
//              '                    <p>选&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;修：'+ item.elective.num +'门   '+ item.elective.time +'学时</p>\n' +
//              '                </li>\n' +
//              '                <li class="fix_margin">\n' +
//              '                    <p class="fix_width">主办单位：'+ item.organizer +'</p>\n' +
//              '                    <p>承办单位：'+ item.organizer_Undertake +'</p>\n' +
//              '                </li>\n' +
//              '                <li class="fix_margin">\n' +
//              '                    <p>学员人数：<span class="textstyle">'+ item.studentNum +'</span> <img class="hot_icon" src="/dsfa/res/dsf_styles/themes/nc/ztb/huo.png" alt=""></p>\n' +
//              '                </li>\n' +
//              '                <li class="course_tag">\n' +
//              '                    '+ tag +'\n' +
//              '                    <div class="operate">\n' +
//              '                        <button class="'+(item.isLearn?'learn':'')+'">学习</button>\n' +
//              '                        <button class="'+(item.isApply?'apply':'')+'">报名</button>\n' +
//              '                    </div>\n' +
//              '                </li>\n' +
//              '            </ul>\n' +
//              '        </li>';
        }

        this._handlers['ztbList'].html(list);
    }

    isShowPage() {
        if (this.showPagenation) {
            $('.pagination.pages').css('display','block')
        } else {
            $('.pagination.pages').css('display','none')
        }
    }

    renderReady() {
        super.renderReady();
        var _this = this;
        _this.newsserch();
    }

    // 跳转专题班详情
    bindDetail(data) {
        $('.course_title').each(function(index){
            var _this = $(this);
            _this.on('click',function(e){
                let jumpUrl = dsf.url.getWebPath('nc/pc/stylecenterindex/views/stylecenterindex.html?id='+data[index].nc_zyb_id);
                window.open(jumpUrl);
            })
        });
    }
    getDetail(data) {
        $('.course_poster').each(function(index){
            var _this = $(this);
            _this.on('click',function(e){
                // console.log(data[index]);
                let jumpUrl = dsf.url.getWebPath('nc/pc/stylecenterindex/views/stylecenterindex.html?id='+data[index].nc_zyb_id);
                // nc_zyb_id：专题班id
                window.open(jumpUrl);
            })
        });
    }

    // 点击事件
    bindApply(data) {
        var _this = this;
        $('.operate').find('button').each(function(index){
            $(this).on('click',function(e){
                // 报名
                let Id = $(this).parents('.operate').attr('id');
                if (e.target.className=='apply') {
                    let url = 'ztb/xymd/addXymdBm';
                    let loading = dsf.layer.loadding();
                    let  params = {
                        "nc_zyb_id": Id
                    };
                    let sourceUrl = dsf.url.getWebPath(url);
                    dsf.http.request(sourceUrl,params,'POST')
                        .done((res) => {
                            if (res.success&&res.state == 20000) {
                                data[index].STATE = '1';
                                dsf.layer.message('报名成功');
                                _this.renderPage(data);
                            } else {
                                dsf.layer.message('报名失败',res.message);
                            }
                        })
                        .error((err) => {
                            dsf.layer.message('服务器异常，请稍后再试！');
                        })
                        .always(() => {
                            dsf.layer.close(loading)
                        }).exec();
                } else if(e.target.className=='hadApply' || e.target.className=='learn') {
                    let courseUrl = dsf.url.getWebPath('nc/pc/course/views/course.html?type=1&id='+Id);
                    window.open(courseUrl);
                } else {
                    return
                }
            })
        });
    }
    newsserch(){
  	
	  	let _this=this;
	  	_this.$newslistbox = _this._handlers['newsserch'];
	  	_this.$newsinp = _this._handlers['newsinp'];
	  	_this.$newslistbox.click(function(){
	  		_this.title = _this.$newsinp.val();
	  		_this.curr = 1;
	  		_this.getListData();
	  	})
	  	
	  	_this.$rightbox = _this._handlers['rightbox'];
	  	_this.$rightbox.keyup(function(){
	  		if(event.keyCode ==13){
		  		_this.title = _this.$newsinp.val();
		  		_this.curr = 1;
		  		_this.getListData();
			}
	  	})
	  }
}
