import dom from '../templates/PdList.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";
import {map} from '../../../decorator/controlmap';

@map("频道列表",'nc.teas.pdlist','PdList')
export class PdList extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.defualtImgUrl = '/res/dsf_styles/themes/img/500.png';
        this.$config={
            dir: {
                "video":{ "btnName": "加入学习",'typeicon':'/dsfa/res/dsf_styles/themes/nc/kc_icon.png' },
                "test":{ "btnName": "考试", 'typeicon':'/dsfa/res/dsf_styles/themes/nc/ks_icon.png'},
                "writing":{  "btnName":"撰写", 'typeicon':'/dsfa/res/dsf_styles/themes/nc/zy_icon.png' }, 
                "question":{ "btnName": "作答", 'typeicon':'/dsfa/res/dsf_styles/themes/nc/wj_icon.png' }
            }
        }
        this.$requestUrl="";
        this.$pagesize="4"
        this.pageConfig={
            pagesize:this.pagesize,
            pagecount:100,
            currpage:1
        }
    }

    set requestUrl(val) {
        this.$requestUrl = val
    }
    get requestUrl() {
        return this.$requestUrl
    }

    set pagesize(val){
        this.$pagesize = val
    }
    get pagesize(){
        return parseInt(this.$pagesize)
    }

    initTemplate() {
        return dom(this);
    }

    createElement() {
        super.createElement();
        this.pdListWrap = this._handlers.pdList
    }

    initEvent() {
       
    }

    renderReady() {
        super.renderReady();
    }

    renderContext() {
        super.renderContext();
        this.pagesize=4;
        renderPagination.call(this)
        if (!this._root._isDesign) {
            this.loadData()
        }else{
            this.requestUrl = dsf.url.getWebPath("teas/tempdata/pd_list.json")
            let args={}
            this.loadData(args)
        }
    }
    
    renderComplete() {
        super.renderComplete();
    }
    loadData(args){
        let _this = this,str="",param={};
        let defualtParam={
            pagesize: _this.pageConfig.pagesize,
            pagestart:_this.pageConfig.currpage,
        }
        param = $.extend({},args,defualtParam)
        dataRequst.call(this,this.requestUrl,param,"GET",function(args){
            _(args.data).forEach(val => {
                str += createHtml.call(_this,val)
            });
            _this.pdListWrap.html(str);
            bindbtnfn.call(this)
        })
    }

    
}
// 创建列表dom字符串
function createHtml(item){
    let str ="";
    str =
        ' <li class="list_item_wrap">'+
                '<div class="list_item">'+
                ' <div class="item_right">'+
                    ' <img src='+item.imgUrl+' alt="" >'+
                    '</div>'+
                    '<div class="item_left">'+
                        '<div class="item_left-top titleWidth">'+
                            '<div class="newStyle fl '+(!item.isNew && 'none')+'">New</div>'+
                            '<div class="titleName fl" >'+item.title+'</div>'+
                            '<img src='+this.$config.dir[item.type].typeicon+' alt="">'+
                        '</div>'+
                        '<div class="item_left-middle titleWidth">'+
                            '<span  class="'+(!item.author && 'none')+'">'+item.author+'-</span><span>'+item.position+'</span>'+
                    ' </div>'+
                    ' <div class="item_left-bottom">'+
                            '<div class="theme_info">'+
                                '<div class="studytime infoStyle fl '+(!item.studytime && 'none')+'">'+
                                    '<i class="icon studytime_icon"></i><span >'+item.studytime+'学时</span>'+
                                '</div>'+
                                '<div class="lll infoStyle fl">'+
                                    '<i class="icon lll_icon"></i><span>'+item.lll+'</span>'+
                                '</div>'+
                            '</div>'+
                            '<div class="btn fr" data-type='+item.type+'>'+this.$config.dir[item.type].btnName+'</div>'+
                        '</div>'+
                ' </div>'+
                '</div>'+
            '</li>'
    return str
}
// 数据请求封装方法
function dataRequst(url,args,queryway,callback){
    let loadding = dsf.layer.loadding();
    dsf.http.request(url, args, queryway,callback)
    .done(function (response) {
       console.log(response)
       if (response.success) {
          if(callback)callback(response)
       } else {
          dsf.layer.message("请求失败,请稍后再试", false)
       }
    })
    .error(function (err) {
        dsf.layer.message("请求失败,请稍后再试", false)
    })
    .always(function () {
       dsf.layer.close(loadding);
    }).exec();
}
// 渲染分页
function renderPagination() {
    let id = 'comment_page';
    var laypage = layui.laypage;
    let _this = this;
    //执行一个laypage实例
    laypage.render({
       "elem": id,
       "count": _this.pageConfig.pagecount,
       "limit": _this.pageConfig.pagesize,
       "curr":_this.pageConfig.currpage,
	   "prev": "<i class='iconfont icon-left'></i>",
       "next": "<i class='iconfont icon-right'></i>",
       "layout": ['prev','page','next', 'count'],
       "jump": (obj, first) => {
          if (!first) {
             //如果pageSize发生变化
             _this.pageConfig.pagesize = obj.limit;
             _this.pageConfig.currpage = obj.curr;
             _this.pageConfig.pagecount = obj.count;
             _this.loadData();
          }
       }
    });
 }
// 绑定按钮方法
function bindbtnfn(){
    $('.btn').on("click",function(evt){
        let targetType = evt.currentTarget.getAttribute('data-type');// 按钮type
        console.log(targetType)
        btnFn[targetType]()
    })
}
// 不同类型按钮处理方法
let btnFn ={
    video : function (){
        alert("加入学习")
    },
    test:function(){
        alert("考试")
    },
    writing:function(){
        alert("撰写")
    },
    question:function(){
        alert("作答")
    }
}
