import JxStudentSerEjs from "../../templates/JxStudentSer.ejs";
import { ControlEditor } from "../../../../editor/ControlEditor";
import { map } from "../../../../decorator/controlmap";

@map("学员服务", "nc.ncctrl.jxstudentser", "JxStudentSer")
export class JxStudentSer extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.moreUrl = ""; //更多URL
    this.headerName = "学员服务"; //头部名称
    this.fontColor = "";
    this.headerImg = "/res/dsf_styles/themes/nc/jx/header-left-bg.png";
    this.paddingLeft = true;
    this.paddingTop = true;
    this.showMore = false; //显示更多按钮
    this.listData = [
      {
        icon: "icon-yiwen",
        bgColor: "#E6A33F",
        name: "常见问题",
      },
      {
        icon: "icon-daibanshixiang",
        bgColor: "#69C13C",
        name: "学习要求",
      },
      {
        icon: "icon-chaxun",
        bgColor: "#FF8F00",
        name: "操作指南",
      },
      {
        icon: "icon-lianxidianhua",
        bgColor: "#F66B6F",
        name: "联系我们",
      },
    ];
    this.$columns = {
      eq: "",
      request: "",
      guild: "",
      askus: "",
    };
  }
  initTemplate() {
    return JxStudentSerEjs(this);
  }
  renderContext(refresh) {
    super.renderContext();
    this.root.event.on(PageEvent.READY, (args) => {
      this._handlers.headerName.html(this.headerName);
      this._handlers.moreUrl.css(
        this.showMore ? { display: "inline-block" } : { display: "none" }
      );
      this._handlers.headerImgChange.attr(
        "src",
        dsf.url.getWebPath(this.headerImg)
      );
      if (this.fontColor) {
        this._handlers.changeHeader.css({ color: this.fontColor });
      }
      this.isPaddingLeft();
      this.isPaddingTop();
    });
  }

  get columns() {
    return this.$columns;
  }
  set columns(val) {
    this.$columns = val;
  }
  initEvent() {
    this.element.on("click.headerMore", ".headerMore", () => {
      this.upUrl(this.moreUrl);
    });
    for (let i = 0; i < 4; i++) {
      this.element.on(`click.context-li-${i}`, `.context-li-${i}`, () => {
        if (i === 0 && this.$columns.eq != '') {
          this.upUrl(this.$columns.eq);
          // dsf.layer.openWindow(dsf.url.getAbsolutePath(this.$columns.eq));
        } else if (i === 1 && this.$columns.request != '') {
          this.upUrl(this.$columns.request);
          // dsf.layer.openWindow(dsf.url.getAbsolutePath(this.$columns.request));
        } else if (i === 2 && this.$columns.guild != '') {
          this.upUrl(this.$columns.guild);
          // dsf.layer.openWindow(dsf.url.getAbsolutePath(this.$columns.guild));
        } else if(i === 3 && this.$columns.askus != ''){
          this.upUrl(this.$columns.askus);
          // dsf.layer.openWindow(dsf.url.getAbsolutePath(this.$columns.askus));
        }
      });
    }
  }
  upUrl(url) {
    let userId = dsf.getCookie("userId");
    if (!userId) {
      window.parent.openLogin();
      return;
    }
    if (url.indexOf("http://") !== -1 || url.indexOf("https://") !== -1) {
      dsf.layer.openWindow(url);
    } else {
      dsf.layer.openWindow(dsf.url.getWebPath(url));
    }
  }
  //是否显示边距
  isPaddingLeft() {
    let dom = this._handlers["ds_jx_jxStudentSer"];
    !this.paddingLeft
      ? dom.removeClass("padding-left-right")
      : dom.addClass("padding-left-right");
  }
  isPaddingTop() {
    let dom = this._handlers["ds_jx_jxStudentSer"];
    !this.paddingTop
      ? dom.removeClass("padding-top-bottom")
      : dom.addClass("padding-top-bottom");
  }
}
