import dom from '../templates/NcHomeWork.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { UrlSetting } from "../../../core/pageAction";

import { map } from '../../../decorator/controlmap';
@map("作业批阅", 'nc.teas.homework', 'NcHomeWork')

export class NcHomeWork extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this._minute = '';

      this._idx = 0;
      this._isPre = true; //上一篇
      this._isLast = false;
      this._scale = 0;
      this._scaleCount = 0;

      this.id = null;
      this._data = [];
      this.total = null;//作业总数
      this.start = 1;//起始批阅数
      this.$sourceUrl = null;

      this.isOnlyOne = 0;
   }

   get sourceUrl() {
      return this.$sourceUrl;
   }
   set sourceUrl(val) {
      this.$sourceUrl = val;
   }

   initTemplate() {
      return dom(this);
   }

   initEvent() {
   }

   createElement() {
      super.createElement();
      this.$iframe = this._handlers['iframe'];
   }

   renderContext() {
      let that = this;
      if (!that._root._isDesign) {
         super.renderContext();
         layui.form.render("select");
         layui.form.render("checkbox");
         that.getHomeWork();
         that.$markingSituation = that._handlers['markingSituation'];
         that.$progress = that._handlers['progress'];
         that.$isRemind = that._handlers['isRemind'];
         that.$showHandle = that._handlers['showHandle'];
         that.$prePage = that._handlers['prePage'];
         that.$nextPage = that._handlers['nextPage'];

         that.$nextPage.on('click', function () {
            that.getHomeWork();
         })

         that.$showHandle.find('button').click(function () {
            let s = $(this).attr('data-t');
            let selectVal = that._handlers['achievement'].find('option:selected').val() || 1;
            let selectText = selectVal == 1 ? '优秀' : selectVal == 2 ? '良好' : selectVal == 3 ? '一般' : '较差'
            let cjType = that._data['cjlx_value'];
            if (s == '取消') window.close();
            let _id = that._data['nc_xxgl_zygl_xyzy_id'];
            if (!_id) return;
            let loadDing = dsf.layer.loadding();
            var recommend = that.getRecommend();
            let aUrl = dsf.url.getWebPath('zygl/handleRead');
            let tj = that._handlers['isCheckbox'].find('input:checked').val(),
               fs = that._handlers['achieveFs'].val(),//分数
               py = that._handlers['comments'].val(),//评语
               params = {
                  nc_xxgl_zygl_xyzy_id: _id,
                  state_text: s,
                  state_value: s == '退回' ? -1 : 2,
                  tj_text: recommend.rt.join('^'),
                  tj_value: recommend.r.join('^'),
                  cj: cjType == 0 ? selectText : fs,
                  py: py
               };
            console.log(params);
            dsf.http.request(aUrl, params, "POST")
               .done(function (res) {
                  if (res.success) {
                     if (that.isOnlyOne == 1) {
                        that.isHideConfirm();
                        return;
                     }
                     that.getHomeWork();
                  } else {
                     dsf.layer.message(res.message, false);
                  }
               })
               .error(function (err) {
                  dsf.layer.message(err.message);
               })
               .always(function () {
                  dsf.layer.close(loadDing);
               }).exec();
         })

         that._timer = setInterval(function () {
            ++that._minute;
            if (that._minute > 20 * 1000 * 60) {
               clearInterval(that._timer);
               that.$isRemind.fadeIn();
            }
         }, 1000);
      }
   }

   renderReady() {
      super.renderReady();
   }
   getRecommend() {
      let r = [],
         rt = [];
      this._handlers['isCheckbox'].find('input:checked').each(function () {
         r.push($(this).val());
         rt.push($(this).attr('title'));
      })
      return {
         r,
         rt
      }
   }
   getHomeWork() {
      let that = this;
      let loadDing = dsf.layer.loadding();
      let params = {
         nc_zyb_id: dsf.url.queryString('nc_zyb_id') || '',
         nc_xxgl_zygl_xyzy_id: dsf.url.queryString('nc_xxgl_zygl_xyzy_id') || ''
      };
      let dUrl = dsf.url.getWebPath('zygl/displayWork');
      dsf.http.request(dUrl, params, "GET")
         .done(function (res) {
            if (res.success) {
               if (res.data && res.data.readCount == res.data.inCorrection) {
                  that.isHideConfirm();
               }
               that._data = res.data.list;
               that.total = res.data.inCorrection;
               that.renderPage(res.data.list);
               that.renderProgress(res.data);
               that.isOnlyOne = res.data.lonelyRead;
               if(that.isOnlyOne == 1) that._handlers['nextPage'].hide();
            } else {
               dsf.layer.message(res.message, false);
            }
         })
         .error(function (err) {
            dsf.layer.message(err.message);
         })
         .always(function () {
            dsf.layer.close(loadDing);
         }).exec();
   }

   isHideConfirm() {
      let that = this;
      dsf.layer.confirm("没有待批阅的作业了,是否关闭当前页面?", () => {
         window.close();
      }, () => {
         console.log('取消')
         that._handlers['achievement'].attr('disabled', true);
         that._handlers['achieveFs'].attr('disabled', true);
         that._handlers['isCheckbox'].find('input').attr('disabled', true);
         that._handlers['comments'].attr('disabled', true);
         layui.form.render('select');
         layui.form.render('checkbox');
         that.$showHandle.hide();
         that.$nextPage.hide();
      })
   }

   preView(id) {
      if (!id) {
         this.$iframe.contents().find('body').html("<img style='transform: translateY(-50%);position: relative;top: 50%' src='/dsfa/res/dsf_styles/themes/img/nodata.png'>").css({ 'text-align': 'center' });
         return;
      }
   }

   renderPage(data) {
      //state_text: 未提交: 0 未批阅: 1 已批阅: 2 推优: 3 退回: -1
      let that = this;
      console.log(data)
      if (data) {
         if (data['state_value'] == 2) {
            that.$showHandle.hide();
         } else {
            that.$showHandle.show();
         }
         let conStr = "<h3 class='con-title' style='font-size:16px;text-align: center;padding: 20px 10px;'>" + data.title + "</h3><div class='con-desc' style='font-size:14px;;text-align: center;padding: 20px 10px;'>" + data.content + "</div>";
         that._handlers['content'].html(conStr);
         that.reSetDoc(data);
      }
   }

   reSetDoc(data) {
      let that = this,
         cj = data['cj_value'] || 1,
         fs = data['cj'] || '',
         comText = data['py'] || '',
         tj = data['tj_value'] || 0;
      //0下拉框 1输入框
      if (data['cjlx_value'] == '0') {
         that._handlers['achievement'].val(cj);
         layui.form.render('select');
         that._handlers['isInput'].hide();
         that._handlers['isSelect'].show();
      } else {
         that._handlers['achieveFs'].val(fs);
         that._handlers['isSelect'].hide();
         that._handlers['isInput'].show();
      }
      layui.form.render("checkbox");
      that._handlers['comments'].val(comText);
   }

   renderProgress(data) {
      if (data) {
         let r = !!data.readCount ? Number(data.readCount) : 0;
         let t = !!data.inCorrection ? Number(data.inCorrection) : 0;
         let pW = parseInt((r / t) * 100);
         if (pW == 0 || isNaN(pW)) {
            this.$progress.find('span').fadeOut();
         } else {
            this.$progress.find('span').fadeIn().html(pW + '%');
         }
         this.$progress.css('width', pW + '%');
         this.$markingSituation.html(r + '/' + t);
      }
   }
}