import dome from '../../templates/Nchnews.ejs';
import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from '../../../../editor/ControlEditor';

@map("华电最新要闻", 'nc.teas.nchnews', 'Nchnews')
export class Nchnews extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.$useVdom = true;

      this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
      this.title = "最新要闻";
      this.ismorebtn = true;
      this.morebtnsrc = '1.html';
      this.$newlist = [];
   }
   initTemplate() {
      return dome(this);
   }
   updated() {
      let _this = this;
   }


   inserted() {
      if (this._root._isDesign) {
      } else {
         this.showlist();
      }
   }
   updated() {
      let _this = this;
   }

   set gtitle(v) {
      this.title = v;
      this.domUpdate();
   }
   get gtitle() {
      return this.title;
   }

   set gismorebtn(v) {
      this.ismorebtn = v;
      this.domUpdate();
   }
   get gismorebtn() {
      return this.ismorebtn;
   }

   set gmorebtnsrc(v) {
      this.morebtnsrc = v;
      this.domUpdate();
   }
   get gmorebtnsrc() {
      return this.morebtnsrc;
   }

   gotopage() {
      var ur = dsf.url.getWebPath(this.morebtnsrc);
      let userId = dsf.getCookie('userId');
      if (!userId) {
         window.parent.openLogin();
         return;
      } else {
         location.href = ur
      }
   }

   //获取图片地址
   getImageSrc(cover) {
      let _this = this;
      if (cover) {
         return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath)
      } else {
         return _this.$defaultImgUrl;
      }
   }
   showlist() {
      var _this = this;
      var loadshow = dsf.layer.loadding();
      let url = dsf.url.getWebPath("nc/news/findNewsList")
      dsf.http.request(url, { pageNum: 1, pageSize: 5 }, "get")
         .done(function (d) {
            console.log(d);
            if (d.success && d.state == 20000) {
               _this.$newlist = d.data.common.info;
               _this.domUpdate();
            } else {
               dsf.layer.message(err.message, false)
            }
         })
         .error(function (err) {
            console.log(err);
            dsf.layer.message(err.message, false)
         })
         .always(function () {
            dsf.layer.close(loadshow);
         }).exec();
   }
   newsdetails(id) {
      var ur = dsf.url.getWebPath('nc/mhsy/views/xwxq.html?id=' + id);
      let userId = dsf.getCookie('userId');
      if (!userId) {
         window.parent.openLogin();
         return;
      } else {
         dsf.openUrl(1, ur);
      }
   }
}
