import dome from '../templates/NcFooter.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("页脚", 'nc.teas.ncfooter', 'NcFooter')

export class NcFooter extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
    }
    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            return
        } else {
            this.getLinks();
        }
    };

    getLinks() {
        // let loading = dsf.layer.loadding();
        let sourceurl = dsf.url.getWebPath('nc/yygl/yqlj/sellAllYqlj');
        dsf.http.request(sourceurl, {}, 'Get')
            .done((res) => {
                if (res.success && res.state == 20000) {
                    if (res.data.list&&res.data.list.length>0) {
                        this.renderLinks(res.data.list);
                    }
                } else {
                    dsf.layer.message(JSON.stringify(res));
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                // dsf.layer.close(loading)
            }).exec();
    }

    renderLinks(data) {
        let linksStr = '';
        for (let i = 0;i < data.length;i++) {
            linksStr += '<li>'+ data[i].name +'</li>';
        }
        this._handlers['links_nav'].html(linksStr);
        this.bindOpen(data);
    }

    bindOpen(data) {
        $('.links_list').find('li').each(function (index) {
            var _this = $(this);
            _this.on('click',function () {
                window.open('http://'+data[index].link);
            })
        })
    }

    renderReady() {
        super.renderReady();
    }

}
