function flexCss(el, parent, num, padding) {
  padding = padding || 0;
  if (padding > 0) {
    parent.css("padding-left", padding + "px");
  }
  const parentWid = parent.outerWidth() - 1 - 2 * padding;
  const elWid = el.outerWidth();
  if (elWid * num > parentWid) {
    console.log(`一行放不下${num}个元素`);
    return;
  }

  const space = Math.floor((parentWid - elWid * num) / (num - 1));
  const perSpace = (space / parentWid) * 100;
  el.css("margin-right", perSpace + "%");

  let target = 0, index = 1;
  while (target <= el.length) {
    target = index * num;
    el.eq(target - 1).css("margin-right", "auto");
    index++
  }
}

export function justifyCss(className, num, padding) {
  $(".floor .inner").each(function () {
    const node = $(this);
    const children = $(this).children(className);
    flexCss(children, node, num, padding);
  })
  window.addEventListener("resize", () => {
    $(".floor .inner").each(function () {
      const node = $(this);
      const children = $(this).children(className);
      flexCss(children, node, num, padding);
    })
  })
}

export function __setReqBabel(params, data) {
  let obj = {};
  _.forOwn(params, (value, key) => {
    obj[value] = data[key]
  })
  return obj;
}

export function __setResBabel(resultBabel, data) {
  if (_.isArray(data)) {
    const res = data.map(item => {
      let obj = {};
      _.forOwn(resultBabel, (value, key) => {
        if (_.isObject(value)) {
          item[value.__name].map(child => {
            let childObj = {};
            _.forOwn(resultBabel[key], (childVal, childKey) => {
              childObj[childKey] = child[childVal]
            })

            obj[key] ? obj[key].push(childObj) : obj[key] = [childObj];
          })
        } else {
          obj[key] = item[value]
        }
      })
      return obj
    })
    return res;
  }

  //data为对象时
  let obj = {};
  _.forOwn(resultBabel, (value, key) => {
    obj[key] = data[value]
  })
  return obj;
}

export function __setUrl(option) {
  const urlStr = _.isFunction(option.url) ? dsf.url.getWebPath(option.url()) : dsf.url.getWebPath(option.url);
  const params = _.isFunction(option.params) ? option.params() : option.params;
  const resultBabel = _.isFunction(option.resultBabel) ? option.resultBabel() : option.resultBabel;
  const staticResult = _.isFunction(option.staticResult) ? option.staticResult() : option.staticResult;
  const loading = option.loading || false;
  return {
    url: urlStr,
    params: params,
    resultBabel: resultBabel,
    staticResult: staticResult,
    loading: loading
  }
}

export function _ajaxFunc(callback, method, option, queryData) {
  let {staticResult, resultBabel} = option;
  if (staticResult) {
    const result = __setResBabel(resultBabel, staticResult);
    callback(result)
    return
  }

  let {url, params, loading} = option;
  queryData ? params = __setReqBabel(params, queryData) : params = {};

  let loadingIndex;
  loading && (loadingIndex = dsf.layer.loadding());

  if (method === "GET") {
    dsf.http.request(url, params, "GET")
      .done(res => {
        res.data = res.data || [];
        const result = __setResBabel(resultBabel, res.data);
        callback(result);
      })
      .always(() => {
        loading && dsf.layer.close(loadingIndex)
      })
      .exec()
  } else if (method === "POST") {
    let _content = option.contentType || "formData";
    let contentType;
    if (_content === "json") {
      contentType = "application/json; charset=utf-8";
      params = JSON.stringify(params);
    }
    dsf.http.request(url, params, "POST", contentType)
      .done(res => {
        if (!res.success) {
          dsf.layer.message(res.message, false);
          return
        }
        res.data = res.data || [];
        const result = __setResBabel(resultBabel, res.data);
        callback(result);
      })
      .error(err => {
        dsf.error(err);
        dsf.layer.message("请求异常, 发生未知错误", false);
      })
      .always(() => {
        loading && dsf.layer.close(loadingIndex)
      })
      .exec()
  }

}

export function interactRoomList(callback) {
  const self = this;
  layui.form.on("select(roomList)", (data) => {
    self.query.roomId = data.value;
    callback && callback()
  })
}

export function interactDormList(callback) {
  const self = this;
  layui.element.on("tab(dormList)", function () {
    self.query.dormId = $(this).data("id");
    callback && callback()
  })
}