import {relyFiles} from "../../../core/relyfiles";
import {
  justifyCss, _ajaxFunc, __setReqBabel, __setUrl, interactRoomList, interactDormList
} from './hostel_common'

const mainDom = require("../templates/hostel.ejs");

@relyFiles([
  'res/libs/jquery-ui/jquery-ui.min.css',
  'res/libs/jquery-ui/jquery-ui.min.js'
])

export class hostel extends dsf.Controls.Control {
  constructor() {
    super();
    this.age = 45;
    this.option = null; //配置
    this.query = {
      currentClassId: "", //当前班级Id
      className: "",
      roomId: "",
      dormId: "",
      reserveId: "",  //预留Id
    };
    this.isFirstTime = true;    //页面第一次加载时
    this.pormiseTimes = 3;    //首次加载页面时总共发起的ajax次数
    this.ptime = 0;   //首次加载页面时这是第几次ajax
    this.personList = null;   //左侧所有人员的数据
    this.couldSeatRoomId = [];    //所有可以入住的房间
  }

  //页面首次加载时判断所有异步是否完成
  pormiseJudge() {
    this.ptime += 1;
    if (this.ptime === this.pormiseTimes) {
      const winHit = $(window).height();
      const screenTop = $(".ds_hostel_floor").offset().top;
      let hit = Math.floor(winHit - screenTop) - 10;
      $(".ds_hostel_floor").height(hit);
      $(".ds_hostel").height(winHit - 1);
      this.queryAllRoom();
    }
  }

  //渲染房间下拉列表
  renderRoomList() {
    const self = this;
    const option = self.option.roomList;
    const myQuery = {
      id: this.query.currentClassId
    };
    const callback = result => {
      const {label} = option;
      $("#roomList label").text(label);
      self.query.roomId = result[0].id;   //房间默认选中第一个
      self.isFirstTime && self.pormiseJudge();

      const optionList = result.map(item => `<option value="${item.id}">${item.roomName}</option>`);
      $("#roomList select").html(optionList);
      layui.form.render("select", "query");

      interactRoomList.call(self, () => {
        self.queryAllRoom();
      })
    };
    _ajaxFunc(callback, "GET", option, myQuery);
  }

  //渲染宿舍列表
  renderDormitoryList() {
    const self = this;
    let option = self.option.dormitoryList;
    const callback = result => {
      self.query.dormId = result[0].id;   //宿舍默认选中第一个
      self.isFirstTime && self.pormiseJudge();

      const listEl = result.map(item => {
        return `<li data-id="${item.id}">${item.dormName}</li>`
      })
      $("#tab").html(listEl);
      $("#tab li:first-child").addClass("layui-this");
      interactDormList.call(self, () => {
        self.queryAllRoom();
      })
    };

    _ajaxFunc(callback, "GET", option);
  }

  //渲染所有的房间
  renderAllRoom(result) {
    const self = this;
    const state = {
      empty: "1",
      occupy: "2",
      unable: "0",
      repair: "-1",
      full: "3",
    }
    const getRoomCss = status => {
      let variable;
      switch (status) {
        case state.empty:
          variable = "normal seat";
          break;
        case state.occupy:
          variable = "seated";
          break;
        case state.unable:
          variable = "broken";
          break;
        case state.repair:
          variable = "broken";
          break;
        case state.full:
          variable = "full";
          break;
      }

      return "room " + variable
    }
    const renderPerson = person => `<div data-pid="${person.personId}" data-sex="${person.sexValue}">
                                      <i class="${person.sexValue==0? 'layui-icon layui-icon-male': 'layui-icon layui-icon-female'}"></i>
                                      <span>${person.personName}</span>
                                      <i name="delete" class="layui-icon layui-icon-delete"></i>
                                    </div>`;
    const renderRoom = (room, personList) => {
      return `<div class="${getRoomCss(room.statusValue)}" data-roomid="${room.roomId}" data-occupy="${room.occupyId}" data-status="${room.statusValue}">
                <div><p>${room.roomTypeText}</p><p>${room.roomNum}</p></div>
                <div style="${room.statusValue === state.occupy ? "display: none" : "display: block"}">${room.statusText}</div>
                <div class="person" style="${room.statusValue === state.occupy ? "display: block" : "display: none"}">${personList}</div>
                <div class="full-person" style="${room.statusValue === state.full ? "display: block" : "display: none"}">${personList}</div>
              </div>`
    };
    const renderFloor = (floor, roomList) => {
      return `<div class="floor">
                <div class="top">
                    <div>${floor.floorName}</div>
                    <div><span>${floor.roomTotal}</span>个房间（<span>${floor.occupyRoomNum}</span>间已用，<span>${floor.emptyRoomNum}</span>间未用，<span>${floor.unableRoomNum}</span>间不可用）</div>
                </div>
                <div class="inner">${roomList}</div>
            </div>`
    };

    const floorList = result.floors;

    for (let i = 0; i < floorList.length; i++) {
      let occupyRoomNum = 0;
      let emptyRoomNum = 0;
      let unableRoomNum = 0;
      let children = floorList[i].roomBoxes || [];
      for (let j = 0; j < children.length; j++) {
        if (children[j].statusValue === state.empty) emptyRoomNum += 1;
        if (children[j].statusValue === state.occupy) occupyRoomNum += 1;
        if (children[j].statusValue === state.unable) unableRoomNum += 1;
      }

      floorList[i].emptyRoomNum = emptyRoomNum;
      floorList[i].occupyRoomNum = occupyRoomNum;
      floorList[i].unableRoomNum = unableRoomNum;
      floorList[i].roomTotal = children.length;
    }

    const couldSeatRoomId = []; //能够入住的房间

    const floorListDOM = floorList.map(floor => {
      const roomList = floor.roomBoxes.map(room => {
        const personList = room.persons.map(person => {
          return renderPerson(person)
        })

        //如果房间可以入住
        if (room.statusValue !== state.unable && room.statusValue !== state.repair) {
          couldSeatRoomId.push(room.roomId);
          return renderRoom(room, personList)
        }
      });
      return renderFloor(floor, roomList)
    });

    self.couldSeatRoomId = couldSeatRoomId;

    if (floorList.length === 0) {
      const noMsg = `<div class="no-msg"><i class="layui-icon">&#xe650;</i>抱歉，没有可以分配的房间</div>`;
      $(".ds_hostel_floor").html(noMsg);
      return
    }
    $(".ds_hostel_floor").html(floorListDOM);
    justifyCss(".room", 5);
    self.interactRoomItemList()
  }

  renderPersonList() {
    const self = this;
    $("#searchInput").val("");  //清空人员框

    let {url, params} = self.option.personList;
    const query = {classId: self.query.currentClassId};
    const queryData = __setReqBabel(params, query);

    dsf.http.request(url, queryData, "GET")
      .done(res => {
        self.query.className = res.data.className;
        $("#classTitle").text(res.data.className);

        const personList = res.data.persons.map(item => {
          item.picture = dsf.url.getWebPath(item.picture);
          return item
        });
        self.personList = personList;   //将personList 赋值给this
        self.isFirstTime && self.pormiseJudge();
        const boyList = personList.filter(item => item.sexValue === "0");
        const girlList = personList.filter(item => item.sexValue === "1");
        $("#boyList").html(renderPersonList(boyList));
        $("#girlList").html(renderPersonList(girlList));

        const winHit = $(window).height();
        const top = $("#boyList").offset().top;
        const hit = winHit - top - 10;
        $("#boyList").height(hit);
        $("#girlList").height(hit);

        self.interactPersonList()
      }).exec()
  }

  interactPersonList() {
    $("._PersonList .person").draggable({
      cursor: "move",
      scroll: false,
      helper: function (event) {
        const name = $(this).text();
        return `<div class='move-ui'>${name}</div>`;
      },
      cursorAt: {
        left: 58,
        top: 18
      },
      start: function (event, ui) {

      },
      stop: function (event, ui) {

      },
      revert: "invalid"
    });
  }

  //添加各个房间的交互
  interactRoomItemList() {
    const self = this;
    const state = {
      empty: 1,
      occupy: 2,
      unable: 0,
      repair: -1,
      full: 3,
    }
    $(".ds_hostel_floor .room").droppable({
      addClasses: false,
      greedy: true,
      over: function (event, ui) {
        //console.log("移动");
        $(".ds_hostel_floor .room").removeClass("hover");
        $(event.target).addClass("hover");
      },
      out: function (event, ui) {
        //console.log("~移除");
        $(event.target).removeClass("hover");
      },
      drop: function (event, ui) {
        //console.log("放入")
        const dragNode = $(ui.draggable);
        const tdNode = $(event.target);
        const status = tdNode.data("status");
        if (status === state.full) {
          $("._PersonList .person").draggable("option", "revert", true);
          return false;
        }

        const _temp = {
          occupyId: tdNode.data("occupy"),
          roomId: tdNode.data("roomid")
        }
        const person = findPersonInfo.call(self, dragNode.parent("li").data("pid"));
        const queryData = _.assign(person, _temp)
        self.save(queryData);
      }
    });
    $(".ds_hostel_floor .room i[name='delete']").on("click", function () {
      const query = {
        personId: $(this).parent().data("pid"),
        occupyId: $(this).parents(".room").data("occupy")
      }
      self.clearOneSeat(query);
    })
  }

  clearOneSeat(queryData) {
    const self = this;
    const option = self.option.cancelOneSeated;
    const callback = result => {
      dsf.layer.message("退房成功", true);
      self.renderPersonList();
      self.queryAllRoom();
    }
    _ajaxFunc(callback, "POST", option, queryData);
  }

  queryAllRoom() {
    const self = this;
    let {url, params, loading} = self.option.querySeated;
    const _q = {
      classId: self.query.currentClassId,
      buildingId: self.query.dormId,
      reserveId: self.query.reserveId,
      roomType: self.query.roomId
    }
    const queryData = __setReqBabel(params, _q);
    let loadIndex;
    if (loading) loadIndex = dsf.layer.loadding();
    dsf.http.request(url, queryData, "GET").done(res => {
      if (!res.data || !res.data.floors) {
        const noMsg = `<div class="no-msg"><i class="layui-icon">&#xe650;</i> ${res.message}</div>`;
        $(".ds_hostel_floor").html(noMsg);
        return
      }

      const result = res.data;
      self.renderAllRoom(result);
      self.renderSelectTime(result.reserveDateDtos)
    }).always(() => {
      if (loading) dsf.layer.close(loadIndex)
    }).exec()
  }

  renderSelectTime(list) {
    const self = this;
    if (_.isArray(list) && list.length > 0) {
      const listDom = list.map(item => `<option value="${item.reserveId}"> ${item.sdate} ~ ${item.edate}</option>`);
      $("#timeList select").html(listDom);
      self.query.reserveId = list[0].reserveId; //timeSelect 默认选中第一个
    } else {
      $("#timeList select").html("");
      self.query.reserveId = null;
    }
    layui.form.render("select", "query");
    layui.form.on("select(timeRangList)", data => {
      self.query.reserveId = data.value;
      self.queryAllRoom();
    })
  }

  interactBtn() {
    const self = this;
    $("#autoBtn").on("click", function () {
      self.autoSave()
    });
    $("#clearBtn").on("click", function () {
      dsf.layer.confirm("此操作会清空当前时间段所有房间的入住信息，是否继续？", () => {
        self.clearAllSeated();
      })
    });
    layui.form.on("submit", () => false);
    $("#searchInput").on("change", function (event) {
      self.filterPersonListByInput($(this).val());
    })
  }

  filterPersonListByInput(keyword) {
    const self = this;
    const personList = self.personList.filter(person => person.personName.indexOf(keyword) !== -1);
    const boyList = personList.filter(item => item.sexValue === "0");
    const girlList = personList.filter(item => item.sexValue === "1");
    $("#boyList").html(renderPersonList(boyList));
    $("#girlList").html(renderPersonList(girlList));
    self.interactPersonList();
  }

  clearAllSeated() {
    const self = this;
    const option = self.option.clearAllSeatInfo;
    const query = {
      classId: self.query.currentClassId,
      reserveId: self.query.reserveId,
    }
    const callback = result => {
      dsf.layer.message("清除成功", true)
      self.queryAllRoom();
      self.renderPersonList();
    }

    _ajaxFunc(callback, "POST", option, query);
  }

  autoSave() {
    const self = this;
    const personIds = self.personList.map(item => item.personId);
    const option = self.option.autoSort;
    const query = {
      personIds: personIds,
      roomIds: self.couldSeatRoomId,
      reserveId: self.query.reserveId,
      classId: self.query.currentClassId
    }
    const callback = result => {
      dsf.layer.message("操作成功", true);
      self.renderPersonList();
      self.queryAllRoom();
    }
    _ajaxFunc(callback, "POST", option, query);
  }

  save(queryData) {
    const self = this;
    const {url, loading} = self.option.save;
    let loadIndex;
    loading && (loadIndex = dsf.layer.loadding());
    dsf.http.request(url, JSON.stringify(queryData), "POST", "application/json; charset=utf-8")
      .done(res => {
        if (!res.success) {
          dsf.layer.message(res.message, false);
          return
        }
        dsf.layer.message("入住成功", true);
        self.renderPersonList();
        self.queryAllRoom();
      })
      .error(err => {
        dsf.error(err);
        dsf.layer.message("入住失败，发生未知错误", false);
      })
      .always(() => {
        loading && (dsf.layer.close(loadIndex));
      })
      .exec()
  }


  mounted() {
    this.setOption();
    this.renderPersonList();
    this.renderDormitoryList();
    this.renderRoomList();
    //创建按钮的交互
    this.interactBtn();
  }

  //加工配置
  setOption() {
    const self = this;
    self.query.currentClassId = dsf.url.queryString(self.option.classId);
    _.forOwn(self.option, (value, key) => {
      if (!_.isObject(value)) {
        self[key] = value;
      } else {
        const qObj = __setUrl(value);
        _.assign(value, qObj)
      }
    })
  }

  render(el) {
    const html = mainDom(this);
    $(el).html(html);
    this.mounted()
  }

}

function findPersonInfo(id) {
  const self = this;
  return _.find(self.personList, item => item.personId === id)
}

function renderPersonList(arr) {
  if (arr.length === 0) return "<li style='width: 100px'>（空）</li>"
  return arr.map(item =>
    `<li data-pid="${item.personId}" data-name="${item.personName}">
        <div class="person">
          <i class="${item.sexValue==0? 'layui-icon layui-icon-male': 'layui-icon layui-icon-female'}"></i>
          ${item.personName}
        </div>
     </li>`
  )
}