import dome from "../../templates/HdSchoolyardImg.ejs";
import { map } from "../../../../decorator/controlmap";
import { ControlEditor } from "../../../../editor/ControlEditor";

@map("首页校园图景", "nc.teas.hdschoolyardimg", "HdSchoolyardImg")
export class HdSchoolyardImg extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$useVdom = true;

    this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.$firstImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/1.png';
    this.$secomdImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/2.png';
    this.$thirdImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/3.png';
    this.$fourthImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/4.png';
    this.$fifthImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/5.png';
    this.$sixthImgUrl = '/dsfa/res/dsf_styles/themes/img/nc/6.png';
    this.title = "校园图景";
    this.ismorebtn = true;
    this.morebtnsrc = '1.html';
    this.detailUrl = '1.html';

    this.$listData = [];
    //请求接口参数
    this.parms = {
      type_value: "05",
      pageNo: 1,
      pageSize: 6,
    };

  }

  set gtitle(v) {
    this.title = v;
    this.domUpdate();
  }
  get gtitle() {
    return this.title;
  }

  set gismorebtn(v) {
    this.ismorebtn = v;
    this.domUpdate();
  }

  get gismorebtn() {
    return this.ismorebtn;
  }

  set gmorebtnsrc(v) {
    this.morebtnsrc = v;
    this.domUpdate();
  }

  get gmorebtnsrc() {
    return this.morebtnsrc;
  }

  set gdetailUrl(v) {
    this.detailUrl = v;
    this.domUpdate();
  }

  get gdetailUrl() {
    return this.detailUrl;
  }

  set firstImgUrl(v) {
    this.$firstImgUrl = v;
    this.domUpdate();
  }
  get firstImgUrl() {
    return this.$firstImgUrl;
  }
  set secomdImgUrl(v) {
    this.$secomdImgUrl = v;
    this.domUpdate();
  }
  get secomdImgUrl() {
    return this.$secomdImgUrl;
  }
  set thirdImgUrl(v) {
    this.$thirdImgUrl = v;
    this.domUpdate();
  }
  get thirdImgUrl() {
    return this.$thirdImgUrl;
  }
  set fourthImgUrl(v) {
    this.$fourthImgUrl = v;
    this.domUpdate();
  }
  get fourthImgUrl() {
    return this.$fourthImgUrl;
  }
  set fifthImgUrl(v) {
    this.$fifthImgUrl = v;
    this.domUpdate();
  }
  get fifthImgUrl() {
    return this.$fifthImgUrl;
  }
  set sixthImgUrl(v) {
    this.$sixthImgUrl = v;
    this.domUpdate();
  }
  get sixthImgUrl() {
    return this.$sixthImgUrl;
  }

  gotopage(evt) {
    // var ur = dsf.url.getWebPath(this.morebtnsrc);
    // dsf.openUrl(1, ur)
    // let userId = dsf.getCookie('userId');
    // if (!userId) {
    //   window.parent.openLogin();
    //   evt.preventDefault();
    // } else {
    //   var ur = dsf.url.getWebPath(this.morebtnsrc);
    //   dsf.openUrl(1, ur)    
    // }
    dsf.layer.message('暂未开放', false)
    console.log('HdSchoolyardImg==>', '暂未开放')

  }

  gotoDetail() {
    // var ur = dsf.url.getWebPath(this.detailUrl);
    // dsf.openUrl(1, ur)
    dsf.layer.message('暂未开放', false)
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
    if (this._root._isDesign) {

    } else {
      // this.postData();
    }

  }
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
  }
  initEvent() { }

  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = dsf.url.getWebPath(cov[0].relativePath);
      }
    } else {
      urls = dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png");
    }
    return urls;
  }

  /**
   * 请求数据
   */
  postData() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('yyzx/pdgl/findZtbGDList');
    dsf.http.request(
      url, _this.parms, 'get'
    ).done(response => {
      if (response.state === 20000) {
        console.log('222===>', response.data)
        // 请求成功
        _this.$listData = response.data;
        _this.domUpdate();
      } else {
        dsf.layer.message(response.message, false)
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }
}
