import dome from '../templates/NcALinks.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';
 
@map("首页学堂友情链接", 'nc.teas.alinks', 'NcALinks')
export class NcALinks extends dsf.Controls.Control {
  constructor(id, isPart) {
      super(id, isPart);
      this._desingerClass = ControlEditor;
      this.$test = [];
      this.sdata = {
         titleicon: '/dsfa/res/dsf_styles/themes/styleClass/links.png', //标题图片
         titleText: '友情链接',
         titleTextcolor: '',
         isshowBar: false, //是否显示菜单
         issBarcoloract: '', //菜单选中色

         isshowChooseBtn: false, //是否显示操作按钮
         Btntext: "按钮名称", //操作按钮文本
         Btnurl: '', //操作按钮链接

         ismoreBtn: false, //是否显示更多按钮			
         moreBtnUrl: '', //更多按钮链接			
         moreBtnColor: '' //更多按钮颜色		
      }
   }

   initTemplate() {
      return dome(this);
   }

   createElement() {
      super.createElement();
   }
  
   renderContext(refresh) {
      
      if(this.sdata.titleicon==''){
			this._handlers.jstitleicon.parents('.titimgbox').hide()
		}else{
			this._handlers.jstitleicon.parents('.titimgbox').show()
			this._handlers.jstitleicon.attr('src', dsf.url.getWebPath(this.sdata.titleicon) );
		}
      this._handlers.jstitletext.text(this.sdata.titleText);
      this._handlers.jstitletext.css('color', this.sdata.titleTextcolor);
      this.isshowBarfun();
      this.getDialogData();
      this.isshowChooseBtnfun();
      this._handlers.jschoosebtn.html(this.sdata.Btntext);
      this.isshowMoreBtnfun();
      this._handlers.jsmorebtn.css('color', this.sdata.moreBtnColor);
      
      	super.renderContext();
		if (this._root._isDesign) {
      	} else {
      		this.showlist();
      	}
   }
   geturls(cover){
		let urls ='';
		if(cover){
			let cov = JSON.parse(cover);
			if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
		}else{
			urls="res/dsf_styles/themes/nc/404.png"
		}
		return urls;
  }
  showlist(){
	  	let _this = this;
  		var loadshow = dsf.layer.loadding();
	    let url = dsf.url.getWebPath("nc/yygl/yqlj/sellAllYqlj")
	    dsf.http.request(url,null,"get")
	   .done(function (res) {
	      console.log(res)
	      if(res.success){
	      	let sd=res.data.list,shtml='';
	      	if(sd.length == 0){
			  shtml='<div style="text-align: center; margin: 20px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"></div>';
			}else{
		      	for(var i=0,len=sd.length;i<len;i++){
		      		let urls = _this.geturls(sd[i].photo)
		      	    shtml+='<div class="item" link="'+sd[i].link+'">'
								+'<img src="'+dsf.url.getWebPath(urls)+'" onerror=\'onerror=null;src="' + dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png") + '"\' />'
							+'</div>';
		      	}
			}
		    _this._handlers.jslinksbox.html(shtml);
		    _this._handlers.jslinksbox.find('.item').click(function(){
		    	let linkUrl = $(this).attr('link');
		    	if(linkUrl == null && linkUrl == undefined){
		    		dsf.layer.message('暂无链接',0)
		    	}else{
		    		if(linkUrl.indexOf('http://')){
		    			linkUrl = 'http://'+linkUrl
		    		}
		    		window.open(linkUrl);
		    	}
		    })
	      }else{
	      	dsf.layer.message(res.message, false)
	      }
	   })
	   .error(function (err) {
	      console.log(err);
	      dsf.layer.message(err.message, false)
	   })
	   .always(function () {
	      dsf.layer.close(loadshow);
	   }).exec();
  }
   renderReady() { //组件加载完成后执行
      super.renderReady();
   }
   initEvent() { }
   
   
   //配置项----------------------------------------------------------
   //   是否显示菜单
   isshowBarfun() {
      let _this = this;
		_this.$jsbarbox = _this._handlers['jsbarbox'];
		if (this.sdata.isshowBar) {
//			兼容
			_this.$jsbarbox.removeClass("none");
            if(_this.sdata.issBarcoloract!=''){
            	_this._handlers.jsbarbox.find('li.act').css({
            		'color': _this.sdata.issBarcoloract,
            		'border-bottom-color': _this.sdata.issBarcoloract,
            	});//选中色
            }else{
            	_this._handlers.jsbarbox.find('li.act').css({
            		'color': _this.sdata.issBarcoloract? _this.sdata.issBarcoloract : '#FF6A00',
            		'border-bottom-color': !!_this.sdata.issBarcoloract? _this.sdata.issBarcoloract : '#FF6A00',
            	});//选中色
            }
		} else {
			_this.$jsbarbox.addClass("none");
		}
   }
   //是否显示操作按钮
   isshowChooseBtnfun() {
      let _this = this;
      _this.$jschoosebtn = _this._handlers['jschoosebtn'];
      if (this.sdata.isshowChooseBtn) {
         _this.$jschoosebtn.removeClass("none");
      } else {
         _this.$jschoosebtn.addClass("none");
      }
      _this.$jschoosebtn.click(function () {
         let ur = dsf.url.getWebPath(_this.sdata.Btnurl);
         dsf.openUrl(1, ur)
      })
   }
   //是否显示更多按钮
   isshowMoreBtnfun() {
      let _this = this;
      _this.$jsmorebtn = _this._handlers['jsmorebtn'];
      if (this.sdata.ismoreBtn) {
         _this.$jsmorebtn.removeClass("none");
      } else {
         _this.$jsmorebtn.addClass("none");
      }
      _this.$jsmorebtn.click(function () {
         let ur = dsf.url.getWebPath(_this.sdata.moreBtnUrl);
         dsf.openUrl(1, ur)
      })
   }
   getDialogData() {
   	  let _this = this;
   	  
      let data = this.$test
      console.log(data);
      console.log(data.length);
      if(data.length>0){
      	_this.sdata.isshowBar = true;
      	let shtml=''
      	for(var i=0,len=data.length;i<len;i++){
            if (i == 0) {
               _this.sdata.moreBtnUrl = data[i].name;
               shtml += '<li class="act" urls="' + data[i].name + '">' + data[i].code + '</li>'
            } else {
               shtml += '<li urls="' + data[i].name + '">' + data[i].code + '</li>'
            }
      	}
      	_this.$jsbarbox = _this._handlers['jsbarbox'];
	    _this.$jsbarbox.html(shtml);
	    _this.$jsbarbox.find('li').click(function () {
	        $(this).addClass('act').siblings().removeClass("act");
	        _this.sdata.moreBtnUrl = $(this).attr('urls');
	    })
      }else{
      	_this.sdata.isshowBar = false;
      }
      _this.isshowBarfun();
   }
   //配置项----------------------------------------------------------end
   
 
}
