import dome from '../templates/NcIndexNoviceSaid.ejs';
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from '../../../decorator/controlmap';

@map("首页学员说", 'nc.teas.ncindexnovicesaid', 'NcIndexNoviceSaid')

export class NcIndexNoviceSaid extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;
        this.mainTitle = '主标题';
	    this.subTitle = '副标题';
	    this.showSubTitle = true;
	    this.switchIcon = false;
	    this.fontCo = '#333';
	    this.iconnum = '1';
        
        this.pageSize = 2;
        this.curr = 1;
        this.xysList = [
            {
                title: '深入学习贯彻习近平新时代中国特色社会主义思想',
                Date: '2019-05-29',
                clickNum: '258912',
                content: '当前，我国经济总量已突破90万亿元，人均达到1万美元左右，经济已由高速增长阶段转向高质量发展阶段，处在投资阶段向创新阶段迈进的关口当前，我国经济总量已突破90万亿元，人均达到1万美元左右，经济已由高速增长阶段转向高质量发展阶段，处在投资阶段向创新阶段迈进的关口',
                person: '余庆'
            },
            {
                title: '深入学习贯彻习近平新时代中国特色社会主义思想',
                Date: '2019-05-29',
                clickNum: '258912',
                content: '当前，我国经济总量已突破90万亿元，人均达到1万美元左右，经济已由高速增长阶段转向高质量发展阶段，处在投资阶段向创新阶段迈进的关口当前，我国经济总量已突破90万亿元，人均达到1万美元左右，经济已由高速增长阶段转向高质量发展阶段，处在投资阶段向创新阶段迈进的关口',
                person: '王永远'
            },
        ];
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        super.renderContext();
        if (this._root._isDesign) {
            this.renderdefaultPage(this.xysList);
        } else {
            this.getListData();
        }
        this._handlers.setMainTitle.html(this.mainTitle);
	    this._handlers.setSubTitle.html(this.subTitle);
	    this.changeColor();
	    this.changeTitleIcon();
	    this.showSub();
	    this.changeTitle()
    };
    renderReady() {
        super.renderReady();
        this.nextPageClick();
        this.jumpToNovice();
    }

    //  右侧翻页点击
    nextPageClick() {
        let _this = this;
        $('.xus_loadMore').on('click',function () {
            // dsf.layer.message('点击了下一页');
            _this.curr = _this.curr+1;
            if (_this.curr == 4) _this.curr = 1;
            console.log(_this.curr);
            _this.getListData();
        })
    }

    //  获取数据
    getListData() {
        let loading = dsf.layer.loadding();
        let url = 'nc/xxgl/xys/findXys';
        let sourceUrl = dsf.url.getWebPath(url);
        let params = {
            pageNum: this.curr,
            pageSize: 2,
            words: ''
        };
        dsf.http.request(sourceUrl,params,'Get')
            .done((res) => {
                if (res.success&&res.state == 20000) {
                    if (res.data.info&&res.data.info.length>0) {
                        this.renderPage(res.data.info);
                    }
                } else {
                    dsf.layer.message(JSON.stringify(res));
                }
            })
            .error((err) => {
                dsf.layer.message('接口异常,请稍后重试', false);
            })
            .always(() => {
                dsf.layer.close(loading)
            }).exec();
    }

    // 渲染DOM
    renderPage(data) {
        let listStr = '';
        if (data&&data.length) {
            for (let i = 0;i < data.length;i++) {
                let item = data[i];
                listStr += '<li class="list_item">\n' +
                    '            <div class="item_title">\n' +
                    '                <div><img src="'+ (item.photo? dsf.url.getWebPath((JSON.parse(item['photo'])[0]['relativePath'])) :'/dsfa/res/dsf_styles/themes/nc/head_logo.png') +'" alt=""></div>\n' +
                    '                <span>' + (item.name?item.name:'') + '</span>\n' +
                    '                <span>'+ (item.ds_update_time?item.ds_update_time.slice(0,10):'') +'</span>\n' +
                    '            </div>\n' +
                    '            <h6>'+ (item.title?item.title:'') +'</h6>\n' +
                    '            <div class="item_content">\n' +
                    '                '+ (item.content?item.content:'暂无') +'\n' +
                    '            </div>\n' +
                    '            <div class="click_num">点击量：&nbsp;&nbsp;<span>'+ (item.llcs?item.llcs:'0') +'</span></div>\n' +
                    '        </li>'
            }
            this._handlers['index_xys'].html(listStr);
            this.jumpDetail(data);
        } else {
            return
        }
    }

    // 跳转学员说
    jumpToNovice() {
        $('.get_novice_said').on('click',function () {
            let userId = dsf.getCookie('userId');
            if (!userId) {
                window.parent.openLogin();
                return;
            } else {
                window.open(dsf.url.getWebPath('nc/mhsy/views/xys.html'));
            }
        });
    }
    // 跳转学员说详情
    jumpDetail(data) {
        $('.xus_list').find('li').each(function (index) {
            var _this = $(this);
            _this.on('click',function (e) {
                let userId = dsf.getCookie('userId');
                if (!userId) {
                    window.parent.openLogin();
                    return;
                } else {
                    let jumpUrl = dsf.url.getWebPath('nc/mhsy/views/xysxq.html?id='+data[index]._id);
                    window.open(jumpUrl);
                }
            })
        });
    }
    // 默认列表DOM
    renderdefaultPage(data) {
        let list = '';
        for (let i = 0;i < data.length;i++) {
            let item = data[i];
            list += '<li class="list_item">\n' +
                '            <div class="item_title">\n' +
                '                <div></div>\n' +
                '                <span>' + item.person + '</span>\n' +
                '                <span>'+ item.Date +'</span>\n' +
                '            </div>\n' +
                '            <h6>'+ item.title +'</h6>\n' +
                '            <p class="item_content">\n' +
                '                '+ item.content +'\n' +
                '            </p>\n' +
                '            <div class="click_num">点击量：&nbsp;&nbsp;<span>'+ item.clickNum +'</span></div>\n' +
                '        </li>'
        }

        this._handlers['index_xys'].html(list);
    }
	// 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
    changeTitle(){
		let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
	}
}


