  /**
   * 请求数据
   */
  postData() {
    let loading = dsf.layer.loadding();
    let _this = this;
    // let url = dsf.url.getWebPath('nc/kjk/frontuse/getKcHomePageSixList');
    let url = dsf.url.getWebPath('meta/list/data');

    dsf.http
      .request(url, _this.parms, 'get')
      .done(response => {
        // console.log('response', response);
        if (response.state === 20000) {
          // 请求成功
          this.postDataSuccess(response.data);
        } else {
          // 请求失败
          _this.$jscourselist = _this._handlers['jscourselist'];
          _this.$jscourselist.html(
            '<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>'
          );
        }
      })
      .error(response => {
        // 请求错误
        dsf.layer.message('请求异常', false);
      })
      .always(response => {
        dsf.layer.close(loading);
      })
      .exec();
  }

  //  跳转详情
  clickDetail(id) {
    let userId = dsf.getCookie('userId');
    if (userId) {
       let src = dsf.url.getWebPath(`/nc/news/views/nm_details.html?id=${id}&type=good_course`);
      let url = dsf.url.getWebPath(
        `nc/pc/menusDetail/views/menusDetail.html?deUrl=${dsf.Base64.encode(src)}`
      );
      // dsf.layer.openWindow(url);
      dsf.openUrl(1, url);
    }
  }

  /**
   * 请求成功处理
   * @param tabId
   * @param data [
   *    {CKL, CODE, COVER: '[
   *      {originalFileName, name, suffix, size, contentType, relativePath, absolutePath, uploadDate, id}
   *    ]', DZL, KCFS, KCSC, KCXS, LABEL_TEXT, NC_ZYB_ID, SFBX, SFJRZX, SFNEW, SFXX, SKJS: [
   *      {ROWNUM, JOB, JSMC},
   *      ......
   *    ], SKJSUNIT, TITLE, fbrq, _id}
   *    ......
   * ]
   */
  postDataSuccess(data) {
    console.log('data=>', data);
    let _this = this;
    let shtml = [],
      isaddHtml = '';
    this.$jscourselist = this._handlers.jscourselist;
    if (data.length > 0) {
      data.forEach(v => {
        let urls = _this.geturls(v['nc_news_matchCmDataSource.cover']);
        shtml.push(
          `<div class="aitem" id="${
            v['nc_news_matchCmDataSource.dsfa_cms_content_id']
          }" style="width:${_this.sdata.width + 'px'};height:${_this.sdata.height + 'px'}">
            <div class="aimgbox">
				      <img src="${dsf.url.getWebPath(urls)}" data-adaptive-background="1" data-description="grandpa"
				        onerror="onerror=null;this.src='${dsf.url.getWebPath(
                  'res/dsf_styles/themes/nc/404.png'
                )}'"/>
						 
						</div>
						<div class="item-foot">
							<div class="ctitle ell2">${
                v['nc_news_matchCmDataSource.cname'] ? v['nc_news_matchCmDataSource.cname'] : ''
              }</div>
							<div class="cteacher">
							  <i class="iconfont icon-touxiang"/><span class="ell">${
                  v['nc_news_matchCmDataSource.author'] ? v['nc_news_matchCmDataSource.author'] : ''
                }</span>
              </div>
					 
            </div>
            <div class="hbox">
              <p class="ell2">${
                v['nc_news_matchCmDataSource.cname'] ? v['nc_news_matchCmDataSource.cname'] : ''
              }</p>
   		<div class="btnbox">
          <span>
       ${v['nc_news_matchCmDataSource.abstract'] ? v['nc_news_matchCmDataSource.abstract'] : ''}
          </span>
				</div>
            </div>
          </div>`
        );
      });
    } else {
      shtml = [
        '<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>',
      ];
    }
    this.$jscourselist.html(shtml.join(''));
    const item = data;
    this.$jscourselist.on('click', '.aitem', item, function() {
      let listItem = item[$(this).index()];
      // console.log('listItem',$(this).index()  , listItem);
      _this.clickDetail(listItem['_id']);
    });
    //标签色
    /*     this.$jscourselist.find('.clabel span').css({
      color: this.plancoursedata.labelcolor,
      border: '1px solid ' + this.plancoursedata.labelcolor,
    }); */
    //移入背景图
    /*     this.$jscourselist.find('.hbox').css({
      background: 'url(' + dsf.url.getWebPath(this.plancoursedata.hoverbg) + ') no-repeat',
      'background-size': '100% 100%',
    }); */
    //移入背景色
    // this.$jscourselist.find('.btnbox span.act').css({
    //   background: this.plancoursedata.btncolor,
    // });
    // 马上学习
    let $aitem = this.$jscourselist.find('.aitem');
    $aitem.find('.jsstyle').click(function() {
      let id = $(this)
        .parents('.aitem')
        .attr('id');
      let userId = dsf.getCookie('userId');
      if (!userId) {
        window.parent.openLogin();
        return;
      }
      _this.checkUserAuth(id);
    });
    // 加入学习
    $aitem.find('.jsadd').click(function() {
      let id = $(this)
        .parents('.aitem')
        .attr('id');
      let userId = dsf.getCookie('userId');
      if (!userId) {
        window.parent.openLogin();
        return;
      }
      _this.addStyleClass(id);
    });
  }

  checkUserAuth(id) {
    //判断有无权限      到课程详情
    let _this = this;
    let checkUrl = dsf.url.getWebPath('nc/kjk/frontuse/kcZtbPriviledge');
    let params = {
      type: 2,
      relId: id,
    };
    dsf.http
      .request(checkUrl, params, 'GET')
      .done(function(res) {
        if (res.success) {
          let path = dsf.url.getWebPath(_this.$detailUrl + '?type=2&id=' + id);
          dsf.openUrl(1, path);
        } else {
          dsf.layer.message(res.message, false);
        }
      })
      .error(function(err) {
        dsf.layer.message('课程检查权限接口异常,请稍后重试', false);
      })
      .always(function() {})
      .exec();
  }
  addStyleClass(id) {
    //判断加入在学
    let _this = this;
    let checkUrl = dsf.url.getWebPath('zxgl/add');
    let params = {
      relid: id,
    };
    dsf.http
      .request(checkUrl, params, 'GET')
      .done(function(res) {
        console.log(res);
        if (res.success) {
          dsf.layer.message(res.message, 6);
          _this.postData();
        } else {
          dsf.layer.message(res.message, false);
        }
      })
      .error(function(err) {
        dsf.layer.message(err.message, false);
      })
      .always(function() {})
      .exec();
  }
