import dome from "../templates/NcLatestNews.ejs";
import { ControlEditor } from "../../../editor/ControlEditor";
import { map } from "../../../decorator/controlmap";

@map("最新新闻", "nc.teas.nclatestnews", "NcLatestNews")
export class NcLatestNews extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.fontColor = "#ea4d4d";
    this.newsList = [
      { name: "最新新闻一" },
      { name: "最新新闻二" },
      { name: "最新新闻三" },
      { name: "最新新闻四" },
    ];
  }

  initTemplate() {
    return dome(this);
  }

  renderContext() {
    super.renderContext();
    if (this._root._isDesign) {
      this.renderNewest(this.newsList);
    } else {
      this.getLatestNews();
    }
    this.changeColor();
  }

  renderReady() {
    super.renderReady();
  }
  //改变字体颜色
  changeColor() {
    if (this.fontColor) {
      this._handlers["module_header_h"].removeClass("commonBorderColor");
      this._handlers["module_header_h"].css({
        "border-bottom-color": this.fontColor,
      });
      $(".news_list li:nth-of-type(1) span").length &&
        $(".news_list li:nth-of-type(1) span").css({
          "background-color": this.fontColor,
        });
      $(".news_list li:nth-of-type(2) span").length &&
        $(".news_list li:nth-of-type(2) span").css({
          "background-color": this.fontColor,
        });
      $(".news_list li:nth-of-type(3) span").length &&
        $(".news_list li:nth-of-type(3) span").css({
          "background-color": this.fontColor,
        });
    } else {
      this._handlers["module_header_h"].addClass("commonBorderColor");
      $(".news_list li:nth-of-type(1) span").length &&
        $(".news_list li:nth-of-type(1) span").addClass("commonBgColor");
      $(".news_list li:nth-of-type(2) span").length &&
        $(".news_list li:nth-of-type(2) span").addClass("commonBgColor");
      $(".news_list li:nth-of-type(3) span").length &&
        $(".news_list li:nth-of-type(3) span").addClass("commonBgColor");
    }
  }
  // 最新新闻
  getLatestNews() {
    let loading = dsf.layer.loadding();
    let sourceUrl = dsf.url.getWebPath("nc/news/findTjNews");
    dsf.http
      .request(sourceUrl, {}, "Get")
      .done((res) => {
        if (res.success && res.state == 20000) {
          this.renderNewest(res.data);
        } else {
          dsf.layer.message("请求失败");
        }
      })
      .error((err) => {
        dsf.layer.message("接口异常,请稍后重试", false);
      })
      .always(() => {
        dsf.layer.close(loading);
      })
      .exec();
  }

  // 推荐新闻
  renderNewest(data) {
    let newestStr = "";
    if (data && data.length) {
      for (var i = 0; i < data.length; i++) {
        newestStr +=
          "<li><span>" + (i + 1) + "</span>" + data[i].name + "</li>";
      }
      this._handlers["newestList"].html(newestStr);
      this.bindDetail(data);
      this.changeColor();
    } else {
      return;
    }
  }

  // 跳转新闻详情
  bindDetail(data) {
    $(".news_list")
      .find("li")
      .each(function(index) {
        var _this = $(this);
        _this.on("click", function(e) {
          let jumpUrl = dsf.url.getWebPath(
            "nc/mhsy/views/xwxq.html?id=" + data[index].id
          );
          window.open(jumpUrl, "_self");
        });
      });
  }
}
