import dome from "../../templates/HdSpecial.ejs";
import { map } from "../../../../decorator/controlmap";
import { ControlEditor } from "../../../../editor/ControlEditor";

@map("首页专题班", "nc.teas.hdspecial", "HdSpecial")
export class HdSpecial extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$useVdom = true;

    this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.title = "专题班";
    this.ismorebtn = true;
    this.morebtnsrc = 'nc/ztb/views/mhlblist.html?v=0.0.1';
    this.detailUrl = 'nc/pc/stylecenterindex/views/stylecenterindex.html'; // gdetailUrl

    this.$ztbList = [];
    //请求接口参数
    this.parms = {
      type_value: "05",
      pageNo: 1,
      pageSize: 4,
    };

  }

  set gtitle(v) {
    this.title = v;
    this.domUpdate();
  }
  get gtitle() {
    return this.title;
  }

  set gismorebtn(v) {
    this.ismorebtn = v;
    this.domUpdate();
  }
  get gismorebtn() {
    return this.ismorebtn;
  }

  set gmorebtnsrc(v) {
    this.morebtnsrc = v;
    this.domUpdate();
  }
  get gmorebtnsrc() {
    return this.morebtnsrc;
  }

  set gdetailUrl(v) {
    this.detailUrl = v;
    this.domUpdate();
  }
  get gdetailUrl() {
    return this.detailUrl;
  }

  gotopage() {
    let userId = dsf.getCookie('userId');
    if (!userId) {
      window.parent.openLogin();
      evt.preventDefault();
    }else {
      let ur = dsf.url.getWebPath(this.morebtnsrc);
      // dsf.openUrl(1, ur)
      var elid = $(window.parent.document).find("#J_content");
      $(elid).attr("src",ur)
      console.log(userId, '===', ur)
    }
  }

  gotoDetail(item) {
    let userId = dsf.getCookie('userId');
    if (!userId) {
      window.parent.openLogin();
      evt.preventDefault();
    }else {
      let ur = dsf.url.getWebPath(`${this.detailUrl}?id=${item.nc_zyb_id}`);
      dsf.openUrl(1, ur)
      // var elid = $(window.parent.document).find("#J_content");
      // $(elid).attr("src",ur)
      // console.log(userId, '===', ur)
    }
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
    if (this._root._isDesign) {

    } else {
      this.postData();
    }

  }
  renderReady() {
    //组件加载完成后执行
    super.renderReady();
    // this.$gotomore = this._handlers['']
  }
  initEvent() { }

  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = dsf.url.getWebPath(cov[0].relativePath);
      }
    } else {
      urls = dsf.url.getWebPath("res/dsf_styles/themes/nc/404.png");
    }
    return urls;
  }

  /**
   * 请求数据
   */
  postData() {
    let loading = dsf.layer.loadding();
    let _this = this;
    let url = dsf.url.getWebPath('yyzx/pdgl/findZtbGDList');
    dsf.http.request(
      url, _this.parms, 'get'
    ).done(response => {
      if (response.state === 20000) {
        console.log('222===>', response.data)
        // 请求成功
        _this.$ztbList = response.data;
        _this.domUpdate();
      } else {
        dsf.layer.message(response.message, false)
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }
}
