// import dome from '../templates/NcABanner.ejs';
import {
   ControlEditor
} from "../../../editor/ControlEditor";
import {
   map
} from "../../../decorator/controlmap";
import {
   relyFiles
} from "../../../core/relyfiles";

const mainDom = require("../templates/NcABanner.ejs");

@map("首页学堂轮播图", "nc.teas.abanner", "NcABanner")
@relyFiles([
   "res/libs/swiper/css/swiper.min.css",
   "res/libs/swiper/js/swiper.min.js"
])
export class NcABanner extends dsf.Controls.Control {
   constructor(id, isPart) {
      super(id, isPart);
      this.$useVdom = true;
      this._desingerClass = ControlEditor;
      this.$defaultImgUrl = "/dsfa/res/dsf_styles/themes/nc/404.png";
      this.banners = [];
      this.defaultBanners = [this.$defaultImgUrl, this.$defaultImgUrl];
      this.$ratio = 2.051;
      this._swiper = null;
   }
   initTemplate() {
      return mainDom(this);
   }
   inserted() {
      if (!this._root._isDesign) {
         this.getBannerList();
      }
   }
   updated() {
      let that = this;
   }
   set ratio(v) {
      this.$ratio = v;
      this.domUpdate();
   }
   get ratio() {
      return this.$ratio;
   }

   get height() {
      let w = this.element.width();
      let h = w / this.ratio;
      return h;
   }

   resize() {
      this.domUpdate();
      // this.renderDefaultPage();
   }

   getBannerList() {
      let that = this;
      let loading = dsf.layer.loadding();
      if (!this.sourceUrl) this.sourceUrl = "nc/lbt/sellByCount";
      let sourceurl = dsf.url.getWebPath(this.sourceUrl);
      let params = {
         count: 5
      };
      dsf.http
         .request(sourceurl, params, "Get")
         .done(res => {
            console.log(res);
            if (res.success) {
               that.renderPage(res.data);
               // if (res.data.length > 0) {
               //    for (let i = 0; i < res.data.length; ++i) {
               //       let item = res.data[i];
               //       item.pcphoto.relativePath = !!item.pcphoto ? dsf.url.getWebPath(item.pcphoto.relativePath) : that.$defaultImgUrl
               //    }
               // }
               // that.banners = res.data;
               // layui.use('carousel', function () {
               //    var carousel = layui.carousel;
               //    carousel.render({
               //       elem: '#banner',
               //       width: '100%',
               //       arrow: 'none',
               //       height: '1080',
               //       indicator: 'inside',
               //       interval: 5000,
               //    });
               //    carousel.on('change(bannerClick)', function (res) {
               //       that.event.trigger(ncModelEvent.bannerClick, { ui: that, data: res });
               //    });
               // });
               // that.domUpdate();
            } else {
               dsf.layer.message(res.message, false);
            }
         })
         .error(err => {
            dsf.layer.message("接口异常,请稍后重试", false);
         })
         .always(() => {
            dsf.layer.close(loading);
         })
         .exec();
   }
   bindToDetail(item) {
      let userId = dsf.getCookie("userId");
      if (!userId) {
         window.parent.openLogin();
         return;
      } else {
         if (item.ljlx_value !== "10" && !!item.lsdz && item.lsdz !== 0) {
            dsf.openUrl(1, item.lsdz);
         }
      }
   }
   renderPage(data) {
      let that = this;
      let bulletStr = "";
      let bannerStr = "";
      for (let i = 0; i < data.length; i++) {
         let item = data[i];
         let imgStr = `<img src="${!!item['pcphoto'] ? dsf.url.getWebPath(item.pcphoto.relativePath) : that.$defaultImgUrl}" onerror='onerror=null;src="${that.$defaultImgUrl}"' alt=''/>`
         bannerStr += '<div class="swiper-slide" data-idx="' + i + '">' +
            "             " + imgStr +
            "         </div>";
         // '<div class="swiper-slide" data-idx="' +
         // i +
         // '">' +
         // '    <div style="width:100%;height:100%;background:url(' +
         // (item.pcphoto ?
         //    dsf.url.getWebPath(item.pcphoto.relativePath) :
         //    that.$defaultImgUrl) +
         // ') no-repeat;background-size: 100% 100%;"></div>' +
         // " </div>";
      }
      this._handlers["bannerTop"].html(bannerStr);
      this._swiper = new Swiper(".banner-swiper-wrap", {
         slidesPerView: 1,
         loop: true,
         autoplay: {
            delay: 5000
         },
         pagination: {
            el: ".banner-top-pagination",
            clickable: true,
            renderBullet: function (idx, className) {
               let item = data[idx];
               // bulletStr = '<div class="bullet-item ' + className + '">' +
               //    '             <div  style="width:100%;height:100%;background:url(' +
               //    (item.pcphoto ?
               //       dsf.url.getWebPath(item.pcphoto.relativePath) :
               //       that.$defaultImgUrl) +
               //    ') no-repeat;background-size: 100% 100%;"></div>' +
               //    "         </div>";
               let imgStr = `<img src="${!!item['pcphoto'] ? dsf.url.getWebPath(item.pcphoto.relativePath) : that.$defaultImgUrl}" onerror='onerror=null;src="${that.$defaultImgUrl}"' alt='' style='width:100%;height:100%;'/>`
               bulletStr = '<div class="bullet-item ' + className + '">' +
                  "           " + imgStr +
                  "         </div>";
               return bulletStr;
            }
         }
      });
      this._handlers['defaultPagination'].show();
      this._handlers['bannerTop'].on('click', '.swiper-slide', function (evt) {
         let idx = $(this).attr('data-idx');
         let userId = dsf.getCookie('userId');
         if (!userId) {
            window.parent.openLogin();
            return;
         } else {
            //登录后
            if (data[idx].ljlx_value !== '10' && !!data[idx].lsdz && data[idx].lsdz != 0) {
               window.open(data[idx].lsdz);
            }
         }
      })
   }
   slideNext() {
      if (this._swiper) {
         this._swiper.slideNext();
      }
   }
   slidePrev() {
      if (this._swiper) {
         this._swiper.slidePrev();
      }
   }
}