import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("专题班课程", 'nc.teas.specialobj', 'Specialobj')
export class Specialobj extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
		this._desingerClass = ControlEditor;
		this.titleText='原原本本学';
		this.parms={
//			id:'2828ab575a6e43aaab09f31de45e915a'
			id:'5a21a77d55b7408090287a08cf97e523'
		}
		this.isquiredata={
			'required':22,
			'requiredTotletime':30,
			'Electived':8,
			'ElectivedTotletime':16,
		};
		this.isquiredata2={
			'required':23,
			'requiredTotletime':31,
			'Electived':9,
			'ElectivedTotletime':17,
		};
		this.spelist=[
    	{
    		'objchoose':'1',           //1:课程   2:考试
    		'objtitle':'绿水青山就是金山银山绿水青山就是金山银山绿水青山就是金山银山绿水青山就是金山银山绿水青山就是金山银山',
    		'required':1,              //1:必修   0:选修
    		'record':'100',             //分数
    		'time':'00:08:00',       
    		'classhour':'1.0',         //学时
    		'Speed':80,                //进度
    		'btnchoose':'1',            //1:学习  2:考试
    		'btnchoosetype':'1'        //1:深色  2:浅色
    		
    	},
    	{
    		'objchoose':'1',           
    		'objtitle':'绿水青山',
    		'required':1,             
    		'record':'59',
    		'classhour':'20.0',
    		'Speed':60,
    		'btnchoose':'1',            
    		'btnchoosetype':'0'       
    		
    	},
    	{
    		'objchoose':'2',           
    		'objtitle':'绿水青山就是金山银山',
    		'required':0,
    		'classhour':'1.0',
    		'Speed':60,
    		'btnchoose':'2', 
    		'btnchoosetype':'1'            
    	},
    	{
    		'objchoose':'2',           
    		'objtitle':'绿水青山就是金山银山',
    		'required':0,
    		'record':'59',
    		'time':'00:23:00',
    		'classhour':'1.0',
    		'Speed':60,
    		'btnchoose':'2', 
    		'btnchoosetype':'0'            
    	},
    	{
    		'objchoose':'3',           
    		'objtitle':'绿水青山就是金山银山',
    		'required':0,
    		'record':'59',
    		'time':'00:23:00',
    		'classhour':'1.0',
    		'Speed':60,
    		'btnchoose':'2', 
    		'btnchoosetype':'0'            
    	},
    	{
    		'objchoose':'4',           
    		'objtitle':'绿水青山就是金山银山',
    		'required':0,
    		'record':'59',
    		'time':'00:23:00',
    		'classhour':'1.0',
    		'Speed':60,
    		'btnchoose':'2', 
    		'btnchoosetype':'0'            
    	},
    	{
    		'objchoose':'5',           
    		'objtitle':'绿水青山就是金山银山',
    		'record':'59',
    		'time':'00:23:00',
    		'classhour':'1.0',
    		'Speed':60,
    		'btnchoose':'4', 
    		'btnchoosetype':'0'            
    	},
    ];

  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    console.log(1);
    let _this=this;
		let url = dsf.url.getWebPath("home/ztb/zjid");
    dsf.http.request_sync(
    	url,
    	_this.parms, 
    	"get"
    )
    .done(function (data) {
    	if(data.state==20000){
    		console.log(data);
    		_this.spelist=data.data;
    		_this.showlist();

    	}
    })
    .error(function (err) {
      console.log(err);
    })
    .always(function () {
    }).exec();
  }
	
  renderContext(refresh) {
		super.renderContext();
	}
  objchoose(text){
  	let arr=['','课程','考试','作业','链接','问卷'];
  	return arr.indexOf(text)
  }
  objisrequire(text){
  	let shtml=``;
  	if(text=='必修'){
  		shtml=`<i class="require1" style="display:inline-block">`+text+`</i>`
  	}else if(text=='选修'){
  		shtml=`<i class="require0" style="display:inline-block">`+text+`</i>`
  	}
  	return shtml
  }
  getbtnchoose(name){
  	console.log(name);
  	let shtml='';
  	switch (name){
  		case '课程':
  			shtml='学习'
  			break;
  		case '考试':
  			shtml='考试'
  			break;
  		case '作业':
  			shtml='撰写'
  			break;
  		case '链接':
  			shtml='参与'
  			break;
  		case '问卷':
  			shtml='参与'
  			break;
  		default:
  			break;
  	}
		return shtml
  }
  
  
  getshowlistitem(arr){
//	study  为0是红色,为1是灰色,
  	let _this=this,shtml='',sd=arr;
  	for(var i=0,len=sd.length;i<len;i++){
  		console.log(sd[i]);
  	  shtml+=`<div class="spe_item">
							<b class="iconc"></b>
							<span class="objchoose objchoose`+_this.objchoose(sd[i].type_text)+`">`+sd[i].type_text+`</span>
							<div class="objname">
								<span class="ell" title="`+sd[i].name+`">`+sd[i].name+`</span>
								`+_this.objisrequire(sd[i].sfbx_text)+`
							</div>
							<div class="rightcon">
								<p class="tecname" style="display:inline-block;opacity:`+(sd[i].skjs==null?0:1)+`">`+sd[i].skjs+`</p>
								<b class="record" style="display:inline-block;opacity:1">成绩:`+sd[i].cj+`分</b>
								<span class="time" style="display:inline-block;">`+(sd[i].kcsc==null?"":sd[i].kcsc)+`</span>
								<span class="classhour" style="display:inline-block;opacity:`+(sd[i].xs==null?0:1)+`">`+sd[i].xs+`学时</span>
								<div class="speedbox">
									<div class="speedcon">
										<b style="width:`+sd[i].jd+`%"></b>
									</div>
									<i>`+sd[i].jd+`%</i>
								</div>
								<span class="btnchoose jsbtnchoose btnchoose`+sd[i].study+`">`+_this.getbtnchoose(sd[i].type_text)+`</span>
							</div>
							<div class="rightonlytext ell" title="`+( !!sd[i].jsdwzw ? sd[i].jsdwzw : "" )+`">`+(!!sd[i].jsdwzw ? sd[i].jsdwzw : "" )+`</div>
						</div>`
  	}
  	return shtml;
  }
  showlist(){
  	let _this=this,shtml='',sd=_this.spelist.data;
  	console.log(666);
  	console.log(sd);
  	_this.$objbox = _this._handlers['objbox'];
  	for(var i=0,len=sd.length;i<len;i++){
  	    shtml+=`<div class="titlebox">
									<p><i></i><span class="titlename" handler="titleText">`+sd[i].dy_name+`</span></p>
									<div class="titleboxright" handler="titleboxright">
										<h6><span>必修：</span><b>`+sd[i].bxcount+`门 `+sd[i].bxxs+`学时</b></h6>
										<h6><span>选修：</span><b>`+sd[i].xxcount+`门 `+sd[i].xxxs+`学时</b></h6>
									</div>
								</div>
								<div class="special_contentbox" handler="special_contentbox">
									`+_this.getshowlistitem(sd[i].CHILDREN)+`
								</div>`
  	}
  	
  	_this.$objbox.html(shtml);
  	console.log('值是:'+_this.spelist.state);
  	if(_this.spelist.state==0){
		  _this.$objbox.find('.record').css('opacity',0);//学习成绩
			_this.$objbox.find('.time').css('opacity',0);//时间
			_this.$objbox.find('.speedbox').css('opacity',0);//进度
			_this.$objbox.find('.btnchoose').remove()
  	}
  }

  isstylechoose(){
  	var _this=this;
  	_this.$specialContentbox = _this._handlers['objbox'];
  	_this.$specialContentbox.find('.jsbtnchoose').click(function(){
  		console.log($(this).text());
  		layui.use('layer', function() {
  		    layer.msg("暂无跳转页面",{icon:0,time:2000}); 
  		})
  	})
  }
	renderReady(){//组件加载完成后执行
		super.renderReady();
		this.isstylechoose()
	}

  initEvent() {
  }
  
}

