import dome from '../templates/NcModuleTitle.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("模块标题", 'nc.teas.ncmoduletitle', 'NcModuleTitle')

export class NcModuleTitle extends dsf.Controls.Control {
    constructor(id, isPart) {
        super(id, isPart);
        this._desingerClass = ControlEditor;

        this.mainTitle = '主标题';
        this.subTitle = '副标题';
        this.showSubTitle = true;
        this.switchIcon = false;
        this.fontCo = '#333';
    }

    initTemplate() {
        return dome(this);
    }

    renderContext() {
        this._handlers.setMainTitle.html(this.mainTitle);
        this._handlers.setSubTitle.html(this.subTitle);
        this.changeColor();
        this.changeTitleIcon();
        this.changeTitle();
    };

    // 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
	changeTitle(){
		let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
	}
}


