import { map } from '../../../../decorator/controlmap';
import { ControlEditor } from "../../../../editor/ControlEditor";
import dome from '../../templates/JxNews.ejs';

@map("新闻", 'nc.ncctrl.jxnews', 'JxNews')
export class JxNews extends dsf.Controls.Control{
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    // 基础属性
    this._mainWidth = '100%';
    this._mainHeight = '525px';
    this.mainMargin = '0px 0px 0px 0px';
    // 接口相关
    this.url = '/nc/news/findNewsLbList';
    this.httpMethed = 'GET';
    this.params = {
      pageSize: 5
    };
    this.paramsKey = {
      pageSize: 'pageSize',
      keyword: 'lmId'
    };
    this.dataKey = {
      text: 'cname',
      time: 'ds_create_time'
    };

    this.tabsIndex = 0;
    this.tabs = [
      {
        name: '通知公告',
        more: '/dsfa/nc/pc/main/views/main.html',
        detail: '/dsfa/nc/mhsy/views/xwxq.html',
        id: 'f2e1651fe85045609d53b37e722340ca'
      },
      {
        name: '新闻动态',
        more: '/dsfa/nc/pc/main/views/main.html',
        detail: '/dsfa/nc/mhsy/views/xwxq.html',
        id: '6c11fa0cbf724b739e41582059c3f645'
      }
    ];
    // 模拟数据
    this.tabsData = {
      // notice: {
      //   isDraw: false,
      //   dom: null,
      //   data: [
      //     {
      //       text: '“众志成城，共克时艰”---省交通干部学院开展爱心捐款活动',
      //       timeDay: '5',
      //       timeMonuth: '02-2020',
      //       link: '#'
      //     }
      //   ]
      // }
    };
  }

  set mainWidth (v) {
    v = $.trim(v);
    if (/$\d*^/.test(v)) {
      this._mainWidth = v + 'px';
    } else {
      this._mainWidth = v;
    }
  }

  get mainWidth () {
    return this._mainWidth;
  }

  set mainHeight (v) {
    v = $.trim(v);
    if (/$\d*^/.test(v)) {
      this._mainHeight = v + 'px';
    } else {
      this._mainHeight = v;
    }
  }

  get mainHeight () {
    return this._mainHeight;
  }

  /*********生命周期**********/
  initTemplate () {
    this.tabsIndex = 0;
    this._initTabsData(true);

    return dome(this);
  }

  // 组件加载完成后执行
  renderReady() {
    super.renderReady();
    // dom
    this.moreDom = this._handlers.more;
    this.tabsDom = this._handlers.tabs;
    this.newsBoxDom = this._handlers.newsBox;
    // 渲染
    this._drawTabsDom();
    // 其他
    if(this._root.isDesign){
      this._postData();
    } else {
      this.postData();
    }
    this.bindTabsEvent();

    if(this._root.isDesign){
      this._desinger.control.element.children('.ds_control_design').css({
        'width': '100px',
        'height': 'auto',
        'left': 'auto',
        'bottom': 'auto'
      })
    }
  }

  /**
   * 初始化tabsData数据
   * @param isClear {boolean} 是否清楚数据缓存
   * @private
   */
  _initTabsData (isClear = false) {
    let tabsData = {};
    this.tabs.forEach(({id}) => {
      const thisTab = this.tabsData[id];
      // 如果数据不存在，或者需要清理数据缓存
      if (thisTab === void 0 || isClear) {
        tabsData[id] = {
          isDraw: false, // 是否已渲染
          dom: null, // 渲染后dom的jq对象
          data: [] // 对应的请求数据
        };
      }
      // 否则使用缓存数据
      else {
        tabsData[id] = this.tabsData[id];
      }
      // 如果数据已渲染，且需要清理数据，则移除已渲染dom
      thisTab && thisTab.isDraw && isClear &&
      thisTab.dom.remove && thisTab.dom.remove();
    });
    this.tabsData = tabsData;
  }

  /**
   * tabs选项卡切换事件
   */
  bindTabsEvent () {
    const _this = this;
    const tabsDom = this.tabsDom;
    tabsDom.delegate('.tabs', 'click', function () {
      const index = +$(this).attr('index');
      if (_this.tabsIndex !== index) {
        // 切换选项卡
        const tabsItemDom = tabsDom.children('.tabs');
        const ulDom = _this.newsBoxDom.children('.data_ul');
        _this.tabsIndex = index;
        tabsItemDom.removeClass('active').eq(index).addClass('active');
        // 更改more跳转
        const thisTab = _this.tabs[index];
        _this.moreDom.attr('_href', dsf.url.getWebPath(thisTab.more));
        // 切换news
        const id = thisTab.id;
        ulDom.hide();
        // 如果不存在对应数据，则请求数据
        if(!_this.tabsData[id].isDraw){
          if(_this._root.isDesign){
            _this._postData();
          } else {
            _this.postData();
          }
        } else {
          const newsActive = _this.tabsData[id].dom;
          newsActive && newsActive.show && newsActive.show();
        }
      }
    });
    this.moreDom.click('click', function () {
      if (_this.isLogin()) {
        self.location.href = ($(this).attr('_href'));
      }
    });
    this.newsBoxDom.delegate('.ds_jx_news_li_text_a', 'click', function () {
      if (_this.isLogin()) {
        window.open($(this).attr('_href'));
      }
    });
  }

  isLogin () {
    let uId = dsf.getCookie('userId');
    if (!uId) {
      window.parent.openLogin();
      return false;
    }
    return true;
  }

  /**
   * 设计器中模拟请求
   */
  _postData () {
    const tab = this.tabs[this.tabsIndex];
    if (!tab) return;
    // 请求成功
    let _textArr = [
      '“众志成城，共克时艰”---省交通干部学院开展爱心捐款活动',
      '同心共战疫，我们在行动----学院开展防疫物资捐赠活动支援社区疫情防控',
      '全省交通运输工作会议在学院召开',
      '学院运用线上线下混合创新培训模式开展江西省教育厅“国培计划”江西省乡村教师访名校项目',
      '学院学院举行第六届职工趣味运动会',
    ];
    let data = [];
    for (let i = 0; i < this.params.pageSize; i++) {
      data.push({
        text: _textArr[parseInt(Math.random() * 5)],
        timeDay: parseInt(Math.random() * 31),
        timeMonuth: '03-2020',
        detail: '#'
      });
    }
    this.tabsData[tab.id].data = data;
    this._drawNewsDom(tab.id);
  }

  /**
   * 请求数据
   */
  postData () {
    const tab = this.tabs[this.tabsIndex];
    if (!tab) return;
    const tabId = tab.id;
    const loading = dsf.layer.loadding();
    const params = {};
    params[this.paramsKey.keyword] = tabId;
    params[this.paramsKey.pageSize] = this.params.pageSize;
    dsf.http.request(
        dsf.url.getWebPath(this.url), params, this.httpMethed
    ).done(response => {
      if (response.state === 20000) {
        // 请求成功
        this.postDataSuccess(tab, response.data);
      } else {
        // 请求失败
        dsf.layer.message('请求异常', false);
      }
    }).error(response => {
      // 请求错误
      dsf.layer.message('请求异常', false);
    }).always(response => {
      dsf.layer.close(loading);
    }).exec();
  }

  /**
   * 请求成功处理
   * @param tabId
   * @param data {
   *  total: int 总条数
   *  totalpage: int 页码
   *  data: [
   *     {id, ds_create_time, djcs, cover, abstract, cname}
   *     ......
   *  ]
   * }
   */
  postDataSuccess ({id, detail}, { data }) {
    if (data.length > this.params.pageSize) {
      data.length = this.params.pageSize;
    }
    this.tabsData[id].data = data.map(v => {
      const time = v[this.dataKey.time].split('-');
      return {
        text: v[this.dataKey.text],
        timeDay: time[2],
        timeMonuth: `${time[1]}-${time[0]}`,
        detail: dsf.url.getWebPath(detail) + '?id=' + v.id
      }
    });
    this._drawNewsDom(id);
  }

  /*******页面渲染*******/
  /**
   * 渲染选项卡
   * @private
   */
  _drawTabsDom () {
    const tabsItemArr = [];
    this.tabs.forEach(({name}, i) =>  {
      tabsItemArr.push(
          this._getTabsItemDomStr(i, name)
      );
    });
    this.tabsDom.html(tabsItemArr.join(''));
  }
  _getTabsItemDomStr (index, name) {
    const active = this.tabsIndex === index ? ' active' : '';
    return `<div class="ds_jx_news_header_tabs_item tabs${active}" index="${index}">${name}</div>`;
  }

  /**
   * 渲染news列表
   * @param id tabs的id
   * @private
   */
  _drawNewsDom (id) {
    const data = this.tabsData[id];
    if (!data.isDraw) {
      const show = this.tabs[this.tabsIndex].id === id;
      const dom = $(this._getNewsItemDomStr(data.data));
      show && dom.show();
      this.newsBoxDom.append(dom);
      dom.data('id', id);
      this.tabsData[id].isDraw = true;
      this.tabsData[id].dom = dom;
    }
  }
  _getNewsItemDomStr (list) {
    const liArr = list.map((item, index) => `<li class="ds_jx_news_li _${index}">
                        <div class="ds_jx_news_li_time">
                            <div class="ds_jx_news_li_time_day">${item.timeDay}</div>
                            <div class="ds_jx_news_li_time_monuth">${item.timeMonuth}</div>
                        </div>
                        <div class="ds_jx_news_li_text">
                            <a class="ds_jx_news_li_text_a" target="_blank"
                            _href="${item.detail}">${item.text}</a>
                        </div>
                    </li>`);
    return `<ul class="data_ul" style="display: none">${liArr.join('')}</ul>`;
  }

  /*******json事件*******/
  changeMainWidth () {
    this.element.css('width', this.mainWidth);
  }

  changeMainHeight () {
    this.element.css('height', this.mainHeight);
  }

  changeMainMargin () {
    this.element.css('margin', this.mainMargin);
  }

  changePageSize () {
    this._initTabsData(true);
    this._drawTabsDom();
    if(this._root.isDesign){
      this._postData();
    } else {
      this.postData();
    }
  }

  // 更新了选项卡
  changeTabsData() {
    this.tabsIndex = 0;
    this._initTabsData();
    this._drawTabsDom();
    if(this._root.isDesign){
      this._postData();
    } else {
      this.postData();
    }
  }
}