import dome from "../templates/Ncdowncard.ejs";
import { map } from "../../../decorator/controlmap";
import { ControlEditor } from "../../../editor/ControlEditor";
import "../../../pd/pd.js";
import "../../nc.js";

//const mainDom = require("../templates/printingDesign.ejs");
//const mainDom1 = require("../templates/printing.ejs");
import html2canvas from "html2canvas";

@map("证书下载", "nc.teas.ncdowncard", "Ncdowncard")
export class Ncdowncard extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.sdtype = null;
    this.ismyurl = false;
    this.sdsrc = "test/a"; //默认接口地址
    this.bgColor = "#dd4400"; //分隔条颜色
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
    //		console.log(this.sdtype);
    //		console.log(this.ismyurl);
    //		console.log(this.sdsrc);
    this.changeColor();
  }
  changeColor() {
    if (!this.bgColor) {
      this._handlers.iBg.addClass("commonBgColor");
    } else {
      this._handlers.iBg.removeClass("commonBgColor");
      this._handlers.iBg.css({
        "background-color": this.listColor,
      });
    }
  }
  renderReady() {
    //组件加载完成后执行

    super.renderReady();
    let _this = this;

    $(".layui-layer").hide();
    $(".layui-layer-shade").hide();
    _this.$jsncdowncard = _this._handlers["jsncdowncard"];

    var print;
    console.log(_this._root._isDesign);
    if (!_this._root._isDesign) {
      $(document).ready(function() {
        var relid = dsf.url.queryString("id");
        var type = dsf.url.queryString("type");
        var mbid = dsf.url.queryString("mbid");
        var userId = dsf.url.queryString("userId") || "";

        //	        var relid = '870be364adb741f3bac54ad87c90cb0c';
        //	        var type = '05';
        //	        var mbid = '879f2c4ae3704722add3f6701bc3386d';

        print = new dsf.PD.printingDesign("printing");
        print.isDesign = false;
        //绑定套打组件加载后事件
        print.event.on("loaded", loaded);
        //读取学员信息
        var q = dsf.queue(true);
        q.step(function(def, v) {
          //查询学员数据
          dsf.http
            .request(
              "/dsfa/nc/zsgl/byzs",
              {
                relId: relid,
                type: type,
                userId: userId,
              },
              "GET"
            )
            .done(function(res) {
              //	                	state:40013 无毕业证书  不显示
              //	                	state:40015尚未毕业   显示有遮罩层.无下载按钮
              //	                	state:20000 有下载按钮
              if (res.success == true) {
                if (res.state == 20000) {
                  print._templateId = res.data.mbid;
                  def.resolve(res.data);
                } else if (res.state == 40013) {
                  _this.$jsncdowncard.hide();
                } else if (res.state == 40014) {
                  _this.$jsncdowncard.hide();
                } else if (res.state == 40015) {
                  _this.$jsncdowncard.find(".shadebox").show();
                  _this.$jsncdowncard.find(".downbtnbox").hide();
                  print._templateId = res.data.mbid;
                  def.resolve(res.data);
                }
              } else {
                if (res.state == 20000) {
                  layui.use("layer", function() {
                    layer.closeAll();
                  });
                  print._templateId = mbid;
                  def.resolve({
                    zsmc: "证书名称",
                    name: "任同学",
                    bydate: "2019-12-30",
                  });
                } else if (res.state == 40013) {
                  layui.use("layer", function() {
                    layer.closeAll();
                  });
                  _this.$jsncdowncard.hide();
                } else if (res.state == 40014) {
                  layui.use("layer", function() {
                    layer.closeAll();
                  });
                  _this.$jsncdowncard.hide();
                } else if (res.state == 40015) {
                  _this.$jsncdowncard.find(".shadebox").show();
                  _this.$jsncdowncard.find(".downbtnbox").hide();
                  print._templateId = res.data.mbid;
                  def.resolve(res.data);
                }
              }
            })
            .exec();
        });
        q.step(function(def, v) {
          //将数据传给套打组件
          print.setData(v);
          print.render(document.getElementById("printing"));
          def.resolve();
        });
        window.setTimeout(q.exec, 50);
      });
      function loaded(args) {
        print.exportImage(function(url) {
          $("#exportImg").attr("src", url);
          $("#downloadLink")
            .removeAttr("disabled")
            .attr("href", url);
        });
      }
    } else {
      //  		console.log('放默认图');
    }
  }
  initEvent() {}
}
