import dome from '../templates/Ncchannel.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("频道", 'nc.teas.ncchannel', 'Ncchannel')
export class Ncchannel extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this._desingerClass = ControlEditor;
    this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.mainTitle = '主标题';
    this.subTitle = '副标题';
    this.showSubTitle = true;
    this.switchIcon = false;
    this.fontCo = '#333';
    this.iconnum = '1';
    
    this.parms={
    	title:'',
    	pageNo:'1',
  		pageSize:'6',
  		typeValue:'01'
    }
    this.newstextlist=[
    	{
    		'name':'学习习近平同志',
    		'namecon':'学习习近平同志系列重要讲话精神学学习习近平同志系列重要讲话精神学同志系列重要讲话精神学学习习近平同志系列重要讲话精神学同志系列重要讲话精神学学习习近平同志系列重要讲话精神学',
    		'num':123,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-1.jpg'
    	},
    	{
    		'name':'学习习近平同志222',
    		'namecon':'学习习近平同',
    		'num':999,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg'
    	},
    	{
    		'name':'学习习近平同志',
    		'namecon':'学习习近平同志系列重要讲话精神学',
    		'num':10254,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-3.jpg'
    	},
    	{
    		'name':'学习习近平同志',
    		'namecon':'学习习近平同志系列重要讲话精神学',
    		'num':666,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-4.jpg'
    	},
    	{
    		'name':'学习习近平同志',
    		'namecon':'学习习近平同志系列重要讲话精神学',
    		'num':10254,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-3.jpg'
    	},
    	{
    		'name':'学习习近平同志',
    		'namecon':'学习习近平同志系列重要讲话精神学',
    		'num':666,
    		'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-4.jpg'
    	}
    ];
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
  	
  	this._handlers.setMainTitle.html(this.mainTitle);
    this._handlers.setSubTitle.html(this.subTitle);
    this.changeColor();
    this.changeTitleIcon();
    this.showSub();
    this.changeTitle();
  }
  geturls(cover){
		let urls ='';
		if(cover){
			let cov = JSON.parse(cover);
			if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
		}else{
			urls="res/dsf_styles/themes/nc/404.png"
		}
		return urls;
  }
	ncchannelList(){
		let loading = dsf.layer.loadding();
		 let _this=this,shtml='',sd=this.newstextlist;
		 
		let url = dsf.url.getWebPath("yyzx/pdgl/pdglList");
    dsf.http.request_sync(
    	url,
    	_this.parms, 
    	"get"
    )
    .done(function (data) {
    	if(data.state==20000){
    		sd=data.data.list
    	}
    })
    .error(function (err) {
      console.log(err);
    })
    .always(function () {
    	dsf.layer.close(loading)
    }).exec();
		 _this.$ds_nc_channelbigbox = _this._handlers['ds_nc_channelbigbox'];
		 if (sd.length==0) {
		 	$('.ds_nc_channelbigbox').html('<div style="text-align:center;padding:40px;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>');
		 } else{
		 	 let chose='';
			 for(var i=0,len=sd.length;i<len;i++){
			 		if (i==0||i==1) {
			 			chose='margin:0'
			 		} else{
			 			chose='';
			 		}
			 		let urls = _this.geturls(sd[i].cover);
			 		let errimg = 'onerror=null;src="${this.$defaultImgUrl}"'
			     shtml+=`<div class="citem" handler="bbb" style="`+chose+`" id="`+sd[i].nc_zyb_id+`">
										<div class="cimgbox">
											<i class="color1"></i>
											<b class="color2"></b>
											<img src="`+dsf.url.getWebPath(urls)+`" onerror='onerror=null;src="${this.$defaultImgUrl}"' data-adaptive-background="1" data-description="grandpa" />
										</div>
										<div class="rcontent">
											<p class="ell" title="'+sd[i].title+'">`+sd[i].title+`</p>
											<h6 class="ell2" title="`+(sd[i].abstract==null?"":sd[i].abstract)+`">`+(sd[i].abstract==null?"":sd[i].abstract)+`</h6>
											<h5><span></span><b>`+(sd[i].djs==null?"0":sd[i].djs)+`</b></h5>
										</div>
									</div>`;
			 }
			 _this.$ds_nc_channelbigbox.html(shtml);
			 _this.$ds_nc_channelbigbox.find('.citem').click(function(){
			 	let id=$(this).attr('id')
			 	let userId = dsf.getCookie('userId');
        if (!userId) {
          window.parent.openLogin();
          return;
        }
			 	dsf.openUrl(1,'/dsfa/nc/pc/channelDetail/views/channelDetail.html?id='+id)
			 })
		 }
	}
	renderReady(){//组件加载完成后执行
		super.renderReady();
		this.ncchannelList();
	}
  initEvent() {
  }
	// 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
    channelshowlist(){
    	this.parms.pageSize = this.pagesizes*2
  		this.ncchannelList()
    }
    changeTitle(){
			let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

				super.renderContext();
				
        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
		}
}

