const mainDom = require('../../templates/NcALunbo.ejs')
import { ControlEditor } from '../../../../editor/ControlEditor'
import { map } from '../../../../decorator/controlmap'
import { relyFiles } from '../../../../core/relyfiles'

@map('轮播', 'nc.ncctrl.jxlunbo', 'NcALunbo')
@relyFiles(['res/libs/swiper/css/swiper.min.css', 'res/libs/swiper/js/swiper.min.js'])
export class NcALunbo extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart)
    this._desingerClass = ControlEditor //拖动/移除
    this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png'
    this._swiper = null
    this.sourceUrl = 'nc/lbt/sellByCount'
    this.isAutoPlay = false
    this.autoPlaydelay = 3
    this.width = 720
    this.height = 240
    this.count = 5
    this.imgLists = []
  }
  initTemplate() {
    return mainDom(this)
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-10 15:03:43
   * @LastEditors: 宽度/高度
   * @LastEditTime:
   */
  setWh() {
    let _this = this
    this._handlers.bannerTop.css({
      width: _this.width,
      height: _this.height,
    })
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-10 15:03:43
   * @LastEditors: 接口地址
   * @LastEditTime:
   */
  set setSourceUrl(v) {
    if (this.sourceUrl !== v) {
      this.sourceUrl = v
      this.getBannerList()
    }
  }
  get setSourceUrl() {
    return this.sourceUrl
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-10 15:03:43
   * @LastEditors: 是否自动播放
   * @LastEditTime:
   */
  set setAutoPlay(v) {
    console.log('setAutoPlay', v)
    this.isAutoPlay = v
  }
  get setAutoPlay() {
    console.log('getAutoPlay', v)
    return this.isAutoPlay
  }

  /**
   * @Name: RONGWEI PENG
   * @Date: 2020-04-26 09:52:59
   * @LastEditTime: Do not edit
   * @Description: 自动播放间隔时间
   * @param {type} {}
   * @return: {}
   */
  set setAutoPlayDelay(v) {
    console.log('setAutoPlayDelay', v)
    this.autoPlaydelay = v
  }
  get setAutoPlayDelay() {
    console.log('getAutoPlayDelay', this.autoPlaydelay)
    return this.autoPlaydelay
  }

  /**
   * @Author: RONGWEI PENG
   * @Date: 2020-04-10 15:03:43
   * @LastEditors: 显示图片数量
   * @LastEditTime:
   */
  set setCount(v) {
    if (this.count !== v) {
      this.count = v
      this.getBannerList()
    }
  }
  get setCount() {
    return this.count
  }

  renderReady() {
    super.renderReady()
    this.setWh()
    if (!this._root._isDesign) {
      this.getBannerList()
    } else {
      this.initSwiper()
    }
  }

  initSwiper() {
    let option = {
      spaceBetween: 3000,
      effect: 'fade',
      // autoplay: this.isAutoPlay
      //   ? {
      //       delay: this.autoPlaydelay, // 5秒切换一次
      //     }
      //   : false,
      loop: true, //循环
      // allowTouchMove: false, // 不允许鼠标拖动
      pagination: {
        el: '.swiper-pagination',
        clickable: true,
      },
    }
    if (this.isAutoPlay) {
      option.autoplay = {
        delay: Number(this.autoPlaydelay) * 1000, // 5秒切换一次
      }
    }
    this._swiper = new Swiper('.swiper-container', option)
  }

  getBannerList() {
    let that = this
    if (this.sourceUrl) {
      let loading = dsf.layer.loadding()
      let sourceurl = dsf.url.getWebPath(this.sourceUrl)
      let params = {
        count: this.count || 5,
      }
      dsf.http
        .request(sourceurl, params, 'Get')
        .done(res => {
          if (res.success) {
            that.renderPage(res.data)
          } else {
            dsf.layer.message(res.message, false)
          }
        })
        .error(err => {
          dsf.layer.message('接口异常,请稍后重试', false)
        })
        .always(() => {
          dsf.layer.close(loading)
        })
        .exec()
    } else {
      this.initSwiper()
    }
  }

  bindToDetail(item) {
    let userId = dsf.getCookie('userId')
    if (!userId) {
      window.parent.openLogin()
      return
    } else {
      if (item.ljlx_value !== '10' && !!item.lsdz && item.lsdz !== 0) {
        dsf.openUrl(1, item.lsdz)
      }
    }
  }
  isjumpPage(url) {
    let userId = dsf.getCookie('userId')
    if (!userId) {
      window.parent.openLogin()
      return
    }
    if (!userId) {
      dsf.layer.message('请先登录')
      return
    }
    if (url && url != '0') {
      dsf.layer.openWindow(url)
    } else {
      // dsf.layer.message('当前图片没有链接地址')
      console.log('当前图片没有链接地址')
    }
  }
  renderPage(data) {
    let that = this
    // let bulletStr = ''
    let bannerStr = ''
    if (data.length > 0) {
      this.imgLists = data
      for (let i = 0; i < data.length; i++) {
        if (data.length > 1) {
          this._handlers['defaultPagination'].show()
        }
        let item = data[i]
        let imgStr = `<img class='lunbo' data-url='${item.lsdz}'  src="${
          !!item['pcphoto'] ? dsf.url.getWebPath(item.pcphoto.relativePath) : that.$defaultImgUrl
        }" onerror='onerror=null;src="${that.$defaultImgUrl}"' alt=''/>`
        bannerStr += `<div  class="swiper-slide" data-idx="${i}"> ${imgStr} </div> `
      }
      this._handlers['bannerTopBox'].html(bannerStr)
      this.initSwiper()
      this.element.on('click', '.lunbo', e => {
        this.isjumpPage(e.target.dataset['url'])
      })
    }
  }
}
