const mainDom = require("../templates/hostelDesign.ejs");
import {justifyCss, _ajaxFunc, interactDormList, interactRoomList, __setUrl} from "./hostel_common"

export class hostelDesign extends dsf.Controls.Control {
  constructor() {
    super();
    this.age = 45;
    this.option = null; //配置
    this.query = {
      currentClassId: "", //当前班级Id
      className: "",
      roomId: "",
      startTime: "",
      endTime: "",
      dormId: ""
    };

    this.isFirstTime = true;    //页面第一次加载时
    this.pormiseTimes = 3;    //首次加载页面时总共发起的ajax次数
    this.ptime = 0;   //首次加载页面时这是第几次ajax
  }

  //页面首次加载时判断所有异步是否完成
  pormiseJudge() {
    this.ptime += 1;
    if (this.ptime === this.pormiseTimes) {
      const winHit = $(window).height();
      const screenTop = $(".ds_hostel_floor").offset().top;
      let hit = Math.floor(winHit - screenTop) - 10;
      $(".ds_hostel_floor").height(hit);
      $(".ds_hostel").height(winHit - 1);
      layui.form.on("checkbox(all)", function (data) {
        if (data.elem.checked) {
          $("input[lay-filter='floor']").prop("checked", true);
          $(".room.normal").addClass("checked")
        } else {
          $("input[lay-filter='floor']").prop("checked", false);
          $(".room.normal").removeClass("checked")
        }
        layui.form.render("checkbox", "floorform");
      })

      this.queryRoomStatus();
    }
  }

  renderClassInfo() {
    const self = this;
    let option = self.option.queryByClassId;
    const myQuery = {
      id: self.query.currentClassId
    };
    const callback = result => {
      $("#classInfo p:first-child").text(result.className);
      $("#classInfo p:last-child").text(result.startTime + " --- " + result.endTime);
      self.query.startTime = result.startTime;
      self.query.endTime = result.endTime;
      self.query.className = result.className;
      self.isFirstTime && self.pormiseJudge();
      self.renderTimeRange(result.startTime, result.endTime)
    };
    _ajaxFunc(callback, "GET", option, myQuery);
  }

  //渲染房间下拉列表
  renderRoomList() {
    const self = this;
    const option = self.option.roomList;
    const myQuery = {
      id: this.query.currentClassId
    };
    const callback = result => {
      const {label} = option;
      $("#roomList label").text(label);
      self.query.roomId = result[0].id;   //房间默认选中第一个
      self.isFirstTime && self.pormiseJudge();

      const optionList = result.map(item => `<option value="${item.id}">${item.roomName}</option>`);
      $("#roomList select").html(optionList);
      layui.form.render("select", "query");
      interactRoomList.call(self, ()=>{
        self.queryRoomStatus();
      })
    };
    _ajaxFunc(callback, "GET", option, myQuery);
  }

  //渲染宿舍列表
  renderDormitoryList() {
    const self = this;
    let option = self.option.dormitoryList;
    const callback = result => {
      self.query.dormId = result[0].id;   //宿舍默认选中第一个
      self.isFirstTime && self.pormiseJudge();

      const listEl = result.map(item => {
        return `<li data-id="${item.id}">${item.dormName}</li>`
      })
      $("#tab").html(listEl);
      $("#tab li:first-child").addClass("layui-this");
      interactDormList.call(self, ()=>{
        self.queryRoomStatus();
      })
    };

    _ajaxFunc(callback, "GET", option);
  }

  renderTimeRange(start, end) {
    const self = this;
    const laydate = layui.laydate;
    laydate.render({
      elem: "#startTime",
      value: start,
      done: function (value) {
        self.query.startTime = value;
      }
    });
    laydate.render({
      elem: "#endTime",
      value: end,
      done: function (value) {
        self.query.endTime = value;
      }
    });
  }

  //渲染所有的房间
  renderRoomItemList(result) {
    const self = this;
    const getRoomCss = status => {
      let variable;
      switch (status) {
        case "1":
          variable = "normal";
          break;
        case "3":
          variable = "seated";
          break;
        case "-1":
          variable = "broken";
          break;
      }
      return "room " + variable
    }
    const renderRoom = room => {
      return `<div class="${getRoomCss(room.status)}" data-roomid="${room.roomId}" data-status="${room.status}">
                <div><p>${room.roomTypeText}</p><p>${room.roomNum}</p></div>
                <div>${room.statusText}</div>
                <div><i class='layui-icon'>&#x1005;</i></div>
              </div>`
    };
    const renderFloor = (floor, roomList) => {
      return `<div class="floor">
                <div class="top">
                    <div>${floor.floorName}</div>
                    <div><span>${floor.roomTotal}</span>个房间（<span>${floor.occupyRoomNum}</span>间已用，<span>${floor.emptyRoomNum}</span>间未用）</div>
                     
                     <div class="checkbox" style=${floor.roomTotal === 0 ? "display:none" : ""}>
                        <form class="layui-form" lay-filter="floorform">
                          <input type="checkbox" title="全选" lay-skin="primary" lay-filter="floor">
                        </form>
                    </div>
                </div>
                <div class="inner">${roomList}</div>
            </div>`
    };
    for (let i = 0; i < result.length; i++) {
      result[i].children = result[i].children || [];
      let occupyRoomNum = 0;
      let emptyRoomNum = 0;
      let children = result[i].children;
      for (let j = 0; j < children.length; j++) {
        if (children[j].status === "1") emptyRoomNum += 1;
        if (children[j].status === "3") occupyRoomNum += 1;
      }

      result[i].emptyRoomNum = emptyRoomNum;
      result[i].occupyRoomNum = occupyRoomNum;
      result[i].roomTotal = children.length;
    }
    const floorList = result.map(floor => {
      const roomList = floor.children.map(room => {
        return renderRoom(room);
      });
      return renderFloor(floor, roomList)
    });
    if (floorList.length === 0) {
      const noMsg = `<div class="no-msg"><i class="layui-icon">&#xe650;</i>抱歉，没有可以分配的房间</div>`;
      $(".ds_hostel_floor").html(noMsg);
      return
    }
    $(".ds_hostel_floor").html(floorList);
    justifyCss(".room", 6);
    layui.form.render("checkbox");

    self.interactRoomItemList()
  }

  //添加选择各个房间的交互
  interactRoomItemList() {
    layui.form.on("checkbox(floor)", data => {
      if (data.elem.checked) {
        $(data.elem).parents(".floor").find(".room.normal").addClass("checked")
      } else {
        $(data.elem).parents(".floor").find(".room.normal").removeClass("checked")
      }

    });
    $(".room.normal").on("click", function () {
      if (!$(this).hasClass("checked")) {
        $(this).addClass("checked");
      } else {
        $(this).removeClass("checked");
      }
    })
  }

  queryRoomStatus() {
    const self = this;
    let option = self.option.roomStatus;
    if (!self.query.startTime || !self.query.endTime) {
      dsf.layer.message("日期范围不能为空", false);
      return;
    }

    let callback = result => {
      self.isFirstTime = false;
      self.renderRoomItemList(result);
    }
    _ajaxFunc(callback, "GET", option, self.query);
  }

  clearSeatedRoom(){
    const self = this;
    const option = self.option.restore;
    const data = {
      businessId: self.query.currentClassId
    }
    const callback = result => {
      dsf.layer.message("清除成功", true);
      self.queryRoomStatus()
    }
    _ajaxFunc(callback, "POST", option, data);
  }

  interactBtn() {
    const self = this;
    $("#queryBtn").on("click", function () {
      self.queryRoomStatus()
    });
    $("#restoreBtn").on("click", function () {
      dsf.layer.confirm("清除预留房间会将当前班级所有已分配且未被占用的房间清除，是否继续？", ()=>{
        self.clearSeatedRoom()
      })
    })
    $("#publishBtn").on("click", function () {
      const idArr = [];
      $(".room.checked").each(function () {
        idArr.push($(this).data("roomid"));
      })
      if (idArr.length === 0) {
        dsf.layer.confirm("未选择任何房间");
        return false
      }

      const reqData = {
        businessId: self.query.currentClassId,
        businessName: self.query.className,
        startTime: self.query.startTime,
        endTime: self.query.endTime,
        roomIdList: idArr
      }
      const option = self.option.publish;
      const callback = result => {
        dsf.layer.message("分配房间成功", true)
        self.queryRoomStatus()
      }
      _ajaxFunc(callback, "POST", option, reqData);
    })
  }

  mounted() {
    this.setOption();
    this.renderClassInfo();
    this.renderDormitoryList();
    this.renderRoomList();
    this.renderTimeRange();
    //创建按钮的交互
    this.interactBtn();
  }

  //加工配置
  setOption() {
    const self = this;
    self.query.currentClassId = dsf.url.queryString(self.option.classId);
    _.forOwn(self.option, (value, key) => {
      if (!_.isObject(value)) {
        self[key] = value;
      } else {
        const qObj = __setUrl(value);
        _.assign(value, qObj)
      }
    })
  }

  render(el) {
    const html = mainDom(this);
    $(el).html(html);
    this.mounted()
  }

}