import dome from "../../templates/HdMainLive.ejs";
import { map } from "../../../../decorator/controlmap";
import { ControlEditor } from "../../../../editor/ControlEditor";

@map("直播组件", "nc.teas.hdmainlive", "HdMainLive")
export class HdMainLive extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
    this.$useVdom = true;
    this._desingerClass = ControlEditor;
    this.sdata = {
      titleicon: "/dsfa/res/dsf_styles/themes/styleClass/teachers.png", //标题图片
      titleText: "直播列表",
      titleTextcolor: "",
      isshowBar: false, //是否显示菜单
      isshowChooseBtn: true, //是否显示操作按钮
      Btntext: "我要申请", //操作按钮文本
      Btnurl: "", //操作按钮链接
      ismoreBtn: true, //是否显示更多按钮
      moreBtnUrl: "nc/szk/views/mslist.html", //更多按钮链接
      moreBtnColor: "", //更多按钮颜色
    };
    this.liveParms = {
      pageNum: 1,
      pageSize: 4,
      querytype: 1,
      keywords: "",
    };
    this.count_1 = "";
    this.menuState = 1;
    this.$userId = "";
    this.$liveList = [];
    this.$defaultImgUrl = "/dsfa/res/dsf_styles/themes/nc/404.png";
    this.liveInPageNum = 1;
    this.lockBackPageNum = 1;
    this.liveActive = {};
  }

  initTemplate() {
    return dome(this);
  }

  inserted() {
    this.getLiveList(this.liveParms);
  }
  updated() {
    let _this = this;
  }
  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
    super.renderContext();
  }
  searchKey() {
    let _this = this;
    console.log(this._handlers.liveSearch.val());
    let _key = _this._handlers.liveSearch.val();
    _this.liveParms.keywords = _key;
    _this.liveParms.pageNum = 1;
    _this.getLiveList(_this.liveParms);
    _this.domUpdate();
  }
  /*//键盘搜索
   keyDown(event){  // 方向键控制元素移动函数
       let _this = this;
       var event = event || window.event;  // 标准化事件对象
       switch(event.keyCode){  // 获取当前按下键盘键的编码
           case 13 :  // 回车
               _this.searchKey();
               break;
       }
       return false
   }*/

  //获取列表
  getLiveList(parms) {
    let _this = this;
    if (!this.isDesign) {
      let url = dsf.url.getWebPath("nc/zbgl/list");
      dsf.http
        .request(url, parms, "get")
        .done(function(data) {
          if (data.state == 20000) {
            let _data = data.data.records;
            if (data.data.count > 0) {
              _this.count_1 = data.data.count;
            } else {
              _this.count_1 = 0;
            }
            _this.$userId = dsf.getCookie("userId");

            let _liveList = [];
            for (let i = 0; i < _data.length; i++) {
              let _info = _data[i];
              let _obj = {};
              let _ndate = new Date();
              let _sdate = new Date(Date.parse(_info.zbrq_sdate.replace(/-/g, "/")));
              let _edate = new Date(Date.parse(_info.zbrq_edate.replace(/-/g, "/")));
              //日期
              _obj.month =
                _ndate.getMonth() == _sdate.getMonth() && _ndate.getDate() == _sdate.getDate()
                  ? "今天"
                  : _this.formatterDate(_sdate, "month") + "." + _this.formatterDate(_sdate, "date");
              //开始时间
              _obj.sTime = _this.formatterDate(_sdate, "time");
              //结束时间
              _obj.eTime = _this.formatterDate(_edate, "time");
              //封面
              _obj.cover = _info.cover;
              //直播名称
              _obj.name = _info.name;
              //主讲人-职务
              _obj.speaker = _info.speaker + (_info.job ? "-" + _info.job : "");
              //预约人数
              _obj.yypeo = _info.yypeo;
              //直播时长
              _obj.sc = _info.sc;
              //直播状态
              _obj.state = _info.state; //1直播中，2预约，3回放
              //预约状态
              _obj.isyy_value = _info.isyy_value; //（当前登录人 已登录0:未预约，1：已预约),-1:未登录
              if (_info.state == 1) {
                //标签显示
                _obj.iconText = "直播中";
                //按钮显示
                _obj.btnText = "进入直播";
                //按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看
                _obj.btnOper = _info.isyy_value == -1 ? -1 : _info.isyy_value == 0 ? 1 : _info.isyy_value == 1 ? 2 : "";
              } else if (_info.state == 2) {
                _obj.iconText = "未开始";
                _obj.btnText = _info.isyy_value == 0 || _info.isyy_value == -1 ? "预约" : _info.isyy_value == 1 ? "已预约" : "";
                _obj.btnOper = _info.isyy_value == -1 ? -1 : _info.isyy_value == 0 ? 3 : _info.isyy_value == 1 ? 4 : "";
              } else if (_info.state == 3) {
                _obj.iconText = "已结束";
                _obj.btnText = "回放";
                _obj.btnOper = _info.isyy_value == -1 ? -1 : 5;
              }
              //剩余天数
              _obj.syts = _info.syts;
              //直播时长（暂无）

              //回放地址
              _obj.playback_url = _info.playback_url;

              //回放状态 （1.视频点播，2.钉钉回放地址，0.不能回放
              _obj.playstatus = _info.playstatus;

              //直播id
              _obj.nc_zbgl_jbxx_id = _info.nc_zbgl_jbxx_id;

              //直播群名字
              _obj.group_name = _info.group_name;

              //直播二维码
              _obj.qrcodeurl = _info.qrcodeurl ? dsf.url.getWebPath(_info.qrcodeurl) : "";

              //显示样式切换
              _obj.hoverChange = 1;

              //索引
              _obj.idx = i;
              _liveList.push(_obj);
            }
            _this.$liveList = _liveList;
            _this.renderPagination();
            _this.domUpdate();
          }
        })
        .error(function(err) {
          console.log(err);
        })
        .always(function() {})
        .exec();
    }
  }
  //按钮操作
  liveOper(item) {
    let _this = this;
    let _info = item;
    console.log(_info.btnOper);
    let _userId = dsf.getCookie("userId");
    if (true) {
      //_userId && _userId != '' && _info.btnOper != -1
      //按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看d
      if (_info.btnOper) {
        if (_info.btnOper == 3) {
          //预约
          _this.handleState(_info);
        } else if (_info.btnOper == 2) {
          let Url;
          Url = dsf.url.getWebPath("nc/pc/live/views/live.html") + "?id=" + _info["nc_zbgl_jbxx_id"];
          dsf.openUrl(1, Url);
        } else if (_info.btnOper == 4) {
          //取消预约
          // _this.handleState(_info);
          let Url;
          Url = dsf.url.getWebPath("nc/pc/live/views/live.html") + "?id=" + _info["nc_zbgl_jbxx_id"];
          dsf.openUrl(1, Url);
        } else if (_info.btnOper == 5 && _info.playstatus != 0) {
          let _url = dsf.url.getWebPath("nc/zbgl/playback");
          dsf.http
            .request(
              _url,
              {
                zbid: _info.nc_zbgl_jbxx_id,
              },
              "POST"
            )
            .done(function(data) {
              if (data.state == "20000") {
                let Url = "";
                //回看 playstatus==1 进入我们系统的直播页面 2 进入钉钉的直播
                if (_info.playstatus == 1) {
                  Url = dsf.url.getWebPath("nc/pc/live/views/live.html") + "?id=" + _info["nc_zbgl_jbxx_id"];
                } else if (_info.playstatus == 2) {
                  //  Url = dsf.url.getAbsolutePath(_info.playback_url);
                  Url = dsf.url.getWebPath("nc/pc/live/views/live.html") + "?id=" + _info["nc_zbgl_jbxx_id"];
                }
                dsf.openUrl(1, Url);
              } else {
                dsf.layer.message(data.message, false);
              }
            })
            .error(function(err) {
              console.log(err);
            })
            .always(function() {})
            .exec();

          // if(_info.playstatus == 2){
          //     let jumpUrl = _info.playback_url;
          //     window.open(jumpUrl, '_blank');
          // }else if(_info.playstatus == 1){
          //     let jumpUrl = _info.playback_url;
          //     window.open(jumpUrl, '_blank');
          // }
        } else if (_info.btnOper == 1) {
          //直播预约
          _this.handleState(_info);
        }
      }
    } else {
      //登录
      window.parent.openLogin();
    }
  }
  //直播状态处理
  handleState(item) {
    let _this = this;
    let url = dsf.url.getWebPath("nc/zbgl/zbOp");
    _this.liveActive = item;
    let _optype = item.btnOper == 3 ? 1 : item.btnOper == 5 ? 2 : item.btnOper == 4 ? 3 : item.btnOper == 1 ? 4 : null;
    //btnOper按钮操作状态 -1:未登录 1:已登陆-直播未预约 2:已登陆-直播已预约 3:已登陆-未开始未预约 4:已登陆-未开始已经预约 5:已结束-观看
    //_optype操作类型(1预约，2.观看，3取消预约,4.加入直播 )
    if (_optype) {
      let parms = {
        nc_zbid: item.nc_zbgl_jbxx_id,
        nc_students_id: dsf.getCookie("userId"), //实际不需要
        optype: _optype,
      };
      if (_optype == 4) {
        dsf.http
          .request(url, parms, "POST")
          .done(function(data) {
            if (data.state == "20000") {
              _this.getLiveList(_this.liveParms);
              _this.liveActive.hoverChange = 2;
              _this.domUpdate();
            } else {
              dsf.layer.message(data.message, false);
            }
          })
          .error(function(err) {
            console.log(err);
          })
          .always(function() {})
          .exec();
      } else {
        dsf.http
          .request(url, parms, "POST")
          .done(function(data) {
            if (data.state == "20000") {
              _this.getLiveList(_this.liveParms);
              _this.domUpdate();
            } else {
              dsf.layer.message(data.message, false);
            }
          })
          .error(function(err) {
            console.log(err);
          })
          .always(function() {})
          .exec();
      }
    }
  }
  //格式化时间
  formatterDate(date, type) {
    if (type == "month") {
      let _month = date.getMonth() + 1;
      if (_month >= 1 && _month <= 9) {
        _month = "0" + _month;
      }
      return _month;
    } else if (type == "date") {
      let _date = date.getDate();
      if (_date >= 0 && _date <= 9) {
        _date = "0" + _date;
      }
      return _date;
    } else if (type == "time") {
      let _h = date.getHours().toString();
      let _m = date.getMinutes().toString();
      if (_h >= 0 && _h <= 9) {
        _h = "0" + _h;
      }
      if (_m >= 0 && _m <= 9) {
        _m = "0" + _m;
      }
      // let _s = date.getSeconds().toString();
      return _h + ":" + _m;
    }
  }
  //鼠标划入
  liveActiveEnter(idx) {
    let _this = this;
    let _userId = dsf.getCookie("userId");
    //_userId == ''
    // _userId && _userId != '' && _this.$liveList[idx].btnOper == 2
    if (_userId && _userId != "" && _this.$liveList[idx].btnOper == 2) {
      _this.$liveList[idx].hoverChange = 2;
      _this.domUpdate();
    }
  }
  //鼠标移出
  liveActiveLeave(idx) {
    this.$liveList[idx].hoverChange = 1;
    this.domUpdate();
  }
  //获取图片地址
  getImageSrc(cover) {
    let _this = this;
    if (cover) {
      return dsf.url.getWebPath(JSON.parse(cover)[0].relativePath);
    } else {
      return _this.$defaultImgUrl;
    }
  }
  //获取二维码
  getQrSrc(qr) {
    let _this = this;
    if (qr) {
      return qr;
    }
  }

  menuChange(res) {
    let _this = this;
    if (res == 1) {
      _this.menuState = 1;
      _this.liveParms.querytype = 1;
      _this.liveParms.pageNum = _this.liveInPageNum;
      _this.liveParms.keywords = "";
      _this.getLiveList(_this.liveParms);
    } else if (res == 2) {
      _this.menuState = 2;
      _this.liveParms.querytype = 2;
      _this.liveParms.pageNum = _this.lockBackPageNum;
      _this.liveParms.keywords = "";
      _this.getLiveList(_this.liveParms);
    }
    _this.domUpdate();
  }
  //  渲染分页
  renderPagination() {
    console.log("渲染分页");
    let _this = this;
    layui.use(["laypage", "layer"], function() {
      let laypage = layui.laypage,
        layer = layui.layer;
      //执行一个laypage实例
      laypage.render({
        elem: "ds_live_list_page",
        count: _this.count_1,
        limit: _this.liveParms.pageSize,
        limits: _this.liveParms.pageSize,
        curr: _this.liveParms.pageNum,
        groups: 4,
        prev: "<i class='iconfont icon-left'></i>",
        next: "<i class='iconfont icon-right'></i>",
        layout: ["prev", "page", "next", "count"],
        jump: (obj, first) => {
          if (!first) {
            if (_this.liveParms.querytype == 1) {
              _this.liveInPageNum = obj.curr;
            } else if (_this.liveParms.querytype == 2) {
              _this.lockBackPageNum = obj.curr;
            }
            _this.liveParms.pageNum = obj.curr;
            _this.getLiveList(_this.liveParms);
            _this.domUpdate();
          }
        },
      });
    });
  }

  geturls(cover) {
    let urls = "";
    if (cover) {
      let cov = JSON.parse(cover);
      if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
    } else {
      urls = "res/dsf_styles/themes/nc/404.png";
    }
    return urls;
  }
  /* renderReady(){//组件加载完成后执行
     super.renderReady();
     this.ncliveList();
    }*/
  initEvent() {}
  // 改变字体颜色
  changeColor() {
    $(".module_title").css("color", this.fontCo);
  }

  //  是否显示副标题
  showSub() {
    if (this.showSubTitle) {
      this._handlers.setSubTitle.css("display", "block");
      this._handlers.setSubTitle.html(this.subTitle);
    } else {
      this._handlers.setSubTitle.css("display", "none");
    }
  }

  // 切换标题icon
  changeTitleIcon() {
    let leftImageUrl = {
      1: require("../../../../assets/themes/nc/icon_title_leftRed.png"),
      2: require("../../../../assets/themes/nc/icon_title_leftWhite.png"),
    };
    let rightImageUrl = {
      1: require("../../../../assets/themes/nc/icon_title_rightRed.png"),
      2: require("../../../../assets/themes/nc/icon_title_rightWhite.png"),
    };
    super.renderContext();

    this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

    this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
    if (this.switchIcon) {
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
    } else {
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
    }
  }

  set changeShowSub(v) {
    this.showSubTitle = v;
    this.showSub();
  }
  get changeShowSub() {
    return this.showSubTitle;
  }

  set changeIcon(v) {
    this.switchIcon = v;
    this.changeTitleIcon();
  }
  get changeIcon() {
    return this.switchIcon;
  }

  handleShowSubTitle() {
    this.showSub();
  }
  handleChangeIcon() {
    this.changeTitleIcon();
  }
  changeTitle() {
    let leftImageUrl = {
      1: require("../../../../assets/themes/nc/icon_title_leftRed.png"),
      2: require("../../../../assets/themes/nc/icon_title_leftWhite.png"),
      3: require("../../../../assets/themes/nc/icon_title_leftyellow.png"),
    };
    let rightImageUrl = {
      1: require("../../../../assets/themes/nc/icon_title_rightRed.png"),
      2: require("../../../../assets/themes/nc/icon_title_rightWhite.png"),
      3: require("../../../../assets/themes/nc/icon_title_rightyellow.png"),
    };
    this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

    this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
    if (this.iconnum == 1) {
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
    } else if (this.iconnum == 2) {
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
    } else if (this.iconnum == 3) {
      this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
      this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
    }
  }
}
