import dome from '../templates/News.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("新闻", 'nc.teas.news', 'News')
export class News extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
		this._desingerClass = ControlEditor;
		this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
		this.mainTitle = '主标题';
    this.subTitle = '副标题';
    this.showSubTitle = true;
    this.switchIcon = false;
    this.fontCo = '#333';
    this.iconnum = '1';
		
		this.parms={
  		words:'',
  		pageNum:'1',
  		pageSize:'6'
  	}
		this.newstextlist=[
    	{'name':'三十三颗红星在诉说','time':'2019-08-09'},
    	{'name':'三十三颗红星在诉说','time':'2019-08-09'},
    	{'name':'三十三颗红星在诉说','time':'2019-08-09'},
    	{'name':'三十三颗红星在诉说三十三颗红星在诉说三十三颗红星在诉说','time':'2019-08-09'},
    	{'name':'三十三颗红星在诉说','time':'2019-08-09'},
    	{'name':'三十三颗红星在诉说','time':'2019-08-09'}
    ];
    this.imgtoplist=[
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-1.jpg','text':'条目1'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg','text':'条目2'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-3.jpg','text':'条目3'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-4.jpg','text':'条目4'}
    ];
    this.imgbottomlist=[
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-1.jpg','text':'这是一段文本','time':'2019-08-09'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg','text':'这是一段文本这是一段文本这是一段文本','time':'2019-08-09'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg','text':'这是一段文本','time':'2019-08-09'},
    	{'src':'/dsfa/res/dsf_styles/themes/clientMainImg/deleteImg/delete1-2.jpg','text':'这是一段文本这是一段文本这是一段文本这是一段文本这是一段文本','time':'2019-08-09'}
    ];
  }

  initTemplate() {
    return dome(this);
  }

  createElement() {
    super.createElement();
    let _this=this;
		let url = dsf.url.getWebPath("nc/news/findNewsList");
    dsf.http.request_sync(
    	url,
    	_this.parms, 
    	"get"
    )
    .done(function (data) {
    	if(data.state==20000){
    		console.log(data);
    		_this.imgtoplist=data.data.lb;
    		_this.newstextlist = data.data.common.info;

    	}
    })
    .error(function (err) {
      console.log(err);
    })
    .always(function () {
    }).exec();
  }

  renderContext(refresh) {
		super.renderContext();
		this._handlers.setMainTitle.html(this.mainTitle);
    this._handlers.setSubTitle.html(this.subTitle);
    this.changeColor();
    this.changeTitleIcon();
    this.showSub();
    this.changeTitle()
	}
  geturls(cover){
		let urls ='';
		if(cover){
			let cov = JSON.parse(cover);
			if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
		}else{
			urls="res/dsf_styles/themes/nc/404.png"
		}
		return urls;
  }
  nbanner(){
  	let _this=this,shtml='',sd=this.imgtoplist;
  	_this.$ds_nc_newbanner = _this._handlers['ds_nc_newbanner'];
		if(sd.length==0){
			_this.$ds_nc_newbanner.html('<div style="text-align: center;margin-top:30px"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>');
		}else{
			for(var i=0,len=sd.length;i<len;i++){
				let urls = _this.geturls(sd[i].cover)
			  shtml+=`<div class="jsbitembox" id="`+sd[i].id+`">
						    	<div class="nc_new_nbanneritem">
						    		<img style="width: 100%;height: 100%;" src="`+dsf.url.getWebPath(urls)+`" onerror='onerror=null;src="${this.$defaultImgUrl}"'>
						    		<p>`+sd[i].cname+`</p>
						    	</div>
					    	</div>`;
			}
			_this.$ds_nc_newbanner.html(shtml);
		}
		_this.$ds_nc_newbanner.find('.jsbitembox').click(function(){
			let id = $(this).attr('id');
			dsf.openUrl(1,'/dsfa/nc/mhsy/views/xwxq.html?id='+id)
		})
  }
  nnewslist(){
  	let _this=this,shtml='',sd=this.newstextlist;
  	_this.$nc_new_nright = _this._handlers['nc_new_nright'];
		if(sd.length==0){
			_this.$nc_new_nright.html('<div style="text-align: center;"><img src="/dsfa/res/dsf_styles/themes/img/nodata.png"/></div>');
		}else{
			for(var i=0,len=sd.length;i<len;i++){
			  shtml+='<div class="nrow jsnrow" id="'+sd[i].id+'" handler="rightrow"><p class="ell">'+sd[i].cname+'</p><span>'+sd[i].ds_create_time+'</span></div>';
			}
			_this.$nc_new_nright.html(shtml);
		}
		_this.$nc_new_nright.find('.jsnrow p').click(function(){
			let id = $(this).parents('.nrow').attr('id');
			dsf.openUrl(1,'/dsfa/nc/mhsy/views/xwxq.html?id='+id)
		})
  }
	nbottomlist(){
		let _this=this,shtml='',sd=this.imgbottomlist;
		_this.$nbottom = _this._handlers['nbottom'];
		
		if(sd.length==0){
			_this.$nbottom.html('<div style="text-align: center;height: 218px;">暂无数据</div>');
		}else{
			for(var i=0,len=sd.length;i<len;i++){
				if(i==3){
			    shtml+='<div class="nc_new_nitem jsnitem" style="margin: 0;">'
										+'<div class="nimgb">'
											+'<img src="'+sd[i].src+'" class="">'
										+'</div>'
										+'<p class="nitemcon ell" title="'+sd[i].text+'">'+sd[i].text+'</p>'
										+'<span>'+sd[i].time+'</span>'
									+'</div>';
				}else{
					shtml+='<div class="nc_new_nitem jsnitem">'
										+'<div class="nimgb">'
											+'<img src="'+sd[i].src+'" class="">'
										+'</div>'
										+'<p class="nitemcon ell" title="'+sd[i].text+'">'+sd[i].text+'</p>'
										+'<span>'+sd[i].time+'</span>'
									+'</div>';
				}
			}
			_this.$nbottom.html(shtml);
		}
	}
	renderReady(){//组件加载完成后执行
		super.renderReady();
		this.nbanner();
		layui.use(['carousel', 'form'], function(){
			var carousel = layui.carousel
			,form = layui.form;
				carousel.render({
				  elem: '#test2'
				  ,interval: 1800
				  ,height: '100%'
				  ,width:'100%'
				  ,arrow:'none'
				});
		})
		this.nnewslist();
//		this.nbottomlist();//最下方横栏暂时隐藏,接口数据没有
	}
//	render(){
//		console.log(2);
//	}
  initEvent() {
  	console.log(222);
  }
	// 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
        		console.log('进');
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
    changeTitle(){
			let leftImageUrl = {
	            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
	            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
	            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
	        };
	        let rightImageUrl = {
	            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
	            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
	            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
	        };
	        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
	
	        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
	        if(this.iconnum==1){
	        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
	        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
	        }else if(this.iconnum==2){
	        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
	        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
	        }else if(this.iconnum==3){
	        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
	        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
	        }
		}
}

