import dome from '../templates/Nclive.ejs';
import { map } from '../../../decorator/controlmap';
import { ControlEditor } from '../../../editor/ControlEditor';

@map("首页直播", 'nc.teas.nvlive', 'Nclive')
export class Nclive extends dsf.Controls.Control {
  constructor(id, isPart) {
    super(id, isPart);
	this._desingerClass = ControlEditor;
	this.$defaultImgUrl = '/dsfa/res/dsf_styles/themes/nc/404.png';
    this.mainTitle = '主标题';
    this.subTitle = '副标题';
    this.showSubTitle = true;
    this.switchIcon = false;
    this.fontCo = '#333';
    this.iconnum = '1';
    this.parms={
    	pageNum:1,
    	pageSize:8
  	}
  }

  initTemplate() {
    return dome(this);  
  }

  createElement() {
    super.createElement();
  }

  renderContext(refresh) {
	super.renderContext();
	this._handlers.setMainTitle.html(this.mainTitle);
    this._handlers.setSubTitle.html(this.subTitle);
    this.changeColor();
    this.changeTitleIcon();
    this.showSub();
    this.changeTitle()
  }
  ncliveList(){
  	let loading = dsf.layer.loadding();
  	let _this = this;
		let url = dsf.url.getWebPath("nc/zbgl/list");
    dsf.http.request_sync(
    	url,
    	_this.parms, 
    	"get"
    )
    .done(function (data) {
    	if(data.state==20000){
    		let shtml='',sd=data.data.records,choosehtml="",islivehtml="";
				_this.$ds_nc_nclive = _this._handlers['ds_nc_nclive'];
		  	for(var i=0,len=sd.length;i<len;i++){
		  			let urls = _this.geturls(sd[i].cover);
		  			if(sd[i].state == 1){
		  				choosehtml='<span class="colorblue">直播预告</span>';
		  				islivehtml='';
		  			}else if(sd[i].state == 2){
		  				choosehtml='<span class="colorred">正在直播</span>';
		  				islivehtml='<div class="liveicon"></div>';
		  			}else if(sd[i].state == 3){
		  				choosehtml='<span class="coloryellow">直播回放</span>';
		  				islivehtml='';
		  			}
		  	    shtml+=`<div class="liveitem" id="`+sd[i]._id+`">
					    	<div class="imgbox">
					    		<img src="`+dsf.url.getWebPath(urls)+`" onerror="onerror=null;src='`+dsf.url.getWebPath('res/dsf_styles/themes/nc/404.png')+`'" />
					    	</div>
					    	<div class="titlebox">
					    		<p class="ell2" title="`+(sd[i].abstract==null?"":sd[i].abstract)+`">`+choosehtml+(sd[i].abstract==null?"":sd[i].abstract)+`</p>
					    	</div>
					    	<div class="footbox">
					    		<p class="p2"><span></span><b>`+sd[i].gkpeo+`</b></p>
					    	</div>
					    	`+islivehtml+`
					    </div>`;
		  	}
		  	_this.$ds_nc_nclive.html(shtml);
		  	_this.$ds_nc_nclive.find('.liveitem').click(function(){
		  		let id = $(this).attr('id');
		  		var ur = dsf.url.getWebPath('nc/pc/main/views/main.html?id='+id);
		  		dsf.openUrl(1,ur)
		  	})
				
    	}
    })
    .error(function (err) {
      console.log(err);
    })
    .always(function () {
    	dsf.layer.close(loading);
    }).exec();
  	
  }
  geturls(cover){
		let urls ='';
		if(cover){
			let cov = JSON.parse(cover);
			if ($.isArray(cov)) {
        urls = cov[0].relativePath;
      }
		}else{
			urls="res/dsf_styles/themes/nc/404.png"
		}
		return urls;
  }
  renderReady(){//组件加载完成后执行
	super.renderReady();
	this.ncliveList();
  }
  initEvent() {
  }
	// 改变字体颜色
    changeColor() {
        $('.module_title').css('color',this.fontCo);
    }

    //  是否显示副标题
    showSub() {
        if (this.showSubTitle) {
            this._handlers.setSubTitle.css('display','block');
            this._handlers.setSubTitle.html(this.subTitle);
        } else {
            this._handlers.setSubTitle.css('display','none');
        }
    }

    // 切换标题icon
    changeTitleIcon() {
        let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png')
        };
        super.renderContext();

        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if (this.switchIcon) {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        } else {
            this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
            this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }
    }

    set changeShowSub(v) {
        this.showSubTitle = v;
        this.showSub();
    }
    get changeShowSub() {
        return this.showSubTitle;
    }

    set changeIcon(v) {
        this.switchIcon = v;
        this.changeTitleIcon();
    }
    get changeIcon() {
        return this.switchIcon;
    }

    handleShowSubTitle() {
        this.showSub();
    }
    handleChangeIcon() {
        this.changeTitleIcon()
    }
    changeTitle(){
		let leftImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_leftRed.png'),
            2: require('../../../assets/themes/nc/icon_title_leftWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_leftyellow.png'),
        };
        let rightImageUrl = {
            1: require('../../../assets/themes/nc/icon_title_rightRed.png'),
            2: require('../../../assets/themes/nc/icon_title_rightWhite.png'),
            3: require('../../../assets/themes/nc/icon_title_rightyellow.png')
        };
        this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));

        this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        if(this.iconnum==1){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[1]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[1]));
        }else if(this.iconnum==2){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[2]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[2]));
        }else if(this.iconnum==3){
        	this._handlers.photoImgLeft.attr("src", dsf.url.getWebPath("res/dsf_styles/" + leftImageUrl[3]));
        	this._handlers.photoImgRight.attr("src", dsf.url.getWebPath("res/dsf_styles/" + rightImageUrl[3]));
        }
	}
}

